import { Vector3 } from 'three';

export enum GameStatus {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  PAUSED = 'PAUSED',
  LEVEL_UP = 'LEVEL_UP',
  GAME_OVER = 'GAME_OVER',
}

export type UpgradeType = 'HEALTH' | 'SPEED' | 'DAMAGE' | 'FIRE_RATE' | 'MULTISHOT' | 'DASH_COOLDOWN';

export interface Upgrade {
  id: string;
  type: UpgradeType;
  name: string;
  description: string;
  rarity: 'COMMON' | 'RARE' | 'LEGENDARY';
  value: number;
}

export interface PlayerStats {
  maxHealth: number;
  moveSpeed: number;
  damage: number;
  fireRate: number; // bullets per second
  projectileSpeed: number;
  multishot: number;
  spread: number;
  dashCooldown: number;
}

export interface EnemyData {
  id: string;
  position: Vector3;
  type: 'CHASER' | 'SHOOTER' | 'TANK';
  health: number;
  maxHealth: number;
  speed: number;
  radius: number;
}

export interface BulletData {
  id: number;
  position: Vector3;
  velocity: Vector3;
  active: boolean;
  lifetime: number;
  isEnemy: boolean;
  damage: number;
}

export const ARENA_SIZE = 60;
export const MAX_BULLETS = 2000;
export const PLAYER_RADIUS = 0.6;
export const CAMERA_HEIGHT = 35;

export const COLORS = {
  background: '#050505',
  player: '#00f3ff', // Cyan
  enemyChaser: '#ff0055', // Red/Pink
  enemyTank: '#ff7700', // Orange
  enemyShooter: '#aa00ff', // Purple
  bulletPlayer: '#ccff00', // Lime
  bulletEnemy: '#ff0000', // Red
  grid: '#1a1a1a',
  uiPrimary: '#ffffff',
  uiSecondary: '#444444',
};

export const UPGRADES_POOL: any[] = [
  { type: 'HEALTH', name: 'Nano-Repair', description: 'Heal 50% HP & Increase Max HP by 25', rarity: 'COMMON', value: 25 },
  { type: 'SPEED', name: 'Velocity Drive', description: 'Movement Speed +15%', rarity: 'COMMON', value: 0.15 },
  { type: 'DAMAGE', name: 'Plasma Core', description: 'Damage +20%', rarity: 'RARE', value: 0.2 },
  { type: 'FIRE_RATE', name: 'Overclocker', description: 'Fire Rate +15%', rarity: 'RARE', value: 0.15 },
  { type: 'MULTISHOT', name: 'Split Chamber', description: 'Add +1 Projectile', rarity: 'LEGENDARY', value: 1 },
  { type: 'DASH_COOLDOWN', name: 'Phase Shift', description: 'Dash Cooldown -20%', rarity: 'COMMON', value: 0.2 },
];

import { create } from 'zustand';
import { GameStatus, PlayerStats, Upgrade } from './types';
import { Vector3 } from 'three';

interface GameState {
  status: GameStatus;
  score: number;
  level: number;
  experience: number;
  experienceToNextLevel: number;
  health: number;
  playerPosition: Vector3;
  stats: PlayerStats;

  // Actions
  setStatus: (status: GameStatus) => void;
  startGame: () => void;
  addScore: (amount: number) => void;
  addExperience: (amount: number) => void;
  takeDamage: (amount: number) => void;
  heal: (amount: number) => void;
  setPlayerPosition: (pos: Vector3) => void;
  applyUpgrade: (upgrade: Upgrade) => void;
  resetGame: () => void;
}

const INITIAL_STATS: PlayerStats = {
  maxHealth: 100,
  moveSpeed: 12,
  damage: 10,
  fireRate: 6,
  projectileSpeed: 25,
  multishot: 1,
  spread: 0.2,
  dashCooldown: 2.0,
};

export const useGameStore = create<GameState>((set, get) => ({
  status: GameStatus.MENU,
  score: 0,
  level: 1,
  experience: 0,
  experienceToNextLevel: 100,
  health: 100,
  playerPosition: new Vector3(0, 0, 0),
  stats: { ...INITIAL_STATS },

  setStatus: (status) => set({ status }),

  startGame: () => set({
    status: GameStatus.PLAYING,
    score: 0,
    level: 1,
    experience: 0,
    experienceToNextLevel: 100,
    health: 100,
    stats: { ...INITIAL_STATS },
    playerPosition: new Vector3(0, 0, 0),
  }),

  addScore: (amount) => set((state) => ({ score: state.score + amount })),

  addExperience: (amount) => {
    const { experience, experienceToNextLevel, level, status } = get();
    let newExp = experience + amount;

    if (newExp >= experienceToNextLevel) {
      set({
        experience: newExp - experienceToNextLevel,
        experienceToNextLevel: Math.floor(experienceToNextLevel * 1.5),
        level: level + 1,
        status: GameStatus.LEVEL_UP,
      });
    } else {
      set({ experience: newExp });
    }
  },

  takeDamage: (amount) => {
    const { health, status } = get();
    if (status !== GameStatus.PLAYING) return;

    const newHealth = health - amount;
    if (newHealth <= 0) {
      set({ health: 0, status: GameStatus.GAME_OVER });
    } else {
      set({ health: newHealth });
    }
  },

  heal: (amount) => set((state) => ({ 
    health: Math.min(state.health + amount, state.stats.maxHealth) 
  })),

  setPlayerPosition: (pos) => set({ playerPosition: pos }),

  applyUpgrade: (upgrade) => set((state) => {
    const newStats = { ...state.stats };

    switch (upgrade.type) {
      case 'HEALTH':
        newStats.maxHealth += upgrade.value;
        return { stats: newStats, health: Math.min(state.health + (state.stats.maxHealth * 0.5), newStats.maxHealth), status: GameStatus.PLAYING };
      case 'SPEED':
        newStats.moveSpeed *= (1 + upgrade.value);
        break;
      case 'DAMAGE':
        newStats.damage *= (1 + upgrade.value);
        break;
      case 'FIRE_RATE':
        newStats.fireRate *= (1 + upgrade.value);
        break;
      case 'MULTISHOT':
        newStats.multishot += upgrade.value;
        break;
      case 'DASH_COOLDOWN':
        newStats.dashCooldown *= (1 - upgrade.value);
        break;
    }
    return { stats: newStats, status: GameStatus.PLAYING };
  }),

  resetGame: () => set({
    status: GameStatus.MENU,
  }),
}));

import React, { Suspense } from 'react';
import { Canvas } from '@react-three/fiber';
import { EffectComposer, Bloom, Vignette } from '@react-three/postprocessing';
import { World } from './World';
import { COLORS } from '../constants';

export const GameCanvas: React.FC = () => {
  return (
    <Canvas
      dpr={[1, 2]} // Optimize pixel ratio
      shadows={false}
      camera={{ position: [0, 35, 20], fov: 45 }}
      gl={{ antialias: false, stencil: false, depth: true }}
    >
      <color attach="background" args={[COLORS.background]} />

      <Suspense fallback={null}>
        <World />
      </Suspense>

      <EffectComposer disableNormalPass>
        <Bloom 
          luminanceThreshold={0.4} 
          luminanceSmoothing={0.9} 
          intensity={1.5} 
          radius={0.6}
        />
        <Vignette eskil={false} offset={0.1} darkness={1.1} />
      </EffectComposer>
    </Canvas>
  );
};

import React, { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import { Plane, Grid } from '@react-three/drei';
import { Player } from './Player';
import { EnemyManager } from './EnemyManager';
import { ARENA_SIZE, COLORS } from '../constants';
import { useGameStore } from '../store';
import { GameStatus } from '../types';

export const World: React.FC = () => {
  const status = useGameStore((state) => state.status);
  const gridRef = useRef<any>(null);

  useFrame((state) => {
    if (gridRef.current) {
      // Subtle breathing effect for the grid
      const time = state.clock.getElapsedTime();
      gridRef.current.material.opacity = 0.3 + Math.sin(time) * 0.1;
    }
  });

  return (
    <>
      {/* Lights */}
      <ambientLight intensity={0.5} />
      <pointLight position={[10, 20, 10]} intensity={1} color={COLORS.player} distance={50} />
      <pointLight position={[-10, 20, -10]} intensity={0.5} color={COLORS.enemyChaser} distance={50} />

      {/* Floor Grid */}
      <Grid
        ref={gridRef}
        position={[0, -0.01, 0]}
        args={[ARENA_SIZE * 2, ARENA_SIZE * 2]}
        cellSize={2}
        cellThickness={1}
        cellColor={COLORS.grid}
        sectionSize={10}
        sectionThickness={1.5}
        sectionColor="#333"
        fadeDistance={40}
        infiniteGrid
      />

      {/* Floor Plane for Raycasting */}
      <Plane 
        args={[ARENA_SIZE * 2, ARENA_SIZE * 2]} 
        rotation={[-Math.PI / 2, 0, 0]} 
        position={[0, -0.1, 0]}
        visible={false}
      />

      {/* Game Entities */}
      {(status === GameStatus.PLAYING || status === GameStatus.LEVEL_UP || status === GameStatus.GAME_OVER) && (
        <>
          <Player />
          <EnemyManager />
        </>
      )}
    </>
  );
};

import React, { useRef, useState } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { Vector3, Plane, Raycaster } from 'three';
import { useGameStore } from '../store';
import { COLORS, PLAYER_RADIUS, ARENA_SIZE } from '../constants';
import { BulletManager } from './BulletManager';
import { GameStatus } from '../types';

export const Player: React.FC = () => {
  const meshRef = useRef<any>(null);
  const { stats, status, setPlayerPosition } = useGameStore();
  const { camera, scene, pointer } = useThree();

  // Local state for movement smoothing
  const [pos] = useState(new Vector3(0, 0, 0));
  const [velocity] = useState(new Vector3(0, 0, 0));
  const [lastShotTime, setLastShotTime] = useState(0);
  const [keys, setKeys] = useState<{ [key: string]: boolean }>({});

  // Raycaster for mouse aiming
  const raycaster = new Raycaster();
  const groundPlane = new Plane(new Vector3(0, 1, 0), 0);
  const mousePos = useRef(new Vector3(0, 0, 0));
  const isShooting = useRef(false);

  // Input handling
  React.useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      setKeys((k) => ({ ...k, [e.code]: true }));
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      setKeys((k) => ({ ...k, [e.code]: false }));
    };
    const handleMouseDown = () => { isShooting.current = true; };
    const handleMouseUp = () => { isShooting.current = false; };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousedown', handleMouseDown);
    window.addEventListener('mouseup', handleMouseUp);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousedown', handleMouseDown);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, []);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    // 1. Movement Logic
    const moveDir = new Vector3(0, 0, 0);
    if (keys['KeyW'] || keys['ArrowUp']) moveDir.z -= 1;
    if (keys['KeyS'] || keys['ArrowDown']) moveDir.z += 1;
    if (keys['KeyA'] || keys['ArrowLeft']) moveDir.x -= 1;
    if (keys['KeyD'] || keys['ArrowRight']) moveDir.x += 1;

    moveDir.normalize();

    // Apply velocity with simple friction/acceleration feel
    velocity.lerp(moveDir.multiplyScalar(stats.moveSpeed), delta * 10);
    pos.add(velocity.clone().multiplyScalar(delta));

    // Clamp position to arena
    pos.x = Math.max(-ARENA_SIZE / 2 + 1, Math.min(ARENA_SIZE / 2 - 1, pos.x));
    pos.z = Math.max(-ARENA_SIZE / 2 + 1, Math.min(ARENA_SIZE / 2 - 1, pos.z));

    meshRef.current.position.copy(pos);
    setPlayerPosition(pos.clone());

    // 2. Aiming Logic (Raycast to floor)
    raycaster.setFromCamera(pointer, camera);
    const target = new Vector3();
    raycaster.ray.intersectPlane(groundPlane, target);
    if (target) {
        mousePos.current.copy(target);
        meshRef.current.lookAt(target.x, 1, target.z);
    }

    // 3. Camera Follow
    const targetCamPos = new Vector3(pos.x, 35, pos.z + 20);
    camera.position.lerp(targetCamPos, delta * 5);
    camera.lookAt(pos.x, 0, pos.z);

    // 4. Shooting Logic (Handled in BulletManager, but triggered here or passed via state)
    // Actually, passing the trigger to BulletManager is cleaner, but let's pass a ref or callback.
  });

  return (
    <>
      <group ref={meshRef} position={[0, 1, 0]}>
        {/* Player Body */}
        <mesh castShadow receiveShadow>
          <boxGeometry args={[1, 1, 1]} />
          <meshStandardMaterial 
            color={COLORS.player} 
            emissive={COLORS.player}
            emissiveIntensity={2}
            roughness={0.2}
            metalness={0.8}
          />
        </mesh>

        {/* Direction Indicator */}
        <mesh position={[0, 0, -0.8]} rotation={[Math.PI / 2, 0, 0]}>
            <coneGeometry args={[0.3, 0.8, 4]} />
            <meshBasicMaterial color="#ffffff" />
        </mesh>
      </group>

      {/* Bullet System needs to know player status */}
      <BulletManager 
        playerPos={pos} 
        isShooting={isShooting.current} 
        aimPos={mousePos.current}
      />
    </>
  );
};

import React, { useRef, useLayoutEffect, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, DynamicDrawUsage } from 'three';
import { useGameStore } from '../store';
import { MAX_BULLETS, COLORS } from '../constants';
import { GameStatus } from '../types';

interface BulletManagerProps {
  playerPos: Vector3;
  isShooting: boolean;
  aimPos: Vector3;
}

// Reuse objects to reduce GC
const dummy = new Object3D();
const _bulletPos = new Vector3();
const _bulletVel = new Vector3();

export const BulletManager: React.FC<BulletManagerProps> = ({ playerPos, isShooting, aimPos }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const { stats, status } = useGameStore();

  // Data structure for active bullets
  // Using a flat array of objects is acceptable for < 2000 items in JS if we don't allocate new ones
  const bullets = useRef(new Array(MAX_BULLETS).fill(0).map(() => ({
    active: false,
    position: new Vector3(),
    velocity: new Vector3(),
    lifetime: 0
  })));

  const lastShot = useRef(0);

  // Initialize instance matrix
  useLayoutEffect(() => {
    if (meshRef.current) {
        meshRef.current.instanceMatrix.setUsage(DynamicDrawUsage);
    }
  }, []);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    const time = state.clock.getElapsedTime();

    // 1. Spawning Logic
    const fireInterval = 1 / stats.fireRate;
    if (isShooting && time - lastShot.current > fireInterval) {
      lastShot.current = time;

      const dir = new Vector3().subVectors(aimPos, playerPos).normalize();

      // Multishot logic
      const startAngle = - (stats.spread * (stats.multishot - 1)) / 2;

      for (let i = 0; i < stats.multishot; i++) {
        const bullet = bullets.current.find(b => !b.active);
        if (bullet) {
            bullet.active = true;
            bullet.lifetime = 2.0; // 2 seconds life
            bullet.position.copy(playerPos).add(new Vector3(0, 0, 0)); // Start at player

            // Calculate spread
            const angle = startAngle + (i * stats.spread);
            // Rotate direction vector around Y axis
            const spreadDir = dir.clone().applyAxisAngle(new Vector3(0, 1, 0), angle);

            bullet.velocity.copy(spreadDir).multiplyScalar(stats.projectileSpeed);
        }
      }
    }

    // 2. Update & Render Logic
    let activeCount = 0;
    for (let i = 0; i < MAX_BULLETS; i++) {
        const b = bullets.current[i];
        if (b.active) {
            // Update pos
            b.position.add(b.velocity.clone().multiplyScalar(delta));
            b.lifetime -= delta;

            // Deactivate if too old or out of bounds (simple optimization)
            if (b.lifetime <= 0) {
                b.active = false;
                // Hide it
                dummy.position.set(0, -100, 0);
            } else {
                dummy.position.copy(b.position);
                dummy.scale.set(1, 1, 1); // Reset scale
            }
            activeCount++;
        } else {
            dummy.position.set(0, -100, 0); // Hide inactive
            dummy.scale.set(0, 0, 0);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;

    // Collision detection is handled by the EnemyManager checking against these bullets usually,
    // OR we expose these bullets via a ref/store. 
    // For performance in React Three Fiber, passing refs is best.
    // We attach the bullets array to the mesh userData so EnemySystem can read it
    meshRef.current.userData = { bullets: bullets.current, damage: stats.damage };
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, MAX_BULLETS]} frustumCulled={false}>
      <sphereGeometry args={[0.2, 8, 8]} />
      <meshBasicMaterial color={COLORS.bulletPlayer} toneMapped={false} />
    </instancedMesh>
  );
};

import React, { useRef, useState } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, DynamicDrawUsage, Color } from 'three';
import { useGameStore } from '../store';
import { ARENA_SIZE, COLORS } from '../constants';
import { GameStatus } from '../types';

const MAX_ENEMIES = 500;
const SPAWN_RATE = 1.5; // Seconds

// Reusable objects
const dummy = new Object3D();
const tempVec = new Vector3();
const tempColor = new Color();

export const EnemyManager: React.FC = () => {
  const meshRef = useRef<InstancedMesh>(null);
  const { playerPosition, addScore, addExperience, takeDamage, status, level } = useGameStore();
  const { scene } = useThree();

  // Enemy State managed in a Ref for performance
  const enemies = useRef(new Array(MAX_ENEMIES).fill(0).map(() => ({
    active: false,
    id: 0,
    type: 0, // 0: Chaser, 1: Tank, 2: Fast
    hp: 100,
    maxHp: 100,
    position: new Vector3(),
    speed: 5,
    radius: 0.8
  })));

  const spawnTimer = useRef(0);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    // 1. Spawning
    spawnTimer.current += delta;
    const currentSpawnRate = Math.max(0.2, SPAWN_RATE - (level * 0.1));

    if (spawnTimer.current > currentSpawnRate) {
        spawnTimer.current = 0;
        const enemy = enemies.current.find(e => !e.active);
        if (enemy) {
            enemy.active = true;
            // Spawn at random edge
            const angle = Math.random() * Math.PI * 2;
            const dist = (ARENA_SIZE / 2) - 2;
            enemy.position.set(Math.cos(angle) * dist, 1, Math.sin(angle) * dist);

            // Stats based on level
            const r = Math.random();
            if (r > 0.8) {
                // Tank
                enemy.type = 1;
                enemy.hp = 50 + (level * 10);
                enemy.maxHp = enemy.hp;
                enemy.speed = 3 + (level * 0.1);
                tempColor.set(COLORS.enemyTank);
            } else if (r > 0.6) {
                // Fast
                enemy.type = 2;
                enemy.hp = 10 + (level * 2);
                enemy.maxHp = enemy.hp;
                enemy.speed = 8 + (level * 0.2);
                tempColor.set(COLORS.enemyShooter);
            } else {
                // Chaser
                enemy.type = 0;
                enemy.hp = 20 + (level * 5);
                enemy.maxHp = enemy.hp;
                enemy.speed = 5 + (level * 0.1);
                tempColor.set(COLORS.enemyChaser);
            }
            meshRef.current.setColorAt(enemies.current.indexOf(enemy), tempColor);
            meshRef.current.instanceColor!.needsUpdate = true;
        }
    }

    // 2. Logic & Collision
    // Access bullet system from scene graph if possible, or assume simple logic
    // Finding the bullet mesh in the scene:
    const bulletMesh = scene.children.find(c => c.type === 'InstancedMesh' && c.userData?.bullets) as InstancedMesh;
    const activeBullets = bulletMesh?.userData?.bullets || [];
    const bulletDamage = bulletMesh?.userData?.damage || 10;

    for (let i = 0; i < MAX_ENEMIES; i++) {
        const e = enemies.current[i];
        if (e.active) {
            // Movement towards player
            tempVec.subVectors(playerPosition, e.position).normalize();
            e.position.add(tempVec.multiplyScalar(e.speed * delta));

            // Separation (boids-lite) - very expensive O(N^2), skip for now or do simple check
            // Keeping it simple: Just move to player.

            // Player Collision
            const distToPlayer = e.position.distanceTo(playerPosition);
            if (distToPlayer < 1.5) {
                takeDamage(10 * delta); // DOT
            }

            // Bullet Collision (Brute force for now, efficient enough for < 1000 bullets x 100 enemies in JS if optimized)
            // Optimization: Spatial Hashing is better, but simple distance check works for demo
            for(let b=0; b < activeBullets.length; b++) {
                const bullet = activeBullets[b];
                if (bullet.active) {
                    const distSq = bullet.position.distanceToSquared(e.position);
                    if (distSq < (e.radius + 0.5) * (e.radius + 0.5)) {
                        e.hp -= bulletDamage;
                        bullet.active = false; // Destroy bullet
                        bullet.lifetime = 0;

                        // Flash effect logic could go here
                    }
                }
            }

            // Death Logic
            if (e.hp <= 0) {
                e.active = false;
                addScore(10 * (e.type + 1));
                addExperience(10 * (e.type + 1));
                dummy.position.set(0, -100, 0);
            } else {
                // Update Mesh
                dummy.position.copy(e.position);
                dummy.lookAt(playerPosition);

                // Scale "pop" on hit could go here
                const scale = e.type === 1 ? 1.5 : 1;
                dummy.scale.set(scale, scale, scale);
            }

        } else {
            dummy.position.set(0, -100, 0);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, MAX_ENEMIES]} frustumCulled={false}>
      <boxGeometry args={[1, 1, 1]} />
      <meshStandardMaterial 
        vertexColors 
        emissive="white" 
        emissiveIntensity={0.5}
        toneMapped={false}
      />
    </instancedMesh>
  );
};

import React, { useEffect, useState } from 'react';
import { useGameStore } from '../store';
import { GameStatus, Upgrade } from '../types';
import { COLORS, UPGRADES_POOL } from '../constants';
import { Heart, Zap, Crosshair, ChevronsUp, Activity, Play, RotateCcw } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

export const GameUI: React.FC = () => {
  const { 
    status, health, stats, score, level, experience, experienceToNextLevel, 
    startGame, resetGame, applyUpgrade 
  } = useGameStore();

  const [availableUpgrades, setAvailableUpgrades] = useState<Upgrade[]>([]);

  // Generate random upgrades on level up
  useEffect(() => {
    if (status === GameStatus.LEVEL_UP) {
      const shuffled = [...UPGRADES_POOL].sort(() => 0.5 - Math.random());
      setAvailableUpgrades(shuffled.slice(0, 3));
    }
  }, [status]);

  const hpPercent = (health / stats.maxHealth) * 100;
  const xpPercent = (experience / experienceToNextLevel) * 100;

  return (
    <div className="absolute inset-0 pointer-events-none flex flex-col justify-between p-6 z-10 font-mono tracking-wider text-white">

      {/* HUD - Always visible during gameplay */}
      {(status === GameStatus.PLAYING || status === GameStatus.LEVEL_UP) && (
        <>
          {/* Top Bar */}
          <div className="flex justify-between items-start w-full">
            <div className="flex flex-col gap-2">
