  position: Vector3;
  type: number; // 0: Slime, 1: Orc, 2: Boss
  health: number;
  maxHealth: number;
  speed: number;
  radius: number;
  scale: number;
  active: boolean;
  // Boss specific
  state?: 'CHASE' | 'CHARGE_PREP' | 'CHARGE';
  stateTimer?: number;
}

export interface BulletData {
  id: number;
  position: Vector3;
  velocity: Vector3;
  active: boolean;
  lifetime: number;
}

export interface CrateData {
  id: number;
  position: Vector3;
  active: boolean;
  rotation: number;
}

