  const trees = useMemo(() => {
    return new Array(40).fill(0).map((_, i) => ({
      x: (Math.random() - 0.5) * ARENA_SIZE * 1.8,
      z: (Math.random() - 0.5) * ARENA_SIZE * 1.8,
      scale: 1 + Math.random() * 2
    })).filter(pos => Math.sqrt(pos.x*pos.x + pos.z*pos.z) > 15); // Clear spawn area
  }, []);

  const rocks = useMemo(() => {
    return new Array(20).fill(0).map((_, i) => ({
      x: (Math.random() - 0.5) * ARENA_SIZE * 1.8,
      z: (Math.random() - 0.5) * ARENA_SIZE * 1.8,
      scale: 0.5 + Math.random(),
    })).filter(pos => Math.sqrt(pos.x*pos.x + pos.z*pos.z) > 10);
  }, []);

  return (
    <group>
      {/* Trees */}
      <Instances range={trees.length}>
        <cylinderGeometry args={[0.2, 0.5, 4, 8]} />
        <meshStandardMaterial color={COLORS.wood} />
        {trees.map((t, i) => (
            <group key={i} position={[t.x, 2, t.z]} scale={[t.scale, t.scale, t.scale]}>
                <Instance />
                {/* Foliage */}
