                            onUpgrade={() => equipment.weapon && upgradeItem(equipment.weapon)}
                            canUpgrade={!!equipment.weapon && score >= Math.floor(equipment.weapon.price * equipment.weapon.level * 0.5)}
                            upgradeCost={equipment.weapon ? Math.floor(equipment.weapon.price * equipment.weapon.level * 0.5) : 0}
                        />
                        <EquipmentSlot 
                            icon={<Shield size={24}/>} 
                            label="Armor" 
                            item={equipment.armor} 
                            onClick={() => unequipItem('armor')} 
                            onUpgrade={() => equipment.armor && upgradeItem(equipment.armor)}
                            canUpgrade={!!equipment.armor && score >= Math.floor(equipment.armor.price * equipment.armor.level * 0.5)}
                            upgradeCost={equipment.armor ? Math.floor(equipment.armor.price * equipment.armor.level * 0.5) : 0}
                        />
                        <EquipmentSlot 
                            icon={<Gem size={24}/>} 
                            label="Accessory" 
                            item={equipment.accessory} 
                            onClick={() => unequipItem('accessory')} 
                            onUpgrade={() => equipment.accessory && upgradeItem(equipment.accessory)}
                            canUpgrade={!!equipment.accessory && score >= Math.floor(equipment.accessory.price * equipment.accessory.level * 0.5)}
                            upgradeCost={equipment.accessory ? Math.floor(equipment.accessory.price * equipment.accessory.level * 0.5) : 0}
                        />

                        <div className="mt-auto w-full text-xs text-slate-500 space-y-2 pt-4 border-t border-slate-800">
                            <div className="flex justify-between"><span>DMG</span> <span className="text-white">{Math.round(stats.damage)}</span></div>
                            <div className="flex justify-between"><span>HP</span> <span className="text-white">{stats.maxHealth}</span></div>
                            <div className="flex justify-between"><span>SPD</span> <span className="text-white">{stats.moveSpeed.toFixed(1)}</span></div>
                            <div className="flex justify-between"><span>MAG</span> <span className="text-white">{stats.magnetRadius.toFixed(1)}</span></div>
                        </div>
                    </div>

                    {/* Inventory Grid */}
                    <div className="w-2/3 bg-slate-950/30 p-6 rounded-lg">
                        <div className="w-full text-slate-400 mb-4 text-sm font-bold">BACKPACK</div>
                        <div className="grid grid-cols-5 gap-3 max-h-[400px] overflow-y-auto">
                            {inventory.map((item, idx) => {
                                const upgradeCost = Math.floor(item.price * item.level * 0.5);
                                return (
                                <div key={idx} className="relative group">
                                    <button 
                                        onClick={() => equipItem(item)}
                                        className="w-full aspect-square bg-slate-800 border border-slate-700 hover:border-blue-500 rounded flex flex-col items-center justify-center p-2 transition-transform"
                                    >
                                        {item.type === 'WEAPON' && <Sword size={20} className="text-slate-400" />}
                                        {item.type === 'ARMOR' && <Shield size={20} className="text-slate-400" />}
                                        {item.type === 'ACCESSORY' && <Gem size={20} className="text-slate-400" />}
                                        <div className="text-[10px] mt-1 text-slate-500 font-bold">Lv.{item.level}</div>
                                    </button>

                                    {/* Upgrade Button Overlay */}
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); upgradeItem(item); }}
                                        className="absolute -top-2 -right-2 bg-slate-900 border border-slate-600 rounded-full p-1 hover:bg-yellow-900 hover:border-yellow-500 z-10"
                                        title={`Upgrade: ${upgradeCost} G`}
                                        disabled={score < upgradeCost}
                                    >
                                        <Hammer size={12} className={score >= upgradeCost ? "text-yellow-400" : "text-slate-600"} />
                                    </button>

                                    {/* Tooltip */}
                                    <div className="absolute bottom-full mb-2 left-0 bg-black px-3 py-2 rounded text-xs w-32 hidden group-hover:block z-50 pointer-events-none border border-slate-700 shadow-xl">
                                        <div className="font-bold text-white mb-1">{item.name}</div>
                                        <div className="text-blue-400">+{item.value} {item.stat}</div>
                                        <div className="text-slate-500 mt-1">Upgrade: <span className="text-yellow-400">{upgradeCost} G</span></div>
                                    </div>
                                </div>
                            )})}
                            {[...Array(Math.max(0, 20 - inventory.length))].map((_, i) => (
                                <div key={`empty-${i}`} className="aspect-square bg-slate-900/50 border border-slate-800 rounded" />
                            ))}
                        </div>
                    </div>
                </div>
            </motion.div>
          )}

          {/* GAME OVER */}
          {status === GameStatus.GAME_OVER && (
            <motion.div 
                initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                className="bg-slate-900/95 border border-red-900 p-12 rounded-lg text-center flex flex-col items-center gap-6 shadow-2xl"
            >
              <h2 className="text-5xl font-serif text-red-500 drop-shadow-md">YOU DIED</h2>
              <div className="flex flex-col gap-1 text-xl text-slate-300">
                 <p>Gold Collected: <span className="text-yellow-400">{score.toLocaleString()}</span></p>
                 <p>Level Reached: {level}</p>
              </div>
              <button 
                onClick={resetGame}
                className="flex items-center gap-3 px-8 py-3 bg-red-800 hover:bg-red-700 text-white font-bold rounded shadow-lg mt-4"
              >
                <RotateCcw size={20} /> TRY AGAIN
              </button>
            </motion.div>
          )}

        </AnimatePresence>
      </div>
    </div>
  );
};

