import { Vector3 } from 'three';

export enum GameStatus {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  PAUSED = 'PAUSED',
  LEVEL_UP = 'LEVEL_UP',
  GAME_OVER = 'GAME_OVER',
  INVENTORY = 'INVENTORY',
  SHOP = 'SHOP',
}

export type UpgradeType = 
  'HEALTH' | 'SPEED' | 'DAMAGE' | 'FIRE_RATE' | 'MULTISHOT' | 'DASH_COOLDOWN' |
  'SKILL_ORBITAL' | 'SKILL_THUNDER' | 'SKILL_REGEN' | 'SKILL_MAGNET' |
  'CRIT_RATE' | 'CRIT_DAMAGE';

export interface Upgrade {
  id: string;
  type: UpgradeType;
  name: string;
  description: string;
  rarity: 'COMMON' | 'RARE' | 'LEGENDARY';
  value: number;
}

export type ProjectileType = 'MAGIC' | 'ARROW' | 'AXE';

export interface Item {
  id: string;
  name: string;
  type: 'WEAPON' | 'ARMOR' | 'ACCESSORY';
  stat: keyof PlayerStats;
  value: number;
  rarity: 'COMMON' | 'RARE' | 'LEGENDARY';
  price: number;
  level: number;
  projectileType?: ProjectileType;
}

export interface PlayerStats {
  maxHealth: number;
  moveSpeed: number;
  damage: number;
  fireRate: number; // bullets per second
  projectileSpeed: number;
  multishot: number;
  spread: number;
  dashCooldown: number;
  magnetRadius: number;
  critRate: number; // 0-1
  critDamage: number; // multiplier (e.g. 1.5)
}

export interface EnemyData {
  id: number;
  position: Vector3;
  type: number; // 0: Slime, 1: Orc, 2: Boss, 3: Shooter
  health: number;
  maxHealth: number;
  speed: number;
  radius: number;
  scale: number;
  active: boolean;
  state?: 'CHASE' | 'CHARGE_PREP' | 'CHARGE' | 'SHOOT';
  stateTimer?: number;
  chargeDir?: Vector3;
}

export interface BulletData {
  id: number;
  position: Vector3;
  velocity: Vector3;
  active: boolean;
  lifetime: number;
}

export interface CrateData {
  id: number;
  position: Vector3;
  active: boolean;
  rotation: number;
}

export interface DropData {
  id: number;
  position: Vector3;
  item: Item | null; // null means just XP/Gold visual
  type: 'ITEM' | 'GOLD' | 'XP';
  active: boolean;
  value: number;
  rotation: number;
}

export interface Skill {
  id: string;
  name: string;
  cooldown: number;
  maxCooldown: number;
  icon: string;
}

export interface SkillLevels {
    orbital: number;
    thunder: number;
    regen: number;
