import { create } from 'zustand';
import { GameStatus, PlayerStats, Upgrade, Item, DropData, SkillLevels } from './types';
import { Vector3 } from 'three';
import { ITEMS_POOL } from './constants';

interface GameState {
  status: GameStatus;
  score: number; // Used as GOLD
  level: number;
  experience: number;
  experienceToNextLevel: number;
  health: number;
  playerPosition: Vector3;
  stats: PlayerStats;
  baseStats: PlayerStats;

  skillLevels: SkillLevels;

  inventory: Item[];
  equipment: {
    weapon: Item | null;
    armor: Item | null;
    accessory: Item | null;
  };

  drops: DropData[];

  skills: {
    dash: number;
    nova: number;
  };
  skillMaxCooldowns: {
    dash: number;
    nova: number;
  };

  setStatus: (status: GameStatus) => void;
  startGame: () => void;
  addScore: (amount: number) => void;
  addExperience: (amount: number) => void;
  takeDamage: (amount: number) => void;
  heal: (amount: number) => void;
  setPlayerPosition: (pos: Vector3) => void;
  applyUpgrade: (upgrade: Upgrade) => void;
  equipItem: (item: Item) => void;
  unequipItem: (slot: 'weapon' | 'armor' | 'accessory') => void;
  buyItem: (item: Item) => boolean;
  upgradeItem: (item: Item) => void;
  resetGame: () => void;

  spawnDrop: (position: Vector3, type: 'ITEM' | 'XP' | 'GOLD', value: number) => void;
  collectDrop: (id: number) => void;
  triggerSkillCooldown: (skill: 'dash' | 'nova') => void;
  tickCooldowns: (delta: number) => void;
}

const INITIAL_STATS: PlayerStats = {
  maxHealth: 100,
  moveSpeed: 10,
  damage: 15,
  fireRate: 2.5,
  projectileSpeed: 20,
  multishot: 1,
  spread: 0.2,
  dashCooldown: 2.0,
  magnetRadius: 5.0,
  critRate: 0.05,
  critDamage: 1.5,
};

const calculateStats = (base: PlayerStats, equipment: GameState['equipment']) => {
  const final = { ...base };
  Object.values(equipment).forEach(item => {
    if (item) {
      // @ts-ignore
      final[item.stat] += item.value;
    }
  });
  return final;
};

export const useGameStore = create<GameState>((set, get) => ({
  status: GameStatus.MENU,
  score: 0,
  level: 1,
  experience: 0,
  experienceToNextLevel: 100,
  health: 100,
  playerPosition: new Vector3(0, 0, 0),
  stats: { ...INITIAL_STATS },
  baseStats: { ...INITIAL_STATS },
  skillLevels: { orbital: 0, thunder: 0, regen: 0 },
  inventory: [],
  equipment: { weapon: null, armor: null, accessory: null },
  drops: [],
  skills: { dash: 0, nova: 0 },
  skillMaxCooldowns: { dash: 2.0, nova: 5.0 },

  setStatus: (status) => set({ status }),

  startGame: () => set({
    status: GameStatus.PLAYING,
    score: 100, // Start with some gold
    level: 1,
    experience: 0,
    experienceToNextLevel: 100,
    health: 100,
    baseStats: { ...INITIAL_STATS },
    stats: { ...INITIAL_STATS },
    skillLevels: { orbital: 0, thunder: 0, regen: 0 },
    playerPosition: new Vector3(0, 0, 0),
    inventory: [{ ...ITEMS_POOL[0] }], // Clone
    equipment: { weapon: null, armor: null, accessory: null },
    drops: [],
    skills: { dash: 0, nova: 0 }
  }),

  addScore: (amount) => set((state) => ({ score: state.score + amount })),

  addExperience: (amount) => {
    // 2x Experience Multiplier
    const adjustedAmount = amount * 2;
    const { experience, experienceToNextLevel, level } = get();
    let newExp = experience + adjustedAmount;

    if (newExp >= experienceToNextLevel) {
      set({
        experience: newExp - experienceToNextLevel,
        experienceToNextLevel: Math.floor(experienceToNextLevel * 1.5),
        level: level + 1,
        status: GameStatus.LEVEL_UP,
      });
    } else {
      set({ experience: newExp });
    }
  },

  takeDamage: (amount) => {
    const { health, status } = get();
    if (status !== GameStatus.PLAYING) return;

    const newHealth = health - amount;
    if (newHealth <= 0) {
      set({ health: 0, status: GameStatus.GAME_OVER });
    } else {
      set({ health: newHealth });
    }
  },

  heal: (amount) => set((state) => ({ 
    health: Math.min(state.health + amount, state.stats.maxHealth) 
  })),

  setPlayerPosition: (pos) => set({ playerPosition: pos }),

  spawnDrop: (position, type, value) => set((state) => {
      if (state.drops.length > 50) return { drops: state.drops };
      // Deep copy item so upgrades don't affect pool
      const poolItem = ITEMS_POOL[Math.floor(Math.random() * ITEMS_POOL.length)];
      const item = type === 'ITEM' ? { ...poolItem } : null;

      return {
          drops: [...state.drops, {
              id: Math.random(),
              position: position.clone(),
              type,
              value,
              item,
              active: true,
              rotation: Math.random() * Math.PI
          }]
      };
  }),

  collectDrop: (id) => set((state) => {
      const drop = state.drops.find(d => d.id === id);
      if (!drop) return { drops: state.drops };

      const newDrops = state.drops.filter(d => d.id !== id);

      if (drop.type === 'XP') {
         get().addExperience(drop.value);
      } else if (drop.type === 'GOLD') {
         get().addScore(drop.value);
      } else if (drop.type === 'ITEM' && drop.item) {
          return { drops: newDrops, inventory: [...state.inventory, drop.item] };
      }

      return { drops: newDrops };
  }),

  triggerSkillCooldown: (skill) => set((state) => ({
      skills: { ...state.skills, [skill]: state.skillMaxCooldowns[skill] }
  })),

  tickCooldowns: (delta) => set((state) => ({
      skills: {
          dash: Math.max(0, state.skills.dash - delta),
          nova: Math.max(0, state.skills.nova - delta)
      }
  })),

  applyUpgrade: (upgrade) => set((state) => {
    const newBase = { ...state.baseStats };
    const newSkillLevels = { ...state.skillLevels };

    switch (upgrade.type) {
      case 'HEALTH': newBase.maxHealth += upgrade.value; break;
      case 'SPEED': newBase.moveSpeed *= (1 + upgrade.value); break;
      case 'DAMAGE': newBase.damage *= (1 + upgrade.value); break;
      case 'FIRE_RATE': newBase.fireRate *= (1 + upgrade.value); break;
      case 'MULTISHOT': newBase.multishot += upgrade.value; break;
      case 'DASH_COOLDOWN': newBase.dashCooldown *= (1 - upgrade.value); break;
      case 'SKILL_MAGNET': newBase.magnetRadius += upgrade.value; break;
      case 'CRIT_RATE': newBase.critRate += upgrade.value; break;
      case 'CRIT_DAMAGE': newBase.critDamage += upgrade.value; break;
      case 'SKILL_ORBITAL': newSkillLevels.orbital++; break;
      case 'SKILL_THUNDER': newSkillLevels.thunder++; break;
      case 'SKILL_REGEN': newSkillLevels.regen++; break;
    }
    const newStats = calculateStats(newBase, state.equipment);
    return { 
        baseStats: newBase,
        stats: newStats, 
        skillLevels: newSkillLevels,
        health: upgrade.type === 'HEALTH' ? Math.min(state.health + 30, newStats.maxHealth) : state.health,
        status: GameStatus.PLAYING,
        skillMaxCooldowns: {
            ...state.skillMaxCooldowns,
            dash: upgrade.type === 'DASH_COOLDOWN' ? state.skillMaxCooldowns.dash * (1 - upgrade.value) : state.skillMaxCooldowns.dash
        }
    };
  }),

  equipItem: (item) => set((state) => {
    const slot = item.type.toLowerCase() as keyof GameState['equipment'];
    const oldItem = state.equipment[slot];
    const newEquipment = { ...state.equipment, [slot]: item };
    const newStats = calculateStats(state.baseStats, newEquipment);
    let newInv = state.inventory.filter(i => i !== item);
    if (oldItem) newInv.push(oldItem);
    return { equipment: newEquipment, stats: newStats, inventory: newInv };
  }),

  unequipItem: (slot) => set((state) => {
    const item = state.equipment[slot];
    if (!item) return state;
    const newEquipment = { ...state.equipment, [slot]: null };
    const newStats = calculateStats(state.baseStats, newEquipment);
    return { equipment: newEquipment, stats: newStats, inventory: [...state.inventory, item] };
  }),

  buyItem: (item) => {
      const state = get();
      if (state.score >= item.price) {
          // Clone item so it is a unique instance
          set({
              score: state.score - item.price,
              inventory: [...state.inventory, { ...item }]
          });
          return true;
      }
      return false;
  },

  upgradeItem: (item) => set((state) => {
      // Cost formula: basePrice * level * 0.5
      const cost = Math.floor(item.price * item.level * 0.5);

      if (state.score >= cost) {
          const upgradeLogic = (i: Item) => {
              if (i === item) {
                  return {
                      ...i,
                      level: i.level + 1,
                      value: i.stat === 'fireRate' || i.stat === 'moveSpeed' || i.stat === 'critRate' 
                             ? parseFloat((i.value * 1.1).toFixed(2)) 
                             : Math.ceil(i.value * 1.2)
                  };
              }
              return i;
          };

          const newInventory = state.inventory.map(upgradeLogic);
          const newEquipment = {
              weapon: state.equipment.weapon ? upgradeLogic(state.equipment.weapon) : null,
              armor: state.equipment.armor ? upgradeLogic(state.equipment.armor) : null,
              accessory: state.equipment.accessory ? upgradeLogic(state.equipment.accessory) : null,
          };

          const newStats = calculateStats(state.baseStats, newEquipment);

          return {
              score: state.score - cost,
              inventory: newInventory,
              equipment: newEquipment,
              stats: newStats
          };
      }
      return {};
  }),

  resetGame: () => set({
    status: GameStatus.MENU,
  }),
}));

import React, { useRef, useEffect, useState } from 'react';
import { useFrame } from '@react-three/fiber';
import { Text } from '@react-three/drei';
import { Vector3, Group } from 'three';
import { useGameStore } from '../store';
import { GameStatus } from '../types';

const MAX_TEXTS = 30;

interface DamageText {
  id: number;
  position: Vector3;
  velocity: Vector3;
  life: number;
  text: string;
  color: string;
  scale: number;
  active: boolean;
}

export const DamageTextManager: React.FC = () => {
  const { status } = useGameStore();
  const groupRef = useRef<Group>(null);

  // Use a ref to store state to avoid re-renders
  const textsRef = useRef<DamageText[]>(
    new Array(MAX_TEXTS).fill(0).map((_, i) => ({
      id: i,
      position: new Vector3(),
      velocity: new Vector3(),
      life: 0,
      text: '',
      color: 'white',
      scale: 1,
      active: false
    }))
  );

  useEffect(() => {
    const handleDamage = (e: CustomEvent) => {
      const { position, damage, isCrit } = e.detail;
      const text = textsRef.current.find(t => !t.active);

      if (text) {
        text.active = true;
        text.position.copy(position).add(new Vector3(0, 1.5, 0));
        text.velocity.set((Math.random() - 0.5) * 2, 3, (Math.random() - 0.5) * 2);
        text.life = 1.0;
        text.text = Math.round(damage).toString();
        text.color = isCrit ? '#ef4444' : 'white'; // Red for crit
        text.scale = isCrit ? 1.5 : 0.8;
      }
    };

    window.addEventListener('damage', handleDamage as EventListener);
    return () => window.removeEventListener('damage', handleDamage as EventListener);
  }, []);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!groupRef.current) return;

    // Update pool
    textsRef.current.forEach((text, i) => {
      const mesh = groupRef.current!.children[i];
      if (!mesh) return;

      if (text.active) {
        text.life -= delta;
        text.velocity.y -= 9.8 * delta; // Gravity
        text.position.add(text.velocity.clone().multiplyScalar(delta));

        mesh.visible = true;
        mesh.position.copy(text.position);
        mesh.lookAt(state.camera.position);

        // Use userData to update internal Text component props if possible, 
        // but with drei Text, we rely on React props mostly. 
        // However, updating 30 Text components via React state is slow.
        // We will force update the Text objects directly if we can, or just rely on the key prop?
        // Actually, drei Text is an abstraction. The best way here is to map the ref array to components
        // and force a re-render only when a new text activates? No, that defeats the loop.

        // For 'drei/Text', we can access the underlying mesh via ref, but here we have a list.
        // Let's rely on a localized state that updates sparingly?
        // No, let's allow React to render these 30 items, but update their transforms via ref.
        // The text content needs to be set.
      } else {
        mesh.visible = false;
      }
    });
  });

  // To avoid re-rendering this component constantly, we use the Ref for transforms (useFrame),
  // but we need to update the actual text content and color.
  // Since 'text' and 'color' change only on spawn, we can use a versioning state to trigger a render only on spawn events.
  const [version, setVersion] = useState(0);

  useEffect(() => {
     const handleDamage = () => setVersion(v => v + 1);
     window.addEventListener('damage', handleDamage);
     return () => window.removeEventListener('damage', handleDamage);
  }, []);

  return (
    <group ref={groupRef}>
      {textsRef.current.map((t) => (
         <Text
           key={t.id}
           position={[0, -100, 0]} // Start hidden/far away
           fontSize={1}
           color={t.color}
           outlineWidth={0.05}
           outlineColor="black"
           anchorX="center"
           anchorY="middle"
           scale={[t.scale, t.scale, t.scale]}
         >
           {t.text}
         </Text>
      ))}
    </group>
  );
};

import React, { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import { Plane, Grid } from '@react-three/drei';
import { Player } from './Player';
import { EnemyManager } from './EnemyManager';
import { CrateManager } from './CrateManager';
import { Environment } from './Environment';
import { DropManager } from './DropManager';
import { EnemyBulletManager } from './EnemyBulletManager';
import { SkillManager } from './SkillManager';
import { DamageTextManager } from './DamageTextManager';
import { ARENA_SIZE, COLORS } from '../constants';
import { useGameStore } from '../store';
import { GameStatus, BulletData } from '../types';
import * as THREE from 'three';

export const World: React.FC = () => {
  const status = useGameStore((state) => state.status);

  // Data Refs for high-performance shared state
  const bulletsDataRef = useRef<BulletData[]>([]);
  const enemyBulletsDataRef = useRef<BulletData[]>([]);

  // Expose enemies list to scene for player auto-target (kept as userData logic or could be ref lifted)
  const sceneRef = useRef<THREE.Group>(null);

  return (
    <group ref={sceneRef}>
      {/* RPG Lighting - Day Mode */}
      <ambientLight intensity={1.0} color="#ffffff" />
      <directionalLight 
        position={[60, 80, 40]} 
        intensity={2.0} 
        castShadow 
        shadow-mapSize={[2048, 2048]}
        shadow-bias={-0.0001}
        color="#fffbeb" // Warm sun
      >
        <orthographicCamera attach="shadow-camera" args={[-80, 80, 80, -80]} />
      </directionalLight>

      {/* Ground & Environment */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.1, 0]} receiveShadow>
        <planeGeometry args={[ARENA_SIZE * 3, ARENA_SIZE * 3]} />
        <meshStandardMaterial color={COLORS.ground} roughness={1} metalness={0} />
      </mesh>

      <Environment />

      {/* Game Logic Entities */}
      {(status === GameStatus.PLAYING || status === GameStatus.LEVEL_UP || status === GameStatus.GAME_OVER || status === GameStatus.INVENTORY || status === GameStatus.SHOP) && (
        <>
          <Player 
            bulletsDataRef={bulletsDataRef} 
            enemyBulletsDataRef={enemyBulletsDataRef}
          />
          <EnemyManager 
            bulletsDataRef={bulletsDataRef} 
            enemyBulletsDataRef={enemyBulletsDataRef}
          />
          <EnemyBulletManager enemyBulletsDataRef={enemyBulletsDataRef} />
          <CrateManager bulletsDataRef={bulletsDataRef} />
          <DropManager />
          <SkillManager />
          <DamageTextManager />
        </>
      )}
    </group>
  );
};

import React, { useRef, useLayoutEffect, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, DynamicDrawUsage, Quaternion } from 'three';
import { useGameStore } from '../store';
import { MAX_BULLETS, COLORS } from '../constants';
import { GameStatus, BulletData, ProjectileType } from '../types';

interface BulletManagerProps {
  playerPos: Vector3;
  targetPos: Vector3 | null;
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  projectileType?: ProjectileType;
}

const dummy = new Object3D();

export const BulletManager: React.FC<BulletManagerProps> = ({ playerPos, targetPos, bulletsDataRef, projectileType = 'MAGIC' }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const { stats, status } = useGameStore();

  // Local storage for bullets logic
  const bullets = useRef(new Array(MAX_BULLETS).fill(0).map((_, i) => ({
    id: i,
    active: false,
    position: new Vector3(),
    velocity: new Vector3(),
    lifetime: 0
  })));

  const lastShot = useRef(0);

  // Sync with parent ref once
  useEffect(() => {
    bulletsDataRef.current = bullets.current;
  }, []);

  useLayoutEffect(() => {
    if (meshRef.current) {
        meshRef.current.instanceMatrix.setUsage(DynamicDrawUsage);
    }
  }, []);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    const time = state.clock.getElapsedTime();

    // 1. Auto-Fire Logic
    const fireInterval = 1 / stats.fireRate;

    if (targetPos && time - lastShot.current > fireInterval) {
      lastShot.current = time;

      const dir = new Vector3().subVectors(targetPos, playerPos).normalize();
      const startAngle = - (stats.spread * (stats.multishot - 1)) / 2;

      for (let i = 0; i < stats.multishot; i++) {
        const bullet = bullets.current.find(b => !b.active);
        if (bullet) {
            bullet.active = true;
            bullet.lifetime = 2.0;
            bullet.position.copy(playerPos).add(new Vector3(0, 1, 0));

            const angle = startAngle + (i * stats.spread);
            const spreadDir = dir.clone().applyAxisAngle(new Vector3(0, 1, 0), angle);

            bullet.velocity.copy(spreadDir).multiplyScalar(stats.projectileSpeed);
        }
      }
    }

    // 2. Update Bullets & check for collisions?
    // Note: Collision is handled in EnemyManager for optimization (iterating enemies vs bullets),
    // but the damage logic resides there. 
    // We need to modify EnemyManager to perform the damage calculation with crits.
    // However, to keep it clean, let's keep collision there but update the damage logic there.
    // See EnemyManager update below.

    let activeCount = 0;
    for (let i = 0; i < MAX_BULLETS; i++) {
        const b = bullets.current[i];
        if (b.active) {
            b.position.add(b.velocity.clone().multiplyScalar(delta));
            b.lifetime -= delta;

            if (b.lifetime <= 0) {
                b.active = false;
                dummy.position.set(0, -100, 0);
            } else {
                dummy.position.copy(b.position);

                if (projectileType === 'AXE') {
                     dummy.rotation.set(0, time * 15, 0);
                } else {
                     const lookAtPos = b.position.clone().add(b.velocity);
                     dummy.lookAt(lookAtPos);
                }

                dummy.scale.set(1, 1, 1);
            }
            activeCount++;
        } else {
            dummy.position.set(0, -100, 0);
            dummy.scale.set(0, 0, 0);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh key={projectileType} ref={meshRef} args={[undefined, undefined, MAX_BULLETS]} frustumCulled={false}>
      {projectileType === 'ARROW' && <cylinderGeometry args={[0.05, 0.05, 1.5, 6]} rotation={[Math.PI / 2, 0, 0]} />}
      {projectileType === 'MAGIC' && <boxGeometry args={[0.2, 0.2, 0.8]} />}
      {projectileType === 'AXE' && <boxGeometry args={[1, 0.1, 1]} />}

      <meshStandardMaterial 
        color={projectileType === 'ARROW' ? '#d4d4d8' : projectileType === 'AXE' ? '#cbd5e1' : COLORS.bulletPlayer} 
        emissive={projectileType === 'MAGIC' ? COLORS.bulletPlayer : '#000'} 
        emissiveIntensity={projectileType === 'MAGIC' ? 2 : 0} 
      />
    </instancedMesh>
  );
};

import React, { useRef } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, Color } from 'three';
import { useGameStore } from '../store';
import { ARENA_SIZE, COLORS } from '../constants';
import { GameStatus, EnemyData, BulletData } from '../types';

const MAX_ENEMIES = 400;

const dummy = new Object3D();
const tempVec = new Vector3();
const tempColor = new Color();

interface EnemyManagerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
}

export const EnemyManager: React.FC<EnemyManagerProps> = ({ bulletsDataRef, enemyBulletsDataRef }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const { playerPosition, addScore, addExperience, takeDamage, status, level, stats, spawnDrop } = useGameStore();

  const enemies = useRef(new Array(MAX_ENEMIES).fill(0).map((_, i) => ({
    id: i,
    active: false,
    type: 0,
    health: 100,
    maxHealth: 100,
    position: new Vector3(),
    speed: 5,
    radius: 0.8,
    scale: 1,
    state: 'CHASE',
    stateTimer: 0
  } as EnemyData)));

  const spawnTimer = useRef(0);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    if (!meshRef.current.userData.enemies) {
        meshRef.current.userData.enemies = enemies.current;
        meshRef.current.name = "EnemyMesh";
    }

    // 1. Spawning
    spawnTimer.current += delta;
    const spawnRate = Math.max(0.1, 0.8 - (level * 0.04));

    if (spawnTimer.current > spawnRate) {
        spawnTimer.current = 0;
        const enemy = enemies.current.find(e => !e.active);
        if (enemy) {
            enemy.active = true;
            let angle, dist, spawnPos;
            do {
                angle = Math.random() * Math.PI * 2;
                dist = (ARENA_SIZE / 2) - 5;
                spawnPos = new Vector3(Math.cos(angle) * dist, 0, Math.sin(angle) * dist);
            } while (spawnPos.distanceTo(playerPosition) < 20);

            enemy.position.copy(spawnPos);

            const r = Math.random();
            if (level > 4 && r > 0.98) {
                // Boss
                enemy.type = 2;
                enemy.health = 500 + (level * 100);
                enemy.speed = 3 + (level * 0.1);
                enemy.radius = 2.5;
                enemy.scale = 3.0;
                enemy.state = 'CHASE';
                tempColor.set(COLORS.enemyBoss);
            } else if (level > 3 && r > 0.85) {
                // Shooter
                enemy.type = 3; 
                enemy.health = 40 + (level * 10);
                enemy.speed = 3.0;
                enemy.radius = 0.8;
                enemy.scale = 0.9;
                enemy.state = 'CHASE';
                tempColor.set(COLORS.enemyShooter);
            } else if (r > 0.75 && level > 2) {
                // Orc
                enemy.type = 1; 
                enemy.health = 60 + (level * 15);
                enemy.speed = 3.5 + (level * 0.1);
                enemy.radius = 1.0;
                enemy.scale = 1.2;
                tempColor.set(COLORS.enemyOrc);
            } else {
                // Slime
                enemy.type = 0;
                enemy.health = 25 + (level * 8);
                enemy.speed = 4 + (level * 0.15);
                enemy.radius = 0.6;
                enemy.scale = 0.8;
                tempColor.set(COLORS.enemySlime);
            }
            enemy.maxHealth = enemy.health;

            meshRef.current.setColorAt(enemies.current.indexOf(enemy), tempColor);
            meshRef.current.instanceColor!.needsUpdate = true;
        }
    }

    // 2. Logic & Collision
    const activeBullets = bulletsDataRef.current;

    // Cache stats for loop
    const baseDamage = stats.damage;
    const critRate = stats.critRate;
    const critDamage = stats.critDamage;

    for (let i = 0; i < MAX_ENEMIES; i++) {
        const e = enemies.current[i];
        if (e.active) {

            const distToPlayer = e.position.distanceTo(playerPosition);

            // AI LOGIC
            if (e.type === 3) { // SHOOTER
                if (distToPlayer > 15) {
                    tempVec.subVectors(playerPosition, e.position).normalize();
                    e.position.add(tempVec.multiplyScalar(e.speed * delta));
                }

                // Shoot logic
                e.stateTimer = (e.stateTimer || 0) + delta;
                if (e.stateTimer > 2.0 && distToPlayer < 20) {
                    e.stateTimer = 0;
                    // Find free bullet
                    const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                    if (bullet) {
                        bullet.active = true;
                        bullet.lifetime = 3.0;
                        bullet.position.copy(e.position).add(new Vector3(0, 1, 0));
                        const aimDir = new Vector3().subVectors(playerPosition, e.position).normalize();
                        bullet.velocity.copy(aimDir).multiplyScalar(15);
                    }
                }

            } else if (e.type === 2) { // BOSS
                 if (e.state === 'CHASE') {
                    tempVec.subVectors(playerPosition, e.position).normalize();
                    e.position.add(tempVec.multiplyScalar(e.speed * delta));

                    e.stateTimer = (e.stateTimer || 0) + delta;
                    if (e.stateTimer > 4) {
                        e.state = 'CHARGE_PREP';
                        e.stateTimer = 0;
                    }
                } else if (e.state === 'CHARGE_PREP') {
                    e.position.x += (Math.random() - 0.5) * 0.2;
                    e.stateTimer = (e.stateTimer || 0) + delta;
                    if (e.stateTimer > 1.5) {
                        e.state = 'CHARGE';
                        e.stateTimer = 0;
                        e.position.y = 0; 
                        tempVec.subVectors(playerPosition, e.position).normalize();
                        e['chargeDir'] = tempVec.clone();
                    }
                } else if (e.state === 'CHARGE') {
                    const dir = e['chargeDir'] as Vector3;
                    e.position.add(dir.multiplyScalar(e.speed * 4 * delta));
                    e.stateTimer = (e.stateTimer || 0) + delta;
                    if (e.stateTimer > 1.0) {
                        e.state = 'CHASE';
                        e.stateTimer = 0;
                    }
                }
            } else {
                // MELEE
                tempVec.subVectors(playerPosition, e.position).normalize();
                e.position.add(tempVec.multiplyScalar(e.speed * delta));
            }

            // Melee Damage to Player
            if (e.type !== 3 && distToPlayer < e.radius + 0.5) {
                takeDamage((e.type === 2 ? 30 : 10) * delta);
            }

            // Hit by Player Bullets
            for(let b=0; b < activeBullets.length; b++) {
                const bullet = activeBullets[b];
                if (bullet.active) {
                    if (bullet.position.distanceTo(e.position) < e.radius + 0.5) {

                        // Calculate Damage
                        const isCrit = Math.random() < critRate;
                        const dmg = isCrit ? baseDamage * critDamage : baseDamage;

                        e.health -= dmg;
                        bullet.active = false;

                        // Show Damage Text
                        window.dispatchEvent(new CustomEvent('damage', { 
                            detail: { position: e.position, damage: dmg, isCrit } 
                        }));

                        if (e.type !== 2 && e.state !== 'CHARGE') {
                            const kbDir = e.position.clone().sub(bullet.position).normalize();
                            e.position.add(kbDir.multiplyScalar(0.4));
                        }
                    }
                }
            }

            // Death
            if (e.health <= 0) {
                e.active = false;
                addScore(10 * (e.type + 1));

                // Drop Logic
                if (Math.random() > 0.8) {
                    spawnDrop(e.position, 'ITEM', 0);
                } else {
                    spawnDrop(e.position, 'XP', e.type === 2 ? 500 : 20 * (e.type + 1));
                }

                dummy.position.set(0, -100, 0);
            } else {
                dummy.position.copy(e.position);
                if (e.type === 2 && e.state === 'CHARGE_PREP') {
                    dummy.scale.set(e.scale * 1.1, e.scale * 1.1, e.scale * 1.1);
                } else {
                    dummy.scale.set(e.scale, e.scale, e.scale);
                }
                if (e.type !== 2) dummy.position.y = Math.abs(Math.sin(state.clock.elapsedTime * 5)) * 0.5;
                dummy.lookAt(playerPosition);
            }

        } else {
            dummy.position.set(0, -100, 0);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, MAX_ENEMIES]} frustumCulled={false}>
      <boxGeometry args={[1, 1, 1]} />
      <meshStandardMaterial vertexColors roughness={0.5} metalness={0.2} />
    </instancedMesh>
  );
};

import React, { useRef, useState } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, Line, Mesh } from 'three';
import { useGameStore } from '../store';
import { GameStatus } from '../types';
import { COLORS } from '../constants';

const dummy = new Object3D();

export const SkillManager: React.FC = () => {
  const { skillLevels, playerPosition, status, stats, heal, takeDamage } = useGameStore();
  const { scene } = useThree();

  // Orbital
  const orbitalRef = useRef<InstancedMesh>(null);

  // Thunder
  const thunderTimer = useRef(0);
  const [thunderPos, setThunderPos] = useState<Vector3 | null>(null);
  const thunderVisualTimer = useRef(0);

  // Regen
  const regenTimer = useRef(0);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;

    const time = state.clock.getElapsedTime();

    // 1. Orbital Blades Logic
    if (skillLevels.orbital > 0 && orbitalRef.current) {
        const count = skillLevels.orbital + 2; // Base 3 blades
        const radius = 3.5;
        const speed = 2.0;
        const damage = stats.damage * 0.5; 

        for (let i = 0; i < count; i++) {
            const angle = (time * speed) + (i * ((Math.PI * 2) / count));
            dummy.position.set(
                playerPosition.x + Math.cos(angle) * radius,
                1.0,
                playerPosition.z + Math.sin(angle) * radius
            );
            dummy.rotation.set(0, -angle, 0);
            dummy.scale.set(1, 1, 1);
            dummy.updateMatrix();
            orbitalRef.current.setMatrixAt(i, dummy.matrix);

            // Simple Collision
            const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
            if (enemiesMesh && enemiesMesh.userData.enemies) {
                const enemies = enemiesMesh.userData.enemies;
                for (let e = 0; e < enemies.length; e++) {
                    if (enemies[e].active) {
                        if (enemies[e].position.distanceTo(dummy.position) < 1.5) {
                             // Orbital damage ticks very fast, let's just do dps
                             // To show numbers, we need a limiter or it floods
                             // For simplicity: raw damage application
                             enemies[e].health -= damage * delta * 60;
                        }
                    }
                }
            }
        }

        // Hide unused
        for (let i = count; i < 20; i++) {
             dummy.position.set(0, -100, 0);
             dummy.updateMatrix();
             orbitalRef.current.setMatrixAt(i, dummy.matrix);
        }
        orbitalRef.current.instanceMatrix.needsUpdate = true;
    } else if (orbitalRef.current) {
        orbitalRef.current.visible = false;
    }

    // 2. Thunder Logic
    if (skillLevels.thunder > 0) {
        thunderTimer.current += delta;
        const cooldown = Math.max(0.5, 3.0 - (skillLevels.thunder * 0.3));

        if (thunderTimer.current > cooldown) {
            thunderTimer.current = 0;
            // Find target
            const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
            if (enemiesMesh && enemiesMesh.userData.enemies) {
                const enemies = enemiesMesh.userData.enemies;
                const activeEnemies = enemies.filter((e: any) => e.active && e.position.distanceTo(playerPosition) < 30);
                if (activeEnemies.length > 0) {
                    const target = activeEnemies[Math.floor(Math.random() * activeEnemies.length)];

                    const isCrit = Math.random() < stats.critRate;
                    const dmg = (stats.damage * 4) * (isCrit ? stats.critDamage : 1);

                    target.health -= dmg;

                    window.dispatchEvent(new CustomEvent('damage', { 
                        detail: { position: target.position, damage: dmg, isCrit } 
                    }));

                    setThunderPos(target.position.clone());
                    thunderVisualTimer.current = 0.2;
                }
            }
        }
    }

    // Thunder Visual Cleanup
    if (thunderVisualTimer.current > 0) {
        thunderVisualTimer.current -= delta;
        if (thunderVisualTimer.current <= 0) setThunderPos(null);
    }

    // 3. Regen Logic
    if (skillLevels.regen > 0) {
        regenTimer.current += delta;
        if (regenTimer.current > 1.0) {
            regenTimer.current = 0;
            heal(skillLevels.regen * 2);
        }
    }

  });

  return (
    <>
      {/* Orbitals */}
      <instancedMesh ref={orbitalRef} args={[undefined, undefined, 20]} frustumCulled={false} visible={skillLevels.orbital > 0}>
        <octahedronGeometry args={[0.4, 0]} />
        <meshStandardMaterial color="#0ea5e9" emissive="#0ea5e9" emissiveIntensity={2} />
      </instancedMesh>

      {/* Thunder Visual */}
      {thunderPos && (
          <mesh position={thunderPos}>
              <cylinderGeometry args={[0.1, 0.1, 20, 8]} />
              <meshBasicMaterial color="yellow" transparent opacity={0.8} />
          </mesh>
      )}
    </>
  );
};

import React, { useRef, useState } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { Vector3, InstancedMesh, Mesh } from 'three';
import { useGameStore } from '../store';
import { COLORS, PLAYER_RADIUS, ARENA_SIZE } from '../constants';
import { BulletManager } from './BulletManager';
import { GameStatus, BulletData } from '../types';

interface PlayerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
}

export const Player: React.FC<PlayerProps> = ({ bulletsDataRef, enemyBulletsDataRef }) => {
  const meshRef = useRef<any>(null);
  const novaRef = useRef<Mesh>(null);
  const { stats, status, setPlayerPosition, skills, triggerSkillCooldown, tickCooldowns, takeDamage, equipment } = useGameStore();
  const { camera, scene } = useThree();

  // Local state for movement
  const [pos] = useState(new Vector3(0, 0, 0));
  const [velocity] = useState(new Vector3(0, 0, 0));
  const [keys, setKeys] = useState<{ [key: string]: boolean }>({});

  const targetEnemyPos = useRef<Vector3 | null>(null);
  const dashVelocity = useRef(new Vector3());
  const dashTime = useRef(0);
  const novaTime = useRef(0);

  // Input handling
  React.useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => setKeys((k) => ({ ...k, [e.code]: true }));
    const handleKeyUp = (e: KeyboardEvent) => setKeys((k) => ({ ...k, [e.code]: false }));

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    tickCooldowns(delta);

    // 1. Movement & Dash
    const moveDir = new Vector3(0, 0, 0);
    if (keys['KeyW'] || keys['ArrowUp']) moveDir.z -= 1;
    if (keys['KeyS'] || keys['ArrowDown']) moveDir.z += 1;
    if (keys['KeyA'] || keys['ArrowLeft']) moveDir.x -= 1;
    if (keys['KeyD'] || keys['ArrowRight']) moveDir.x += 1;
    moveDir.normalize();

    // Dash Skill (Space)
    if (keys['Space'] && skills.dash <= 0) {
        triggerSkillCooldown('dash');
        dashTime.current = 0.2; // Dash duration
        dashVelocity.current.copy(moveDir.length() > 0 ? moveDir : new Vector3(0, 0, -1).applyQuaternion(meshRef.current.quaternion));
        dashVelocity.current.multiplyScalar(40); // Dash speed
    }

    if (dashTime.current > 0) {
        // Dashing
        dashTime.current -= delta;
        velocity.copy(dashVelocity.current);
    } else {
        // Normal Move
        velocity.lerp(moveDir.multiplyScalar(stats.moveSpeed), delta * 8);
    }

    pos.add(velocity.clone().multiplyScalar(delta));

    // Clamp
    pos.x = Math.max(-ARENA_SIZE / 2 + 2, Math.min(ARENA_SIZE / 2 - 2, pos.x));
    pos.z = Math.max(-ARENA_SIZE / 2 + 2, Math.min(ARENA_SIZE / 2 - 2, pos.z));

    meshRef.current.position.copy(pos);
    setPlayerPosition(pos.clone());

    // 2. Nova Skill (Q)
    if (keys['KeyQ'] && skills.nova <= 0) {
        triggerSkillCooldown('nova');
        novaTime.current = 0.5; // Visual effect duration

        // AOE Logic
        const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
        if (enemiesMesh && enemiesMesh.userData.enemies) {
            const enemies = enemiesMesh.userData.enemies;
            for (let i = 0; i < enemies.length; i++) {
                if (enemies[i].active && enemies[i].position.distanceTo(pos) < 10) {

                    const isCrit = Math.random() < stats.critRate;
                    const dmg = (stats.damage * 5) * (isCrit ? stats.critDamage : 1);

                    enemies[i].health -= dmg;

                    window.dispatchEvent(new CustomEvent('damage', { 
                        detail: { position: enemies[i].position, damage: dmg, isCrit } 
                    }));

                    // Knockback
                    const dir = enemies[i].position.clone().sub(pos).normalize();
                    enemies[i].position.add(dir.multiplyScalar(5));
                }
            }
        }
    }

    // Nova Visuals
    if (novaTime.current > 0) {
        novaTime.current -= delta;
        if (novaRef.current) {
            novaRef.current.visible = true;
            const scale = (0.5 - novaTime.current) * 40;
            novaRef.current.scale.set(scale, 1, scale);
            novaRef.current.material.opacity = novaTime.current * 2;
        }
    } else if (novaRef.current) {
        novaRef.current.visible = false;
    }

    // 3. Auto-Targeting Logic
    const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
    let closestDist = 25;
    let closestPos = null;

    if (enemiesMesh && enemiesMesh.userData.enemies) {
        const enemies = enemiesMesh.userData.enemies;
        for (let i = 0; i < enemies.length; i++) {
            if (enemies[i].active) {
                const dist = pos.distanceTo(enemies[i].position);
                if (dist < closestDist) {
                    closestDist = dist;
                    closestPos = enemies[i].position;
                }
            }
        }
    }

    targetEnemyPos.current = closestPos;

    if (closestPos) {
        meshRef.current.lookAt(closestPos.x, 0, closestPos.z);
    } else if (moveDir.lengthSq() > 0.1) {
        const lookTarget = pos.clone().add(moveDir);
        meshRef.current.lookAt(lookTarget.x, 0, lookTarget.z);
    }

    // 4. Enemy Bullet Collision
    const enemyBullets = enemyBulletsDataRef.current;
    if (dashTime.current <= 0) { // Invincible during dash
        for(let i = 0; i < enemyBullets.length; i++) {
            const b = enemyBullets[i];
            if (b.active && b.position.distanceTo(pos) < PLAYER_RADIUS) {
                takeDamage(10);
                b.active = false;
            }
        }
    }

    // 5. Camera Follow
    const targetCamPos = new Vector3(pos.x, 35, pos.z + 28);
    camera.position.lerp(targetCamPos, delta * 4);
    camera.lookAt(pos.x, 0, pos.z);
  });

  return (
    <>
      <group ref={meshRef} position={[0, 1, 0]}>
        {/* RPG Character - Abstract Knight */}
        <group position={[0, 0, 0]}>
            {/* Body */}
            <mesh castShadow receiveShadow position={[0, 0.5, 0]}>
                <capsuleGeometry args={[0.4, 1, 4, 8]} />
                <meshStandardMaterial color={COLORS.player} roughness={0.4} metalness={0.6} />
            </mesh>
            {/* Head */}
            <mesh castShadow position={[0, 1.4, 0]}>
                <boxGeometry args={[0.5, 0.5, 0.5]} />
                <meshStandardMaterial color="#cbd5e1" metalness={0.8} roughness={0.2} />
            </mesh>
            {/* Weapon Hand */}
            <mesh position={[0.6, 0.5, 0.4]}>
                <boxGeometry args={[0.2, 0.2, 0.8]} />
                <meshStandardMaterial color="#94a3b8" />
            </mesh>
             {/* Cape */}
            <mesh position={[0, 0.6, -0.4]} rotation={[0.2, 0, 0]}>
                <boxGeometry args={[0.6, 1.2, 0.1]} />
                <meshStandardMaterial color="#1e40af" />
            </mesh>
        </group>

        {/* Nova Visual */}
        <mesh ref={novaRef} rotation={[-Math.PI/2, 0, 0]} position={[0, -0.9, 0]} visible={false}>
            <ringGeometry args={[0.8, 1, 32]} />
            <meshBasicMaterial color="#3b82f6" transparent opacity={0.5} />
        </mesh>
      </group>

      <BulletManager 
        playerPos={pos} 
        targetPos={targetEnemyPos.current}
        bulletsDataRef={bulletsDataRef}
        projectileType={equipment.weapon?.projectileType}
      />
    </>
  );
};

