                                        <div className="text-slate-500 mt-1">Upgrade: <span className="text-yellow-400">{upgradeCost} G</span></div>
                                    </div>
                                </div>
                            )})}
                            {[...Array(Math.max(0, 20 - inventory.length))].map((_, i) => (
                                <div key={`empty-${i}`} className="aspect-square bg-slate-900/50 border border-slate-800 rounded" />
                            ))}
                        </div>
                    </div>
                </div>
            </motion.div>
          )}

          {/* GAME OVER */}
          {status === GameStatus.GAME_OVER && (
            <motion.div 
                initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                className="bg-slate-900/95 border border-red-900 p-12 rounded-lg text-center flex flex-col items-center gap-6 shadow-2xl"
            >
