                                        onClick={(e) => { e.stopPropagation(); upgradeItem(item); }}
                                        className="absolute -top-2 -right-2 bg-slate-900 border border-slate-600 rounded-full p-1 hover:bg-yellow-900 hover:border-yellow-500 z-10"
                                        title={`Upgrade: ${upgradeCost} G`}
                                        disabled={score < upgradeCost}
                                    >
                                        <Hammer size={12} className={score >= upgradeCost ? "text-yellow-400" : "text-slate-600"} />
                                    </button>

                                    {/* Tooltip */}
                                    <div className="absolute bottom-full mb-2 left-0 bg-black px-3 py-2 rounded text-xs w-32 hidden group-hover:block z-50 pointer-events-none border border-slate-700 shadow-xl">
                                        <div className="font-bold text-white mb-1">{item.name}</div>
                                        <div className="text-blue-400">+{item.value} {item.stat}</div>
                                        <div className="text-slate-500 mt-1">Upgrade: <span className="text-yellow-400">{upgradeCost} G</span></div>
                                    </div>
                                </div>
                            )})}
                            {[...Array(Math.max(0, 20 - inventory.length))].map((_, i) => (
                                <div key={`empty-${i}`} className="aspect-square bg-slate-900/50 border border-slate-800 rounded" />
                            ))}
                        </div>
                    </div>
                </div>
            </motion.div>
          )}

          {/* GAME OVER */}
          {status === GameStatus.GAME_OVER && (
            <motion.div 
                initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                className="bg-slate-900/95 border border-red-900 p-12 rounded-lg text-center flex flex-col items-center gap-6 shadow-2xl pointer-events-auto"
            >
              <h2 className="text-5xl font-serif text-red-500 drop-shadow-md">YOU DIED</h2>
              <div className="flex flex-col gap-1 text-xl text-slate-300">
                 <p>Gold Collected: <span className="text-yellow-400">{score.toLocaleString()}</span></p>
                 <p>Level Reached: {level}</p>
              </div>
              <button 
                onClick={resetGame}
                className="flex items-center gap-3 px-8 py-3 bg-red-800 hover:bg-red-700 text-white font-bold rounded shadow-lg mt-4"
              >
                <RotateCcw size={20} /> TRY AGAIN
              </button>
            </motion.div>
          )}

        </AnimatePresence>
      </div>
    </div>
  );
};

