import { Vector3 } from 'three';

export enum GameStatus {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  PAUSED = 'PAUSED',
  LEVEL_UP = 'LEVEL_UP',
  GAME_OVER = 'GAME_OVER',
  INVENTORY = 'INVENTORY',
  SHOP = 'SHOP',
}

export type UpgradeType = 
  'HEALTH' | 'SPEED' | 'DAMAGE' | 'FIRE_RATE' | 'MULTISHOT' | 'DASH_COOLDOWN' |
  'SKILL_ORBITAL' | 'SKILL_THUNDER' | 'SKILL_REGEN' | 'SKILL_MAGNET' |
  'CRIT_RATE' | 'CRIT_DAMAGE' | 'DEFENSE' | 'MAX_MANA';

export interface Upgrade {
  id: string;
  type: UpgradeType;
  name: string;
  description: string;
  rarity: 'COMMON' | 'RARE' | 'LEGENDARY';
  value: number;
}

export type ProjectileType = 'MAGIC' | 'ARROW' | 'AXE';
export type AbilityType = 'METEOR' | 'ARROW_RAIN' | 'AXE_AURA' | 'NONE';
export type ItemType = 'WEAPON' | 'ARMOR' | 'ACCESSORY' | 'POTION' | 'CORE';
export type Rarity = 'COMMON' | 'RARE' | 'EPIC' | 'LEGENDARY' | 'MYTHIC';

export interface Item {
  id: string;
  name: string;
  type: ItemType;
  stat?: keyof PlayerStats; // Potions/Cores might not have a stat mapping
  value: number;
  rarity: Rarity;
  price: number;
  level: number;
  projectileType?: ProjectileType;
  ability?: AbilityType;
  description?: string;
  stackSize?: number; // For potions/cores
  quantity?: number; // Current held amount
}

export interface PlayerStats {
  maxHealth: number;
  maxMana: number;
  regen: number; // HP per second
  moveSpeed: number;
  damage: number;
  fireRate: number; // bullets per second
  projectileSpeed: number;
  multishot: number;
  spread: number;
  dashCooldown: number;
  magnetRadius: number;
  critRate: number; // 0-1
  critDamage: number; // multiplier (e.g. 1.5)
  defense: number; // Reduces incoming damage
}

export interface EnemyData {
  id: number;
  position: Vector3;
  type: number; // 0: Slime, 1: Orc, 2: Boss, 3: Shooter
  health: number;
  maxHealth: number;
  speed: number;
  radius: number;
  scale: number;
  active: boolean;
  state?: 'CHASE' | 'CHARGE_PREP' | 'CHARGE' | 'SHOOT';
  stateTimer?: number;
  chargeDir?: Vector3;
}

export interface BulletData {
  id: number;
  position: Vector3;
  velocity: Vector3;
  active: boolean;
  lifetime: number;
  type: ProjectileType; // To track logic in loop
  state?: number; // 0: Out, 1: Return (for boomerang)
  pierce?: number; // How many enemies it can hit
  hitIds: number[]; // Track enemies hit to prevent hitting same enemy every frame
}

export interface CrateData {
  id: number;
  position: Vector3;
  active: boolean;
  rotation: number;
}

export interface DropData {
  id: number;
  position: Vector3;
  item: Item | null; // null means just XP/Gold visual
  type: 'ITEM' | 'GOLD' | 'XP';
  active: boolean;
  value: number;
  rotation: number;
}

export interface SkillLevels {
    orbital: number;
    thunder: number;
    regen: number;
}

import { create } from 'zustand';
import { GameStatus, PlayerStats, Upgrade, Item, DropData, SkillLevels, Rarity } from './types';
import { Vector3 } from 'three';
import { ITEMS_POOL } from './constants';

interface GameState {
  status: GameStatus;
  score: number; // Used as GOLD
  level: number;
  experience: number;
  experienceToNextLevel: number;
  health: number;
  mana: number;
  playerPosition: Vector3;
  stats: PlayerStats;
  baseStats: PlayerStats;

  skillLevels: SkillLevels;

  inventory: Item[];
  equipment: {
    weapon: Item | null;
    armor: Item | null;
    accessory: Item | null;
  };

  drops: DropData[];

  skills: {
    dash: number;
    weaponAbility: number;
  };
  skillMaxCooldowns: {
    dash: number;
    weaponAbility: number;
  };

  potionCooldown: number;

  setStatus: (status: GameStatus) => void;
  startGame: () => void;
  addScore: (amount: number) => void;
  addExperience: (amount: number) => void;
  takeDamage: (amount: number) => void;
  useMana: (amount: number) => boolean;
  heal: (amount: number) => void;
  restoreMana: (amount: number) => void;
  setPlayerPosition: (pos: Vector3) => void;
  applyUpgrade: (upgrade: Upgrade) => void;
  equipItem: (item: Item) => void;
  unequipItem: (slot: 'weapon' | 'armor' | 'accessory') => void;
  buyItem: (item: Item, quantity?: number) => boolean;
  sellItem: (item: Item) => void;
  gachaSummon: () => Item | null;
  upgradeItem: (item: Item) => { success: boolean, msg: string };
  resetGame: () => void;

  spawnDrop: (position: Vector3, type: 'ITEM' | 'XP' | 'GOLD', value: number, rarityOverride?: Rarity) => void;
  collectDrop: (id: number) => void;
  triggerSkillCooldown: (skill: 'dash' | 'weaponAbility') => void;
  tickCooldowns: (delta: number) => void;
}

const INITIAL_STATS: PlayerStats = {
  maxHealth: 100,
  maxMana: 100,
  regen: 1.0, // Base regen
  moveSpeed: 10,
  damage: 15,
  fireRate: 2.0,
  projectileSpeed: 20,
  multishot: 1,
  spread: 0.2,
  dashCooldown: 2.0,
  magnetRadius: 5.0,
  critRate: 0.05,
  critDamage: 1.5,
  defense: 0
};

const calculateStats = (base: PlayerStats, equipment: GameState['equipment']) => {
  const final = { ...base };
  Object.values(equipment).forEach(item => {
    if (item && item.stat) {
      // @ts-ignore
      final[item.stat] += item.value;
    }
  });
  return final;
};

export const useGameStore = create<GameState>((set, get) => ({
  status: GameStatus.MENU,
  score: 0,
  level: 1,
  experience: 0,
  experienceToNextLevel: 100,
  health: 100,
  mana: 100,
  playerPosition: new Vector3(0, 0, 0),
  stats: { ...INITIAL_STATS },
  baseStats: { ...INITIAL_STATS },
  skillLevels: { orbital: 0, thunder: 0, regen: 0 },
  inventory: [],
  equipment: { weapon: null, armor: null, accessory: null },
  drops: [],
  skills: { dash: 0, weaponAbility: 0 },
  skillMaxCooldowns: { dash: 2.0, weaponAbility: 8.0 },
  potionCooldown: 0,

  setStatus: (status) => set({ status }),

  startGame: () => set({
    status: GameStatus.PLAYING,
    score: 100, // Start with some gold
    level: 1,
    experience: 0,
    experienceToNextLevel: 100,
    health: 100,
    mana: 100,
    baseStats: { ...INITIAL_STATS },
    stats: { ...INITIAL_STATS },
    skillLevels: { orbital: 0, thunder: 0, regen: 0 },
    playerPosition: new Vector3(0, 0, 0),
    inventory: [
        { ...ITEMS_POOL.find(i => i.id === 'potion_hp')!, id: 'start_hp', quantity: 100 },
        { ...ITEMS_POOL.find(i => i.id === 'potion_mana')!, id: 'start_mana', quantity: 100 }
    ], 
    equipment: { weapon: null, armor: null, accessory: null },
    drops: [],
    skills: { dash: 0, weaponAbility: 0 }
  }),

  addScore: (amount) => set((state) => ({ score: state.score + amount })),

  addExperience: (amount) => {
    const adjustedAmount = amount * 2;
    const { experience, experienceToNextLevel, level } = get();
    let newExp = experience + adjustedAmount;

    if (newExp >= experienceToNextLevel) {
      set({
        experience: newExp - experienceToNextLevel,
        experienceToNextLevel: Math.floor(experienceToNextLevel * 1.5),
        level: level + 1,
        status: GameStatus.LEVEL_UP,
      });
    } else {
      set({ experience: newExp });
    }
  },

  takeDamage: (amount) => {
    const { health, status, stats, playerPosition } = get();
    if (status !== GameStatus.PLAYING) return;

    const reductionMultiplier = 100 / (100 + stats.defense);
    const actualDamage = Math.max(1, amount * reductionMultiplier);

    const newHealth = health - actualDamage;

    // Dispatch Damage Text Event for Player
    window.dispatchEvent(new CustomEvent('damage', { 
        detail: { position: playerPosition, damage: actualDamage, isCrit: false, isPlayer: true } 
    }));

    if (newHealth <= 0) {
      set({ health: 0, status: GameStatus.GAME_OVER });
    } else {
      set({ health: newHealth });
    }
  },

  useMana: (amount) => {
      const { mana } = get();
      if (mana >= amount) {
          set({ mana: mana - amount });
          return true;
      }
      return false;
  },

  heal: (amount) => set((state) => ({ 
    health: Math.min(state.health + amount, state.stats.maxHealth) 
  })),

  restoreMana: (amount) => set((state) => ({ 
    mana: Math.min(state.mana + amount, state.stats.maxMana) 
  })),

  setPlayerPosition: (pos) => set({ playerPosition: pos }),

  spawnDrop: (position, type, value, rarityOverride) => set((state) => {
      if (state.drops.length > 99) {
          return { drops: state.drops };
      }

      let item = null;
      if (type === 'ITEM') {
          // If rarityOverride is provided (Boss drops), filter by that
          // Otherwise, normal random logic
          let pool = ITEMS_POOL;

          if (rarityOverride) {
              pool = ITEMS_POOL.filter(i => i.rarity === rarityOverride && i.type !== 'POTION' && i.type !== 'CORE');
              // Fallback to Legendary if no Mythic found etc.
              if (pool.length === 0) pool = ITEMS_POOL.filter(i => i.type !== 'POTION' && i.type !== 'CORE');
          } else {
               // Normal enemies mostly drop potions or cores or gold
               const r = Math.random();
               if (r > 0.95) {
                   // Gear (Common/Rare)
                   pool = ITEMS_POOL.filter(i => (i.rarity === 'COMMON' || i.rarity === 'RARE') && i.type !== 'POTION' && i.type !== 'CORE');
               } else if (r > 0.6) {
                   // Cores
                   pool = ITEMS_POOL.filter(i => i.type === 'CORE');
               } else {
                   // Potions
                   pool = ITEMS_POOL.filter(i => i.type === 'POTION');
               }
          }

          const template = pool[Math.floor(Math.random() * pool.length)];
          item = { ...template, id: Math.random().toString() };
          item.quantity = 1;

          // Random Plus Logic (+1 to +3) for Gear
          if (item.type === 'WEAPON' || item.type === 'ARMOR' || item.type === 'ACCESSORY') {
               const plusChance = Math.random();
               let plus = 0;
               if (plusChance > 0.95) plus = 3;
               else if (plusChance > 0.85) plus = 2;
               else if (plusChance > 0.60) plus = 1;

               if (plus > 0) {
                   item.level += plus;
                   // Pre-calc stats
                   for(let i=0; i<plus; i++) {
                       item.value = item.stat === 'fireRate' || item.stat === 'moveSpeed' || item.stat === 'critRate' 
                             ? parseFloat((item.value * 1.05).toFixed(2)) 
                             : Math.ceil(item.value * 1.1);
                   }
               }
          }
      }

      return {
          drops: [...state.drops, {
              id: Math.random(),
              position: position.clone(),
              type,
              value,
              item,
              active: true,
              rotation: Math.random() * Math.PI
          }]
      };
  }),

  collectDrop: (id) => set((state) => {
      const drop = state.drops.find(d => d.id === id);
      if (!drop) return { drops: state.drops };

      const newDrops = state.drops.filter(d => d.id !== id);

      if (drop.type === 'XP') {
         get().addExperience(drop.value);
      } else if (drop.type === 'GOLD') {
         get().addScore(drop.value);
      } else if (drop.type === 'ITEM' && drop.item) {
          // Stack logic for Potions/Cores
          const existingStack = state.inventory.find(i => i.name === drop.item!.name && (i.type === 'POTION' || i.type === 'CORE'));
          if (existingStack) {
              existingStack.quantity = (existingStack.quantity || 1) + 1;
              return { drops: newDrops, inventory: [...state.inventory] };
          }
          return { drops: newDrops, inventory: [...state.inventory, { ...drop.item }] };
      }

      return { drops: newDrops };
  }),

  triggerSkillCooldown: (skill) => set((state) => ({
      skills: { ...state.skills, [skill]: state.skillMaxCooldowns[skill] }
  })),

  tickCooldowns: (delta) => {
      const state = get();
      const newSkills = {
          dash: Math.max(0, state.skills.dash - delta),
          weaponAbility: Math.max(0, state.skills.weaponAbility - delta)
      };

      // Passive Regen
      const regenAmount = (state.stats.regen + state.skillLevels.regen) * delta;
      const newHealth = Math.min(state.stats.maxHealth, state.health + regenAmount);

      // Auto Potion Logic
      let newPotionCD = Math.max(0, state.potionCooldown - delta);
      let newHealthAfterPot = newHealth;
      let newManaAfterPot = state.mana;
      let inventory = state.inventory;

      if (newPotionCD <= 0) {
          // Check HP Potion
          if (newHealth < state.stats.maxHealth * 0.5) {
              const hpPotIndex = inventory.findIndex(i => i.id === 'potion_hp' || i.name === 'Health Potion');
              if (hpPotIndex !== -1) {
                  const pot = inventory[hpPotIndex];
                  newHealthAfterPot = Math.min(state.stats.maxHealth, newHealth + pot.value);
                  newPotionCD = 10; // 10s Cooldown
                  // Reduce Quantity
                  if ((pot.quantity || 1) > 1) {
                      pot.quantity = (pot.quantity || 1) - 1;
                      inventory = [...inventory];
                  } else {
                      inventory = inventory.filter((_, idx) => idx !== hpPotIndex);
                  }
              }
          }
          // Check Mana Potion
          if (newPotionCD <= 0 && state.mana < state.stats.maxMana * 0.5) {
               const manaPotIndex = inventory.findIndex(i => i.id === 'potion_mana' || i.name === 'Mana Potion');
               if (manaPotIndex !== -1) {
                  const pot = inventory[manaPotIndex];
                  newManaAfterPot = Math.min(state.stats.maxMana, state.mana + pot.value);
                  newPotionCD = 10;
                   if ((pot.quantity || 1) > 1) {
                      pot.quantity = (pot.quantity || 1) - 1;
                      inventory = [...inventory];
                  } else {
                      inventory = inventory.filter((_, idx) => idx !== manaPotIndex);
                  }
               }
          }
      }

      set({
          skills: newSkills,
          health: newHealthAfterPot,
          mana: newManaAfterPot,
          potionCooldown: newPotionCD,
          inventory: inventory
      });
  },

  applyUpgrade: (upgrade) => set((state) => {
    const newBase = { ...state.baseStats };
    const newSkillLevels = { ...state.skillLevels };

    switch (upgrade.type) {
      case 'HEALTH': newBase.maxHealth += upgrade.value; break;
      case 'MAX_MANA': newBase.maxMana += upgrade.value; break;
      case 'DEFENSE': newBase.defense += upgrade.value; break;
      case 'SPEED': newBase.moveSpeed *= (1 + upgrade.value); break;
      case 'DAMAGE': newBase.damage *= (1 + upgrade.value); break;
      case 'FIRE_RATE': newBase.fireRate *= (1 + upgrade.value); break;
      case 'MULTISHOT': newBase.multishot += upgrade.value; break;
      case 'DASH_COOLDOWN': newBase.dashCooldown *= (1 - upgrade.value); break;
      case 'SKILL_MAGNET': newBase.magnetRadius += upgrade.value; break;
      case 'CRIT_RATE': newBase.critRate += upgrade.value; break;
      case 'CRIT_DAMAGE': newBase.critDamage += upgrade.value; break;
      case 'SKILL_ORBITAL': newSkillLevels.orbital++; break;
      case 'SKILL_THUNDER': newSkillLevels.thunder++; break;
      case 'SKILL_REGEN': newBase.regen += upgrade.value; break;
    }
    const newStats = calculateStats(newBase, state.equipment);
    return { 
        baseStats: newBase,
        stats: newStats, 
        skillLevels: newSkillLevels,
        health: upgrade.type === 'HEALTH' ? Math.min(state.health + 30, newStats.maxHealth) : state.health,
        mana: upgrade.type === 'MAX_MANA' ? Math.min(state.mana + 20, newStats.maxMana) : state.mana,
        status: GameStatus.PLAYING,
        skillMaxCooldowns: {
            ...state.skillMaxCooldowns,
            dash: upgrade.type === 'DASH_COOLDOWN' ? state.skillMaxCooldowns.dash * (1 - upgrade.value) : state.skillMaxCooldowns.dash
        }
    };
  }),

  equipItem: (item) => set((state) => {
    if (item.type === 'POTION' || item.type === 'CORE') return state; // Cannot equip consumables
    const slot = item.type.toLowerCase() as keyof GameState['equipment'];
    const oldItem = state.equipment[slot];
    const newEquipment = { ...state.equipment, [slot]: item };
    const newStats = calculateStats(state.baseStats, newEquipment);
    let newInv = state.inventory.filter(i => i !== item);
    if (oldItem) newInv.push(oldItem);
    return { equipment: newEquipment, stats: newStats, inventory: newInv };
  }),

  unequipItem: (slot) => set((state) => {
    const item = state.equipment[slot];
    if (!item) return state;
    const newEquipment = { ...state.equipment, [slot]: null };
    const newStats = calculateStats(state.baseStats, newEquipment);
    return { equipment: newEquipment, stats: newStats, inventory: [...state.inventory, item] };
  }),

  buyItem: (item, quantity = 1) => {
      const state = get();
      const totalCost = item.price * quantity;

      if (state.score >= totalCost) {
          // Stack check
          const existing = state.inventory.find(i => i.name === item.name && (item.type === 'POTION' || item.type === 'CORE'));
          let newInv = [...state.inventory];

          if (existing) {
              existing.quantity = (existing.quantity || 1) + quantity;
          } else {
              // Gear usually doesn't stack but bulk buying gear implies buying copies
              // If gear, add multiple copies. If stackable, add stack
              if (item.type === 'POTION' || item.type === 'CORE') {
                  newInv.push({ ...item, quantity: quantity, id: Math.random().toString() });
              } else {
                  for(let i=0; i<quantity; i++) {
                       newInv.push({ ...item, quantity: 1, id: Math.random().toString() });
                  }
              }
          }

          set({
              score: state.score - totalCost,
              inventory: newInv
          });
          return true;
      }
      return false;
  },

  sellItem: (item) => set((state) => {
      let newInv = state.inventory.filter(i => i !== item);
      const sellValue = Math.floor(item.price * 0.4); // 40% sell back value
      return {
          inventory: newInv,
          score: state.score + sellValue
      };
  }),

  gachaSummon: () => {
    const state = get();
    const COST = 500;

    if (state.score < COST) return null;

    const gearPool = ITEMS_POOL.filter(i => i.type !== 'POTION' && i.type !== 'CORE');

    const rand = Math.random();
    let rarity: Rarity = 'COMMON';

    if (rand > 0.98) rarity = 'LEGENDARY'; // 2%
    else if (rand > 0.85) rarity = 'EPIC'; // 13%
    else if (rand > 0.60) rarity = 'RARE'; // 25%

    let pool = gearPool.filter(i => i.rarity === rarity);
    if (pool.length === 0) pool = gearPool.filter(i => i.rarity === 'COMMON');

    const template = pool[Math.floor(Math.random() * pool.length)];
    const newItem = { ...template, id: Math.random().toString(), quantity: 1 };

    set({
        score: state.score - COST,
        inventory: [...state.inventory, newItem]
    });

    return newItem;
  },

  upgradeItem: (item) => {
      const state = get();
      const core = state.inventory.find(i => i.type === 'CORE');
      const coreIndex = state.inventory.findIndex(i => i.type === 'CORE');

      const requiredCores = Math.ceil(item.level / 2);
      const goldCost = Math.floor(item.price * item.level * 0.5);

      if (state.score < goldCost) return { success: false, msg: "Not enough Gold" };
      if (!core || (core.quantity || 1) < requiredCores) return { success: false, msg: `Need ${requiredCores} Cores` };

      // Success Chance
      const chance = Math.max(10, 100 - (item.level * 10));
      const roll = Math.random() * 100;
      const success = roll < chance;

      // Consume Cores
      const newInventory = [...state.inventory];
      const coreItem = newInventory[coreIndex];
      if ((coreItem.quantity || 1) > requiredCores) {
          coreItem.quantity = (coreItem.quantity || 1) - requiredCores;
      } else {
          newInventory.splice(coreIndex, 1);
      }

      set({ score: state.score - goldCost, inventory: newInventory });

      if (success) {
           const upgradeLogic = (i: Item) => {
              if (i === item) {
                  return {
                      ...i,
                      level: i.level + 1,
                      value: i.stat === 'fireRate' || i.stat === 'moveSpeed' || i.stat === 'critRate' 
                             ? parseFloat((i.value * 1.05).toFixed(2)) 
                             : Math.ceil(i.value * 1.1)
                  };
              }
              return i;
          };

          const updatedInventory = get().inventory.map(upgradeLogic);
          const updatedEquipment = {
              weapon: state.equipment.weapon ? upgradeLogic(state.equipment.weapon) : null,
              armor: state.equipment.armor ? upgradeLogic(state.equipment.armor) : null,
              accessory: state.equipment.accessory ? upgradeLogic(state.equipment.accessory) : null,
          };
          const newStats = calculateStats(state.baseStats, updatedEquipment);

          set({ inventory: updatedInventory, equipment: updatedEquipment, stats: newStats });
          return { success: true, msg: "Upgrade Successful!" };
      } else {
          return { success: false, msg: "Upgrade Failed..." };
      }
  },

  resetGame: () => set({
    status: GameStatus.MENU,
  }),
}));

import React, { useRef, useLayoutEffect, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, DynamicDrawUsage } from 'three';
import { useGameStore } from '../store';
import { MAX_BULLETS, COLORS } from '../constants';
import { GameStatus, BulletData, ProjectileType } from '../types';

interface BulletManagerProps {
  playerPos: Vector3;
  targetPos: Vector3 | null;
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  projectileType?: ProjectileType;
}

const dummy = new Object3D();

export const BulletManager: React.FC<BulletManagerProps> = ({ playerPos, targetPos, bulletsDataRef, projectileType = 'MAGIC' }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const { stats, status } = useGameStore();

  // Local storage for bullets logic
  const bullets = useRef(new Array(MAX_BULLETS).fill(0).map((_, i) => ({
    id: i,
    active: false,
    position: new Vector3(),
    velocity: new Vector3(),
    lifetime: 0,
    type: 'MAGIC' as ProjectileType,
    state: 0,
    pierce: 1,
    hitIds: [] as number[]
  })));

  const lastShot = useRef(0);

  // Sync with parent ref once
  useEffect(() => {
    bulletsDataRef.current = bullets.current;
  }, []);

  useLayoutEffect(() => {
    if (meshRef.current) {
        meshRef.current.instanceMatrix.setUsage(DynamicDrawUsage);
    }
  }, []);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    const time = state.clock.getElapsedTime();

    // 1. Auto-Fire Logic
    const fireInterval = 1 / stats.fireRate;

    if (targetPos && time - lastShot.current > fireInterval) {
      lastShot.current = time;

      const dir = new Vector3().subVectors(targetPos, playerPos).normalize();
      const startAngle = - (stats.spread * (stats.multishot - 1)) / 2;

      for (let i = 0; i < stats.multishot; i++) {
        const bullet = bullets.current.find(b => !b.active);
        if (bullet) {
            bullet.active = true;
            bullet.lifetime = projectileType === 'AXE' ? 1.5 : 3.0;
            bullet.position.copy(playerPos).add(new Vector3(0, 1, 0));
            bullet.type = projectileType;
            bullet.state = 0; // Reset state
            bullet.hitIds = []; // Clear hit list

            // Stats per weapon type
            bullet.pierce = projectileType === 'AXE' ? 99 : 1; // Axes pierce all
            if (projectileType === 'MAGIC') bullet.pierce = 2; // Staff pierces 1 enemy

            const angle = startAngle + (i * stats.spread);
            const spreadDir = dir.clone().applyAxisAngle(new Vector3(0, 1, 0), angle);

            // Projectile Speed logic
            let speed = stats.projectileSpeed;
            if (projectileType === 'AXE') speed *= 0.8;
            if (projectileType === 'MAGIC') speed *= 0.6; // Staff is slow
            if (projectileType === 'ARROW') speed *= 1.5; // Bow is fast

            bullet.velocity.copy(spreadDir).multiplyScalar(speed);
        }
      }
    }

    // 2. Bullet Update Logic
    let activeCount = 0;
    for (let i = 0; i < MAX_BULLETS; i++) {
        const b = bullets.current[i];
        if (b.active) {

            if (b.type === 'AXE') {
                // Boomerang Logic
                // State 0: Going Out. State 1: Returning.
                if (b.state === 0) {
                    b.velocity.multiplyScalar(0.95); // Drag
                    if (b.velocity.length() < 2) {
                        b.state = 1; // Start returning
                        b.hitIds = []; // Reset hit list so it can hit enemies again on return
                    }
                } else {
                    // Return to player
                    const toPlayer = new Vector3().subVectors(playerPos, b.position).normalize();
                    b.velocity.add(toPlayer.multiplyScalar(50 * delta)); // Accelerate back

                    // Catch axe
                    if (b.position.distanceTo(playerPos) < 1.5) {
                        b.active = false;
                    }
                }
                b.position.add(b.velocity.clone().multiplyScalar(delta));
            } else {
                // Normal Linear movement
                b.position.add(b.velocity.clone().multiplyScalar(delta));
            }

            b.lifetime -= delta;

            if (b.lifetime <= 0) {
                b.active = false;
                dummy.position.set(0, -100, 0);
            } else {
                dummy.position.copy(b.position);

                if (b.type === 'AXE') {
                     dummy.rotation.set(0, time * 20, 0); // Spin fast
                     dummy.scale.set(1.5, 1.5, 1.5);
                } else if (b.type === 'MAGIC') {
                     dummy.rotation.set(time, time, time);
                     dummy.scale.set(2, 2, 2); // Big hitbox visual
                } else {
                     // ARROW
                     const lookAtPos = b.position.clone().add(b.velocity);
                     dummy.lookAt(lookAtPos);
                     dummy.scale.set(1, 1, 1);
                }
            }
            activeCount++;
        } else {
            dummy.position.set(0, -100, 0);
            dummy.scale.set(0, 0, 0);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh key={projectileType} ref={meshRef} args={[undefined, undefined, MAX_BULLETS]} frustumCulled={false}>
      {/* Dynamic geometry based on equipped weapon? 
          Actually InstancedMesh needs one geometry. 
          We can switch geometry based on the `projectileType` prop passed in, causing re-mount when weapon changes.
      */}
      {projectileType === 'ARROW' && <cylinderGeometry args={[0.05, 0.05, 1.5, 6]} rotation={[Math.PI / 2, 0, 0]} />}
      {projectileType === 'MAGIC' && <dodecahedronGeometry args={[0.3, 0]} />} 
      {projectileType === 'AXE' && <boxGeometry args={[1, 0.1, 1]} />}

      <meshStandardMaterial 
        color={projectileType === 'ARROW' ? '#d4d4d8' : projectileType === 'AXE' ? '#94a3b8' : COLORS.bulletPlayer} 
        emissive={projectileType === 'MAGIC' ? COLORS.bulletPlayer : '#000'} 
        emissiveIntensity={projectileType === 'MAGIC' ? 2 : 0} 
      />
    </instancedMesh>
  );
};

import React, { useRef } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, Color } from 'three';
import { useGameStore } from '../store';
import { ARENA_SIZE, COLORS } from '../constants';
import { GameStatus, EnemyData, BulletData } from '../types';

const MAX_ENEMIES = 400;

const dummy = new Object3D();
const tempVec = new Vector3();
const tempColor = new Color();

interface EnemyManagerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
}

export const EnemyManager: React.FC<EnemyManagerProps> = ({ bulletsDataRef, enemyBulletsDataRef }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const { playerPosition, addScore, addExperience, takeDamage, status, level, stats, spawnDrop } = useGameStore();

  const enemies = useRef(new Array(MAX_ENEMIES).fill(0).map((_, i) => ({
    id: i,
    active: false,
    type: 0,
    health: 100,
    maxHealth: 100,
    position: new Vector3(),
    speed: 5,
    radius: 0.8,
    scale: 1,
    state: 'CHASE',
    stateTimer: 0
  } as EnemyData)));

  const spawnTimer = useRef(0);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    if (!meshRef.current.userData.enemies) {
        meshRef.current.userData.enemies = enemies.current;
        meshRef.current.name = "EnemyMesh";
    }

    // 1. Spawning
    spawnTimer.current += delta;
    const spawnRate = Math.max(0.1, 0.8 - (level * 0.04));

    if (spawnTimer.current > spawnRate) {
        spawnTimer.current = 0;
        const enemy = enemies.current.find(e => !e.active);
        if (enemy) {
            enemy.active = true;
            let angle, dist, spawnPos;
            do {
                angle = Math.random() * Math.PI * 2;
                dist = (ARENA_SIZE / 2) - 5;
                spawnPos = new Vector3(Math.cos(angle) * dist, 0, Math.sin(angle) * dist);
            } while (spawnPos.distanceTo(playerPosition) < 20);

            enemy.position.copy(spawnPos);

            const r = Math.random();
            if (level > 4 && r > 0.98) {
                // Boss
                enemy.type = 2;
                enemy.health = 500 + (level * 100);
                enemy.speed = 3 + (level * 0.1);
                enemy.radius = 2.5;
                enemy.scale = 3.0;
                enemy.state = 'CHASE';
                tempColor.set(COLORS.enemyBoss);
            } else if (level > 3 && r > 0.85) {
                // Shooter
                enemy.type = 3; 
                enemy.health = 40 + (level * 10);
                enemy.speed = 3.0;
                enemy.radius = 0.8;
                enemy.scale = 0.9;
                enemy.state = 'CHASE';
                tempColor.set(COLORS.enemyShooter);
            } else if (r > 0.75 && level > 2) {
                // Orc
                enemy.type = 1; 
                enemy.health = 60 + (level * 15);
                enemy.speed = 3.5 + (level * 0.1);
                enemy.radius = 1.0;
                enemy.scale = 1.2;
                tempColor.set(COLORS.enemyOrc);
            } else {
                // Slime
                enemy.type = 0;
                enemy.health = 25 + (level * 8);
                enemy.speed = 4 + (level * 0.15);
                enemy.radius = 0.6;
                enemy.scale = 0.8;
                tempColor.set(COLORS.enemySlime);
            }
            enemy.maxHealth = enemy.health;

            meshRef.current.setColorAt(enemies.current.indexOf(enemy), tempColor);
            meshRef.current.instanceColor!.needsUpdate = true;
        }
    }

    // 2. Logic & Collision
    const activeBullets = bulletsDataRef.current;
    const baseDamage = stats.damage;
    const critRate = stats.critRate;
    const critDamage = stats.critDamage;

    for (let i = 0; i < MAX_ENEMIES; i++) {
        const e = enemies.current[i];
        if (e.active) {

            const distToPlayer = e.position.distanceTo(playerPosition);

            // AI Movement (Simplified)
            if (e.type === 3 && distToPlayer > 15) { // Shooter keep distance
                 tempVec.subVectors(playerPosition, e.position).normalize();
                 e.position.add(tempVec.multiplyScalar(e.speed * delta));
            } else if (e.type !== 3) {
                 // Melee / Boss
                 tempVec.subVectors(playerPosition, e.position).normalize();
                 e.position.add(tempVec.multiplyScalar(e.speed * delta));
            }

            // Shooter Firing Logic
            if (e.type === 3) {
                e.stateTimer = (e.stateTimer || 0) + delta;
                if (e.stateTimer > 2.0 && distToPlayer < 25) {
                    e.stateTimer = 0;
                    const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                    if (bullet) {
                        bullet.active = true;
                        bullet.lifetime = 3.0;
                        bullet.position.copy(e.position).add(new Vector3(0, 1, 0));
                        const aimDir = new Vector3().subVectors(playerPosition, e.position).normalize();
                        bullet.velocity.copy(aimDir).multiplyScalar(15);
                    }
                }
            }

            // Player Collision Damage
            if (e.type !== 3 && distToPlayer < e.radius + 0.5) {
                takeDamage((e.type === 2 ? 30 : 10) * delta);
            }

            // Bullet Collision
            for(let b=0; b < activeBullets.length; b++) {
                const bullet = activeBullets[b];
                if (bullet.active) {
                    // Check already hit for multi-hit projectiles like Axe
                    if (bullet.hitIds && bullet.hitIds.includes(e.id)) continue;

                    // Larger hit radius for Magic
                    const hitRadius = e.radius + (bullet.type === 'MAGIC' ? 1.5 : 0.5); 

                    if (bullet.position.distanceTo(e.position) < hitRadius) {

                        const isCrit = Math.random() < critRate;
                        const dmg = (isCrit ? baseDamage * critDamage : baseDamage);

                        e.health -= dmg;

                        window.dispatchEvent(new CustomEvent('damage', { 
                            detail: { position: e.position, damage: dmg, isCrit } 
                        }));

                        // Add to hit list
                        if (bullet.hitIds) bullet.hitIds.push(e.id);

                        // Magic AOE splash
                        if (bullet.type === 'MAGIC') {
                            // Hit other nearby enemies
                            for(let j=0; j<MAX_ENEMIES; j++) {
                                if(i!==j && enemies.current[j].active && enemies.current[j].position.distanceTo(e.position) < 4.0) {
                                    enemies.current[j].health -= dmg * 0.5; // 50% splash dmg
                                }
                            }
                        }

                        // Knockback
                        if (e.type !== 2) {
                            const kbDir = e.position.clone().sub(bullet.position).normalize();
                            e.position.add(kbDir.multiplyScalar(0.4));
                        }

                        // Pierce Logic
                        if (bullet.pierce && bullet.pierce > 0) {
                            bullet.pierce--;
                            if (bullet.pierce <= 0) bullet.active = false;
                        } else {
                            bullet.active = false;
                        }
                    }
                }
            }

            // Death Logic
            if (e.health <= 0) {
                e.active = false;
                addScore(10 * (e.type + 1));

                // Drop Logic
                if (e.type === 2) { 
                    // Boss Drop (Guaranteed 1 Drop)
                    const roll = Math.random();
                    if (roll > 0.995) spawnDrop(e.position, 'ITEM', 0, 'MYTHIC'); // 0.5%
                    else if (roll > 0.99) spawnDrop(e.position, 'ITEM', 0, 'LEGENDARY'); // 0.5%
                    else if (roll > 0.98) spawnDrop(e.position, 'ITEM', 0, 'EPIC'); // 1%
                    else spawnDrop(e.position, 'ITEM', 0, 'RARE'); // Fallback Rare

                    spawnDrop(e.position.clone().add(new Vector3(1,0,0)), 'XP', 1000); 
                } else {
                    // Normal Drop (Reduced rates 60%)
                    // Standard: 25% chance -> Reduced to 10% chance
                    if (Math.random() > 0.90) {
                        spawnDrop(e.position, 'ITEM', 0);
                    } else {
                        spawnDrop(e.position, 'XP', e.type === 3 ? 30 : 20);
                    }
                }
                dummy.position.set(0, -100, 0);
            } else {
                dummy.position.copy(e.position);
                dummy.scale.set(e.scale, e.scale, e.scale);
                if (e.type !== 2) dummy.position.y = Math.abs(Math.sin(state.clock.elapsedTime * 5)) * 0.5;
                dummy.lookAt(playerPosition);
            }

        } else {
            dummy.position.set(0, -100, 0);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, MAX_ENEMIES]} frustumCulled={false}>
      <boxGeometry args={[1, 1, 1]} />
      <meshStandardMaterial vertexColors roughness={0.5} metalness={0.2} />
    </instancedMesh>
  );
};

