const ItemIcon = ({ item, size }: { item: Item, size: number }) => {
    if (item.type === 'POTION') return <FlaskConical size={size} />;
    if (item.type === 'CORE') return <Hexagon size={size} />;
    if (item.type === 'ACCESSORY') return <Gem size={size} />;
    if (item.type === 'ARMOR') return <Shield size={size} />;
    if (item.projectileType === 'MAGIC') return <Wand2 size={size} />;
    if (item.projectileType === 'ARROW') return <Crosshair size={size} />;
    if (item.projectileType === 'AXE') return <Axe size={size} />;
    return <Sword size={size} />;
};

interface ShopItemProps {
    item: Item;
    buyItem: (i: Item, q?: number) => boolean;
    score: number;
    bulk: boolean;
}

const ShopItem: React.FC<ShopItemProps> = ({ item, buyItem, score, bulk }) => {
    const qty = bulk ? 10 : 1;
    const finalPrice = item.price * qty;

    return (
        <div className="bg-slate-800 p-4 rounded border border-slate-700 flex flex-col gap-2 relative overflow-hidden group">
            <div className="flex justify-between items-start z-10">
                <h3 className={`font-bold ${item.rarity === 'MYTHIC' ? 'text-red-400' : item.rarity === 'EPIC' ? 'text-purple-400' : 'text-slate-200'}`}>{item.name}</h3>
                <ItemIcon item={item} size={16} />
            </div>

            {item.setName && (
                 <div className="text-[10px] text-yellow-500 font-bold uppercase tracking-wider flex items-center gap-1 z-10">
                    <Layers size={10} /> {item.setName}
                 </div>
            )}

            <p className="text-xs text-slate-400 z-10">{item.description || `+${item.value} ${item.stat}`}</p>

            {item.setName && (
                <p className="text-[10px] text-slate-500 italic z-10 mt-1">Set Bonus: {item.setBonus}</p>
            )}

            <div className="mt-auto pt-2 flex justify-between items-center z-10">
                <span className="text-yellow-400 font-mono">{finalPrice} G</span>
                <button 
                    onClick={() => buyItem(item, qty)}
                    disabled={score < finalPrice}
                    className={`px-3 py-1 rounded text-sm font-bold flex items-center gap-1 ${score >= finalPrice ? 'bg-blue-600 hover:bg-blue-500 text-white' : 'bg-slate-700 text-slate-500 cursor-not-allowed'}`}
                >
                    BUY {bulk && <span className="text-[10px] bg-black/20 px-1 rounded">x10</span>}
                </button>
            </div>
        </div>
    );
};

const EquipmentSlot = ({ 
    type, icon, label, item, onClick, onUpgrade, canUpgrade, onHover 
}: { 
    type: ItemType, icon?: any, label: string, item: Item | null, onClick: () => void, onUpgrade?: () => void, canUpgrade?: boolean, onHover: (i: Item | null) => void
}) => {
    // Determine icon based on type if not provided, or based on item if equipped
    const renderIcon = () => {
        if (item) return <ItemIcon item={item} size={24} />;
        if (type === 'WEAPON') return <Sword size={24} />;
        if (type === 'ARMOR') return <Shield size={24} />;
        if (type === 'ACCESSORY') return <Gem size={24} />;
        return <Sword size={24} />;
    };

    return (
        <div 
            className="w-full flex gap-2"
            onMouseEnter={() => item && onHover(item)}
            onMouseLeave={() => onHover(null)}
        >
            <button onClick={onClick} disabled={!item} className={`flex-1 flex items-center gap-4 p-3 rounded border transition-colors ${item ? 'bg-slate-800 border-slate-600 hover:bg-slate-700' : 'bg-slate-900 border-slate-800 text-slate-600'}`}>
                <div className={`p-2 rounded-full ${item ? 'bg-blue-500/20 text-blue-400' : 'bg-slate-800'}`}>
                    {renderIcon()}
                </div>
                <div className="text-left">
                    <div className="text-xs uppercase font-bold tracking-wider opacity-50">{label}</div>
                    <div className={`font-serif ${item ? 'text-white' : 'text-slate-600'} ${item?.rarity === 'LEGENDARY' ? 'text-yellow-400' : item?.rarity === 'MYTHIC' ? 'text-red-500' : ''}`}>
                        {item ? `${item.name} ${item.level > 1 ? `+${item.level-1}` : ''}` : 'Empty'}
                    </div>
                </div>
            </button>
            {item && onUpgrade && (
                <button 
                    onClick={(e) => { e.stopPropagation(); onUpgrade(); }}
                    disabled={!canUpgrade}
                    className={`w-12 flex flex-col items-center justify-center border rounded ${canUpgrade ? 'bg-slate-800 border-slate-600 hover:bg-blue-900 hover:border-blue-400' : 'bg-slate-900 border-slate-800 opacity-50'}`}
                >
                    <Hammer size={16} className={canUpgrade ? "text-yellow-400" : "text-slate-600"} />
                    <span className="text-[9px] font-mono text-slate-400 mt-1">{item.level}</span>
                </button>
            )}
        </div>
    );
};

import React, { useEffect, useState } from 'react';
import { useGameStore } from '../store';
import { GameStatus, Upgrade, Item, Rarity, ItemType } from '../types';
import { COLORS, UPGRADES_POOL, ITEMS_POOL } from '../constants';
import { 
  Heart, Zap, Sparkles, Play, RotateCcw, 
  Backpack, Shield, Sword, Gem, X, User, Flame, Wind, ShoppingBag, Coins, Hammer, MoveRight, Star, Dna, FlaskConical, CircleDollarSign, Package,
  Crosshair, Axe, Wand2, Hexagon, Layers
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

export const GameUI: React.FC = () => {
  const { 
    status, health, mana, stats, score, level, experience, experienceToNextLevel, 
    inventory, equipment, setStatus, skills, skillMaxCooldowns,
    startGame, resetGame, applyUpgrade, equipItem, unequipItem, buyItem, upgradeItem, sellItem, gachaSummon
  } = useGameStore();

  const [availableUpgrades, setAvailableUpgrades] = useState<Upgrade[]>([]);
  const [shopTab, setShopTab] = useState<'GEAR' | 'CONSUMABLES'>('CONSUMABLES');
  const [hoveredItem, setHoveredItem] = useState<Item | null>(null);
  const [bulkBuy, setBulkBuy] = useState(false);

  useEffect(() => {
    if (status === GameStatus.LEVEL_UP) {
      const shuffled = [...UPGRADES_POOL].sort(() => 0.5 - Math.random());
      setAvailableUpgrades(shuffled.slice(0, 3));
    }
  }, [status]);

  const toggleInventory = () => {
    if (status === GameStatus.PLAYING) setStatus(GameStatus.INVENTORY);
    else if (status === GameStatus.INVENTORY) setStatus(GameStatus.PLAYING);
  };

  const toggleShop = () => {
      if (status === GameStatus.PLAYING) setStatus(GameStatus.SHOP);
      else if (status === GameStatus.SHOP) setStatus(GameStatus.PLAYING);
  };

  const hpPercent = (health / stats.maxHealth) * 100;
  const manaPercent = (mana / stats.maxMana) * 100;
  const xpPercent = (experience / experienceToNextLevel) * 100;

  const getRarityColor = (rarity: Rarity) => {
      switch(rarity) {
          case 'MYTHIC': return 'text-red-500 border-red-500 shadow-red-500/50';
          case 'LEGENDARY': return 'text-yellow-400 border-yellow-400 shadow-yellow-400/50';
          case 'EPIC': return 'text-purple-400 border-purple-400 shadow-purple-400/50';
          case 'RARE': return 'text-blue-400 border-blue-400 shadow-blue-400/50';
          default: return 'text-slate-200 border-slate-600';
      }
  };

  // Helper to count equipped set items
  const getSetCount = (setName?: string) => {
      if (!setName) return 0;
      let count = 0;
      (Object.values(equipment) as (Item | null)[]).forEach(i => {
          if (i?.setName === setName) count++;
      });
      return count;
  };

  return (
    <div className="absolute inset-0 pointer-events-none z-10 font-sans text-slate-100 select-none">

      {/* HUD */}
      {(status === GameStatus.PLAYING || status === GameStatus.LEVEL_UP || status === GameStatus.INVENTORY || status === GameStatus.SHOP) && (
        <div className="absolute inset-0 flex flex-col justify-between p-4 md:p-6">

          {/* Top Bar */}
          <div className="flex justify-between items-start pointer-events-auto">
             <div className="flex items-center gap-4 bg-slate-900/80 p-2 pr-6 rounded-r-full border-l-4 border-blue-500 backdrop-blur-sm">
                <div className="bg-slate-800 p-2 rounded-full border border-slate-600">
                    <User size={24} className="text-blue-400" />
                </div>
                <div>
                    <div className="text-xl font-bold leading-none">Lv. {level}</div>
                    <div className="text-xs text-slate-400">Hero</div>
                </div>
             </div>
             <div className="bg-slate-900/80 px-4 py-2 rounded-md border-t-2 border-yellow-500 backdrop-blur-sm flex items-center gap-2">
                <Coins size={20} className="text-yellow-400" />
                <div className="text-2xl font-mono text-yellow-400">{score.toLocaleString()}</div>
             </div>
          </div>

          {/* Bottom Bar */}
          <div className="flex flex-col gap-4 w-full max-w-2xl mx-auto pb-4">

             {/* Skills */}
             <div className="flex justify-center gap-4 pointer-events-auto">
                <div className="relative flex flex-col items-center">
                    <div className={`w-14 h-14 rounded border-2 flex items-center justify-center bg-slate-900 ${skills.weaponAbility > 0 ? 'border-slate-600' : 'border-purple-400 shadow-[0_0_15px_rgba(168,85,247,0.5)]'}`}>
                        <Zap size={28} className={skills.weaponAbility > 0 ? 'text-slate-500' : 'text-purple-400'} />
                        {skills.weaponAbility > 0 && (
                            <div className="absolute inset-0 bg-black/60 flex items-center justify-center font-bold text-lg">
                                {Math.ceil(skills.weaponAbility)}
                            </div>
                        )}
                    </div>
                    <div className="text-xs font-bold mt-1 bg-black/50 px-2 rounded">R / Right Click</div>
                </div>

                <div className="relative flex flex-col items-center">
                    <div className={`w-14 h-14 rounded border-2 flex items-center justify-center bg-slate-900 ${skills.dash > 0 ? 'border-slate-600' : 'border-green-400 shadow-[0_0_15px_rgba(74,222,128,0.5)]'}`}>
                        <Wind size={28} className={skills.dash > 0 ? 'text-slate-500' : 'text-green-400'} />
                        {skills.dash > 0 && (
                            <div className="absolute inset-0 bg-black/60 flex items-center justify-center font-bold text-lg">
                                {Math.ceil(skills.dash)}
                            </div>
                        )}
                    </div>
                    <div className="text-xs font-bold mt-1 bg-black/50 px-2 rounded">SPACE</div>
                </div>
             </div>

             {/* Status Bars */}
             <div className="flex flex-col gap-2">
                 {/* HP */}
                 <div className="relative h-5 bg-slate-900 rounded-full border border-slate-700 overflow-hidden">
                    <div 
                        className="absolute top-0 left-0 h-full bg-gradient-to-r from-red-600 to-red-500 transition-all duration-300" 
                        style={{ width: `${hpPercent}%` }}
                    />
                    <div className="absolute inset-0 flex items-center justify-center text-[10px] font-bold drop-shadow-md z-10">
                        {Math.ceil(health)} / {stats.maxHealth} HP
                    </div>
                 </div>

                 {/* Mana */}
                 <div className="relative h-5 bg-slate-900 rounded-full border border-slate-700 overflow-hidden">
                    <div 
                        className="absolute top-0 left-0 h-full bg-gradient-to-r from-blue-600 to-blue-500 transition-all duration-300" 
                        style={{ width: `${manaPercent}%` }}
                    />
                    <div className="absolute inset-0 flex items-center justify-center text-[10px] font-bold drop-shadow-md z-10">
                        {Math.ceil(mana)} / {stats.maxMana} MP
                    </div>
                 </div>

                 {/* XP */}
                 <div className="relative h-2 bg-slate-900 rounded-full border border-slate-700 overflow-hidden">
                    <div 
                        className="absolute top-0 left-0 h-full bg-gradient-to-r from-yellow-600 to-yellow-400 transition-all duration-300"
                        style={{ width: `${xpPercent}%` }}
                    />
                 </div>
             </div>

             <div className="flex justify-center mt-2 pointer-events-auto gap-4">
                <button 
                    onClick={toggleInventory}
                    className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 border border-slate-600 rounded-md transition-colors text-sm font-bold"
                >
                    <Backpack size={16} /> INVENTORY
                </button>
                <button 
                    onClick={toggleShop}
                    className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 border border-slate-600 rounded-md transition-colors text-sm font-bold"
                >
                    <ShoppingBag size={16} /> SHOP
                </button>
             </div>
          </div>
        </div>
      )}

      {/* Overlays */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
        <AnimatePresence>

          {/* MENU */}
          {status === GameStatus.MENU && (
            <motion.div 
                initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                className="flex flex-col items-center gap-8 bg-slate-900/90 p-16 rounded-xl border border-slate-700 shadow-2xl backdrop-blur-md pointer-events-auto"
            >
              <h1 className="text-6xl font-serif font-black text-transparent bg-clip-text bg-gradient-to-b from-blue-300 to-blue-600 drop-shadow-sm">
                AETHER SURVIVOR
              </h1>
              <p className="text-slate-400 max-w-md text-center">
                Battle the endless horde. Collect loot. Build your legend.<br/>
                Auto-attacks enabled. Move to survive.<br/>
                <span className="text-purple-400 font-bold">R / Right Click</span> for Weapon Skill. <span className="text-green-400 font-bold">SPACE</span> to Dash.
              </p>
              <button 
                onClick={startGame}
                className="flex items-center gap-3 px-10 py-4 bg-blue-600 hover:bg-blue-500 text-white font-bold rounded shadow-lg hover:shadow-blue-500/25 transition-all transform hover:-translate-y-1"
              >
                <Play size={24} /> START ADVENTURE
              </button>
            </motion.div>
          )}

          {/* SHOP SCREEN */}
          {status === GameStatus.SHOP && (
            <motion.div 
                initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }}
                className="bg-slate-900 border border-slate-700 rounded-lg p-8 w-[900px] h-[700px] shadow-2xl flex flex-col gap-6 pointer-events-auto"
            >
                <div className="flex justify-between items-center border-b border-slate-700 pb-4">
                    <div className="flex items-center gap-3">
                        <ShoppingBag className="text-yellow-400" />
                        <h2 className="text-2xl font-serif text-slate-200">MERCHANT</h2>
                    </div>
                    <div className="flex items-center gap-4">
                         <div className="text-yellow-400 font-mono text-xl">{score.toLocaleString()} G</div>
                         <button onClick={toggleShop} className="p-2 hover:bg-slate-800 rounded-full"><X size={24}/></button>
                    </div>
                </div>

                <div className="flex gap-4">
                    <button onClick={() => setShopTab('CONSUMABLES')} className={`flex-1 p-2 font-bold rounded ${shopTab === 'CONSUMABLES' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-400'}`}>SUPPLIES</button>
                    <button onClick={() => setShopTab('GEAR')} className={`flex-1 p-2 font-bold rounded ${shopTab === 'GEAR' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-400'}`}>SETS & GEAR</button>
                </div>

                {/* Bulk Buy Toggle */}
                <div className="flex justify-end pt-2">
                    <button 
                        onClick={() => setBulkBuy(!bulkBuy)} 
                        className={`flex items-center gap-2 px-3 py-1 rounded text-xs font-bold border ${bulkBuy ? 'bg-blue-600 border-blue-400 text-white' : 'bg-slate-800 border-slate-600 text-slate-400'}`}
                    >
                        <Package size={14}/> BUY x10
                    </button>
                </div>

                <div className="flex-1 overflow-y-auto">
                    {shopTab === 'CONSUMABLES' && (
                        <div className="grid grid-cols-2 gap-4">
                             {/* Gacha Banner */}
                            <div className="col-span-2 bg-gradient-to-r from-purple-900 to-slate-900 p-6 rounded-lg border border-purple-500/30 flex justify-between items-center relative overflow-hidden group">
                                <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10"></div>
                                <div className="z-10">
                                    <h3 className="text-2xl font-bold text-white mb-1 flex items-center gap-2"><Star className="text-yellow-400" fill="currentColor"/> MYSTERY SUMMON</h3>
                                    <p className="text-purple-200 text-sm">Obtain random weapons and accessories. <br/>Chance for <span className="text-orange-400 font-bold">LEGENDARY</span> items!</p>
                                </div>
                                <button 
                                    onClick={() => gachaSummon()}
                                    className="z-10 px-8 py-4 bg-purple-600 hover:bg-purple-500 text-white font-bold rounded shadow-lg flex flex-col items-center hover:scale-105 transition-transform"
                                >
                                    <span>SUMMON</span>
                                    <span className="text-xs text-purple-200">500 G</span>
                                </button>
                            </div>

                            {ITEMS_POOL.filter(i => i.type === 'POTION' || i.type === 'CORE').map((item, idx) => (
                                <ShopItem key={idx} item={item} buyItem={buyItem} score={score} bulk={bulkBuy} />
                            ))}
                        </div>
                    )}

                    {shopTab === 'GEAR' && (
                        <div className="grid grid-cols-3 gap-4">
                            {/* Only Rare and Epic in Shop */}
                            {ITEMS_POOL.filter(i => (i.type !== 'POTION' && i.type !== 'CORE' && (i.rarity === 'RARE' || i.rarity === 'EPIC'))).map((item, idx) => (
                                <ShopItem key={idx} item={item} buyItem={buyItem} score={score} bulk={bulkBuy} />
                            ))}
                        </div>
                    )}
                </div>
            </motion.div>
          )}

          {/* INVENTORY SCREEN */}
          {status === GameStatus.INVENTORY && (
            <motion.div 
                initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}
                className="bg-slate-900 border border-slate-700 rounded-lg p-8 w-[900px] h-[700px] shadow-2xl flex flex-col gap-6 pointer-events-auto"
            >
                <div className="flex justify-between items-center border-b border-slate-700 pb-4">
                    <h2 className="text-2xl font-serif text-slate-200">INVENTORY & EQUIPMENT</h2>
                    <div className="flex items-center gap-4">
                         <div className="text-yellow-400 font-mono text-xl">{score.toLocaleString()} G</div>
                        <button onClick={toggleInventory} className="p-2 hover:bg-slate-800 rounded-full"><X size={24}/></button>
                    </div>
                </div>

                <div className="flex gap-8 h-full">
                    {/* Character Equipment Panel */}
                    <div className="w-1/3 flex flex-col gap-4 items-center bg-slate-950/50 p-6 rounded-lg">
                        <div className="w-full text-center text-slate-400 mb-4 text-sm font-bold">EQUIPMENT</div>

                        <EquipmentSlot 
                            type="WEAPON"
                            label="Weapon" 
                            item={equipment.weapon} 
                            onClick={() => unequipItem('weapon')}
                            onUpgrade={() => equipment.weapon && upgradeItem(equipment.weapon)}
                            canUpgrade={!!equipment.weapon}
                            onHover={setHoveredItem}
                        />
                        <EquipmentSlot 
                            type="ARMOR"
                            label="Armor" 
                            item={equipment.armor} 
                            onClick={() => unequipItem('armor')} 
                            onUpgrade={() => equipment.armor && upgradeItem(equipment.armor)}
                            canUpgrade={!!equipment.armor}
                            onHover={setHoveredItem}
                        />
                        <EquipmentSlot 
                            type="ACCESSORY"
                            label="Accessory" 
                            item={equipment.accessory} 
                            onClick={() => unequipItem('accessory')} 
                            onUpgrade={() => equipment.accessory && upgradeItem(equipment.accessory)}
                            canUpgrade={!!equipment.accessory}
                            onHover={setHoveredItem}
                        />

                        {/* Set Bonus Display */}
                        <div className="w-full bg-slate-900/50 rounded p-3 text-xs space-y-2 mt-2">
                             <div className="text-slate-500 font-bold text-center border-b border-slate-800 pb-1 mb-1">SET BONUSES</div>
                             {['Elven Set', 'Viking Set', 'Inferno Set'].map(set => {
                                 const count = getSetCount(set);
                                 return (
                                    <div key={set} className={`flex justify-between ${count >= 3 ? 'text-green-400 font-bold' : 'text-slate-600'}`}>
                                        <span>{set} ({count}/3)</span>
                                        {count >= 3 && <Sparkles size={12}/>}
                                    </div>
                                 )
                             })}
                        </div>

                        <div className="mt-auto w-full text-xs text-slate-500 space-y-1 pt-4 border-t border-slate-800">
                            <div className="flex justify-between"><span>DMG</span> <span className="text-white">{Math.round(stats.damage)}</span></div>
                            <div className="flex justify-between"><span>DEF</span> <span className="text-blue-400">{Math.round(stats.defense)}</span></div>
                            <div className="flex justify-between"><span>REGEN</span> <span className="text-green-400">{stats.regen.toFixed(1)}/s</span></div>
                            <div className="flex justify-between"><span>CRIT</span> <span className="text-yellow-400">{(stats.critRate * 100).toFixed(0)}%</span></div>
                            <div className="flex justify-between"><span>HP</span> <span className="text-white">{stats.maxHealth}</span></div>
                            <div className="flex justify-between"><span>MANA</span> <span className="text-blue-400">{stats.maxMana}</span></div>
                        </div>
                    </div>

                    {/* Inventory Grid */}
                    <div className="w-2/3 bg-slate-950/30 p-6 rounded-lg flex flex-col">
                        <div className="w-full text-slate-400 mb-4 text-sm font-bold flex justify-between">
                            <span>BACKPACK</span>
                            <span className="text-xs font-normal">Right-click to Equip</span>
                        </div>
                        <div className="grid grid-cols-6 gap-2 max-h-[500px] overflow-y-auto">
                            {inventory.map((item, idx) => {
                                const isConsumable = item.type === 'POTION' || item.type === 'CORE';
                                return (
                                <div 
                                    key={idx} 
                                    className="relative group w-full aspect-square"
                                    onMouseEnter={() => setHoveredItem(item)}
                                    onMouseLeave={() => setHoveredItem(null)}
                                >
                                    <button 
                                        onClick={() => !isConsumable && equipItem(item)}
                                        onContextMenu={(e) => { e.preventDefault(); !isConsumable && equipItem(item); }}
                                        className={`w-full h-full bg-slate-800 border-2 ${getRarityColor(item.rarity)} hover:scale-105 rounded flex flex-col items-center justify-center p-1 transition-transform`}
                                    >
                                        <ItemIcon item={item} size={20} />

                                        {isConsumable && <div className="absolute top-0 right-0 bg-black/60 text-[10px] px-1 rounded-bl text-white font-mono">{item.quantity}</div>}
                                        {item.level > 1 && <div className="text-[10px] mt-1 text-yellow-400 font-bold">+{item.level - 1}</div>}
                                    </button>

                                    {/* Action Buttons Overlay on Hover */}
                                    <div className="absolute -top-2 -right-2 flex gap-1 z-10 opacity-0 group-hover:opacity-100 transition-opacity">
                                        {!isConsumable && (
                                            <button 
                                                onClick={(e) => { e.stopPropagation(); upgradeItem(item); }}
                                                className="bg-slate-900 border border-slate-600 rounded-full p-1 hover:bg-yellow-900 hover:border-yellow-500"
                                                title="Upgrade"
                                            >
                                                <Hammer size={10} className="text-yellow-400" />
                                            </button>
                                        )}
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); sellItem(item); }}
                                            className="bg-slate-900 border border-slate-600 rounded-full p-1 hover:bg-red-900 hover:border-red-500"
                                            title="Sell"
                                        >
                                            <CircleDollarSign size={10} className="text-green-400" />
                                        </button>
                                    </div>

                                    {/* TOOLTIP: Comparison Logic */}
                                    {hoveredItem === item && (
                                        <div className={`fixed z-50 pointer-events-none p-4 rounded bg-slate-900 border border-slate-600 shadow-2xl w-64 text-left ${idx < 6 ? 'top-[40%] translate-y-12' : '-translate-y-full top-[50%]'} left-[50%] ml-12`}>
                                            <div className={`${getRarityColor(item.rarity)} border-b pb-2 mb-2 font-bold flex justify-between`}>
                                                <span>{item.name} {item.level > 1 && `+${item.level-1}`}</span>
                                            </div>
                                            <div className="text-sm text-slate-300">
                                                {item.type !== 'CORE' && <div>+{item.value} {item.stat}</div>}
                                                {item.ability && <div className="text-purple-400 italic text-xs mt-1">{item.description}</div>}
                                                {item.setName && (
                                                    <div className="mt-2 text-xs">
                                                        <div className="text-yellow-500 font-bold">{item.setName}</div>
                                                        <div className="text-slate-400">{item.setBonus}</div>
                                                        <div className="text-slate-500 italic">(3 pieces required)</div>
                                                    </div>
                                                )}
                                                {item.description && !item.ability && <div className="text-slate-500 italic text-xs mt-1">{item.description}</div>}
                                            </div>

                                            {/* Cost Info */}
                                            {!isConsumable && (
                                                 <div className="mt-2 pt-2 border-t border-slate-800 text-xs">
                                                    <div className="flex justify-between text-yellow-400">
                                                        <span>Upgrade Cost:</span>
                                                        <span>{Math.floor(item.price * item.level * 0.5)} G</span>
                                                    </div>
                                                    <div className="flex justify-between text-blue-400">
                                                        <span>Core Cost:</span>
                                                        <span>{Math.ceil(item.level / 2)} Core</span>
                                                    </div>
                                                    <div className="flex justify-between text-slate-400">
                                                        <span>Success Rate:</span>
                                                        <span>{Math.max(10, 100 - (item.level * 10))}%</span>
                                                    </div>
                                                 </div>
                                            )}
                                        </div>
                                    )}
                                </div>
                            )})}
                            {[...Array(Math.max(0, 30 - inventory.length))].map((_, i) => (
                                <div key={`empty-${i}`} className="aspect-square bg-slate-900/50 border border-slate-800 rounded" />
                            ))}
                        </div>
                    </div>
                </div>
            </motion.div>
          )}

          {/* LEVEL UP */}
          {status === GameStatus.LEVEL_UP && (
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center pointer-events-auto">
                <motion.div 
                    initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}
                    className="flex flex-col items-center gap-8"
                >
                    <h2 className="text-4xl font-serif text-yellow-400 drop-shadow-lg">LEVEL UP!</h2>
                    <div className="flex flex-wrap justify-center gap-6">
                        {availableUpgrades.map((upgrade, idx) => (
                            <motion.button 
                                key={idx}
                                initial={{ y: 50, opacity: 0 }}
                                animate={{ y: 0, opacity: 1 }}
                                transition={{ delay: idx * 0.1 }}
                                onClick={() => applyUpgrade(upgrade)}
                                className="relative w-64 aspect-[3/4] bg-slate-800 rounded-xl border-2 border-slate-600 hover:border-yellow-400 hover:scale-105 transition-all shadow-xl overflow-hidden flex flex-col p-6 text-center items-center justify-between group"
                            >
                                <div className="absolute inset-0 bg-gradient-to-b from-slate-700/50 to-slate-900/50 z-0" />
                                <div className="relative z-10 flex flex-col items-center gap-4">
                                    <div className={`p-4 rounded-full ${upgrade.rarity === 'LEGENDARY' ? 'bg-orange-500' : upgrade.rarity === 'RARE' ? 'bg-blue-500' : 'bg-slate-500'} text-white shadow-lg`}>
                                        <Sparkles size={32} />
                                    </div>
                                    <h3 className="text-xl font-bold">{upgrade.name}</h3>
                                    <div className="h-px w-full bg-slate-600 my-2" />
                                    <p className="text-sm text-slate-300">{upgrade.description}</p>
                                </div>
                                <div className="relative z-10 text-xs uppercase tracking-widest opacity-50 font-bold">
                                    {upgrade.rarity}
                                </div>
                            </motion.button>
                        ))}
                    </div>
                </motion.div>
            </div>
          )}

          {/* GAME OVER */}
          {status === GameStatus.GAME_OVER && (
            <motion.div 
                initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                className="bg-slate-900/95 border border-red-900 p-12 rounded-lg text-center flex flex-col items-center gap-6 shadow-2xl pointer-events-auto"
            >
              <h2 className="text-5xl font-serif text-red-500 drop-shadow-md">YOU DIED</h2>
              <div className="flex flex-col gap-1 text-xl text-slate-300">
                 <p>Gold Collected: <span className="text-yellow-400">{score.toLocaleString()}</span></p>
                 <p>Level Reached: {level}</p>
              </div>
              <button 
                onClick={resetGame}
                className="flex items-center gap-3 px-8 py-3 bg-red-800 hover:bg-red-700 text-white font-bold rounded shadow-lg mt-4"
              >
                <RotateCcw size={20} /> TRY AGAIN
              </button>
            </motion.div>
          )}

        </AnimatePresence>
      </div>
    </div>
  );
};

const ItemIcon = ({ item, size }: { item: Item, size: number }) => {
    if (item.type === 'POTION') return <FlaskConical size={size} />;
    if (item.type === 'CORE') return <Hexagon size={size} />;
    if (item.type === 'ACCESSORY') return <Gem size={size} />;
    if (item.type === 'ARMOR') return <Shield size={size} />;
    if (item.projectileType === 'MAGIC') return <Wand2 size={size} />;
    if (item.projectileType === 'ARROW') return <Crosshair size={size} />;
    if (item.projectileType === 'AXE') return <Axe size={size} />;
    return <Sword size={size} />;
};

interface ShopItemProps {
    item: Item;
    buyItem: (i: Item, q?: number) => boolean;
    score: number;
    bulk: boolean;
}

const ShopItem: React.FC<ShopItemProps> = ({ item, buyItem, score, bulk }) => {
    const qty = bulk ? 10 : 1;
    const finalPrice = item.price * qty;

    return (
        <div className="bg-slate-800 p-4 rounded border border-slate-700 flex flex-col gap-2 relative overflow-hidden group">
            <div className="flex justify-between items-start z-10">
                <h3 className={`font-bold ${item.rarity === 'MYTHIC' ? 'text-red-400' : item.rarity === 'EPIC' ? 'text-purple-400' : 'text-slate-200'}`}>{item.name}</h3>
                <ItemIcon item={item} size={16} />
            </div>

            {item.setName && (
                 <div className="text-[10px] text-yellow-500 font-bold uppercase tracking-wider flex items-center gap-1 z-10">
                    <Layers size={10} /> {item.setName}
                 </div>
            )}

            <p className="text-xs text-slate-400 z-10">{item.description || `+${item.value} ${item.stat}`}</p>

            {item.setName && (
                <p className="text-[10px] text-slate-500 italic z-10 mt-1">Set Bonus: {item.setBonus}</p>
            )}

            <div className="mt-auto pt-2 flex justify-between items-center z-10">
                <span className="text-yellow-400 font-mono">{finalPrice} G</span>
                <button 
                    onClick={() => buyItem(item, qty)}
                    disabled={score < finalPrice}
                    className={`px-3 py-1 rounded text-sm font-bold flex items-center gap-1 ${score >= finalPrice ? 'bg-blue-600 hover:bg-blue-500 text-white' : 'bg-slate-700 text-slate-500 cursor-not-allowed'}`}
                >
                    BUY {bulk && <span className="text-[10px] bg-black/20 px-1 rounded">x10</span>}
                </button>
            </div>
        </div>
    );
};

const EquipmentSlot = ({ 
    type, icon, label, item, onClick, onUpgrade, canUpgrade, onHover 
}: { 
    type: ItemType, icon?: any, label: string, item: Item | null, onClick: () => void, onUpgrade?: () => void, canUpgrade?: boolean, onHover: (i: Item | null) => void
}) => {
    // Determine icon based on type if not provided, or based on item if equipped
    const renderIcon = () => {
        if (item) return <ItemIcon item={item} size={24} />;
        if (type === 'WEAPON') return <Sword size={24} />;
        if (type === 'ARMOR') return <Shield size={24} />;
        if (type === 'ACCESSORY') return <Gem size={24} />;
        return <Sword size={24} />;
    };

    return (
        <div 
            className="w-full flex gap-2"
            onMouseEnter={() => item && onHover(item)}
            onMouseLeave={() => onHover(null)}
        >
            <button onClick={onClick} disabled={!item} className={`flex-1 flex items-center gap-4 p-3 rounded border transition-colors ${item ? 'bg-slate-800 border-slate-600 hover:bg-slate-700' : 'bg-slate-900 border-slate-800 text-slate-600'}`}>
                <div className={`p-2 rounded-full ${item ? 'bg-blue-500/20 text-blue-400' : 'bg-slate-800'}`}>
                    {renderIcon()}
                </div>
                <div className="text-left">
                    <div className="text-xs uppercase font-bold tracking-wider opacity-50">{label}</div>
                    <div className={`font-serif ${item ? 'text-white' : 'text-slate-600'} ${item?.rarity === 'LEGENDARY' ? 'text-yellow-400' : item?.rarity === 'MYTHIC' ? 'text-red-500' : ''}`}>
                        {item ? `${item.name} ${item.level > 1 ? `+${item.level-1}` : ''}` : 'Empty'}
                    </div>
                </div>
            </button>
            {item && onUpgrade && (
                <button 
                    onClick={(e) => { e.stopPropagation(); onUpgrade(); }}
                    disabled={!canUpgrade}
                    className={`w-12 flex flex-col items-center justify-center border rounded ${canUpgrade ? 'bg-slate-800 border-slate-600 hover:bg-blue-900 hover:border-blue-400' : 'bg-slate-900 border-slate-800 opacity-50'}`}
                >
                    <Hammer size={16} className={canUpgrade ? "text-yellow-400" : "text-slate-600"} />
                    <span className="text-[9px] font-mono text-slate-400 mt-1">{item.level}</span>
                </button>
            )}
        </div>
    );
};

