export enum GameStatus {
  MENU = 'MENU',
  HERO_SELECT = 'HERO_SELECT',
  PLAYING = 'PLAYING',
  PAUSED = 'PAUSED',
  LEVEL_UP = 'LEVEL_UP',
  GAME_OVER = 'GAME_OVER',
  INVENTORY = 'INVENTORY',
  SHOP = 'SHOP',
}

export type HeroClass = 'ARCHER' | 'WIZARD' | 'BARBARIAN';

export type UpgradeType = 
  'HEALTH' | 'SPEED' | 'DAMAGE' | 'FIRE_RATE' | 'MULTISHOT' | 'DASH_COOLDOWN' |
  'SKILL_ORBITAL' | 'SKILL_THUNDER' | 'SKILL_REGEN' | 'SKILL_MAGNET' |
  'SKILL_DASH' | 'SKILL_WEAPON' |
  'CRIT_RATE' | 'CRIT_DAMAGE' | 'DEFENSE' | 'MAX_MANA';

export interface Upgrade {
  id: string;
  type: UpgradeType;
  name: string;
  description: string;
  rarity: 'COMMON' | 'RARE' | 'LEGENDARY';
  value: number;
}

export type ProjectileType = 'MAGIC' | 'ARROW' | 'AXE' | 'FIREBALL';
export type AbilityType = 'METEOR' | 'ARROW_RAIN' | 'AXE_AURA' | 'FIREBALL' | 'AXE_SPIN' | 'NONE';
export type ItemType = 'WEAPON' | 'ARMOR' | 'ACCESSORY' | 'POTION' | 'CORE';
export type Rarity = 'COMMON' | 'RARE' | 'EPIC' | 'LEGENDARY' | 'MYTHIC';

export interface PlayerStats {
  maxHealth: number;
  maxMana: number;
  regen: number; // HP per second
  manaRegen: number; // Mana per second
  moveSpeed: number;
  damage: number;
  fireRate: number; // bullets per second
  projectileSpeed: number;
  multishot: number;
  spread: number;
  dashCooldown: number;
  cooldownReduction: number; // 0-1 (percentage)
  magnetRadius: number;
  critRate: number; // 0-1
  critDamage: number; // multiplier (e.g. 1.5)
  defense: number; // Reduces incoming damage
  skillDamage: number; // Multiplier for skill damage
}

export interface Item {
  id: string;
  name: string;
  type: ItemType;
  stats: Partial<PlayerStats>; // Changed from stat/value to stats object
  rarity: Rarity;
  price: number;
  level: number;
  projectileType?: ProjectileType;
  ability?: AbilityType;
  description?: string;
  stackSize?: number; 
  quantity?: number; 

  // Set Mechanics
  setName?: string;
  setBonus?: string; 
  setBonusStats?: Partial<PlayerStats>; 
}

export interface EnemyData {
  id: number;
  position: Vector3;
  type: number; // 0: Slime, 1: Orc, 2: Boss, 3: Shooter
  health: number;
  maxHealth: number;
  speed: number;
  radius: number;
  scale: number;
  active: boolean;
  state?: 'CHASE' | 'CHARGE_PREP' | 'CHARGE' | 'SHOOT';
  stateTimer?: number;
  chargeDir?: Vector3;
}

export interface BulletData {
  id: number;
  position: Vector3;
  velocity: Vector3;
