  lifetime: number;
  type: ProjectileType; 
  state?: number; 
  pierce?: number; 
  hitIds: number[]; 
  damageMultiplier?: number; 
}

export interface CrateData {
  id: number;
  position: Vector3;
  active: boolean;
  rotation: number;
}

export interface DropData {
  id: number;
  position: Vector3;
  item: Item | null; 
  type: 'ITEM' | 'GOLD' | 'XP';
