                              <div className="p-4 bg-slate-900 rounded-full mb-2">
                                  {h === 'ARCHER' && <Crosshair size={32} className="text-green-400"/>}
                                  {h === 'WIZARD' && <Wand2 size={32} className="text-blue-400"/>}
