  maxHealth: 100,
  maxMana: 100,
  regen: 1.0, 
  manaRegen: 1.0,
  moveSpeed: 10,
  damage: 15,
  fireRate: 2.0,
  projectileSpeed: 20,
  multishot: 1,
  spread: 0.2,
  dashCooldown: 2.0,
  cooldownReduction: 0,
  magnetRadius: 5.0,
  critRate: 0.05,
  critDamage: 1.5,
  defense: 0,
  skillDamage: 1.0
};

const calculateStats = (base: PlayerStats, equipment: GameState['equipment']) => {
  const final = { ...base };
  const sets: Record<string, number> = {};

  // 1. Apply Equipment Stats
  Object.values(equipment).forEach(item => {
    if (item) {
        if (item.stats) {
            Object.entries(item.stats).forEach(([key, val]) => {
                const k = key as keyof PlayerStats;
                const v = val as number;

                if (k === 'moveSpeed' || k === 'fireRate') {
                     // @ts-ignore
                     final[k] += v;
                } else if (k === 'cooldownReduction') {
                     // Additive percentage (capped at some point elsewhere if needed)
                     final[k] = Math.min(0.75, final[k] + v);
                } else {
                     // @ts-ignore
                     final[k] += v;
                }
            });
        }
        if (item.setName) {
            sets[item.setName] = (sets[item.setName] || 0) + 1;
        }
    }
  });

  // 2. Apply Set Bonuses
  Object.entries(sets).forEach(([setName, count]) => {
      if (count >= 3) {
          const setItem = Object.values(equipment).find(i => i?.setName === setName);
          if (setItem && setItem.setBonusStats) {
              Object.entries(setItem.setBonusStats).forEach(([stat, val]) => {
                  if (stat === 'damage' || stat === 'moveSpeed' || stat === 'fireRate') {
                      // Multiplier for these stats in bonus
                      // @ts-ignore
                      final[stat] *= (1 + val);
                  } else {
                      // Additive for others
                      // @ts-ignore
                      final[stat] += val;
                  }
              });
          }
      }
  });

  // 3. Staff Slowdown (50% slower attack speed)
  if (equipment.weapon && equipment.weapon.projectileType === 'MAGIC') {
      final.fireRate *= 0.5;
  }

  return final;
};

export const useGameStore = create<GameState>((set, get) => ({
  status: GameStatus.MENU,
  hero: 'ARCHER',
  score: 0,
  level: 1,
  experience: 0,
  experienceToNextLevel: 100,
  health: 100,
  mana: 100,
  playerPosition: new Vector3(0, 0, 0),
  stats: { ...INITIAL_STATS },
  baseStats: { ...INITIAL_STATS },
  skillLevels: { orbital: 0, thunder: 0, regen: 0, magnet: 0, dash: 0, weapon: 0 },
  passiveSkillState: { orbitalCooldown: 0, orbitalMaxCooldown: 1, thunderCooldown: 0, thunderMaxCooldown: 1 },
  inventory: [],
  equipment: { weapon: null, armor: null, accessory: null },
  drops: [],
  skills: { dash: 0, weaponAbility: 0 },
  skillMaxCooldowns: { dash: 2.0, weaponAbility: 8.0 },
  potionCooldown: 0,
  isInvincible: false,

  setStatus: (status) => set({ status }),

  selectHero: (hero) => set({ hero }),

  startGame: () => {
      const state = get();
      const heroStats = HERO_STATS[state.hero];
      const startStats = { ...INITIAL_STATS, ...heroStats.stats };

      const startWeapon = { ...ITEMS_POOL.find(i => i.id === heroStats.weaponId)!, id: 'start_wep', quantity: 1 };

      const equipment = { weapon: startWeapon, armor: null, accessory: null };

      set({
        status: GameStatus.PLAYING,
        score: 100,
        level: 1,
        experience: 0,
        experienceToNextLevel: 100,
        health: startStats.maxHealth,
        mana: startStats.maxMana,
        baseStats: startStats,
        stats: calculateStats(startStats, equipment),
        skillLevels: { orbital: 0, thunder: 0, regen: 0, magnet: 0, dash: 0, weapon: 0 },
        playerPosition: new Vector3(0, 0, 0),
        inventory: [
            { ...ITEMS_POOL.find(i => i.id === 'potion_hp')!, id: 'start_hp', quantity: 5 },
            { ...ITEMS_POOL.find(i => i.id === 'potion_mana')!, id: 'start_mana', quantity: 5 }
        ], 
        equipment: equipment,
        drops: [],
        skills: { dash: 0, weaponAbility: 0 }
      });
  },

  addScore: (amount) => set((state) => ({ score: state.score + amount })),

  addExperience: (amount) => {
    const adjustedAmount = amount * 2;
    const { experience, experienceToNextLevel, level } = get();
    let newExp = experience + adjustedAmount;

    if (newExp >= experienceToNextLevel) {
      set({
        experience: newExp - experienceToNextLevel,
        experienceToNextLevel: Math.floor(experienceToNextLevel * 1.5),
        level: level + 1,
        status: GameStatus.LEVEL_UP,
      });
    } else {
      set({ experience: newExp });
    }
  },

  takeDamage: (amount) => {
    const { health, status, stats, playerPosition, isInvincible } = get();
    if (status !== GameStatus.PLAYING || isInvincible) return;

    const reductionMultiplier = 100 / (100 + stats.defense);
    const actualDamage = Math.max(1, amount * reductionMultiplier);

    const newHealth = health - actualDamage;

    window.dispatchEvent(new CustomEvent('damage', { 
        detail: { position: playerPosition, damage: actualDamage, isCrit: false, isPlayer: true } 
    }));

    if (newHealth <= 0) {
      set({ health: 0, status: GameStatus.GAME_OVER });
    } else {
      set({ health: newHealth });
    }
  },

  useMana: (amount) => {
      const { mana } = get();
      if (mana >= amount) {
          set({ mana: mana - amount });
          return true;
      }
      return false;
  },

  heal: (amount) => set((state) => ({ 
    health: Math.min(state.health + amount, state.stats.maxHealth) 
  })),

  restoreMana: (amount) => set((state) => ({ 
    mana: Math.min(state.mana + amount, state.stats.maxMana) 
  })),

  setPlayerPosition: (pos) => set({ playerPosition: pos }),
  setInvincible: (invincible) => set({ isInvincible: invincible }),

  spawnDrop: (position, type, value, rarityOverride) => set((state) => {
      if (state.drops.length > 99) return { drops: state.drops };

      let item = null;
      if (type === 'ITEM') {
          let pool = ITEMS_POOL;

          if (rarityOverride) {
              pool = ITEMS_POOL.filter(i => i.rarity === rarityOverride && i.type !== 'POTION' && i.type !== 'CORE');
              if (pool.length === 0) pool = ITEMS_POOL.filter(i => i.type !== 'POTION' && i.type !== 'CORE');
          } else {
               const r = Math.random();
               if (r > 0.90) { // 10% Potion
                   pool = ITEMS_POOL.filter(i => i.type === 'POTION');
               } else if (r > 0.60) { // 30% Core
                   pool = ITEMS_POOL.filter(i => i.type === 'CORE');
               } else { // 60% Gear
                   pool = ITEMS_POOL.filter(i => (i.rarity === 'COMMON' || i.rarity === 'RARE') && i.type !== 'POTION' && i.type !== 'CORE');
               }
          }

          const preferred: Item[] = [];
          pool.forEach(i => {
              let isPref = false;
              if (state.hero === 'ARCHER') {
                  if (i.projectileType === 'ARROW' || i.stats.fireRate || i.stats.moveSpeed) isPref = true;
              } else if (state.hero === 'WIZARD') {
                  if (i.projectileType === 'MAGIC' || i.stats.maxMana) isPref = true;
              } else if (state.hero === 'BARBARIAN') {
                  if (i.projectileType === 'AXE' || i.stats.defense || i.stats.maxHealth) isPref = true;
              }
              if (isPref) preferred.push(i);
          });

          if (preferred.length > 0 && Math.random() < 0.5) {
              pool = preferred;
          }

          if (pool.length > 0) {
              const template = pool[Math.floor(Math.random() * pool.length)];
              item = { ...template, id: Math.random().toString(), stats: { ...template.stats } }; 
              item.quantity = 1;

              // Random Plus Logic
              if (item.type === 'WEAPON' || item.type === 'ARMOR' || item.type === 'ACCESSORY') {
                   const plusChance = Math.random();
                   let plus = 0;
                   if (plusChance > 0.95) plus = 3;
                   else if (plusChance > 0.85) plus = 2;
                   else if (plusChance > 0.60) plus = 1;

                   if (plus > 0) {
                       item.level += plus;
                       // Increase all stats
                       Object.keys(item.stats).forEach((k) => {
                           const key = k as keyof PlayerStats;
                           const v = item.stats[key]!;
                           // Special scaling for % stats
                           if (key === 'fireRate' || key === 'moveSpeed' || key === 'critRate' || key === 'cooldownReduction' || key === 'skillDamage') {
                               item.stats[key] = parseFloat((v * (1 + 0.05 * plus)).toFixed(2));
                           } else {
                               item.stats[key] = Math.ceil(v * (1 + 0.1 * plus));
                           }
                       });
                   }
              }
          }
      }

      return {
          drops: [...state.drops, {
              id: Math.random(),
              position: position.clone(),
              type,
              value,
              item,
              active: true,
              rotation: Math.random() * Math.PI
          }]
      };
  }),

  collectDrop: (id) => set((state) => {
      const drop = state.drops.find(d => d.id === id);
      if (!drop) return { drops: state.drops };

      const newDrops = state.drops.filter(d => d.id !== id);

      if (drop.type === 'XP') {
         get().addExperience(drop.value);
      } else if (drop.type === 'GOLD') {
         get().addScore(drop.value);
      } else if (drop.type === 'ITEM' && drop.item) {
          const existingStack = state.inventory.find(i => i.name === drop.item!.name && (i.type === 'POTION' || i.type === 'CORE'));
          if (existingStack) {
              existingStack.quantity = (existingStack.quantity || 1) + 1;
              return { drops: newDrops, inventory: [...state.inventory] };
          }
          return { drops: newDrops, inventory: [...state.inventory, { ...drop.item }] };
      }

      return { drops: newDrops };
  }),

  triggerSkillCooldown: (skill) => set((state) => {
      // Reduce CD based on skill level (e.g. 10% per level)
      const level = skill === 'dash' ? state.skillLevels.dash : state.skillLevels.weapon;
      const reduction = Math.min(0.5, level * 0.1); 
      const cooldown = state.skillMaxCooldowns[skill] * (1 - state.stats.cooldownReduction) * (1 - reduction);

      return {
          skills: { ...state.skills, [skill]: cooldown }
      };
  }),

  updatePassiveCooldowns: (partial) => set((state) => ({
      passiveSkillState: { ...state.passiveSkillState, ...partial }
  })),

  tickCooldowns: (delta) => {
      const state = get();
      const newSkills = {
          dash: Math.max(0, state.skills.dash - delta),
          weaponAbility: Math.max(0, state.skills.weaponAbility - delta)
      };

      const regenAmount = (state.stats.regen + state.skillLevels.regen) * delta;
      const manaRegenAmount = state.stats.manaRegen * delta;

      const newHealth = Math.min(state.stats.maxHealth, state.health + regenAmount);
      const newMana = Math.min(state.stats.maxMana, state.mana + manaRegenAmount);

      // Auto Potion
      let newPotionCD = Math.max(0, state.potionCooldown - delta);
      let newHealthAfterPot = newHealth;
      let newManaAfterPot = newMana;
      let inventory = state.inventory;

      if (newPotionCD <= 0) {
          if (newHealth < state.stats.maxHealth * 0.5) {
              const hpPotIndex = inventory.findIndex(i => i.id === 'potion_hp');
              if (hpPotIndex !== -1) {
                  const pot = inventory[hpPotIndex];
                  newHealthAfterPot = Math.min(state.stats.maxHealth, newHealth + (pot.stats.maxHealth || 50));
                  newPotionCD = 10;
                  if ((pot.quantity || 1) > 1) {
                      pot.quantity = (pot.quantity || 1) - 1;
                      inventory = [...inventory];
                  } else {
                      inventory = inventory.filter((_, idx) => idx !== hpPotIndex);
                  }
              }
          }
          if (newPotionCD <= 0 && newMana < state.stats.maxMana * 0.5) {
               const manaPotIndex = inventory.findIndex(i => i.id === 'potion_mana');
               if (manaPotIndex !== -1) {
                  const pot = inventory[manaPotIndex];
                  newManaAfterPot = Math.min(state.stats.maxMana, newMana + (pot.stats.maxMana || 50));
                  newPotionCD = 10;
                   if ((pot.quantity || 1) > 1) {
                      pot.quantity = (pot.quantity || 1) - 1;
                      inventory = [...inventory];
                  } else {
                      inventory = inventory.filter((_, idx) => idx !== manaPotIndex);
                  }
               }
          }
      }

      set({
          skills: newSkills,
          health: newHealthAfterPot,
          mana: newManaAfterPot,
          potionCooldown: newPotionCD,
          inventory: inventory
      });
  },

  applyUpgrade: (upgrade) => set((state) => {
    const newBase = { ...state.baseStats };
    const newSkillLevels = { ...state.skillLevels };

    switch (upgrade.type) {
      case 'HEALTH': newBase.maxHealth += upgrade.value; break;
      case 'MAX_MANA': newBase.maxMana += upgrade.value; break;
      case 'DEFENSE': newBase.defense += upgrade.value; break;
      case 'SPEED': newBase.moveSpeed *= (1 + upgrade.value); break;
      case 'DAMAGE': newBase.damage *= (1 + upgrade.value); break;
      case 'FIRE_RATE': newBase.fireRate *= (1 + upgrade.value); break;
      case 'MULTISHOT': newBase.multishot += upgrade.value; break;
      case 'DASH_COOLDOWN': newBase.dashCooldown *= (1 - upgrade.value); break;
      case 'SKILL_MAGNET': newBase.magnetRadius += upgrade.value; break;
      case 'CRIT_RATE': newBase.critRate += upgrade.value; break;
      case 'CRIT_DAMAGE': newBase.critDamage += upgrade.value; break;
      case 'SKILL_ORBITAL': newSkillLevels.orbital++; break;
      case 'SKILL_THUNDER': newSkillLevels.thunder++; break;
      case 'SKILL_REGEN': newSkillLevels.regen += upgrade.value; break;
      case 'SKILL_MAGNET': newSkillLevels.magnet += upgrade.value; break;
      case 'SKILL_DASH': newSkillLevels.dash++; break;
      case 'SKILL_WEAPON': newSkillLevels.weapon++; break;
    }
    const newStats = calculateStats(newBase, state.equipment);
    return { 
        baseStats: newBase,
        stats: newStats, 
        skillLevels: newSkillLevels,
        health: upgrade.type === 'HEALTH' ? Math.min(state.health + 30, newStats.maxHealth) : state.health,
        mana: upgrade.type === 'MAX_MANA' ? Math.min(state.mana + 20, newStats.maxMana) : state.mana,
        status: GameStatus.PLAYING,
        skillMaxCooldowns: {
            ...state.skillMaxCooldowns,
            dash: upgrade.type === 'DASH_COOLDOWN' ? state.skillMaxCooldowns.dash * (1 - upgrade.value) : state.skillMaxCooldowns.dash
        }
    };
  }),

  equipItem: (item) => set((state) => {
    if (item.type === 'POTION' || item.type === 'CORE') return state;
    const slot = item.type.toLowerCase() as keyof GameState['equipment'];
    const oldItem = state.equipment[slot];
    const newEquipment = { ...state.equipment, [slot]: item };
    const newStats = calculateStats(state.baseStats, newEquipment);
    let newInv = state.inventory.filter(i => i !== item);
    if (oldItem) newInv.push(oldItem);
    return { equipment: newEquipment, stats: newStats, inventory: newInv };
  }),

  unequipItem: (slot) => set((state) => {
    const item = state.equipment[slot];
    if (!item) return state;
    const newEquipment = { ...state.equipment, [slot]: null };
    const newStats = calculateStats(state.baseStats, newEquipment);
    return { equipment: newEquipment, stats: newStats, inventory: [...state.inventory, item] };
  }),

  buyItem: (item, quantity = 1) => {
      const state = get();
      const totalCost = item.price * quantity;
      if (state.score >= totalCost) {
          const existing = state.inventory.find(i => i.name === item.name && (item.type === 'POTION' || item.type === 'CORE'));
          let newInv = [...state.inventory];
          if (existing) {
              existing.quantity = (existing.quantity || 1) + quantity;
          } else {
              if (item.type === 'POTION' || item.type === 'CORE') {
                  newInv.push({ ...item, quantity: quantity, id: Math.random().toString() });
              } else {
                  for(let i=0; i<quantity; i++) {
                       newInv.push({ ...item, quantity: 1, id: Math.random().toString(), stats: { ...item.stats } });
                  }
              }
          }
          set({ score: state.score - totalCost, inventory: newInv });
          return true;
      }
      return false;
  },

  sellItem: (item) => set((state) => {
      let newInv = state.inventory.filter(i => i !== item);
      const sellValue = Math.floor(item.price * 0.4);
      return { inventory: newInv, score: state.score + sellValue };
  }),

  gachaSummon: () => {
    const state = get();
    const COST = 500;
    if (state.score < COST) return null;

    const gearPool = ITEMS_POOL.filter(i => i.type !== 'POTION' && i.type !== 'CORE');
    const rand = Math.random();
    let rarity: Rarity = 'COMMON';
    if (rand > 0.98) rarity = 'LEGENDARY';
    else if (rand > 0.85) rarity = 'EPIC';
    else if (rand > 0.60) rarity = 'RARE';

    let pool = gearPool.filter(i => i.rarity === rarity);
    if (pool.length === 0) pool = gearPool.filter(i => i.rarity === 'COMMON');

    const template = pool[Math.floor(Math.random() * pool.length)];
    const newItem = { ...template, id: Math.random().toString(), quantity: 1, stats: { ...template.stats } };

    set({ score: state.score - COST, inventory: [...state.inventory, newItem] });
    return newItem;
  },

  upgradeItem: (item) => {
      const state = get();
      const core = state.inventory.find(i => i.type === 'CORE');
      const coreIndex = state.inventory.findIndex(i => i.type === 'CORE');

      const requiredCores = Math.ceil(item.level / 2);
      const goldCost = Math.floor(item.price * item.level * 0.5);

      if (state.score < goldCost) return { success: false, msg: "Not enough Gold" };
      if (!core || (core.quantity || 1) < requiredCores) return { success: false, msg: `Need ${requiredCores} Cores` };

      // Success Chance
      const chance = Math.max(10, 100 - (item.level * 10));
      const roll = Math.random() * 100;
      const success = roll < chance;

      const newInventory = [...state.inventory];
      const coreItem = newInventory[coreIndex];
      if ((coreItem.quantity || 1) > requiredCores) {
          coreItem.quantity = (coreItem.quantity || 1) - requiredCores;
      } else {
          newInventory.splice(coreIndex, 1);
      }

      set({ score: state.score - goldCost, inventory: newInventory });

      if (success) {
           const upgradeLogic = (i: Item) => {
              if (i === item) {
                  const updatedStats = { ...i.stats };
                  Object.keys(updatedStats).forEach(k => {
                      const key = k as keyof PlayerStats;
                      const val = updatedStats[key]!;
                      if (key === 'fireRate' || key === 'moveSpeed' || key === 'critRate' || key === 'cooldownReduction' || key === 'skillDamage') {
                          updatedStats[key] = parseFloat((val * 1.05).toFixed(2));
                      } else {
                          updatedStats[key] = Math.ceil(val * 1.1);
                      }
                  });
                  return {
                      ...i,
                      level: i.level + 1,
                      stats: updatedStats
                  };
              }
              return i;
          };

          const updatedInventory = get().inventory.map(upgradeLogic);
          const updatedEquipment = {
              weapon: state.equipment.weapon ? upgradeLogic(state.equipment.weapon) : null,
              armor: state.equipment.armor ? upgradeLogic(state.equipment.armor) : null,
              accessory: state.equipment.accessory ? upgradeLogic(state.equipment.accessory) : null,
          };
          const newStats = calculateStats(state.baseStats, updatedEquipment);

          set({ inventory: updatedInventory, equipment: updatedEquipment, stats: newStats });
          return { success: true, msg: "Upgrade Successful!" };
      } else {
          return { success: false, msg: "Upgrade Failed..." };
      }
  },

  resetGame: () => set({
    status: GameStatus.MENU,
  }),
}));

import React, { useRef, useState } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { Vector3, InstancedMesh, Mesh } from 'three';
import { useGameStore } from '../store';
import { COLORS, PLAYER_RADIUS, ARENA_SIZE } from '../constants';
import { BulletManager } from './BulletManager';
import { GameStatus, BulletData } from '../types';

interface PlayerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
}

export const Player: React.FC<PlayerProps> = ({ bulletsDataRef, enemyBulletsDataRef }) => {
  const meshRef = useRef<any>(null);
  const axeSpinRef = useRef<Mesh>(null);

  const { stats, status, setPlayerPosition, skills, triggerSkillCooldown, tickCooldowns, takeDamage, equipment, useMana, setInvincible } = useGameStore();
  const { camera, scene } = useThree();

  // Local state for movement
  const [pos] = useState(new Vector3(0, 0, 0));
  const [velocity] = useState(new Vector3(0, 0, 0));
  const [keys, setKeys] = useState<{ [key: string]: boolean }>({});

  const targetEnemyPos = useRef<Vector3 | null>(null);
  const dashVelocity = useRef(new Vector3());
  const dashTime = useRef(0);
  const axeSpinTime = useRef(0);

  // Input handling
  React.useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => setKeys((k) => ({ ...k, [e.code]: true }));
    const handleKeyUp = (e: KeyboardEvent) => setKeys((k) => ({ ...k, [e.code]: false }));
    const handleMouseDown = (e: MouseEvent) => {
        if (e.button === 2) setKeys((k) => ({ ...k, 'RightClick': true })); // Right click for ability
    };
    const handleMouseUp = (e: MouseEvent) => {
        if (e.button === 2) setKeys((k) => ({ ...k, 'RightClick': false }));
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousedown', handleMouseDown);
    window.addEventListener('mouseup', handleMouseUp);
    // Disable context menu
    window.addEventListener('contextmenu', (e) => e.preventDefault());

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousedown', handleMouseDown);
      window.removeEventListener('mouseup', handleMouseUp);
      window.removeEventListener('contextmenu', (e) => e.preventDefault());
    };
  }, []);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    tickCooldowns(delta);

    // 1. Movement Vector
    const moveDir = new Vector3(0, 0, 0);
    if (keys['KeyW'] || keys['ArrowUp']) moveDir.z -= 1;
    if (keys['KeyS'] || keys['ArrowDown']) moveDir.z += 1;
    if (keys['KeyA'] || keys['ArrowLeft']) moveDir.x -= 1;
    if (keys['KeyD'] || keys['ArrowRight']) moveDir.x += 1;
    moveDir.normalize();

    // 2. Weapon Special Ability (R or Right Click)
    if ((keys['KeyR'] || keys['RightClick']) && skills.weaponAbility <= 0 && equipment.weapon) {

        // Mana Cost Logic (20 Mana)
        if (useMana(20)) {
            triggerSkillCooldown('weaponAbility');

            const ability = equipment.weapon.ability;

            if (ability === 'FIREBALL') {
                const bullet = bulletsDataRef.current.find(b => !b.active);
                if (bullet) {
                    bullet.active = true;
                    bullet.lifetime = 4.0;
                    bullet.position.copy(pos).add(new Vector3(0, 1.5, 0));

                    // Fire straight ahead
                    const lookDir = new Vector3(0, 0, -1).applyQuaternion(meshRef.current.quaternion).normalize();
                    bullet.velocity.copy(lookDir).multiplyScalar(15); 
                    bullet.type = 'FIREBALL'; 
                    bullet.pierce = 0; // Explodes on impact logic handled in EnemyManager? Or just high damage single hit
                    bullet.damageMultiplier = 5.0 * stats.skillDamage; 
                }
            } else if (ability === 'ARROW_RAIN') {
                const count = 16;
                for (let i = 0; i < count; i++) {
                    const bullet = bulletsDataRef.current.find(b => !b.active);
                    if (bullet) {
                        bullet.active = true;
                        bullet.lifetime = 1.0;
                        bullet.position.copy(pos).add(new Vector3(0, 1, 0));
                        const angle = (Math.PI * 2 * i) / count;
                        bullet.velocity.set(Math.cos(angle), 0, Math.sin(angle)).multiplyScalar(25);
                        bullet.type = 'ARROW';
                        bullet.pierce = 1;
                        bullet.damageMultiplier = 1.0 * stats.skillDamage;
                    }
                }
            } else if (ability === 'AXE_SPIN') {
                axeSpinTime.current = 3.0;
            }
        }
    }

    // Axe Spin Logic
    if (axeSpinTime.current > 0) {
        axeSpinTime.current -= delta;
        if (axeSpinRef.current) {
            axeSpinRef.current.visible = true;
            axeSpinRef.current.rotation.y += delta * 15;

            // Aura Damage
             const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
             if (enemiesMesh && enemiesMesh.userData.enemies) {
                 const enemies = enemiesMesh.userData.enemies;
                 for (let i = 0; i < enemies.length; i++) {
                    if (enemies[i].active && enemies[i].position.distanceTo(pos) < 3.5) {
                        enemies[i].health -= stats.damage * delta * 8 * stats.skillDamage; // Very High DPS
                    }
                 }
             }
        }
    } else if (axeSpinRef.current) {
        axeSpinRef.current.visible = false;
    }


    // 3. Dash Skill (Space)
    if (keys['Space'] && skills.dash <= 0) {
        triggerSkillCooldown('dash');
        dashTime.current = 0.2; // Dash duration
        dashVelocity.current.copy(moveDir.length() > 0 ? moveDir.normalize() : new Vector3(0, 0, -1).applyQuaternion(meshRef.current.quaternion));
        dashVelocity.current.multiplyScalar(40); // Dash speed
        setInvincible(true);
    }

    // 4. Velocity Application
    if (dashTime.current > 0) {
        // Normal Dash
        dashTime.current -= delta;
        velocity.copy(dashVelocity.current);
        if (dashTime.current <= 0) {
             setInvincible(false);
        }
    } else {
        // Normal Move
        velocity.lerp(moveDir.multiplyScalar(stats.moveSpeed), delta * 8);
    }

    pos.add(velocity.clone().multiplyScalar(delta));

    // Clamp Bounds
    pos.x = Math.max(-ARENA_SIZE / 2 + 2, Math.min(ARENA_SIZE / 2 - 2, pos.x));
    pos.z = Math.max(-ARENA_SIZE / 2 + 2, Math.min(ARENA_SIZE / 2 - 2, pos.z));

    meshRef.current.position.copy(pos);
    setPlayerPosition(pos.clone());


    // 6. Auto-Targeting Logic
    const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
    let closestDist = 25; // Range
    // Staff has lower range but AOE, Bow long range.
    if (equipment.weapon?.projectileType === 'ARROW') closestDist = 35;
    if (equipment.weapon?.projectileType === 'AXE') closestDist = 30; // Increased Axe Range

    let closestPos = null;

    if (enemiesMesh && enemiesMesh.userData.enemies) {
        const enemies = enemiesMesh.userData.enemies;
        for (let i = 0; i < enemies.length; i++) {
            if (enemies[i].active) {
                const dist = pos.distanceTo(enemies[i].position);
                if (dist < closestDist) {
                    closestDist = dist;
                    closestPos = enemies[i].position;
                }
            }
        }
    }

    targetEnemyPos.current = closestPos;

    if (closestPos) {
        meshRef.current.lookAt(closestPos.x, 0, closestPos.z);
    } else if (velocity.lengthSq() > 0.1) {
        const lookTarget = pos.clone().add(velocity);
        meshRef.current.lookAt(lookTarget.x, 0, lookTarget.z);
    }

    // 7. Enemy Bullet Collision
    const enemyBullets = enemyBulletsDataRef.current;
    if (dashTime.current <= 0) { // Check locally active if invincibility toggle hasn't propogated yet for safety
        for(let i = 0; i < enemyBullets.length; i++) {
            const b = enemyBullets[i];
            if (b.active && b.position.distanceTo(pos) < PLAYER_RADIUS + 0.5) { // Increased hit radius
                const dmg = 10;
                takeDamage(dmg);
                b.active = false;

                // Dispatch Visual Event for Player Hit
                window.dispatchEvent(new CustomEvent('damage', { 
                    detail: { position: pos, damage: dmg, isCrit: false, isPlayer: true } 
                }));
            }
        }
    }

    // 8. Camera Follow
    const targetCamPos = new Vector3(pos.x, 35, pos.z + 28);
    camera.position.lerp(targetCamPos, delta * 4);
    camera.lookAt(pos.x, 0, pos.z);
  });

  return (
    <>
      <group ref={meshRef} position={[0, 1, 0]}>
        {/* RPG Character - Abstract Knight */}
        <group position={[0, 0, 0]}>
            {/* Body */}
            <mesh castShadow receiveShadow position={[0, 0.5, 0]}>
                <capsuleGeometry args={[0.4, 1, 4, 8]} />
                <meshStandardMaterial color={COLORS.player} roughness={0.4} metalness={0.6} />
            </mesh>
            {/* Head */}
            <mesh castShadow position={[0, 1.4, 0]}>
                <boxGeometry args={[0.5, 0.5, 0.5]} />
                <meshStandardMaterial color="#cbd5e1" metalness={0.8} roughness={0.2} />
            </mesh>
            {/* Weapon Hand */}
            <mesh position={[0.6, 0.5, 0.4]}>
                <boxGeometry args={[0.2, 0.2, 0.8]} />
                <meshStandardMaterial color="#94a3b8" />
            </mesh>
             {/* Cape */}
            <mesh position={[0, 0.6, -0.4]} rotation={[0.2, 0, 0]}>
                <boxGeometry args={[0.6, 1.2, 0.1]} />
                <meshStandardMaterial color="#1e40af" />
            </mesh>
        </group>

        {/* Axe Spin Visual */}
        <group ref={axeSpinRef} visible={false}>
            {/* 4 axes spinning */}
            {[0, 1, 2, 3].map(i => (
                <mesh key={i} position={[Math.cos(i * Math.PI/2) * 2.5, 1, Math.sin(i * Math.PI/2) * 2.5]} rotation={[0, i * Math.PI/2, Math.PI/2]}>
                     <boxGeometry args={[0.2, 1.2, 1.5]} />
                     <meshStandardMaterial color="#ef4444" />
                </mesh>
            ))}
            {/* Wind effect */}
            <mesh rotation={[-Math.PI/2, 0, 0]} position={[0, 0.5, 0]}>
                 <ringGeometry args={[2, 3, 32]} />
                 <meshStandardMaterial color="#ffffff" transparent opacity={0.3} />
            </mesh>
        </group>
      </group>

      <BulletManager 
        playerPos={pos} 
        targetPos={targetEnemyPos.current}
        bulletsDataRef={bulletsDataRef}
        projectileType={equipment.weapon?.projectileType}
      />
    </>
  );
};

import React, { useRef, useLayoutEffect, useEffect } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, DynamicDrawUsage, BufferGeometry, Color, InstancedBufferAttribute } from 'three';
import { useGameStore } from '../store';
import { MAX_BULLETS, COLORS } from '../constants';
import { GameStatus, BulletData, ProjectileType } from '../types';

interface BulletManagerProps {
  playerPos: Vector3;
  targetPos: Vector3 | null;
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  projectileType?: ProjectileType;
}

const dummy = new Object3D();
const tempColor = new Color();
const tempVec = new Vector3();

export const BulletManager: React.FC<BulletManagerProps> = ({ playerPos, targetPos, bulletsDataRef, projectileType = 'MAGIC' }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const { stats, status } = useGameStore();
  const { scene } = useThree();

  // Local storage for bullets logic
  const bullets = useRef(new Array(MAX_BULLETS).fill(0).map((_, i) => ({
    id: i,
    active: false,
    position: new Vector3(),
    velocity: new Vector3(),
    lifetime: 0,
    type: 'MAGIC' as ProjectileType,
    state: 0,
    pierce: 1,
    hitIds: [] as number[]
  })));

  const lastShot = useRef(0);

  // Sync with parent ref once
  useEffect(() => {
    bulletsDataRef.current = bullets.current;
  }, []);

  useLayoutEffect(() => {
    if (meshRef.current) {
        meshRef.current.instanceMatrix.setUsage(DynamicDrawUsage);
        // Initialize colors
        const colors = new Float32Array(MAX_BULLETS * 3);
        for(let i=0; i<MAX_BULLETS; i++) {
            tempColor.set('#000000');
            tempColor.toArray(colors, i*3);
        }
        meshRef.current.geometry.setAttribute('color', new InstancedBufferAttribute(colors, 3));
    }
  }, []);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    const time = state.clock.getElapsedTime();

    // 1. Auto-Fire Logic
    const fireInterval = 1 / stats.fireRate;

    if (targetPos && time - lastShot.current > fireInterval) {
      lastShot.current = time;

      const dir = new Vector3().subVectors(targetPos, playerPos).normalize();
      const startAngle = - (stats.spread * (stats.multishot - 1)) / 2;

      for (let i = 0; i < stats.multishot; i++) {
        const bullet = bullets.current.find(b => !b.active);
        if (bullet) {
            bullet.active = true;
            // Increased Axe Lifetime to 2.0s
            bullet.lifetime = projectileType === 'AXE' ? 2.0 : 3.0;
            bullet.position.copy(playerPos).add(new Vector3(0, 1, 0));
            bullet.type = projectileType;
            bullet.state = 0; // Reset state
            bullet.hitIds = []; // Clear hit list

            // Stats per weapon type
            bullet.pierce = projectileType === 'AXE' ? 99 : 1; // Axes pierce all
            if (projectileType === 'MAGIC') bullet.pierce = 2; // Staff pierces 1 enemy

            const angle = startAngle + (i * stats.spread);
            const spreadDir = dir.clone().applyAxisAngle(new Vector3(0, 1, 0), angle);

            // Projectile Speed logic
            let speed = stats.projectileSpeed;
            if (projectileType === 'AXE') speed *= 0.8;
            if (projectileType === 'MAGIC') speed *= 0.6; // Staff is slow
            if (projectileType === 'ARROW') speed *= 1.5; // Bow is fast

            bullet.velocity.copy(spreadDir).multiplyScalar(speed);
        }
      }
    }

    // 2. Bullet Update Logic
    const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
    let activeCount = 0;

    for (let i = 0; i < MAX_BULLETS; i++) {
        const b = bullets.current[i];
        if (b.active) {

            if (b.type === 'FIREBALL') {
                // Homing Logic
                if (enemiesMesh && enemiesMesh.userData.enemies) {
                    let closest = null;
                    let closestDist = 20; // Homing range
                    for (const e of enemiesMesh.userData.enemies) {
                        if (e.active) {
                            const d = b.position.distanceTo(e.position);
                            if (d < closestDist) {
                                closestDist = d;
                                closest = e.position;
                            }
                        }
                    }

                    if (closest) {
                        tempVec.subVectors(closest, b.position).normalize();
                        // Steer velocity towards target (lerp velocity)
                        b.velocity.lerp(tempVec.multiplyScalar(stats.projectileSpeed), delta * 5); 
                    }
                }
                b.position.add(b.velocity.clone().multiplyScalar(delta));
            } else if (b.type === 'AXE') {
                // Boomerang Logic
                if (b.state === 0) {
                    b.velocity.multiplyScalar(0.95); // Drag
                    if (b.velocity.length() < 2) {
                        b.state = 1; // Start returning
                        b.hitIds = []; // Reset hit list so it can hit enemies again on return
                    }
                } else {
                    // Return to player
                    const toPlayer = new Vector3().subVectors(playerPos, b.position).normalize();
                    b.velocity.add(toPlayer.multiplyScalar(50 * delta)); // Accelerate back

                    // Catch axe
                    if (b.position.distanceTo(playerPos) < 1.5) {
                        b.active = false;
                    }
                }
                b.position.add(b.velocity.clone().multiplyScalar(delta));
            } else {
                // Normal Linear movement
                b.position.add(b.velocity.clone().multiplyScalar(delta));
            }

            b.lifetime -= delta;

            if (b.lifetime <= 0) {
                b.active = false;
                dummy.position.set(0, -100, 0);
            } else {
                dummy.position.copy(b.position);

                if (b.type === 'AXE') {
                     dummy.rotation.set(0, time * 20, 0); 
                     dummy.scale.set(1.5, 1.5, 1.5);
                     tempColor.set('#94a3b8');
                } else if (b.type === 'MAGIC') {
                     dummy.rotation.set(time, time, time);
                     dummy.scale.set(2, 2, 2); 
                     tempColor.set(COLORS.bulletPlayer);
                } else if (b.type === 'FIREBALL') {
                     dummy.rotation.set(time*2, time*2, time*2);
                     dummy.scale.set(3, 3, 3); // BIG
                     tempColor.set('#ef4444'); // RED
                } else {
                     // ARROW
                     const lookAtPos = b.position.clone().add(b.velocity);
                     dummy.lookAt(lookAtPos);
                     dummy.scale.set(1, 1, 1);
                     tempColor.set('#d4d4d8');
                }
            }
            activeCount++;
        } else {
            dummy.position.set(0, -100, 0);
            dummy.scale.set(0, 0, 0);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
        meshRef.current.setColorAt(i, tempColor);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;
    if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;
  });

  // Explicitly bake rotation into Arrow Geometry so lookAt works correctly
  const onGeometryUpdate = (geo: BufferGeometry) => {
      if (projectileType === 'ARROW' && geo) {
          geo.rotateX(Math.PI / 2); // Rotate cylinder so it points along Z-axis (matching velocity lookAt)
      }
  };

  return (
    <instancedMesh key={projectileType} ref={meshRef} args={[undefined, undefined, MAX_BULLETS]} frustumCulled={false}>
      {projectileType === 'ARROW' && <cylinderGeometry args={[0.05, 0.05, 1.5, 6]} ref={onGeometryUpdate} />}
      {projectileType === 'MAGIC' && <dodecahedronGeometry args={[0.3, 0]} />} 
      {projectileType === 'AXE' && <boxGeometry args={[1, 0.1, 1]} />}

      {/* vertexColors must be true for instanceColor to work */}
      <meshStandardMaterial 
        vertexColors
        emissive={projectileType === 'MAGIC' ? COLORS.bulletPlayer : '#000'} 
        emissiveIntensity={projectileType === 'MAGIC' ? 2 : 0} 
      />
    </instancedMesh>
  );
};

import React, { useRef } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, Color } from 'three';
import { useGameStore } from '../store';
import { ARENA_SIZE, COLORS } from '../constants';
import { GameStatus, EnemyData, BulletData } from '../types';

const MAX_ENEMIES = 400;

const dummy = new Object3D();
const tempVec = new Vector3();
const tempColor = new Color();

interface EnemyManagerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
}

export const EnemyManager: React.FC<EnemyManagerProps> = ({ bulletsDataRef, enemyBulletsDataRef }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const { playerPosition, addScore, addExperience, takeDamage, status, level, stats, spawnDrop } = useGameStore();

  const enemies = useRef(new Array(MAX_ENEMIES).fill(0).map((_, i) => ({
    id: i,
    active: false,
    type: 0,
    health: 100,
    maxHealth: 100,
    position: new Vector3(),
    speed: 5,
    radius: 0.8,
    scale: 1,
    state: 'CHASE',
    stateTimer: 0,
    burnDuration: 0
  } as EnemyData)));

  const spawnTimer = useRef(0);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    if (!meshRef.current.userData.enemies) {
        meshRef.current.userData.enemies = enemies.current;
        meshRef.current.name = "EnemyMesh";
    }

    // 1. Spawning
    spawnTimer.current += delta;
    const spawnRate = Math.max(0.1, 0.8 - (level * 0.04));

    if (spawnTimer.current > spawnRate) {
        spawnTimer.current = 0;
        const enemy = enemies.current.find(e => !e.active);
        if (enemy) {
            enemy.active = true;
            enemy.burnDuration = 0; // Reset burn
            let angle, dist, spawnPos;
            do {
                angle = Math.random() * Math.PI * 2;
                dist = (ARENA_SIZE / 2) - 5;
                spawnPos = new Vector3(Math.cos(angle) * dist, 0, Math.sin(angle) * dist);
            } while (spawnPos.distanceTo(playerPosition) < 20);

            enemy.position.copy(spawnPos);

            const r = Math.random();
            if (level > 4 && r > 0.98) {
                // Boss
                enemy.type = 2;
                enemy.health = 500 + (level * 100);
                enemy.speed = 3 + (level * 0.1);
                enemy.radius = 2.5;
                enemy.scale = 3.0;
                enemy.state = 'CHASE';
                tempColor.set(COLORS.enemyBoss);
            } else if (level > 3 && r > 0.85) {
                // Shooter
                enemy.type = 3; 
                enemy.health = 40 + (level * 10);
                enemy.speed = 3.0;
                enemy.radius = 0.8;
                enemy.scale = 0.9;
                enemy.state = 'CHASE';
                tempColor.set(COLORS.enemyShooter);
            } else if (r > 0.75 && level > 2) {
                // Orc
                enemy.type = 1; 
                enemy.health = 60 + (level * 15);
                enemy.speed = 3.5 + (level * 0.1);
                enemy.radius = 1.0;
                enemy.scale = 1.2;
                tempColor.set(COLORS.enemyOrc);
            } else {
                // Slime
                enemy.type = 0;
                enemy.health = 25 + (level * 8);
                enemy.speed = 4 + (level * 0.15);
                enemy.radius = 0.6;
                enemy.scale = 0.8;
                tempColor.set(COLORS.enemySlime);
            }
            enemy.maxHealth = enemy.health;

            meshRef.current.setColorAt(enemies.current.indexOf(enemy), tempColor);
            meshRef.current.instanceColor!.needsUpdate = true;
        }
    }

    // 2. Logic & Collision
    const activeBullets = bulletsDataRef.current;
    const baseDamage = stats.damage;
    const critRate = stats.critRate;
    const critDamage = stats.critDamage;

    for (let i = 0; i < MAX_ENEMIES; i++) {
        const e = enemies.current[i];
        if (e.active) {

            const distToPlayer = e.position.distanceTo(playerPosition);

            // Burn Logic
            if (e.burnDuration && e.burnDuration > 0) {
                e.burnDuration -= delta;
                const burnDmg = stats.damage * 0.5 * delta; // 50% DPS burn
                e.health -= burnDmg;
                // Maybe spawn small damage text occasionally? skipping for perf
            }

            // AI Movement (Simplified)
            if (e.type === 3 && distToPlayer > 15) { // Shooter keep distance
                 tempVec.subVectors(playerPosition, e.position).normalize();
                 e.position.add(tempVec.multiplyScalar(e.speed * delta));
            } else if (e.type !== 3) {
                 // Melee / Boss
                 tempVec.subVectors(playerPosition, e.position).normalize();
                 e.position.add(tempVec.multiplyScalar(e.speed * delta));
            }

            // Shooter Firing Logic
            if (e.type === 3) {
                e.stateTimer = (e.stateTimer || 0) + delta;
                if (e.stateTimer > 2.0 && distToPlayer < 25) {
                    e.stateTimer = 0;
                    const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                    if (bullet) {
                        bullet.active = true;
                        bullet.lifetime = 3.0;
                        bullet.position.copy(e.position).add(new Vector3(0, 1, 0));
                        const aimDir = new Vector3().subVectors(playerPosition, e.position).normalize();
                        bullet.velocity.copy(aimDir).multiplyScalar(15);
                    }
                }
            }

            // Player Collision Damage
            if (e.type !== 3 && distToPlayer < e.radius + 0.5) {
                takeDamage((e.type === 2 ? 30 : 10) * delta);
            }

            // Bullet Collision
            for(let b=0; b < activeBullets.length; b++) {
                const bullet = activeBullets[b];
                if (bullet.active) {
                    // Check already hit for multi-hit projectiles like Axe
                    if (bullet.hitIds && bullet.hitIds.includes(e.id)) continue;

                    // Larger hit radius for Magic / Fireball
                    let hitRadius = e.radius + 0.5;
                    if (bullet.type === 'MAGIC') hitRadius += 1.0;
                    if (bullet.type === 'FIREBALL') hitRadius += 1.5;

                    if (bullet.position.distanceTo(e.position) < hitRadius) {

                        const isCrit = Math.random() < critRate;
                        let dmg = (isCrit ? baseDamage * critDamage : baseDamage);
                        if (bullet.damageMultiplier) dmg *= bullet.damageMultiplier;

                        e.health -= dmg;

                        window.dispatchEvent(new CustomEvent('damage', { 
                            detail: { position: e.position, damage: dmg, isCrit } 
                        }));

                        // Add to hit list
                        if (bullet.hitIds) bullet.hitIds.push(e.id);

                        // Burn effect for Fireball
                        if (bullet.type === 'FIREBALL') {
                            e.burnDuration = 3.0;
                        }

                        // Magic AOE splash
                        if (bullet.type === 'MAGIC') {
                            // Hit other nearby enemies
                            for(let j=0; j<MAX_ENEMIES; j++) {
                                if(i!==j && enemies.current[j].active && enemies.current[j].position.distanceTo(e.position) < 4.0) {
                                    enemies.current[j].health -= dmg * 0.5; // 50% splash dmg
                                }
                            }
                        }

                        // Knockback
                        if (e.type !== 2) {
                            const kbDir = e.position.clone().sub(bullet.position).normalize();
                            e.position.add(kbDir.multiplyScalar(0.4));
                        }

                        // Pierce Logic
                        if (bullet.pierce && bullet.pierce > 0) {
                            bullet.pierce--;
                            if (bullet.pierce <= 0) bullet.active = false;
                        } else {
                            bullet.active = false;
                        }
                    }
                }
            }

            // Death Logic
            if (e.health <= 0) {
                e.active = false;
                addScore(10 * (e.type + 1));

                // Drop Logic
                if (e.type === 2) { 
                    // Boss Drop (Guaranteed 1 Drop)
                    const roll = Math.random();
                    if (roll > 0.995) spawnDrop(e.position, 'ITEM', 0, 'MYTHIC'); // 0.5%
                    else if (roll > 0.99) spawnDrop(e.position, 'ITEM', 0, 'LEGENDARY'); // 0.5%
                    else if (roll > 0.98) spawnDrop(e.position, 'ITEM', 0, 'EPIC'); // 1%
                    else spawnDrop(e.position, 'ITEM', 0, 'RARE'); // Fallback Rare

                    spawnDrop(e.position.clone().add(new Vector3(1,0,0)), 'XP', 1000); 
                } else {
                    // Normal Drop (Reduced rates 60%)
                    // Standard: 25% chance -> Reduced to 10% chance
                    if (Math.random() > 0.90) {
                        spawnDrop(e.position, 'ITEM', 0);
                    } else {
                        spawnDrop(e.position, 'XP', e.type === 3 ? 30 : 20);
                    }
                }
                dummy.position.set(0, -100, 0);
            } else {
                dummy.position.copy(e.position);
                dummy.scale.set(e.scale, e.scale, e.scale);
                if (e.type !== 2) dummy.position.y = Math.abs(Math.sin(state.clock.elapsedTime * 5)) * 0.5;
                dummy.lookAt(playerPosition);
            }

        } else {
            dummy.position.set(0, -100, 0);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, MAX_ENEMIES]} frustumCulled={false}>
      <boxGeometry args={[1, 1, 1]} />
      <meshStandardMaterial vertexColors roughness={0.5} metalness={0.2} />
    </instancedMesh>
  );
};

import { Vector3 } from 'three';

export enum GameStatus {
  MENU = 'MENU',
  HERO_SELECT = 'HERO_SELECT',
  PLAYING = 'PLAYING',
  PAUSED = 'PAUSED',
  LEVEL_UP = 'LEVEL_UP',
  GAME_OVER = 'GAME_OVER',
  INVENTORY = 'INVENTORY',
  SHOP = 'SHOP',
  GACHA_REVEAL = 'GACHA_REVEAL', // New status for gacha animation
}

export type HeroClass = 'ARCHER' | 'WIZARD' | 'BARBARIAN';

export type UpgradeType = 
  'HEALTH' | 'SPEED' | 'DAMAGE' | 'FIRE_RATE' | 'MULTISHOT' | 'DASH_COOLDOWN' |
  'SKILL_ORBITAL' | 'SKILL_THUNDER' | 'SKILL_REGEN' | 'SKILL_MAGNET' |
  'SKILL_DASH' | 'SKILL_WEAPON' |
  'CRIT_RATE' | 'CRIT_DAMAGE' | 'DEFENSE' | 'MAX_MANA';

export interface Upgrade {
  id: string;
  type: UpgradeType;
  name: string;
  description: string;
  rarity: 'COMMON' | 'RARE' | 'LEGENDARY';
  value: number;
}

export type ProjectileType = 'MAGIC' | 'ARROW' | 'AXE' | 'FIREBALL';
export type AbilityType = 'METEOR' | 'ARROW_RAIN' | 'AXE_AURA' | 'FIREBALL' | 'AXE_SPIN' | 'NONE';
export type ItemType = 'WEAPON' | 'ARMOR' | 'ACCESSORY' | 'POTION' | 'CORE' | 'PET';
export type Rarity = 'COMMON' | 'RARE' | 'EPIC' | 'LEGENDARY' | 'MYTHIC';

export interface PlayerStats {
  maxHealth: number;
  maxMana: number;
  regen: number; // HP per second
