import React, { useRef, useState } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { Vector3, InstancedMesh, Mesh } from 'three';
import { useGameStore } from '../store';
import { COLORS, PLAYER_RADIUS, ARENA_SIZE } from '../constants';
import { BulletManager } from './BulletManager';
import { GameStatus, BulletData } from '../types';

interface PlayerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
}

export const Player: React.FC<PlayerProps> = ({ bulletsDataRef, enemyBulletsDataRef }) => {
  const meshRef = useRef<any>(null);
  const axeSpinRef = useRef<Mesh>(null);

  const { stats, status, setPlayerPosition, skills, triggerSkillCooldown, tickCooldowns, takeDamage, equipment, useMana, setInvincible, obstacles } = useGameStore();
  const { camera, scene } = useThree();

  // Local state for movement
  const [pos] = useState(new Vector3(0, 0, 0));
  const [velocity] = useState(new Vector3(0, 0, 0));
  const [keys, setKeys] = useState<{ [key: string]: boolean }>({});

  const targetEnemyPos = useRef<Vector3 | null>(null);
  const dashVelocity = useRef(new Vector3());
  const dashTime = useRef(0);
  const axeSpinTime = useRef(0);

  // Input handling
  React.useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => setKeys((k) => ({ ...k, [e.code]: true }));
    const handleKeyUp = (e: KeyboardEvent) => setKeys((k) => ({ ...k, [e.code]: false }));
    const handleMouseDown = (e: MouseEvent) => {
        if (e.button === 2) setKeys((k) => ({ ...k, 'RightClick': true })); // Right click for ability
    };
    const handleMouseUp = (e: MouseEvent) => {
        if (e.button === 2) setKeys((k) => ({ ...k, 'RightClick': false }));
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousedown', handleMouseDown);
    window.addEventListener('mouseup', handleMouseUp);
    // Disable context menu
    window.addEventListener('contextmenu', (e) => e.preventDefault());

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousedown', handleMouseDown);
      window.removeEventListener('mouseup', handleMouseUp);
      window.removeEventListener('contextmenu', (e) => e.preventDefault());
    };
  }, []);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    tickCooldowns(delta);

    // 1. Movement Vector
    const moveDir = new Vector3(0, 0, 0);
    if (keys['KeyW'] || keys['ArrowUp']) moveDir.z -= 1;
    if (keys['KeyS'] || keys['ArrowDown']) moveDir.z += 1;
    if (keys['KeyA'] || keys['ArrowLeft']) moveDir.x -= 1;
    if (keys['KeyD'] || keys['ArrowRight']) moveDir.x += 1;
    moveDir.normalize();

    // 2. Weapon Special Ability
    if ((keys['KeyR'] || keys['RightClick']) && skills.weaponAbility <= 0 && equipment.weapon) {
        if (useMana(20)) {
            triggerSkillCooldown('weaponAbility');
            const ability = equipment.weapon.ability;

            if (ability === 'FIREBALL') {
                const bullet = bulletsDataRef.current.find(b => !b.active);
                if (bullet) {
                    bullet.active = true;
                    bullet.lifetime = 4.0;
                    bullet.position.copy(pos).add(new Vector3(0, 1.5, 0));
                    const lookDir = new Vector3(0, 0, -1).applyQuaternion(meshRef.current.quaternion).normalize();
                    bullet.velocity.copy(lookDir).multiplyScalar(15); 
                    bullet.type = 'FIREBALL'; 
                    bullet.pierce = 0; 
                    bullet.damageMultiplier = 5.0 * stats.skillDamage; 
                    bullet.effect = { type: 'BURN', duration: 5, value: 10 };
                }
            } else if (ability === 'ARROW_RAIN') {
                const count = 16;
                for (let i = 0; i < count; i++) {
                    const bullet = bulletsDataRef.current.find(b => !b.active);
                    if (bullet) {
                        bullet.active = true;
                        bullet.lifetime = 1.0;
                        bullet.position.copy(pos).add(new Vector3(0, 1, 0));
                        const angle = (Math.PI * 2 * i) / count;
                        bullet.velocity.set(Math.cos(angle), 0, Math.sin(angle)).multiplyScalar(25);
                        bullet.type = 'ARROW';
                        bullet.pierce = 1;
                        bullet.damageMultiplier = 1.0 * stats.skillDamage;
                    }
                }
            } else if (ability === 'AXE_SPIN') {
                axeSpinTime.current = 3.0;
            }
        }
    }

    // Axe Spin Logic
    if (axeSpinTime.current > 0) {
        axeSpinTime.current -= delta;
        if (axeSpinRef.current) {
            axeSpinRef.current.visible = true;
            axeSpinRef.current.rotation.y += delta * 15;
             const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
             if (enemiesMesh && enemiesMesh.userData.enemies) {
                 const enemies = enemiesMesh.userData.enemies;
                 for (let i = 0; i < enemies.length; i++) {
                    if (enemies[i].active && enemies[i].position.distanceTo(pos) < 3.5) {
                        enemies[i].health -= stats.damage * delta * 8 * stats.skillDamage; 
                    }
                 }
             }
        }
    } else if (axeSpinRef.current) {
        axeSpinRef.current.visible = false;
    }

    // 3. Dash Skill
    if (keys['Space'] && skills.dash <= 0) {
        triggerSkillCooldown('dash');
        dashTime.current = 0.2; 
        dashVelocity.current.copy(moveDir.length() > 0 ? moveDir.normalize() : new Vector3(0, 0, -1).applyQuaternion(meshRef.current.quaternion));
        dashVelocity.current.multiplyScalar(40); 
        setInvincible(true);
    }

    // 4. Velocity Application
    if (dashTime.current > 0) {
        dashTime.current -= delta;
        velocity.copy(dashVelocity.current);
        if (dashTime.current <= 0) {
             setInvincible(false);
        }
    } else {
        velocity.lerp(moveDir.multiplyScalar(stats.moveSpeed), delta * 8);
    }

    // 5. Collision Detection & Position Update
    const proposedPos = pos.clone().add(velocity.clone().multiplyScalar(delta));

    // Check against Obstacles
    let collided = false;
    for (const obs of obstacles) {
        const dist = proposedPos.distanceTo(obs.position);
        const minDistance = obs.radius + 0.4; // obstacle radius + player radius
        if (dist < minDistance) {
            // Simple pushback/slide logic
            const dir = new Vector3().subVectors(proposedPos, obs.position).normalize();
            proposedPos.copy(obs.position).add(dir.multiplyScalar(minDistance));
            collided = true;
        }
    }

    // Clamp Bounds
    proposedPos.x = Math.max(-ARENA_SIZE / 2 + 2, Math.min(ARENA_SIZE / 2 - 2, proposedPos.x));
    proposedPos.z = Math.max(-ARENA_SIZE / 2 + 2, Math.min(ARENA_SIZE / 2 - 2, proposedPos.z));

    pos.copy(proposedPos);
    meshRef.current.position.copy(pos);
    setPlayerPosition(pos.clone());

    // 6. Auto-Targeting
    const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
    let closestDist = 25; 
    if (equipment.weapon?.projectileType === 'ARROW') closestDist = 35;
    if (equipment.weapon?.projectileType === 'AXE') closestDist = 30; 

    let closestPos = null;

    if (enemiesMesh && enemiesMesh.userData.enemies) {
        const enemies = enemiesMesh.userData.enemies;
        for (let i = 0; i < enemies.length; i++) {
            if (enemies[i].active) {
                const dist = pos.distanceTo(enemies[i].position);
                if (dist < closestDist) {
                    closestDist = dist;
                    closestPos = enemies[i].position;
                }
            }
        }
    }

    targetEnemyPos.current = closestPos;

    if (closestPos) {
        meshRef.current.lookAt(closestPos.x, 0, closestPos.z);
    } else if (velocity.lengthSq() > 0.1) {
        const lookTarget = pos.clone().add(velocity);
        meshRef.current.lookAt(lookTarget.x, 0, lookTarget.z);
    }

    // 7. Enemy Bullet Collision
    const enemyBullets = enemyBulletsDataRef.current;
    if (dashTime.current <= 0) { 
        for(let i = 0; i < enemyBullets.length; i++) {
            const b = enemyBullets[i];
            if (b.active && b.position.distanceTo(pos) < PLAYER_RADIUS + 0.5) { 
                const dmg = 10;
                takeDamage(dmg);
                b.active = false;
                window.dispatchEvent(new CustomEvent('damage', { 
                    detail: { position: pos, damage: dmg, isCrit: false, isPlayer: true } 
                }));
            }
        }
    }

    // 8. Camera Follow
    const targetCamPos = new Vector3(pos.x, 35, pos.z + 28);
    camera.position.lerp(targetCamPos, delta * 4);
    camera.lookAt(pos.x, 0, pos.z);
  });

  return (
    <>
      <group ref={meshRef} position={[0, 1, 0]}>
        {/* RPG Character */}
        <group position={[0, 0, 0]}>
            <mesh castShadow receiveShadow position={[0, 0.5, 0]}>
                <capsuleGeometry args={[0.4, 1, 4, 8]} />
                <meshStandardMaterial color={COLORS.player} roughness={0.4} metalness={0.6} />
            </mesh>
            <mesh castShadow position={[0, 1.4, 0]}>
                <boxGeometry args={[0.5, 0.5, 0.5]} />
                <meshStandardMaterial color="#cbd5e1" metalness={0.8} roughness={0.2} />
            </mesh>
            <mesh position={[0.6, 0.5, 0.4]}>
                <boxGeometry args={[0.2, 0.2, 0.8]} />
                <meshStandardMaterial color="#94a3b8" />
            </mesh>
            <mesh position={[0, 0.6, -0.4]} rotation={[0.2, 0, 0]}>
                <boxGeometry args={[0.6, 1.2, 0.1]} />
                <meshStandardMaterial color="#1e40af" />
            </mesh>
        </group>

        {/* Axe Spin Visual */}
        <group ref={axeSpinRef} visible={false}>
            {[0, 1, 2, 3].map(i => (
                <mesh key={i} position={[Math.cos(i * Math.PI/2) * 2.5, 1, Math.sin(i * Math.PI/2) * 2.5]} rotation={[0, i * Math.PI/2, Math.PI/2]}>
                     <boxGeometry args={[0.2, 1.2, 1.5]} />
                     <meshStandardMaterial color="#ef4444" />
                </mesh>
            ))}
            <mesh rotation={[-Math.PI/2, 0, 0]} position={[0, 0.5, 0]}>
                 <ringGeometry args={[2, 3, 32]} />
                 <meshStandardMaterial color="#ffffff" transparent opacity={0.3} />
            </mesh>
        </group>
      </group>

      <BulletManager 
        playerPos={pos} 
        targetPos={targetEnemyPos.current}
        bulletsDataRef={bulletsDataRef}
        projectileType={equipment.weapon?.projectileType}
      />
    </>
  );
};

import React, { useRef } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, Color } from 'three';
import { useGameStore } from '../store';
import { ARENA_SIZE, COLORS } from '../constants';
import { GameStatus, EnemyData, BulletData } from '../types';

const MAX_ENEMIES = 400;

const dummy = new Object3D();
const tempVec = new Vector3();
const tempColor = new Color();

interface EnemyManagerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
}

export const EnemyManager: React.FC<EnemyManagerProps> = ({ bulletsDataRef, enemyBulletsDataRef }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const { playerPosition, addScore, addExperience, takeDamage, status, level, stats, spawnDrop } = useGameStore();

  const enemies = useRef(new Array(MAX_ENEMIES).fill(0).map((_, i) => ({
    id: i,
    active: false,
    type: 0,
    health: 100,
    maxHealth: 100,
    position: new Vector3(),
    speed: 5,
    radius: 0.8,
    scale: 1,
    state: 'CHASE',
    stateTimer: 0,
    burnDuration: 0,
    poisonTimer: 0,
    freezeTimer: 0,
    slowTimer: 0,
    slowFactor: 0
  } as EnemyData)));

  const spawnTimer = useRef(0);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    if (!meshRef.current.userData.enemies) {
        meshRef.current.userData.enemies = enemies.current;
        meshRef.current.name = "EnemyMesh";
    }

    // 1. Spawning
    spawnTimer.current += delta;
    const spawnRate = Math.max(0.1, 0.8 - (level * 0.04));

    if (spawnTimer.current > spawnRate) {
        spawnTimer.current = 0;
        const enemy = enemies.current.find(e => !e.active);
        if (enemy) {
            enemy.active = true;
            // Reset statuses
            enemy.burnTimer = 0;
            enemy.poisonTimer = 0;
            enemy.freezeTimer = 0;
            enemy.slowTimer = 0;
            enemy.slowFactor = 0;

            let angle, dist, spawnPos;
            do {
                angle = Math.random() * Math.PI * 2;
                dist = (ARENA_SIZE / 2) - 5;
                spawnPos = new Vector3(Math.cos(angle) * dist, 0, Math.sin(angle) * dist);
            } while (spawnPos.distanceTo(playerPosition) < 20);

            enemy.position.copy(spawnPos);

            const r = Math.random();
            if (level > 4 && r > 0.98) {
                enemy.type = 2; // Boss
                enemy.health = 500 + (level * 100);
                enemy.speed = 3 + (level * 0.1);
                enemy.radius = 2.5;
                enemy.scale = 3.0;
                tempColor.set(COLORS.enemyBoss);
            } else if (level > 3 && r > 0.85) {
                enemy.type = 3; // Shooter
                enemy.health = 40 + (level * 10);
                enemy.speed = 3.0;
                enemy.radius = 0.8;
                enemy.scale = 0.9;
                tempColor.set(COLORS.enemyShooter);
            } else if (r > 0.75 && level > 2) {
                enemy.type = 1; // Orc
                enemy.health = 60 + (level * 15);
                enemy.speed = 3.5 + (level * 0.1);
                enemy.radius = 1.0;
                enemy.scale = 1.2;
                tempColor.set(COLORS.enemyOrc);
            } else {
                enemy.type = 0; // Slime
                enemy.health = 25 + (level * 8);
                enemy.speed = 4 + (level * 0.15);
                enemy.radius = 0.6;
                enemy.scale = 0.8;
                tempColor.set(COLORS.enemySlime);
            }
            enemy.maxHealth = enemy.health;

            meshRef.current.setColorAt(enemies.current.indexOf(enemy), tempColor);
            meshRef.current.instanceColor!.needsUpdate = true;
        }
    }

    // 2. Logic & Collision
    const activeBullets = bulletsDataRef.current;
    const baseDamage = stats.damage;
    const critRate = stats.critRate;
    const critDamage = stats.critDamage;

    for (let i = 0; i < MAX_ENEMIES; i++) {
        const e = enemies.current[i];
        if (e.active) {

            const distToPlayer = e.position.distanceTo(playerPosition);

            // --- Status Effects Logic ---
            let currentSpeed = e.speed;
            let canMove = true;

            // Burn / Poison DoT
            if (e.burnTimer && e.burnTimer > 0) {
                e.burnTimer -= delta;
                e.health -= 5 * delta; // Base burn dmg
            }
            if (e.poisonTimer && e.poisonTimer > 0) {
                e.poisonTimer -= delta;
                e.health -= 3 * delta; // Poison dmg
            }

            // Freeze / Stun
            if (e.freezeTimer && e.freezeTimer > 0) {
                e.freezeTimer -= delta;
                canMove = false;
                // Tint Blue
                tempColor.set('#60a5fa');
                meshRef.current.setColorAt(i, tempColor);
                meshRef.current.instanceColor!.needsUpdate = true;
            } 

            // Slow
            if (e.slowTimer && e.slowTimer > 0) {
                e.slowTimer -= delta;
                currentSpeed *= (1 - (e.slowFactor || 0.5));
            }

            // Restore Color if not frozen
            if ((!e.freezeTimer || e.freezeTimer <= 0) && e.active) {
                 if (e.type === 2) tempColor.set(COLORS.enemyBoss);
                 else if (e.type === 3) tempColor.set(COLORS.enemyShooter);
                 else if (e.type === 1) tempColor.set(COLORS.enemyOrc);
                 else tempColor.set(COLORS.enemySlime);

                 // Poison Tint (Greenish)
                 if (e.poisonTimer && e.poisonTimer > 0) tempColor.lerp(new Color('#4ade80'), 0.5);
                 // Burn Tint (Reddish/Orange)
                 if (e.burnTimer && e.burnTimer > 0) tempColor.lerp(new Color('#f97316'), 0.5);

                 meshRef.current.setColorAt(i, tempColor);
                 meshRef.current.instanceColor!.needsUpdate = true;
            }

            // AI Movement
            if (canMove) {
                if (e.type === 3 && distToPlayer > 15) { // Shooter keep distance
                     tempVec.subVectors(playerPosition, e.position).normalize();
                     e.position.add(tempVec.multiplyScalar(currentSpeed * delta));
                } else if (e.type !== 3) {
                     tempVec.subVectors(playerPosition, e.position).normalize();
                     e.position.add(tempVec.multiplyScalar(currentSpeed * delta));
                }
            }

            // Shooter Firing Logic
            if (e.type === 3 && canMove) {
                e.stateTimer = (e.stateTimer || 0) + delta;
                if (e.stateTimer > 2.0 && distToPlayer < 25) {
                    e.stateTimer = 0;
                    const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                    if (bullet) {
                        bullet.active = true;
                        bullet.lifetime = 3.0;
                        bullet.position.copy(e.position).add(new Vector3(0, 1, 0));
                        const aimDir = new Vector3().subVectors(playerPosition, e.position).normalize();
                        bullet.velocity.copy(aimDir).multiplyScalar(15);
                    }
                }
            }

            // Player Collision Damage
            if (e.type !== 3 && distToPlayer < e.radius + 0.5 && canMove) {
                takeDamage((e.type === 2 ? 30 : 10) * delta);
            }

            // Bullet Collision
            for(let b=0; b < activeBullets.length; b++) {
                const bullet = activeBullets[b];
                if (bullet.active) {
                    if (bullet.hitIds && bullet.hitIds.includes(e.id)) continue;

                    let hitRadius = e.radius + 0.5;
                    if (bullet.type === 'MAGIC') hitRadius += 1.0;
                    if (bullet.type === 'FIREBALL') hitRadius += 1.5;

                    if (bullet.position.distanceTo(e.position) < hitRadius) {

                        const isCrit = Math.random() < critRate;
                        let dmg = (isCrit ? baseDamage * critDamage : baseDamage);
                        if (bullet.damageMultiplier) dmg *= bullet.damageMultiplier;

                        e.health -= dmg;

                        window.dispatchEvent(new CustomEvent('damage', { 
                            detail: { position: e.position, damage: dmg, isCrit } 
                        }));

                        if (bullet.hitIds) bullet.hitIds.push(e.id);

                        // Apply Bullet Effects
                        if (bullet.effect) {
                            const { type, duration, value } = bullet.effect;
                            if (type === 'BURN') e.burnTimer = duration;
                            if (type === 'POISON') e.poisonTimer = duration;
                            if (type === 'STUN' || type === 'FREEZE') e.freezeTimer = duration;
                            if (type === 'SLOW') {
                                e.slowTimer = duration;
                                e.slowFactor = value || 0.5;
                            }
                        }

                        // Fallback logic for old fireball type if stats not set
                        if (bullet.type === 'FIREBALL') {
                            e.burnTimer = 3.0;
                        }

                        // Magic AOE
                        if (bullet.type === 'MAGIC') {
                            for(let j=0; j<MAX_ENEMIES; j++) {
                                if(i!==j && enemies.current[j].active && enemies.current[j].position.distanceTo(e.position) < 4.0) {
                                    enemies.current[j].health -= dmg * 0.5; 
                                }
                            }
                        }

                        // Knockback
                        if (e.type !== 2 && canMove) {
                            const kbDir = e.position.clone().sub(bullet.position).normalize();
                            e.position.add(kbDir.multiplyScalar(0.4));
                        }

                        if (bullet.pierce && bullet.pierce > 0) {
                            bullet.pierce--;
                            if (bullet.pierce <= 0) bullet.active = false;
                        } else {
                            bullet.active = false;
                        }
                    }
                }
            }

            // Death Logic
            if (e.health <= 0) {
                e.active = false;
                addScore(10 * (e.type + 1));

                if (e.type === 2) { 
                    const roll = Math.random();
                    if (roll > 0.995) spawnDrop(e.position, 'ITEM', 0, 'MYTHIC'); 
                    else if (roll > 0.99) spawnDrop(e.position, 'ITEM', 0, 'LEGENDARY'); 
                    else if (roll > 0.98) spawnDrop(e.position, 'ITEM', 0, 'EPIC'); 
                    else spawnDrop(e.position, 'ITEM', 0, 'RARE'); 

                    spawnDrop(e.position.clone().add(new Vector3(1,0,0)), 'XP', 1000); 
                } else {
                    if (Math.random() > 0.90) {
                        spawnDrop(e.position, 'ITEM', 0);
                    } else {
                        spawnDrop(e.position, 'XP', e.type === 3 ? 30 : 20);
                    }
                }
                dummy.position.set(0, -100, 0);
            } else {
                dummy.position.copy(e.position);
                dummy.scale.set(e.scale, e.scale, e.scale);
                if (e.type !== 2) dummy.position.y = Math.abs(Math.sin(state.clock.elapsedTime * 5)) * 0.5;
                dummy.lookAt(playerPosition);
            }

        } else {
            dummy.position.set(0, -100, 0);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, MAX_ENEMIES]} frustumCulled={false}>
      <boxGeometry args={[1, 1, 1]} />
      <meshStandardMaterial vertexColors roughness={0.5} metalness={0.2} />
    </instancedMesh>
  );
};

import React, { useRef, useLayoutEffect, useEffect } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, DynamicDrawUsage, BufferGeometry, Color, InstancedBufferAttribute } from 'three';
import { useGameStore } from '../store';
import { MAX_BULLETS, COLORS } from '../constants';
import { GameStatus, BulletData, ProjectileType } from '../types';

interface BulletManagerProps {
  playerPos: Vector3;
  targetPos: Vector3 | null;
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  projectileType?: ProjectileType;
}

const dummy = new Object3D();
const tempColor = new Color();
const tempVec = new Vector3();

export const BulletManager: React.FC<BulletManagerProps> = ({ playerPos, targetPos, bulletsDataRef, projectileType = 'MAGIC' }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const { stats, status, equipment } = useGameStore();
  const { scene } = useThree();

  // Local storage for bullets logic
  const bullets = useRef(new Array(MAX_BULLETS).fill(0).map((_, i) => ({
    id: i,
    active: false,
    position: new Vector3(),
    velocity: new Vector3(),
    lifetime: 0,
    type: 'MAGIC' as ProjectileType,
    state: 0,
    pierce: 1,
    hitIds: [] as number[],
    effect: undefined
  })));

  const lastShot = useRef(0);

  // Sync with parent ref once
  useEffect(() => {
    bulletsDataRef.current = bullets.current;
  }, []);

  useLayoutEffect(() => {
    if (meshRef.current) {
        meshRef.current.instanceMatrix.setUsage(DynamicDrawUsage);
        // Initialize colors
        const colors = new Float32Array(MAX_BULLETS * 3);
        for(let i=0; i<MAX_BULLETS; i++) {
            tempColor.set('#000000');
            tempColor.toArray(colors, i*3);
        }
        meshRef.current.geometry.setAttribute('color', new InstancedBufferAttribute(colors, 3));
    }
  }, []);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    const time = state.clock.getElapsedTime();

    // 1. Auto-Fire Logic
    const fireInterval = 1 / stats.fireRate;

    if (targetPos && time - lastShot.current > fireInterval) {
      lastShot.current = time;

      const dir = new Vector3().subVectors(targetPos, playerPos).normalize();
      const startAngle = - (stats.spread * (stats.multishot - 1)) / 2;

      for (let i = 0; i < stats.multishot; i++) {
        const bullet = bullets.current.find(b => !b.active);
        if (bullet) {
            bullet.active = true;
            // Increased Axe Lifetime to 2.0s
            bullet.lifetime = projectileType === 'AXE' ? 2.0 : 3.0;
            bullet.position.copy(playerPos).add(new Vector3(0, 1, 0));
            bullet.type = projectileType;
            bullet.state = 0; // Reset state
            bullet.hitIds = []; // Clear hit list

            // Transfer Item Effects to Bullet
            if (equipment.weapon && equipment.weapon.onHitEffect) {
                // Apply chance logic here or in EnemyManager? 
                // Better to pass the effect and check chance in EnemyManager on impact 
                // BUT current BulletData interface expects an effect object.
                // Let's pass the effect object directly.
                // If chance property exists, EnemyManager will roll.
                bullet.effect = equipment.weapon.onHitEffect;
            } else {
                bullet.effect = undefined;
            }

            // Stats per weapon type
            bullet.pierce = projectileType === 'AXE' ? 99 : 1; // Axes pierce all
            if (projectileType === 'MAGIC') bullet.pierce = 2; // Staff pierces 1 enemy

            const angle = startAngle + (i * stats.spread);
            const spreadDir = dir.clone().applyAxisAngle(new Vector3(0, 1, 0), angle);

            // Projectile Speed logic
            let speed = stats.projectileSpeed;
            if (projectileType === 'AXE') speed *= 0.8;
            if (projectileType === 'MAGIC') speed *= 0.6; // Staff is slow
            if (projectileType === 'ARROW') speed *= 1.5; // Bow is fast

            bullet.velocity.copy(spreadDir).multiplyScalar(speed);
        }
      }
    }

    // 2. Bullet Update Logic
    const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;

    for (let i = 0; i < MAX_BULLETS; i++) {
        const b = bullets.current[i];
        if (b.active) {

            if (b.type === 'FIREBALL') {
                // Homing Logic
                if (enemiesMesh && enemiesMesh.userData.enemies) {
                    let closest = null;
                    let closestDist = 20; // Homing range
                    for (const e of enemiesMesh.userData.enemies) {
                        if (e.active) {
                            const d = b.position.distanceTo(e.position);
                            if (d < closestDist) {
                                closestDist = d;
                                closest = e.position;
                            }
                        }
                    }

                    if (closest) {
                        tempVec.subVectors(closest, b.position).normalize();
                        // Steer velocity towards target (lerp velocity)
                        b.velocity.lerp(tempVec.multiplyScalar(stats.projectileSpeed), delta * 5); 
                    }
                }
                b.position.add(b.velocity.clone().multiplyScalar(delta));
            } else if (b.type === 'AXE') {
                // Boomerang Logic
                if (b.state === 0) {
                    b.velocity.multiplyScalar(0.95); // Drag
                    if (b.velocity.length() < 2) {
                        b.state = 1; // Start returning
                        b.hitIds = []; // Reset hit list so it can hit enemies again on return
                    }
                } else {
                    // Return to player
                    const toPlayer = new Vector3().subVectors(playerPos, b.position).normalize();
                    b.velocity.add(toPlayer.multiplyScalar(50 * delta)); // Accelerate back

                    // Catch axe
                    if (b.position.distanceTo(playerPos) < 1.5) {
                        b.active = false;
                    }
                }
                b.position.add(b.velocity.clone().multiplyScalar(delta));
            } else {
                // Normal Linear movement
                b.position.add(b.velocity.clone().multiplyScalar(delta));
            }

            b.lifetime -= delta;

            if (b.lifetime <= 0) {
                b.active = false;
                dummy.position.set(0, -100, 0);
            } else {
                dummy.position.copy(b.position);

                if (b.type === 'AXE') {
                     dummy.rotation.set(0, time * 20, 0); 
                     dummy.scale.set(1.5, 1.5, 1.5);
                     tempColor.set('#94a3b8');
                } else if (b.type === 'MAGIC') {
                     dummy.rotation.set(time, time, time);
                     dummy.scale.set(2, 2, 2); 
                     tempColor.set(COLORS.bulletPlayer);
                } else if (b.type === 'FIREBALL') {
                     dummy.rotation.set(time*2, time*2, time*2);
                     dummy.scale.set(3, 3, 3); // BIG
                     tempColor.set('#ef4444'); // RED
                } else {
                     // ARROW
                     const lookAtPos = b.position.clone().add(b.velocity);
                     dummy.lookAt(lookAtPos);
                     dummy.scale.set(1, 1, 1);
                     tempColor.set('#d4d4d8');
                }
            }
        } else {
            dummy.position.set(0, -100, 0);
            dummy.scale.set(0, 0, 0);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
        meshRef.current.setColorAt(i, tempColor);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;
    if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;
  });

  // Explicitly bake rotation into Arrow Geometry so lookAt works correctly
  const onGeometryUpdate = (geo: BufferGeometry) => {
      if (projectileType === 'ARROW' && geo) {
          geo.rotateX(Math.PI / 2); // Rotate cylinder so it points along Z-axis (matching velocity lookAt)
      }
  };

  return (
    <instancedMesh key={projectileType} ref={meshRef} args={[undefined, undefined, MAX_BULLETS]} frustumCulled={false}>
      {projectileType === 'ARROW' && <cylinderGeometry args={[0.05, 0.05, 1.5, 6]} ref={onGeometryUpdate} />}
      {projectileType === 'MAGIC' && <dodecahedronGeometry args={[0.3, 0]} />} 
      {projectileType === 'AXE' && <boxGeometry args={[1, 0.1, 1]} />}

      {/* vertexColors must be true for instanceColor to work */}
      <meshStandardMaterial 
        vertexColors
        emissive={projectileType === 'MAGIC' ? COLORS.bulletPlayer : '#000'} 
        emissiveIntensity={projectileType === 'MAGIC' ? 2 : 0} 
      />
    </instancedMesh>
  );
};

import React, { useRef, useState } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { Vector3, InstancedMesh, Mesh } from 'three';
import { useGameStore } from '../store';
import { COLORS, PLAYER_RADIUS, ARENA_SIZE } from '../constants';
import { BulletManager } from './BulletManager';
import { GameStatus, BulletData } from '../types';

interface PlayerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
}

export const Player: React.FC<PlayerProps> = ({ bulletsDataRef, enemyBulletsDataRef }) => {
  const meshRef = useRef<any>(null);
  const axeSpinRef = useRef<Mesh>(null);

  const { stats, status, setPlayerPosition, skills, triggerSkillCooldown, tickCooldowns, takeDamage, equipment, useMana, setInvincible, obstacles } = useGameStore();
  const { camera, scene } = useThree();

  // Local state for movement
  const [pos] = useState(new Vector3(0, 0, 0));
  const [velocity] = useState(new Vector3(0, 0, 0));
  const [keys, setKeys] = useState<{ [key: string]: boolean }>({});

  const targetEnemyPos = useRef<Vector3 | null>(null);
  const dashVelocity = useRef(new Vector3());
  const dashTime = useRef(0);
  const axeSpinTime = useRef(0);

  // Input handling
  React.useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => setKeys((k) => ({ ...k, [e.code]: true }));
    const handleKeyUp = (e: KeyboardEvent) => setKeys((k) => ({ ...k, [e.code]: false }));
    const handleMouseDown = (e: MouseEvent) => {
        if (e.button === 2) setKeys((k) => ({ ...k, 'RightClick': true })); // Right click for ability
    };
    const handleMouseUp = (e: MouseEvent) => {
        if (e.button === 2) setKeys((k) => ({ ...k, 'RightClick': false }));
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousedown', handleMouseDown);
    window.addEventListener('mouseup', handleMouseUp);
    // Disable context menu
    window.addEventListener('contextmenu', (e) => e.preventDefault());

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousedown', handleMouseDown);
      window.removeEventListener('mouseup', handleMouseUp);
      window.removeEventListener('contextmenu', (e) => e.preventDefault());
    };
  }, []);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    tickCooldowns(delta);

    // 1. Movement Vector
    const moveDir = new Vector3(0, 0, 0);
    if (keys['KeyW'] || keys['ArrowUp']) moveDir.z -= 1;
    if (keys['KeyS'] || keys['ArrowDown']) moveDir.z += 1;
    if (keys['KeyA'] || keys['ArrowLeft']) moveDir.x -= 1;
    if (keys['KeyD'] || keys['ArrowRight']) moveDir.x += 1;
    moveDir.normalize();

    // 2. Weapon Special Ability
    if ((keys['KeyR'] || keys['RightClick']) && skills.weaponAbility <= 0 && equipment.weapon) {
        // Increased mana cost by 50% (20 -> 30)
        if (useMana(30)) {
            triggerSkillCooldown('weaponAbility');
            const ability = equipment.weapon.ability;

            if (ability === 'FIREBALL') {
                const bullet = bulletsDataRef.current.find(b => !b.active);
                if (bullet) {
                    bullet.active = true;
                    bullet.lifetime = 4.0;
                    bullet.position.copy(pos).add(new Vector3(0, 1.5, 0));
                    const lookDir = new Vector3(0, 0, -1).applyQuaternion(meshRef.current.quaternion).normalize();
                    bullet.velocity.copy(lookDir).multiplyScalar(15); 
                    bullet.type = 'FIREBALL'; 
                    bullet.pierce = 0; 
                    bullet.damageMultiplier = 5.0 * stats.skillDamage; 
                    bullet.effect = { type: 'BURN', duration: 5, value: 10 };
                }
            } else if (ability === 'ARROW_RAIN') {
                const count = 16;
                for (let i = 0; i < count; i++) {
                    const bullet = bulletsDataRef.current.find(b => !b.active);
                    if (bullet) {
                        bullet.active = true;
                        bullet.lifetime = 1.0;
                        bullet.position.copy(pos).add(new Vector3(0, 1, 0));
                        const angle = (Math.PI * 2 * i) / count;
                        bullet.velocity.set(Math.cos(angle), 0, Math.sin(angle)).multiplyScalar(25);
                        bullet.type = 'ARROW';
                        bullet.pierce = 1;
                        bullet.damageMultiplier = 1.0 * stats.skillDamage;
                    }
                }
            } else if (ability === 'AXE_SPIN') {
                axeSpinTime.current = 3.0;
            }
        }
    }

    // Axe Spin Logic
    if (axeSpinTime.current > 0) {
        axeSpinTime.current -= delta;
        if (axeSpinRef.current) {
            axeSpinRef.current.visible = true;
            axeSpinRef.current.rotation.y += delta * 15;
             const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
             if (enemiesMesh && enemiesMesh.userData.enemies) {
                 const enemies = enemiesMesh.userData.enemies;
                 for (let i = 0; i < enemies.length; i++) {
                    if (enemies[i].active && enemies[i].position.distanceTo(pos) < 3.5) {
                        enemies[i].health -= stats.damage * delta * 8 * stats.skillDamage; 
                    }
                 }
             }
        }
    } else if (axeSpinRef.current) {
        axeSpinRef.current.visible = false;
    }

    // 3. Dash Skill
    if (keys['Space'] && skills.dash <= 0) {
        // Add 2 Mana cost for Dash
        if (useMana(2)) {
            triggerSkillCooldown('dash');
            dashTime.current = 0.2; 
            dashVelocity.current.copy(moveDir.length() > 0 ? moveDir.normalize() : new Vector3(0, 0, -1).applyQuaternion(meshRef.current.quaternion));
            dashVelocity.current.multiplyScalar(40); 
            setInvincible(true);
        }
    }

    // 4. Velocity Application
    if (dashTime.current > 0) {
        dashTime.current -= delta;
        velocity.copy(dashVelocity.current);
        if (dashTime.current <= 0) {
             setInvincible(false);
        }
    } else {
        velocity.lerp(moveDir.multiplyScalar(stats.moveSpeed), delta * 8);
    }

    // 5. Collision Detection & Position Update
    const proposedPos = pos.clone().add(velocity.clone().multiplyScalar(delta));

    // Check against Obstacles
    let collided = false;
    for (const obs of obstacles) {
        const dist = proposedPos.distanceTo(obs.position);
        const minDistance = obs.radius + 0.4; // obstacle radius + player radius
        if (dist < minDistance) {
            // Simple pushback/slide logic
            const dir = new Vector3().subVectors(proposedPos, obs.position).normalize();
            proposedPos.copy(obs.position).add(dir.multiplyScalar(minDistance));
            collided = true;
        }
    }

    // Clamp Bounds
    proposedPos.x = Math.max(-ARENA_SIZE / 2 + 2, Math.min(ARENA_SIZE / 2 - 2, proposedPos.x));
    proposedPos.z = Math.max(-ARENA_SIZE / 2 + 2, Math.min(ARENA_SIZE / 2 - 2, proposedPos.z));

    pos.copy(proposedPos);
    meshRef.current.position.copy(pos);
    setPlayerPosition(pos.clone());

    // 6. Auto-Targeting
    const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
    let closestDist = 25; 
    if (equipment.weapon?.projectileType === 'ARROW') closestDist = 35;
    // Increased Axe Range
    if (equipment.weapon?.projectileType === 'AXE') closestDist = 45; 

    let closestPos = null;

    if (enemiesMesh && enemiesMesh.userData.enemies) {
        const enemies = enemiesMesh.userData.enemies;
        for (let i = 0; i < enemies.length; i++) {
            if (enemies[i].active) {
                const dist = pos.distanceTo(enemies[i].position);
                if (dist < closestDist) {
                    closestDist = dist;
                    closestPos = enemies[i].position;
                }
            }
        }
    }

    targetEnemyPos.current = closestPos;

    if (closestPos) {
        meshRef.current.lookAt(closestPos.x, 0, closestPos.z);
    } else if (velocity.lengthSq() > 0.1) {
        const lookTarget = pos.clone().add(velocity);
        meshRef.current.lookAt(lookTarget.x, 0, lookTarget.z);
    }

    // 7. Enemy Bullet Collision
    const enemyBullets = enemyBulletsDataRef.current;
    if (dashTime.current <= 0) { 
        for(let i = 0; i < enemyBullets.length; i++) {
            const b = enemyBullets[i];
            if (b.active && b.position.distanceTo(pos) < PLAYER_RADIUS + 0.5) { 
                const dmg = 10;
                takeDamage(dmg);
                b.active = false;
                window.dispatchEvent(new CustomEvent('damage', { 
                    detail: { position: pos, damage: dmg, isCrit: false, isPlayer: true } 
                }));
            }
        }
    }

    // 8. Camera Follow
    const targetCamPos = new Vector3(pos.x, 35, pos.z + 28);
    camera.position.lerp(targetCamPos, delta * 4);
    camera.lookAt(pos.x, 0, pos.z);
  });

  return (
    <>
      <group ref={meshRef} position={[0, 1, 0]}>
        {/* RPG Character */}
        <group position={[0, 0, 0]}>
            <mesh castShadow receiveShadow position={[0, 0.5, 0]}>
                <capsuleGeometry args={[0.4, 1, 4, 8]} />
                <meshStandardMaterial color={COLORS.player} roughness={0.4} metalness={0.6} />
            </mesh>
            <mesh castShadow position={[0, 1.4, 0]}>
                <boxGeometry args={[0.5, 0.5, 0.5]} />
                <meshStandardMaterial color="#cbd5e1" metalness={0.8} roughness={0.2} />
            </mesh>
            <mesh position={[0.6, 0.5, 0.4]}>
                <boxGeometry args={[0.2, 0.2, 0.8]} />
                <meshStandardMaterial color="#94a3b8" />
            </mesh>
            <mesh position={[0, 0.6, -0.4]} rotation={[0.2, 0, 0]}>
                <boxGeometry args={[0.6, 1.2, 0.1]} />
                <meshStandardMaterial color="#1e40af" />
            </mesh>
        </group>

        {/* Axe Spin Visual */}
        <group ref={axeSpinRef} visible={false}>
            {[0, 1, 2, 3].map(i => (
                <mesh key={i} position={[Math.cos(i * Math.PI/2) * 2.5, 1, Math.sin(i * Math.PI/2) * 2.5]} rotation={[0, i * Math.PI/2, Math.PI/2]}>
                     <boxGeometry args={[0.2, 1.2, 1.5]} />
                     <meshStandardMaterial color="#ef4444" />
                </mesh>
            ))}
            <mesh rotation={[-Math.PI/2, 0, 0]} position={[0, 0.5, 0]}>
                 <ringGeometry args={[2, 3, 32]} />
                 <meshStandardMaterial color="#ffffff" transparent opacity={0.3} />
            </mesh>
        </group>
      </group>

      <BulletManager 
        playerPos={pos} 
        targetPos={targetEnemyPos.current}
        bulletsDataRef={bulletsDataRef}
        projectileType={equipment.weapon?.projectileType}
      />
    </>
  );
};

import React, { useRef, useState } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, Line, Mesh } from 'three';
import { useGameStore } from '../store';
import { GameStatus, BulletData } from '../types';
import { COLORS } from '../constants';

const dummy = new Object3D();

interface SkillManagerProps {
    enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
}

export const SkillManager: React.FC<SkillManagerProps> = ({ enemyBulletsDataRef }) => {
  const { skillLevels, playerPosition, status, stats, heal, takeDamage, updatePassiveCooldowns, useMana } = useGameStore();
  const { scene } = useThree();

  // Orbital State Machine
  // 0: Spinning (4s), 1: Shooting (instant -> travel), 2: Cooldown (2s)
  const orbitalState = useRef(2); // Start in cooldown/ready state logic so we can check mana before activating
  const orbitalTimer = useRef(2.0); // Start ready
  const orbitalRef = useRef<InstancedMesh>(null);
  const orbitalBlades = useRef<{ active: boolean, pos: Vector3, vel: Vector3 }[]>([]);

  // Thunder
  const thunderTimer = useRef(0);
  const [thunderPositions, setThunderPositions] = useState<Vector3[]>([]);
  const thunderVisualTimer = useRef(0);

  // Regen
  const regenTimer = useRef(0);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;

    const time = state.clock.getElapsedTime();

    // --- ORBITAL BLADES ---
    if (skillLevels.orbital > 0) {
        const count = skillLevels.orbital + 2; 
        const damage = stats.damage * 0.8;

        // Initialize blade data if needed
        if (orbitalBlades.current.length !== count) {
            orbitalBlades.current = new Array(count).fill(0).map(() => ({ active: true, pos: new Vector3(), vel: new Vector3() }));
        }

        if (orbitalState.current === 2) {
            // COOLDOWN / READY PHASE
            orbitalTimer.current += delta;
            updatePassiveCooldowns({ orbitalCooldown: 2 - orbitalTimer.current, orbitalMaxCooldown: 2 });

            // Hide all
            for (let i = 0; i < 20; i++) {
                dummy.position.set(0, -100, 0);
                dummy.updateMatrix();
                orbitalRef.current?.setMatrixAt(i, dummy.matrix);
            }

            if (orbitalTimer.current > 2.0) {
                // Try to activate. Reduced mana cost to 7 (approx 50% of 15)
                if (useMana(7)) {
                    orbitalState.current = 0;
                    orbitalTimer.current = 0;
                }
                // If no mana, stays in "Ready" state (state 2 > 2.0s) basically doing nothing but waiting for mana
            }
        } else if (orbitalState.current === 0) {
            // SPINNING PHASE (4s)
            orbitalTimer.current += delta;
            updatePassiveCooldowns({ orbitalCooldown: 4 - orbitalTimer.current, orbitalMaxCooldown: 4 });

            const radius = 4.0;
            const speed = 3.0;

            for (let i = 0; i < count; i++) {
                const angle = (time * speed) + (i * ((Math.PI * 2) / count));
                orbitalBlades.current[i].active = true;
                orbitalBlades.current[i].pos.set(
                    playerPosition.x + Math.cos(angle) * radius,
                    1.0,
                    playerPosition.z + Math.sin(angle) * radius
                );

                // Visual Update
                dummy.position.copy(orbitalBlades.current[i].pos);
                dummy.rotation.set(0, -angle, 0);
                dummy.scale.set(1.5, 1.5, 1.5);
                dummy.updateMatrix();
                orbitalRef.current?.setMatrixAt(i, dummy.matrix);
            }

            // Hit logic during spin
            const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
            if (enemiesMesh && enemiesMesh.userData.enemies) {
                const enemies = enemiesMesh.userData.enemies;
                for (let i = 0; i < count; i++) {
                    const bladePos = orbitalBlades.current[i].pos;
                    for (let e = 0; e < enemies.length; e++) {
                        if (enemies[e].active && enemies[e].position.distanceTo(bladePos) < 2.0) {
                             enemies[e].health -= damage * delta * 5; // DPS check
                        }
                    }
                }
            }

            if (orbitalTimer.current > 4.0) {
                orbitalState.current = 1;
                orbitalTimer.current = 0;

                // Calculate shoot directions
                const enemies = enemiesMesh?.userData?.enemies || [];
                const activeEnemies = enemies.filter((e: any) => e.active);

                for(let i=0; i<count; i++) {
                    let target = null;
                    let minDist = 50;

                    for(const e of activeEnemies) {
                         const d = e.position.distanceTo(playerPosition);
                         if (d < minDist) {
                             minDist = d;
                             target = e.position;
                         }
                    }

                    const dir = new Vector3();
                    if (target) {
                        dir.subVectors(target, orbitalBlades.current[i].pos).normalize();
                    } else {
                        dir.subVectors(orbitalBlades.current[i].pos, playerPosition).normalize();
                    }
                    orbitalBlades.current[i].vel.copy(dir).multiplyScalar(20);
                }
            }

        } else if (orbitalState.current === 1) {
            // SHOOTING PHASE
            let activeCount = 0;
            for (let i = 0; i < count; i++) {
                const blade = orbitalBlades.current[i];
                if (blade.active) {
                    blade.pos.add(blade.vel.clone().multiplyScalar(delta));

                    // Collision
                    const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
                    if (enemiesMesh && enemiesMesh.userData.enemies) {
                        const enemies = enemiesMesh.userData.enemies;
                         for (let e = 0; e < enemies.length; e++) {
                            if (enemies[e].active && enemies[e].position.distanceTo(blade.pos) < 1.5) {
                                 enemies[e].health -= damage * 5;
                                 blade.active = false; 
                                 window.dispatchEvent(new CustomEvent('damage', { 
                                    detail: { position: enemies[e].position, damage: damage * 5, isCrit: false } 
                                 }));
                            }
                        }
                    }

                    // Bounds check
                    if (blade.pos.distanceTo(playerPosition) > 50) blade.active = false;

                    // Update Visual
                    if (blade.active) {
                         dummy.position.copy(blade.pos);
                         dummy.rotation.set(0, time * 10, 0);
                         dummy.scale.set(1.5, 1.5, 1.5);
                         dummy.updateMatrix();
                         orbitalRef.current?.setMatrixAt(i, dummy.matrix);
                         activeCount++;
                    } else {
                         dummy.position.set(0, -100, 0);
                         dummy.updateMatrix();
                         orbitalRef.current?.setMatrixAt(i, dummy.matrix);
                    }
                } else {
                     dummy.position.set(0, -100, 0);
                     dummy.updateMatrix();
                     orbitalRef.current?.setMatrixAt(i, dummy.matrix);
                }
            }

            if (activeCount === 0 || orbitalTimer.current > 2.0) {
                orbitalState.current = 2;
                orbitalTimer.current = 0;
            }
            orbitalTimer.current += delta;
        }

        orbitalRef.current!.instanceMatrix.needsUpdate = true;
    } else {
        if (orbitalRef.current) orbitalRef.current.visible = false;
    }

    // --- THUNDER ---
    if (skillLevels.thunder > 0) {
        thunderTimer.current += delta;
        updatePassiveCooldowns({ thunderCooldown: 2 - thunderTimer.current, thunderMaxCooldown: 2 });

        if (thunderTimer.current > 2.0) { // Fixed 2s cooldown

            const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
            if (enemiesMesh && enemiesMesh.userData.enemies) {
                const enemies = enemiesMesh.userData.enemies;
                const activeEnemies = enemies.filter((e: any) => e.active && e.position.distanceTo(playerPosition) < 40);

                if (activeEnemies.length > 0) {
                    // Reduced mana cost to 2 (approx 50% of 5)
                    if (useMana(2)) {
                        thunderTimer.current = 0;
                        const hitCount = 1 + skillLevels.thunder; 
                        const hits: Vector3[] = [];

                        for(let i=0; i<hitCount; i++) {
                             if (activeEnemies.length === 0) break;
                             const idx = Math.floor(Math.random() * activeEnemies.length);
                             const target = activeEnemies[idx];

                             const isCrit = Math.random() < stats.critRate;
                             const dmg = (stats.damage * 4) * (isCrit ? stats.critDamage : 1);
                             target.health -= dmg;

                             window.dispatchEvent(new CustomEvent('damage', { 
                                detail: { position: target.position, damage: dmg, isCrit } 
                             }));

                             hits.push(target.position.clone());
                             activeEnemies.splice(idx, 1);
                        }

                        setThunderPositions(hits);
                        thunderVisualTimer.current = 0.25;
                    }
                }
            }
        }
    }

    // Thunder Visual Cleanup
    if (thunderVisualTimer.current > 0) {
        thunderVisualTimer.current -= delta;
        if (thunderVisualTimer.current <= 0) setThunderPositions([]);
    }

    // --- REGEN ---
    if (skillLevels.regen > 0) {
        regenTimer.current += delta;
        if (regenTimer.current > 1.0) {
            regenTimer.current = 0;
            heal(skillLevels.regen * 2);
        }
    }

  });

  return (
    <>
      {/* Orbitals */}
      <instancedMesh ref={orbitalRef} args={[undefined, undefined, 20]} frustumCulled={false} visible={skillLevels.orbital > 0}>
        <octahedronGeometry args={[0.4, 0]} />
        <meshStandardMaterial color="#0ea5e9" emissive="#0ea5e9" emissiveIntensity={2} />
      </instancedMesh>

      {/* Thunder Visual */}
      {thunderPositions.map((pos, i) => (
          <mesh key={i} position={pos}>
              <cylinderGeometry args={[0.1, 0.1, 30, 8]} />
              <meshBasicMaterial color="yellow" transparent opacity={0.8} />
          </mesh>
      ))}
    </>
  );
};

import React, { useEffect, useState } from 'react';
import { useGameStore } from '../store';
import { GameStatus, Upgrade, Item, Rarity, ItemType, HeroClass } from '../types';
import { COLORS, UPGRADES_POOL, ITEMS_POOL, HERO_STATS, PETS_POOL } from '../constants';
import { 
  Heart, Zap, Sparkles, Play, RotateCcw, 
  Backpack, Shield, Sword, Gem, X, User, Flame, Wind, ShoppingBag, Coins, Hammer, MoveRight, Star, Dna, FlaskConical, CircleDollarSign, Package,
  Crosshair, Axe, Wand2, Hexagon, Layers, Activity, Magnet, Ghost, Dices
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

export const GameUI: React.FC = () => {
  const { 
    status, health, mana, stats, score, gems, level, experience, experienceToNextLevel, 
    inventory, equipment, setStatus, skills, skillMaxCooldowns, skillLevels, passiveSkillState, gachaResults,
    startGame, resetGame, applyUpgrade, equipItem, unequipItem, buyItem, upgradeItem, sellItem, performSummon, clearGachaResults, selectHero, hero, potionCooldown
  } = useGameStore();

  const [availableUpgrades, setAvailableUpgrades] = useState<Upgrade[]>([]);
  const [shopTab, setShopTab] = useState<'SUPPLIES' | 'PETS' | 'SUMMON'>('SUPPLIES');
  const [hoveredItem, setHoveredItem] = useState<Item | null>(null);

  useEffect(() => {
    if (status === GameStatus.LEVEL_UP) {
      const shuffled = [...UPGRADES_POOL].sort(() => 0.5 - Math.random());
      setAvailableUpgrades(shuffled.slice(0, 3));
    }
  }, [status]);

  const toggleInventory = () => {
    if (status === GameStatus.PLAYING) setStatus(GameStatus.INVENTORY);
    else if (status === GameStatus.INVENTORY) setStatus(GameStatus.PLAYING);
  };

  const toggleShop = () => {
      if (status === GameStatus.PLAYING) setStatus(GameStatus.SHOP);
      else if (status === GameStatus.SHOP) setStatus(GameStatus.PLAYING);
  };

  const hpPercent = (health / stats.maxHealth) * 100;
  const manaPercent = (mana / stats.maxMana) * 100;
  const xpPercent = (experience / experienceToNextLevel) * 100;

  // Find Potions
  const hpPotion = inventory.find(i => i.id.includes('potion_hp'));
  const manaPotion = inventory.find(i => i.id.includes('potion_mana'));

  const getRarityColor = (rarity: Rarity) => {
      switch(rarity) {
          case 'MYTHIC': return 'text-red-500 border-red-500 shadow-red-500/50';
          case 'LEGENDARY': return 'text-yellow-400 border-yellow-400 shadow-yellow-400/50';
          case 'EPIC': return 'text-purple-400 border-purple-400 shadow-purple-400/50';
          case 'RARE': return 'text-blue-400 border-blue-400 shadow-blue-400/50';
          default: return 'text-slate-200 border-slate-600';
      }
  };

  const getRarityTextColor = (rarity?: Rarity) => {
      switch(rarity) {
          case 'MYTHIC': return 'text-red-500';
          case 'LEGENDARY': return 'text-yellow-400';
          case 'EPIC': return 'text-purple-400';
          case 'RARE': return 'text-blue-400';
          default: return 'text-slate-200';
      }
  };

  const getSetCount = (setName?: string) => {
      if (!setName) return 0;
      let count = 0;
      (Object.values(equipment) as (Item | null)[]).forEach(i => {
          if (i?.setName === setName) count++;
      });
      return count;
  };

  return (
    <div className="absolute inset-0 pointer-events-none z-10 font-sans text-slate-100 select-none">

      {/* HUD */}
      {(status === GameStatus.PLAYING || status === GameStatus.LEVEL_UP || status === GameStatus.INVENTORY || status === GameStatus.SHOP) && (
        <div className="absolute inset-0 flex flex-col justify-between p-4 md:p-6">

          {/* Top Bar */}
          <div className="flex justify-between items-start pointer-events-auto">
             <div className="flex items-center gap-4 bg-slate-900/80 p-2 pr-6 rounded-r-full border-l-4 border-blue-500 backdrop-blur-sm">
                <div className="bg-slate-800 p-2 rounded-full border border-slate-600">
                    <User size={24} className="text-blue-400" />
                </div>
                <div>
                    <div className="text-xl font-bold leading-none">Lv. {level}</div>
                    <div className="text-xs text-slate-400">{hero}</div>
                </div>
             </div>

             <div className="flex gap-4">
                 <div className="bg-slate-900/80 px-4 py-2 rounded-md border-t-2 border-emerald-500 backdrop-blur-sm flex items-center gap-2">
                    <Gem size={20} className="text-emerald-400" />
                    <div className="text-2xl font-mono text-emerald-400">{gems.toLocaleString()}</div>
                 </div>
                 <div className="bg-slate-900/80 px-4 py-2 rounded-md border-t-2 border-yellow-500 backdrop-blur-sm flex items-center gap-2">
                    <Coins size={20} className="text-yellow-400" />
                    <div className="text-2xl font-mono text-yellow-400">{score.toLocaleString()}</div>
                 </div>
             </div>
          </div>

          {/* Bottom Center Bar */}
          <div className="flex flex-col gap-2 w-full max-w-2xl mx-auto pb-4 items-center">

             {/* Unified Skills Bar (Active & Passive & Potions) */}
             <div className="flex justify-center items-end gap-3 pointer-events-auto mb-1">

                {/* HP Potion */}
                <PotionSlot 
                    icon={<Heart size={20} className="text-red-500" />} 
                    item={hpPotion} 
                    cooldown={potionCooldown} 
                    label="HP"
                />

                {/* Active: Weapon */}
                <div className="relative flex flex-col items-center">
                    <div className={`w-14 h-14 rounded border-2 flex items-center justify-center bg-slate-900 ${skills.weaponAbility > 0 ? 'border-slate-600' : 'border-purple-400 shadow-[0_0_15px_rgba(168,85,247,0.5)]'}`}>
                        {equipment.weapon?.ability === 'FIREBALL' ? <Flame size={28} className="text-orange-500"/> :
                         equipment.weapon?.ability === 'AXE_SPIN' ? <RotateCcw size={28} className="text-red-500"/> :
                         <Zap size={28} className={skills.weaponAbility > 0 ? 'text-slate-500' : 'text-purple-400'} />}

                        {/* Level Indicator Active */}
                        <div className="absolute -top-2 -right-2 bg-slate-800 border border-slate-600 w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold">
                            {skillLevels.weapon || 0}
                        </div>

                        {skills.weaponAbility > 0 && (
                            <div className="absolute inset-0 bg-black/60 flex items-center justify-center font-bold text-lg">
                                {Math.ceil(skills.weaponAbility)}
                            </div>
                        )}
                    </div>
                    <div className="text-[10px] font-bold mt-1 bg-black/50 px-2 rounded">R / Click</div>
                </div>

                {/* Active: Dash */}
                <div className="relative flex flex-col items-center">
                    <div className={`w-14 h-14 rounded border-2 flex items-center justify-center bg-slate-900 ${skills.dash > 0 ? 'border-slate-600' : 'border-green-400 shadow-[0_0_15px_rgba(74,222,128,0.5)]'}`}>
                        <Wind size={28} className={skills.dash > 0 ? 'text-slate-500' : 'text-green-400'} />

                         {/* Level Indicator Active */}
                         <div className="absolute -top-2 -right-2 bg-slate-800 border border-slate-600 w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold">
                            {skillLevels.dash || 0}
                        </div>

                        {skills.dash > 0 && (
                            <div className="absolute inset-0 bg-black/60 flex items-center justify-center font-bold text-lg">
                                {Math.ceil(skills.dash)}
                            </div>
                        )}
                    </div>
                    <div className="text-[10px] font-bold mt-1 bg-black/50 px-2 rounded">SPACE</div>
                </div>

                {/* Passives - Large Size, Hidden if 0 */}
                <SkillIcon icon={<Zap size={28} className="text-yellow-400"/>} level={skillLevels.thunder} cd={passiveSkillState.thunderCooldown} maxCd={passiveSkillState.thunderMaxCooldown} />
                <SkillIcon icon={<Activity size={28} className="text-blue-400"/>} level={skillLevels.orbital} cd={passiveSkillState.orbitalCooldown} maxCd={passiveSkillState.orbitalMaxCooldown} />
                <SkillIcon icon={<Heart size={28} className="text-green-400"/>} level={skillLevels.regen} />
                <SkillIcon icon={<Magnet size={28} className="text-purple-400"/>} level={skillLevels.magnet} />

                {/* Mana Potion */}
                <PotionSlot 
                    icon={<FlaskConical size={20} className="text-blue-400" />} 
                    item={manaPotion} 
                    cooldown={potionCooldown} 
                    label="MP"
                />

             </div>

             {/* Status Bars */}
             <div className="flex flex-col gap-1 w-full">
                 <div className="relative h-6 bg-slate-900 rounded border border-slate-700 overflow-hidden shadow-lg">
                    <div className="absolute top-0 left-0 h-full bg-gradient-to-r from-red-700 to-red-500 transition-all duration-300" style={{ width: `${hpPercent}%` }} />
                    <div className="absolute inset-0 flex items-center justify-center text-xs font-bold drop-shadow-[0_1px_2px_rgba(0,0,0,0.8)] z-10 tracking-wider">
                        {Math.ceil(health)} / {stats.maxHealth} HP
                    </div>
                 </div>
                 <div className="relative h-6 bg-slate-900 rounded border border-slate-700 overflow-hidden shadow-lg">
                    <div className="absolute top-0 left-0 h-full bg-gradient-to-r from-blue-700 to-blue-500 transition-all duration-300" style={{ width: `${manaPercent}%` }} />
                    <div className="absolute inset-0 flex items-center justify-center text-xs font-bold drop-shadow-[0_1px_2px_rgba(0,0,0,0.8)] z-10 tracking-wider">
                        {Math.ceil(mana)} / {stats.maxMana} MP
                    </div>
                 </div>
                 <div className="relative h-2 bg-slate-900 rounded-full border border-slate-700 overflow-hidden mt-1">
                    <div className="absolute top-0 left-0 h-full bg-gradient-to-r from-yellow-600 to-yellow-400 transition-all duration-300" style={{ width: `${xpPercent}%` }} />
                 </div>
             </div>

             <div className="flex justify-center mt-2 pointer-events-auto gap-4">
                <button onClick={toggleInventory} className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 border border-slate-600 rounded-md transition-colors text-sm font-bold">
                    <Backpack size={16} /> INVENTORY
                </button>
                <button onClick={toggleShop} className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 border border-slate-600 rounded-md transition-colors text-sm font-bold">
                    <ShoppingBag size={16} /> SHOP
                </button>
             </div>
          </div>
        </div>
      )}

      {/* Overlays */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
        <AnimatePresence>

          {/* MENU / HERO SELECT */}
          {status === GameStatus.MENU && (
             <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="flex flex-col items-center gap-8 bg-slate-900/90 p-12 rounded-xl border border-slate-700 shadow-2xl backdrop-blur-md pointer-events-auto">
                  <h1 className="text-6xl font-serif font-black text-transparent bg-clip-text bg-gradient-to-b from-blue-300 to-blue-600 drop-shadow-sm">AETHER SURVIVOR</h1>
                  <h2 className="text-xl text-slate-400">SELECT YOUR HERO</h2>

                  <div className="flex gap-6">
                      {(['ARCHER', 'WIZARD', 'BARBARIAN'] as HeroClass[]).map(h => (
                          <button 
                            key={h}
                            onClick={() => { selectHero(h); startGame(); }}
                            className="w-48 bg-slate-800 hover:bg-slate-700 border-2 border-slate-600 hover:border-blue-400 rounded-lg p-4 flex flex-col items-center gap-2 transition-all hover:-translate-y-1"
                          >
                              <div className="p-4 bg-slate-900 rounded-full mb-2">
                                  {h === 'ARCHER' && <Crosshair size={32} className="text-green-400"/>}
                                  {h === 'WIZARD' && <Wand2 size={32} className="text-blue-400"/>}
                                  {h === 'BARBARIAN' && <Axe size={32} className="text-red-400"/>}
                              </div>
                              <div className="font-bold text-lg">{h}</div>
                              <div className="text-xs text-slate-400 text-center">{HERO_STATS[h].description}</div>
                          </button>
                      ))}
                  </div>
             </motion.div>
          )}

          {/* SHOP SCREEN */}
          {status === GameStatus.SHOP && (
            <motion.div 
                initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }}
                className="bg-slate-900 border border-slate-700 rounded-lg p-8 w-[900px] h-[700px] shadow-2xl flex flex-col gap-6 pointer-events-auto"
            >
                <div className="flex justify-between items-center border-b border-slate-700 pb-4">
                    <div className="flex items-center gap-3">
                        <ShoppingBag className="text-yellow-400" />
                        <h2 className="text-2xl font-serif text-slate-200">MERCHANT</h2>
                    </div>
                    <div className="flex items-center gap-4">
                         <div className="flex items-center gap-1 bg-slate-950 px-3 py-1 rounded border border-slate-800">
                             <Gem size={16} className="text-emerald-400" />
                             <span className="text-emerald-400 font-mono">{gems.toLocaleString()}</span>
                         </div>
                         <div className="flex items-center gap-1 bg-slate-950 px-3 py-1 rounded border border-slate-800">
                             <Coins size={16} className="text-yellow-400" />
                             <span className="text-yellow-400 font-mono">{score.toLocaleString()}</span>
                         </div>
                         <button onClick={toggleShop} className="p-2 hover:bg-slate-800 rounded-full"><X size={24}/></button>
                    </div>
                </div>

                <div className="flex gap-4">
                    <button onClick={() => setShopTab('SUPPLIES')} className={`flex-1 p-3 font-bold rounded flex items-center justify-center gap-2 ${shopTab === 'SUPPLIES' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}>
                        <FlaskConical size={18}/> SUPPLIES
                    </button>
                    <button onClick={() => setShopTab('PETS')} className={`flex-1 p-3 font-bold rounded flex items-center justify-center gap-2 ${shopTab === 'PETS' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}>
                        <Ghost size={18}/> PETS
                    </button>
                    <button onClick={() => setShopTab('SUMMON')} className={`flex-1 p-3 font-bold rounded flex items-center justify-center gap-2 ${shopTab === 'SUMMON' ? 'bg-purple-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}>
                        <Dices size={18}/> SUMMON
                    </button>
                </div>

                <div className="flex-1 overflow-y-auto bg-slate-950/30 rounded p-4">
                    {shopTab === 'SUPPLIES' && (
