                                >
                                    <div className="absolute -top-3 bg-yellow-500 text-black text-xs font-bold px-2 py-1 rounded">BEST VALUE</div>
                                    <div className="p-4 bg-slate-900 rounded-full group-hover:rotate-12 transition-transform border border-purple-500">
                                        <Sparkles size={32} className="text-purple-400" />
                                    </div>
                                    <div className="text-center">
                                        <div className="font-bold text-lg text-white">Summon 10x</div>
                                        <div className="text-emerald-400 font-mono text-sm">900 Gems</div>
                                    </div>
                                </button>
                            </div>

                            <div className="bg-slate-900/80 p-4 rounded text-xs text-slate-500 grid grid-cols-5 gap-4 text-center w-full max-w-lg">
                                <div>
                                    <div className="font-bold text-slate-300">Common</div>
                                    <div>50%</div>
                                </div>
                                <div>
                                    <div className="font-bold text-blue-400">Rare</div>
                                    <div>30%</div>
                                </div>
                                <div>
                                    <div className="font-bold text-purple-400">Epic</div>
                                    <div>15%</div>
                                </div>
                                <div>
                                    <div className="font-bold text-yellow-400">Legend</div>
                                    <div>4%</div>
                                </div>
                                <div>
                                    <div className="font-bold text-red-500">Mythic</div>
                                    <div>1%</div>
