                            canUpgrade={!!equipment.armor}
                            onHover={setHoveredItem}
                            textColorClass={getRarityTextColor(equipment.armor?.rarity)}
                        />
                        <EquipmentSlot 
                            type="ACCESSORY"
                            label="Accessory" 
                            item={equipment.accessory} 
                            onClick={() => unequipItem('accessory')} 
