                         <span className="text-emerald-400 font-mono text-lg">{gems.toLocaleString()}</span>
                     </div>
                     <div className="flex-1 flex items-center justify-center gap-2 bg-slate-950 px-3 py-2 rounded border border-slate-800">
                         <Coins size={20} className="text-yellow-400" />
                         <span className="text-yellow-400 font-mono text-lg">{score.toLocaleString()}</span>
                     </div>
                </div>

                <div className="flex gap-2">
                    <button onClick={() => setShopTab('SUPPLIES')} className={`flex-1 p-2 text-sm font-bold rounded flex items-center justify-center gap-2 ${shopTab === 'SUPPLIES' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}>
                        <FlaskConical size={14}/> SUPPLIES
                    </button>
                    <button onClick={() => setShopTab('PETS')} className={`flex-1 p-2 text-sm font-bold rounded flex items-center justify-center gap-2 ${shopTab === 'PETS' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}>
                        <Ghost size={14}/> PETS
                    </button>
                    <button onClick={() => setShopTab('SUMMON')} className={`flex-1 p-2 text-sm font-bold rounded flex items-center justify-center gap-2 ${shopTab === 'SUMMON' ? 'bg-purple-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}>
                        <Dices size={14}/> SUMMON
                    </button>
                </div>

                <div className="flex-1 overflow-y-auto bg-slate-950/30 rounded p-2">
                    {shopTab === 'SUPPLIES' && (
                        <div className="grid grid-cols-2 gap-3">
                            {ITEMS_POOL.filter(i => i.type === 'POTION' || i.type === 'CORE').map((item, idx) => (
                                <ShopItem key={idx} item={item} buyItem={buyItem} score={score} />
                            ))}
                        </div>
                    )}

                    {shopTab === 'PETS' && (
                        <div className="grid grid-cols-2 gap-3">
                             {PETS_POOL.filter(p => p.rarity === 'COMMON' || p.rarity === 'RARE').map((item, idx) => (
                                <ShopItem key={idx} item={item} buyItem={buyItem} score={score} />
                            ))}
                            {PETS_POOL.length === 0 && <div className="text-slate-500 italic col-span-2 text-center mt-10">All pets are out of stock...</div>}
                        </div>
                    )}

                    {shopTab === 'SUMMON' && (
                         <div className="flex flex-col gap-6 items-center justify-center h-full">
                            <div className="text-center space-y-2">
                                <h3 className="text-2xl font-serif text-purple-300">MYSTERY SUMMON</h3>
                                <p className="text-slate-400 text-sm">Use gems to summon powerful Equipment and Pets.</p>
                            </div>

                            <div className="flex flex-col gap-4 w-full px-8">
                                <button 
                                    onClick={() => performSummon(1)}
                                    className="w-full bg-slate-800 hover:bg-slate-700 border-2 border-slate-600 hover:border-purple-400 rounded-xl p-4 flex items-center justify-between transition-all"
                                >
                                    <div className="flex items-center gap-4">
                                        <div className="p-2 bg-slate-900 rounded-full"><Gem size={20} className="text-emerald-400" /></div>
                                        <div className="font-bold">Summon 1x</div>
                                    </div>
                                    <div className="text-emerald-400 font-mono">100 GEMS</div>
                                </button>

                                <button 
                                    onClick={() => performSummon(10)}
                                    className="w-full bg-gradient-to-r from-purple-900 to-slate-900 border-2 border-purple-500 hover:border-yellow-400 rounded-xl p-4 flex items-center justify-between transition-all shadow-xl"
                                >
                                     <div className="flex items-center gap-4">
                                        <div className="p-2 bg-slate-900 rounded-full border border-purple-500"><Sparkles size={20} className="text-purple-400" /></div>
                                        <div>
                                            <div className="font-bold text-white">Summon 10x</div>
                                            <div className="text-[10px] text-yellow-500 font-bold uppercase">Best Value</div>
                                        </div>
                                    </div>
                                    <div className="text-emerald-400 font-mono">900 GEMS</div>
                                </button>
                            </div>

                            <div className="bg-slate-900/80 p-3 rounded text-[10px] text-slate-500 grid grid-cols-5 gap-2 text-center w-full">
                                <div><div className="font-bold text-slate-300">Common</div><div>50%</div></div>
                                <div><div className="font-bold text-blue-400">Rare</div><div>30%</div></div>
                                <div><div className="font-bold text-purple-400">Epic</div><div>15%</div></div>
                                <div><div className="font-bold text-yellow-400">Legend</div><div>4%</div></div>
                                <div><div className="font-bold text-red-500">Mythic</div><div>1%</div></div>
                            </div>
                         </div>
                    )}
                </div>
            </motion.div>
          )}

           {/* GACHA REVEAL */}
           {status === GameStatus.GACHA_REVEAL && (
             <div className="absolute inset-0 bg-black/90 z-50 flex items-center justify-center p-12 pointer-events-auto overflow-hidden">
                <div className="flex flex-col items-center gap-8 w-full h-full">
                    <h2 className="text-4xl font-serif text-white animate-pulse">SUMMONING...</h2>

                    <div className="flex flex-wrap justify-center gap-4 max-w-5xl overflow-y-auto p-4">
                        {gachaResults.map((item, idx) => (
                            <motion.div 
                                key={idx}
                                initial={{ scale: 0, rotateY: 180 }}
                                animate={{ scale: 1, rotateY: 0 }}
                                transition={{ delay: idx * 0.1, type: 'spring' }}
                                className={`w-40 h-56 bg-slate-800 rounded-xl border-2 flex flex-col items-center p-4 gap-2 shadow-2xl relative overflow-hidden ${
                                    item.rarity === 'MYTHIC' ? 'border-red-500 shadow-red-500/50' :
                                    item.rarity === 'LEGENDARY' ? 'border-yellow-400 shadow-yellow-400/50' :
                                    item.rarity === 'EPIC' ? 'border-purple-500 shadow-purple-500/50' :
                                    item.rarity === 'RARE' ? 'border-blue-400' : 'border-slate-600'
                                }`}
                            >
                                {/* Glow Effect for high tier */}
                                {(item.rarity === 'LEGENDARY' || item.rarity === 'MYTHIC') && (
                                    <div className="absolute inset-0 bg-gradient-to-t from-yellow-500/20 to-transparent animate-pulse" />
                                )}

                                <div className="text-[10px] font-bold uppercase tracking-widest text-slate-400 mt-2">{item.rarity}</div>
                                <div className={`p-3 rounded-full bg-slate-900 border border-slate-700 mt-2`}>
                                     <ItemIcon item={item} size={32} />
                                </div>
                                <div className={`text-center font-bold text-sm leading-tight mt-2 ${getRarityTextColor(item.rarity)}`}>
                                    {item.name}
                                </div>
                                {item.level > 1 && <div className="text-xs text-yellow-500 font-bold">+{item.level-1}</div>}
