                <div className="flex flex-col items-center gap-8 w-full h-full">
                    <h2 className="text-4xl font-serif text-white animate-pulse">SUMMONING...</h2>

                    <div className="flex flex-wrap justify-center gap-4 max-w-5xl overflow-y-auto p-4">
                        {gachaResults.map((item, idx) => (
                            <motion.div 
                                key={idx}
                                initial={{ scale: 0, rotateY: 180 }}
                                animate={{ scale: 1, rotateY: 0 }}
                                transition={{ delay: idx * 0.1, type: 'spring' }}
                                className={`w-40 h-56 bg-slate-800 rounded-xl border-2 flex flex-col items-center p-4 gap-2 shadow-2xl relative overflow-hidden ${
                                    item.rarity === 'MYTHIC' ? 'border-red-500 shadow-red-500/50' :
                                    item.rarity === 'LEGENDARY' ? 'border-yellow-400 shadow-yellow-400/50' :
                                    item.rarity === 'EPIC' ? 'border-purple-500 shadow-purple-500/50' :
                                    item.rarity === 'RARE' ? 'border-blue-400' : 'border-slate-600'
                                }`}
                            >
                                {/* Glow Effect for high tier */}
                                {(item.rarity === 'LEGENDARY' || item.rarity === 'MYTHIC') && (
                                    <div className="absolute inset-0 bg-gradient-to-t from-yellow-500/20 to-transparent animate-pulse" />
                                )}

                                <div className="text-[10px] font-bold uppercase tracking-widest text-slate-400 mt-2">{item.rarity}</div>
                                <div className={`p-3 rounded-full bg-slate-900 border border-slate-700 mt-2`}>
                                     <ItemIcon item={item} size={32} />
                                </div>
                                <div className={`text-center font-bold text-sm leading-tight mt-2 ${getRarityTextColor(item.rarity)}`}>
                                    {item.name}
                                </div>
                                {item.level > 1 && <div className="text-xs text-yellow-500 font-bold">+{item.level-1}</div>}
                                {item.type === 'PET' && <div className="mt-auto mb-2 text-[10px] bg-slate-700 px-2 py-1 rounded text-white">PET</div>}
                            </motion.div>
                        ))}
                    </div>

                    <button 
                        onClick={clearGachaResults}
                        className="mt-auto px-8 py-3 bg-slate-800 hover:bg-slate-700 border border-slate-600 rounded text-lg font-bold"
                    >
                        CONTINUE
                    </button>
                </div>
             </div>
           )}

          {/* INVENTORY SCREEN - Right Side */}
          {status === GameStatus.INVENTORY && (
            <motion.div 
                initial={{ x: '100%' }} animate={{ x: 0 }} exit={{ x: '100%' }}
                className="absolute right-0 top-0 h-full w-[600px] bg-slate-900 border-l border-slate-700 p-8 shadow-2xl flex flex-col gap-6 pointer-events-auto"
            >
                <div className="flex justify-between items-center border-b border-slate-700 pb-4">
                    <h2 className="text-2xl font-serif text-slate-200">INVENTORY</h2>
                     <button onClick={toggleInventory} className="p-2 hover:bg-slate-800 rounded-full"><X size={24}/></button>
                </div>

                 {/* Currency Display in Inventory */}
                 <div className="flex items-center justify-between bg-slate-950 px-4 py-3 rounded border border-slate-800">
                     <span className="text-slate-400 font-bold text-sm">GOLD AVAILABLE</span>
                     <div className="flex items-center gap-2">
                        <Coins size={20} className="text-yellow-400" />
                        <span className="text-yellow-400 font-mono text-xl">{score.toLocaleString()}</span>
                     </div>
                 </div>

                <div className="flex flex-col gap-6 h-full overflow-hidden">
                    {/* Character Equipment Panel */}
                    <div className="flex flex-col gap-4 items-center bg-slate-950/50 p-4 rounded-lg">
                        <div className="w-full text-center text-slate-400 mb-2 text-xs font-bold uppercase tracking-widest">Equipped Gear</div>

                        <div className="grid grid-cols-2 gap-4 w-full">
                            <EquipmentSlot 
                                type="WEAPON"
                                label="Weapon" 
                                item={equipment.weapon} 
                                onClick={() => unequipItem('weapon')}
                                onUpgrade={() => equipment.weapon && upgradeItem(equipment.weapon)}
                                canUpgrade={!!equipment.weapon}
                                onHover={setHoveredItem}
                                textColorClass={getRarityTextColor(equipment.weapon?.rarity)}
                            />
                            <EquipmentSlot 
                                type="ARMOR"
                                label="Armor" 
                                item={equipment.armor} 
                                onClick={() => unequipItem('armor')} 
                                onUpgrade={() => equipment.armor && upgradeItem(equipment.armor)}
                                canUpgrade={!!equipment.armor}
                                onHover={setHoveredItem}
                                textColorClass={getRarityTextColor(equipment.armor?.rarity)}
                            />
                            <EquipmentSlot 
                                type="ACCESSORY"
                                label="Accessory" 
                                item={equipment.accessory} 
                                onClick={() => unequipItem('accessory')} 
                                onUpgrade={() => equipment.accessory && upgradeItem(equipment.accessory)}
                                canUpgrade={!!equipment.accessory}
                                onHover={setHoveredItem}
                                textColorClass={getRarityTextColor(equipment.accessory?.rarity)}
                            />
                            <EquipmentSlot 
                                type="PET"
                                label="Pet" 
                                item={equipment.pet} 
                                onClick={() => unequipItem('pet')} 
                                onUpgrade={() => equipment.pet && upgradeItem(equipment.pet)}
                                canUpgrade={!!equipment.pet}
                                onHover={setHoveredItem}
                                textColorClass={getRarityTextColor(equipment.pet?.rarity)}
                            />
                        </div>

                        {/* Stats Summary */}
                        <div className="w-full grid grid-cols-3 gap-2 text-[10px] text-slate-500 pt-4 border-t border-slate-800">
                            <div className="flex flex-col"><span className="font-bold text-slate-400">DMG</span> <span className="text-white text-base">{Math.round(stats.damage)}</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">DEF</span> <span className="text-blue-400 text-base">{Math.round(stats.defense)}</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">REGEN</span> <span className="text-green-400 text-base">{stats.regen.toFixed(1)}/s</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">MANA REG</span> <span className="text-blue-400 text-base">{stats.manaRegen.toFixed(1)}/s</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">CRIT</span> <span className="text-yellow-400 text-base">{(stats.critRate * 100).toFixed(0)}%</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">CDR</span> <span className="text-purple-400 text-base">{(stats.cooldownReduction * 100).toFixed(0)}%</span></div>
                        </div>
                    </div>

                    {/* Inventory Grid */}
                    <div className="flex-1 bg-slate-950/30 p-4 rounded-lg flex flex-col overflow-hidden">
                        <div className="w-full text-slate-400 mb-2 text-xs font-bold uppercase tracking-widest flex justify-between">
                            <span>Backpack</span>
                            <span className="text-[10px] font-normal text-slate-600">Right-click to Equip</span>
                        </div>
                        <div className="grid grid-cols-5 gap-2 overflow-y-auto pr-2">
                            {inventory.map((item, idx) => {
                                const isConsumable = item.type === 'POTION' || item.type === 'CORE';
                                const reqLevel = getLevelRequirement(item.rarity);
                                const canEquip = level >= reqLevel;

                                return (
                                <div 
                                    key={idx} 
                                    className="relative group w-full aspect-square"
                                    onMouseEnter={() => setHoveredItem(item)}
                                    onMouseLeave={() => setHoveredItem(null)}
                                >
                                    <button 
                                        onClick={() => !isConsumable && canEquip && equipItem(item)}
                                        onContextMenu={(e) => { e.preventDefault(); !isConsumable && canEquip && equipItem(item); }}
                                        className={`w-full h-full bg-slate-800 border-2 ${getRarityColor(item.rarity)} ${!canEquip && !isConsumable ? 'opacity-50 cursor-not-allowed grayscale' : 'hover:scale-105'} rounded flex flex-col items-center justify-center p-1 transition-transform relative`}
                                    >
                                        <ItemIcon item={item} size={20} />

                                        {isConsumable && <div className="absolute top-0 right-0 bg-black/60 text-[10px] px-1 rounded-bl text-white font-mono">{item.quantity}</div>}
                                        {item.level > 1 && <div className="text-[10px] mt-1 text-yellow-400 font-bold">+{item.level - 1}</div>}

                                        {/* Level Lock Icon */}
                                        {!isConsumable && !canEquip && (
                                            <div className="absolute inset-0 flex items-center justify-center bg-black/40 text-red-500 font-bold text-xs drop-shadow-md">
                                                Lv.{reqLevel}
                                            </div>
                                        )}
                                    </button>

                                    {/* Action Buttons Overlay on Hover */}
                                    <div className="absolute -top-2 -right-2 flex gap-1 z-10 opacity-0 group-hover:opacity-100 transition-opacity">
                                        {!isConsumable && (
                                            <button 
                                                onClick={(e) => { e.stopPropagation(); upgradeItem(item); }}
                                                className="bg-slate-900 border border-slate-600 rounded-full p-1 hover:bg-yellow-900 hover:border-yellow-500"
                                                title="Upgrade"
                                            >
                                                <Hammer size={10} className="text-yellow-400" />
                                            </button>
                                        )}
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); sellItem(item); }}
                                            className="bg-slate-900 border border-slate-600 rounded-full p-1 hover:bg-red-900 hover:border-red-500"
                                            title="Sell"
                                        >
                                            <CircleDollarSign size={10} className="text-green-400" />
                                        </button>
                                    </div>

                                    {/* TOOLTIP */}
                                    {hoveredItem === item && (
                                        <div className={`fixed z-50 pointer-events-none p-4 rounded bg-slate-900 border border-slate-600 shadow-2xl w-64 text-left top-1/2 -translate-y-1/2 right-[620px]`}>
                                            <div className={`${getRarityColor(item.rarity)} border-b pb-2 mb-2 font-bold flex justify-between`}>
                                                <span>{item.name} {item.level > 1 && `+${item.level-1}`}</span>
                                            </div>
                                            <div className="text-sm text-slate-300">
                                                {/* Iterate stats */}
                                                {Object.entries(item.stats).map(([key, val]) => (
                                                    <div key={key}>+{val} {key}</div>
                                                ))}
                                                {item.ability && <div className="text-purple-400 italic text-xs mt-1">{item.description}</div>}
                                                {item.setName && (
                                                    <div className="mt-2 text-xs">
                                                        <div className="text-yellow-500 font-bold">{item.setName}</div>
                                                        <div className="text-slate-400">{item.setBonus}</div>
                                                        <div className="text-slate-500 italic">(3 pieces required)</div>
                                                    </div>
                                                )}
                                                {item.description && !item.ability && <div className="text-slate-500 italic text-xs mt-1">{item.description}</div>}

                                                {/* Equip Requirement */}
                                                {!isConsumable && (
                                                    <div className={`mt-2 text-xs font-bold ${level >= reqLevel ? 'text-green-400' : 'text-red-500'}`}>
                                                        Requires Level {reqLevel}
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    )}
                                </div>
                            )})}
                            {[...Array(Math.max(0, 30 - inventory.length))].map((_, i) => (
                                <div key={`empty-${i}`} className="aspect-square bg-slate-900/50 border border-slate-800 rounded" />
                            ))}
                        </div>
                    </div>
                </div>
            </motion.div>
          )}

          {/* LEVEL UP */}
          {status === GameStatus.LEVEL_UP && (
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center pointer-events-auto">
                <motion.div 
                    initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}
                    className="flex flex-col items-center gap-8"
                >
                    <h2 className="text-4xl font-serif text-yellow-400 drop-shadow-lg">LEVEL UP!</h2>
                    <div className="flex flex-wrap justify-center gap-6">
                        {availableUpgrades.map((upgrade, idx) => (
                            <motion.button 
                                key={idx}
                                initial={{ y: 50, opacity: 0 }}
                                animate={{ y: 0, opacity: 1 }}
                                transition={{ delay: idx * 0.1 }}
                                onClick={() => applyUpgrade(upgrade)}
                                className="relative w-64 aspect-[3/4] bg-slate-800 rounded-xl border-2 border-slate-600 hover:border-yellow-400 hover:scale-105 transition-all shadow-xl overflow-hidden flex flex-col p-6 text-center items-center justify-between group"
                            >
                                <div className="absolute inset-0 bg-gradient-to-b from-slate-700/50 to-slate-900/50 z-0" />
                                <div className="relative z-10 flex flex-col items-center gap-4">
                                    <div className={`p-4 rounded-full ${upgrade.rarity === 'LEGENDARY' ? 'bg-orange-500' : upgrade.rarity === 'RARE' ? 'bg-blue-500' : 'bg-slate-500'} text-white shadow-lg`}>
                                        <Sparkles size={32} />
                                    </div>
                                    <h3 className="text-xl font-bold">{upgrade.name}</h3>
                                    <div className="h-px w-full bg-slate-600 my-2" />
                                    <p className="text-sm text-slate-300">{upgrade.description}</p>
                                </div>
                                <div className="relative z-10 text-xs uppercase tracking-widest opacity-50 font-bold">
                                    {upgrade.rarity}
                                </div>
                            </motion.button>
                        ))}
                    </div>
                </motion.div>
            </div>
          )}

          {/* GAME OVER */}
          {status === GameStatus.GAME_OVER && (
            <motion.div 
                initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                className="bg-slate-900/95 border border-red-900 p-12 rounded-lg text-center flex flex-col items-center gap-6 shadow-2xl pointer-events-auto"
            >
              <h2 className="text-5xl font-serif text-red-500 drop-shadow-md">YOU DIED</h2>
              <div className="flex flex-col gap-1 text-xl text-slate-300">
                 <p>Gold Collected: <span className="text-yellow-400">{score.toLocaleString()}</span></p>
                 <p>Level Reached: {level}</p>
              </div>
              <button 
                onClick={resetGame}
                className="flex items-center gap-3 px-8 py-3 bg-red-800 hover:bg-red-700 text-white font-bold rounded shadow-lg mt-4"
              >
                <RotateCcw size={20} /> TRY AGAIN
              </button>
            </motion.div>
          )}

        </AnimatePresence>
      </div>
    </div>
  );
};

// Tooltip wrapper for skills
const SkillTooltipWrapper = ({ children, desc }: { children?: React.ReactNode, desc?: string }) => {
    const [show, setShow] = useState(false);
    return (
        <div className="relative flex flex-col items-center" onMouseEnter={() => setShow(true)} onMouseLeave={() => setShow(false)}>
            {children}
            {show && desc && (
                <div className="absolute bottom-full mb-2 w-48 bg-slate-900 border border-slate-600 p-2 rounded text-xs text-slate-200 z-50 shadow-xl pointer-events-none">
                    {desc}
                </div>
            )}
        </div>
    )
}

// Active Skill Slot
const ActiveSkillSlot = ({ icon, level, cooldown, label, desc, borderColor }: any) => {
    return (
        <SkillTooltipWrapper desc={desc}>
             <div className="relative flex flex-col items-center">
                    <div className={`w-14 h-14 rounded border-2 flex items-center justify-center bg-slate-900 ${borderColor}`}>
                        {icon}

                        <div className="absolute -top-2 -right-2 bg-slate-800 border border-slate-600 w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold">
                            {level || 0}
                        </div>

                        {cooldown > 0 && (
                            <div className="absolute inset-0 bg-black/60 flex items-center justify-center font-bold text-lg">
                                {Math.ceil(cooldown)}
                            </div>
                        )}
                    </div>
                    <div className="text-[10px] font-bold mt-1 bg-black/50 px-2 rounded">{label}</div>
            </div>
        </SkillTooltipWrapper>
    )
}

// Skill Icon: Larger (w-14 h-14) and Hidden if Level 0
const SkillIcon = ({ icon, level, cd, maxCd, desc }: { icon: any, level: number, cd?: number, maxCd?: number, desc?: string }) => {
    if (level <= 0) return null; // Hidden if not obtained

    return (
        <SkillTooltipWrapper desc={desc}>
            <div className="relative flex flex-col items-center">
                <div className="w-14 h-14 rounded border-2 flex items-center justify-center bg-slate-900 border-slate-600 shadow-md">
                    {icon}

                    {/* Level Indicator */}
                    <div className="absolute -top-2 -right-2 bg-slate-800 border border-slate-600 w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold z-10">
                        {level}
                    </div>

                    {/* Cooldown Overlay */}
                    {cd !== undefined && maxCd !== undefined && cd > 0 && (
                        <div className="absolute inset-0 bg-black/60 flex items-center justify-center font-bold text-lg rounded overflow-hidden">
                            <div className="text-white">{Math.ceil(cd)}</div>
                        </div>
                    )}
                </div>
                {/* Passive Label */}
                <div className="text-[10px] font-bold mt-1 bg-black/50 px-2 rounded opacity-50">PASSIVE</div>
            </div>
        </SkillTooltipWrapper>
    )
}

const PotionSlot = ({ icon, item, cooldown, label }: { icon: any, item: Item | undefined, cooldown: number, label: string }) => {
    return (
        <div className="relative flex flex-col items-center">
            <div className={`w-10 h-10 rounded border flex items-center justify-center ${item ? 'bg-slate-800 border-slate-600' : 'bg-slate-900 border-slate-800 opacity-50'}`}>
                {icon}

                {/* Quantity */}
                {item && (
                     <div className="absolute -top-2 -right-2 bg-slate-700 border border-slate-600 w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-mono z-10 shadow">
                        {item.quantity || 0}
                     </div>
                )}

                {/* Cooldown */}
                {cooldown > 0 && item && (
                     <div className="absolute inset-0 bg-black/60 rounded flex items-center justify-center">
                         <div className="text-[10px] font-bold text-white">{Math.ceil(cooldown)}</div>
                     </div>
                )}
            </div>
            <div className="text-[9px] font-bold mt-1 text-slate-500">{label}</div>
        </div>
    );
};

const ItemIcon = ({ item, size }: { item: Item, size: number }) => {
    if (item.type === 'POTION') return <FlaskConical size={size} />;
    if (item.type === 'CORE') return <Hexagon size={size} />;
    if (item.type === 'ACCESSORY') return <Gem size={size} />;
    if (item.type === 'ARMOR') return <Shield size={size} />;
    if (item.type === 'PET') return <Ghost size={size} />;
    if (item.projectileType === 'MAGIC') return <Wand2 size={size} />;
    if (item.projectileType === 'ARROW') return <Crosshair size={size} />;
    if (item.projectileType === 'AXE') return <Axe size={size} />;
    return <Sword size={size} />;
};

interface ShopItemProps {
    item: Item;
    buyItem: (i: Item, q?: number) => boolean;
    score: number;
}

const ShopItem: React.FC<ShopItemProps> = ({ item, buyItem, score }) => {
    const price1 = item.price;
    const price10 = item.price * 10;

    return (
        <div className="bg-slate-800 p-4 rounded border border-slate-700 flex flex-col gap-2 relative overflow-hidden group">
            <div className="flex justify-between items-start z-10">
                <h3 className={`font-bold ${item.rarity === 'MYTHIC' ? 'text-red-400' : item.rarity === 'EPIC' ? 'text-purple-400' : 'text-slate-200'}`}>{item.name}</h3>
                <ItemIcon item={item} size={16} />
            </div>

            {item.setName && (
                 <div className="text-[10px] text-yellow-500 font-bold uppercase tracking-wider flex items-center gap-1 z-10">
                    <Layers size={10} /> {item.setName}
                 </div>
            )}

            <p className="text-xs text-slate-400 z-10">
                {item.description || Object.entries(item.stats).map(([k,v]) => `+${v} ${k}`).join(', ')}
            </p>

            {item.setName && (
                <p className="text-[10px] text-slate-500 italic z-10 mt-1">Set Bonus: {item.setBonus}</p>
            )}

            <div className="mt-auto pt-2 flex justify-between gap-2 items-center z-10">
                 <button 
                    onClick={() => buyItem(item, 1)}
                    disabled={score < price1}
                    className={`flex-1 py-1 rounded text-xs font-bold flex flex-col items-center ${score >= price1 ? 'bg-blue-600 hover:bg-blue-500 text-white' : 'bg-slate-700 text-slate-500 cursor-not-allowed'}`}
                >
                    <span>BUY 1</span>
                    <span className="font-mono">{price1} G</span>
                </button>
                <button 
                    onClick={() => buyItem(item, 10)}
                    disabled={score < price10}
                    className={`flex-1 py-1 rounded text-xs font-bold flex flex-col items-center border border-slate-600 ${score >= price10 ? 'bg-slate-800 hover:bg-slate-700 text-white' : 'bg-slate-900 text-slate-600 cursor-not-allowed'}`}
                >
                    <span>BUY 10</span>
                    <span className="font-mono text-yellow-500">{price10} G</span>
                </button>
            </div>
        </div>
    );
};

const EquipmentSlot = ({ 
    type, icon, label, item, onClick, onUpgrade, canUpgrade, onHover, textColorClass
}: { 
    type: ItemType, icon?: any, label: string, item: Item | null, onClick: () => void, onUpgrade?: () => void, canUpgrade?: boolean, onHover: (i: Item | null) => void, textColorClass?: string
}) => {
    // Determine icon based on type if not provided, or based on item if equipped
    const renderIcon = () => {
        if (item) return <ItemIcon item={item} size={24} />;
        if (type === 'WEAPON') return <Sword size={24} />;
        if (type === 'ARMOR') return <Shield size={24} />;
        if (type === 'ACCESSORY') return <Gem size={24} />;
        if (type === 'PET') return <Ghost size={24} />;
        return <Sword size={24} />;
    };

    return (
        <div 
            className="w-full flex gap-2"
            onMouseEnter={() => item && onHover(item)}
            onMouseLeave={() => onHover(null)}
        >
            <button onClick={onClick} disabled={!item} className={`flex-1 flex items-center gap-4 p-3 rounded border transition-colors ${item ? 'bg-slate-800 border-slate-600 hover:bg-slate-700' : 'bg-slate-900 border-slate-800 text-slate-600'}`}>
                <div className={`p-2 rounded-full ${item ? 'bg-blue-500/20 text-blue-400' : 'bg-slate-800'}`}>
                    {renderIcon()}
                </div>
                <div className="text-left">
                    <div className="text-xs uppercase font-bold tracking-wider opacity-50">{label}</div>
                    <div className={`font-serif ${item ? textColorClass || 'text-white' : 'text-slate-600'}`}>
                        {item ? `${item.name} ${item.level > 1 ? `+${item.level-1}` : ''}` : 'Empty'}
                    </div>
                </div>
            </button>
            {item && onUpgrade && (
                <button 
                    onClick={(e) => { e.stopPropagation(); onUpgrade(); }}
                    disabled={!canUpgrade}
                    className={`w-12 flex flex-col items-center justify-center border rounded ${canUpgrade ? 'bg-slate-800 border-slate-600 hover:bg-blue-900 hover:border-blue-400' : 'bg-slate-900 border-slate-800 opacity-50'}`}
                >
                    <Hammer size={16} className={canUpgrade ? "text-yellow-400" : "text-slate-600"} />
                    <span className="text-[9px] font-mono text-slate-400 mt-1">{item.level}</span>
                </button>
            )}
        </div>
    );
};

import { Vector3 } from 'three';

export enum GameStatus {
  MENU = 'MENU',
  HERO_SELECT = 'HERO_SELECT',
  PLAYING = 'PLAYING',
  PAUSED = 'PAUSED',
  LEVEL_UP = 'LEVEL_UP',
  GAME_OVER = 'GAME_OVER',
  INVENTORY = 'INVENTORY',
  SHOP = 'SHOP',
  GACHA_REVEAL = 'GACHA_REVEAL', 
}

export type HeroClass = 'ARCHER' | 'WIZARD' | 'BARBARIAN';

export type UpgradeType = 
  'HEALTH' | 'SPEED' | 'DAMAGE' | 'FIRE_RATE' | 'MULTISHOT' | 'DASH_COOLDOWN' |
  'SKILL_ORBITAL' | 'SKILL_THUNDER' | 'SKILL_REGEN' | 'SKILL_MAGNET' |
  'SKILL_DASH' | 'SKILL_WEAPON' |
  'CRIT_RATE' | 'CRIT_DAMAGE' | 'DEFENSE' | 'MAX_MANA';

