                <div className="flex justify-between items-center border-b border-slate-700 pb-4">
                    <h2 className="text-2xl font-serif text-slate-200">INVENTORY</h2>
                     <button onClick={toggleInventory} className="p-2 hover:bg-slate-800 rounded-full"><X size={24}/></button>
                </div>

                 {/* Currency Display in Inventory */}
                 <div className="flex items-center justify-between bg-slate-950 px-4 py-3 rounded border border-slate-800">
                     <span className="text-slate-400 font-bold text-sm">GOLD AVAILABLE</span>
                     <div className="flex items-center gap-2">
                        <Coins size={20} className="text-yellow-400" />
                        <span className="text-yellow-400 font-mono text-xl">{score.toLocaleString()}</span>
                     </div>
                 </div>

                <div className="flex flex-col gap-6 h-full overflow-hidden">
                    {/* Character Equipment Panel */}
                    <div className="flex flex-col gap-4 items-center bg-slate-950/50 p-4 rounded-lg">
                        <div className="w-full text-center text-slate-400 mb-2 text-xs font-bold uppercase tracking-widest">Equipped Gear</div>

                        <div className="grid grid-cols-2 gap-4 w-full">
                            <EquipmentSlot 
                                type="WEAPON"
                                label="Weapon" 
                                item={equipment.weapon} 
                                onClick={() => unequipItem('weapon')}
                                onUpgrade={() => equipment.weapon && upgradeItem(equipment.weapon)}
                                canUpgrade={!!equipment.weapon}
                                onHover={setHoveredItem}
                                textColorClass={getRarityTextColor(equipment.weapon?.rarity)}
                            />
                            <EquipmentSlot 
                                type="ARMOR"
                                label="Armor" 
                                item={equipment.armor} 
                                onClick={() => unequipItem('armor')} 
                                onUpgrade={() => equipment.armor && upgradeItem(equipment.armor)}
                                canUpgrade={!!equipment.armor}
                                onHover={setHoveredItem}
                                textColorClass={getRarityTextColor(equipment.armor?.rarity)}
                            />
                            <EquipmentSlot 
                                type="ACCESSORY"
                                label="Accessory" 
                                item={equipment.accessory} 
                                onClick={() => unequipItem('accessory')} 
                                onUpgrade={() => equipment.accessory && upgradeItem(equipment.accessory)}
                                canUpgrade={!!equipment.accessory}
                                onHover={setHoveredItem}
                                textColorClass={getRarityTextColor(equipment.accessory?.rarity)}
                            />
                            <EquipmentSlot 
                                type="PET"
                                label="Pet" 
                                item={equipment.pet} 
                                onClick={() => unequipItem('pet')} 
                                onUpgrade={() => equipment.pet && upgradeItem(equipment.pet)}
                                canUpgrade={!!equipment.pet}
                                onHover={setHoveredItem}
                                textColorClass={getRarityTextColor(equipment.pet?.rarity)}
                            />
                        </div>

                        {/* Stats Summary */}
                        <div className="w-full grid grid-cols-3 gap-2 text-[10px] text-slate-500 pt-4 border-t border-slate-800">
                            <div className="flex flex-col"><span className="font-bold text-slate-400">DMG</span> <span className="text-white text-base">{Math.round(stats.damage)}</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">DEF</span> <span className="text-blue-400 text-base">{Math.round(stats.defense)}</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">REGEN</span> <span className="text-green-400 text-base">{stats.regen.toFixed(1)}/s</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">MANA REG</span> <span className="text-blue-400 text-base">{stats.manaRegen.toFixed(1)}/s</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">CRIT</span> <span className="text-yellow-400 text-base">{(stats.critRate * 100).toFixed(0)}%</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">CDR</span> <span className="text-purple-400 text-base">{(stats.cooldownReduction * 100).toFixed(0)}%</span></div>
                        </div>
                    </div>

                    {/* Inventory Grid */}
                    <div className="flex-1 bg-slate-950/30 p-4 rounded-lg flex flex-col overflow-hidden">
                        <div className="w-full text-slate-400 mb-2 text-xs font-bold uppercase tracking-widest flex justify-between">
                            <span>Backpack</span>
                            <span className="text-[10px] font-normal text-slate-600">Right-click to Equip</span>
                        </div>
                        <div className="grid grid-cols-5 gap-2 overflow-y-auto pr-2">
                            {inventory.map((item, idx) => {
                                const isConsumable = item.type === 'POTION' || item.type === 'CORE';
                                const reqLevel = getLevelRequirement(item.rarity);
                                const canEquip = level >= reqLevel;

                                return (
                                <div 
                                    key={idx} 
                                    className="relative group w-full aspect-square"
                                    onMouseEnter={() => setHoveredItem(item)}
                                    onMouseLeave={() => setHoveredItem(null)}
                                >
                                    <button 
                                        onClick={() => !isConsumable && canEquip && equipItem(item)}
                                        onContextMenu={(e) => { e.preventDefault(); !isConsumable && canEquip && equipItem(item); }}
                                        className={`w-full h-full bg-slate-800 border-2 ${getRarityColor(item.rarity)} ${!canEquip && !isConsumable ? 'opacity-50 cursor-not-allowed grayscale' : 'hover:scale-105'} rounded flex flex-col items-center justify-center p-1 transition-transform relative`}
                                    >
                                        <ItemIcon item={item} size={20} />

                                        {isConsumable && <div className="absolute top-0 right-0 bg-black/60 text-[10px] px-1 rounded-bl text-white font-mono">{item.quantity}</div>}
                                        {item.level > 1 && <div className="text-[10px] mt-1 text-yellow-400 font-bold">+{item.level - 1}</div>}

                                        {/* Level Lock Icon */}
                                        {!isConsumable && !canEquip && (
                                            <div className="absolute inset-0 flex items-center justify-center bg-black/40 text-red-500 font-bold text-xs drop-shadow-md">
                                                Lv.{reqLevel}
                                            </div>
                                        )}
                                    </button>

                                    {/* Action Buttons Overlay on Hover */}
                                    <div className="absolute -top-2 -right-2 flex gap-1 z-10 opacity-0 group-hover:opacity-100 transition-opacity">
                                        {!isConsumable && (
                                            <button 
                                                onClick={(e) => { e.stopPropagation(); upgradeItem(item); }}
                                                className="bg-slate-900 border border-slate-600 rounded-full p-1 hover:bg-yellow-900 hover:border-yellow-500"
                                                title="Upgrade"
                                            >
                                                <Hammer size={10} className="text-yellow-400" />
                                            </button>
                                        )}
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); sellItem(item); }}
                                            className="bg-slate-900 border border-slate-600 rounded-full p-1 hover:bg-red-900 hover:border-red-500"
                                            title="Sell"
                                        >
                                            <CircleDollarSign size={10} className="text-green-400" />
                                        </button>
                                    </div>

                                    {/* TOOLTIP */}
                                    {hoveredItem === item && (
                                        <div className={`fixed z-50 pointer-events-none p-4 rounded bg-slate-900 border border-slate-600 shadow-2xl w-64 text-left top-1/2 -translate-y-1/2 right-[620px]`}>
                                            <div className={`${getRarityColor(item.rarity)} border-b pb-2 mb-2 font-bold flex justify-between`}>
                                                <span>{item.name} {item.level > 1 && `+${item.level-1}`}</span>
                                            </div>
                                            <div className="text-sm text-slate-300">
                                                {/* Iterate stats */}
                                                {Object.entries(item.stats).map(([key, val]) => (
                                                    <div key={key}>+{val} {key}</div>
                                                ))}
                                                {item.ability && <div className="text-purple-400 italic text-xs mt-1">{item.description}</div>}
                                                {item.setName && (
                                                    <div className="mt-2 text-xs">
                                                        <div className="text-yellow-500 font-bold">{item.setName}</div>
                                                        <div className="text-slate-400">{item.setBonus}</div>
                                                        <div className="text-slate-500 italic">(3 pieces required)</div>
                                                    </div>
                                                )}
                                                {item.description && !item.ability && <div className="text-slate-500 italic text-xs mt-1">{item.description}</div>}

                                                {/* Equip Requirement */}
                                                {!isConsumable && (
                                                    <div className={`mt-2 text-xs font-bold ${level >= reqLevel ? 'text-green-400' : 'text-red-500'}`}>
                                                        Requires Level {reqLevel}
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    )}
                                </div>
                            )})}
                            {[...Array(Math.max(0, 30 - inventory.length))].map((_, i) => (
                                <div key={`empty-${i}`} className="aspect-square bg-slate-900/50 border border-slate-800 rounded" />
                            ))}
                        </div>
                    </div>
                </div>
            </motion.div>
          )}

          {/* LEVEL UP */}
          {status === GameStatus.LEVEL_UP && (
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center pointer-events-auto">
                <motion.div 
                    initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}
                    className="flex flex-col items-center gap-8"
                >
                    <h2 className="text-4xl font-serif text-yellow-400 drop-shadow-lg">LEVEL UP!</h2>
                    <div className="flex flex-wrap justify-center gap-6">
                        {availableUpgrades.map((upgrade, idx) => (
                            <motion.button 
                                key={idx}
                                initial={{ y: 50, opacity: 0 }}
                                animate={{ y: 0, opacity: 1 }}
                                transition={{ delay: idx * 0.1 }}
                                onClick={() => applyUpgrade(upgrade)}
                                className="relative w-64 aspect-[3/4] bg-slate-800 rounded-xl border-2 border-slate-600 hover:border-yellow-400 hover:scale-105 transition-all shadow-xl overflow-hidden flex flex-col p-6 text-center items-center justify-between group"
                            >
                                <div className="absolute inset-0 bg-gradient-to-b from-slate-700/50 to-slate-900/50 z-0" />
                                <div className="relative z-10 flex flex-col items-center gap-4">
                                    <div className={`p-4 rounded-full ${upgrade.rarity === 'LEGENDARY' ? 'bg-orange-500' : upgrade.rarity === 'RARE' ? 'bg-blue-500' : 'bg-slate-500'} text-white shadow-lg`}>
                                        <Sparkles size={32} />
                                    </div>
                                    <h3 className="text-xl font-bold">{upgrade.name}</h3>
                                    <div className="h-px w-full bg-slate-600 my-2" />
                                    <p className="text-sm text-slate-300">{upgrade.description}</p>
                                </div>
                                <div className="relative z-10 text-xs uppercase tracking-widest opacity-50 font-bold">
                                    {upgrade.rarity}
                                </div>
                            </motion.button>
                        ))}
                    </div>
                </motion.div>
            </div>
          )}

          {/* GAME OVER */}
          {status === GameStatus.GAME_OVER && (
            <motion.div 
                initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                className="bg-slate-900/95 border border-red-900 p-12 rounded-lg text-center flex flex-col items-center gap-6 shadow-2xl pointer-events-auto"
            >
              <h2 className="text-5xl font-serif text-red-500 drop-shadow-md">YOU DIED</h2>
              <div className="flex flex-col gap-1 text-xl text-slate-300">
                 <p className="text-purple-400 font-bold text-2xl">Reached Wave {wave}</p>
                 <p>Gold Collected: <span className="text-yellow-400">{score.toLocaleString()}</span></p>
                 <p>Level Reached: {level}</p>
              </div>
              <button 
                onClick={resetGame}
                className="flex items-center gap-3 px-8 py-3 bg-red-800 hover:bg-red-700 text-white font-bold rounded shadow-lg mt-4"
              >
                <RotateCcw size={20} /> TRY AGAIN
              </button>
            </motion.div>
          )}

        </AnimatePresence>
      </div>
    </div>
  );
};

// Tooltip wrapper for skills
const SkillTooltipWrapper = ({ children, desc }: { children?: React.ReactNode, desc?: string }) => {
    const [show, setShow] = useState(false);
    return (
        <div className="relative flex flex-col items-center" onMouseEnter={() => setShow(true)} onMouseLeave={() => setShow(false)}>
            {children}
            {show && desc && (
                <div className="absolute bottom-full mb-2 w-48 bg-slate-900 border border-slate-600 p-2 rounded text-xs text-slate-200 z-50 shadow-xl pointer-events-none">
                    {desc}
                </div>
            )}
        </div>
    )
}

// Active Skill Slot
const ActiveSkillSlot = ({ icon, level, cooldown, label, desc, borderColor }: any) => {
    return (
        <SkillTooltipWrapper desc={desc}>
             <div className="relative flex flex-col items-center">
                    <div className={`w-14 h-14 rounded border-2 flex items-center justify-center bg-slate-900 ${borderColor}`}>
                        {icon}

                        <div className="absolute -top-2 -right-2 bg-slate-800 border border-slate-600 w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold">
                            {level || 0}
                        </div>

                        {cooldown > 0 && (
                            <div className="absolute inset-0 bg-black/60 flex items-center justify-center font-bold text-lg">
                                {Math.ceil(cooldown)}
                            </div>
                        )}
                    </div>
                    <div className="text-[10px] font-bold mt-1 bg-black/50 px-2 rounded">{label}</div>
            </div>
        </SkillTooltipWrapper>
    )
}

// Skill Icon: Larger (w-14 h-14) and Hidden if Level 0
const SkillIcon = ({ icon, level, cd, maxCd, desc }: { icon: any, level: number, cd?: number, maxCd?: number, desc?: string }) => {
    if (level <= 0) return null; // Hidden if not obtained

    return (
        <SkillTooltipWrapper desc={desc}>
            <div className="relative flex flex-col items-center">
                <div className="w-14 h-14 rounded border-2 flex items-center justify-center bg-slate-900 border-slate-600 shadow-md">
                    {icon}

                    {/* Level Indicator */}
                    <div className="absolute -top-2 -right-2 bg-slate-800 border border-slate-600 w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold z-10">
                        {level}
                    </div>

                    {/* Cooldown Overlay */}
                    {cd !== undefined && maxCd !== undefined && cd > 0 && (
                        <div className="absolute inset-0 bg-black/60 flex items-center justify-center font-bold text-lg rounded overflow-hidden">
                            <div className="text-white">{Math.ceil(cd)}</div>
                        </div>
                    )}
                </div>
                {/* Passive Label */}
                <div className="text-[10px] font-bold mt-1 bg-black/50 px-2 rounded opacity-50">PASSIVE</div>
            </div>
        </SkillTooltipWrapper>
    )
}

const PotionSlot = ({ icon, item, cooldown, label }: { icon: any, item: Item | undefined, cooldown: number, label: string }) => {
    return (
        <div className="relative flex flex-col items-center">
            <div className={`w-10 h-10 rounded border flex items-center justify-center ${item ? 'bg-slate-800 border-slate-600' : 'bg-slate-900 border-slate-800 opacity-50'}`}>
                {icon}

                {/* Quantity */}
                {item && (
                     <div className="absolute -top-2 -right-2 bg-slate-700 border border-slate-600 w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-mono z-10 shadow">
                        {item.quantity || 0}
                     </div>
                )}

                {/* Cooldown */}
                {cooldown > 0 && item && (
                     <div className="absolute inset-0 bg-black/60 rounded flex items-center justify-center">
                         <div className="text-[10px] font-bold text-white">{Math.ceil(cooldown)}</div>
                     </div>
                )}
            </div>
            <div className="text-[9px] font-bold mt-1 text-slate-500">{label}</div>
        </div>
    );
};

const ItemIcon = ({ item, size }: { item: Item, size: number }) => {
    if (item.type === 'POTION') return <FlaskConical size={size} />;
    if (item.type === 'CORE') return <Hexagon size={size} />;
    if (item.type === 'ACCESSORY') return <Gem size={size} />;
    if (item.type === 'ARMOR') return <Shield size={size} />;
    if (item.type === 'PET') return <Ghost size={size} />;
    if (item.projectileType === 'MAGIC') return <Wand2 size={size} />;
    if (item.projectileType === 'ARROW') return <Crosshair size={size} />;
    if (item.projectileType === 'AXE') return <Axe size={size} />;
    return <Sword size={size} />;
};

interface ShopItemProps {
    item: Item;
    buyItem: (i: Item, q?: number) => boolean;
    score: number;
}

const ShopItem: React.FC<ShopItemProps> = ({ item, buyItem, score }) => {
    const price1 = item.price;
    const price10 = item.price * 10;

    return (
        <div className="bg-slate-800 p-4 rounded border border-slate-700 flex flex-col gap-2 relative overflow-hidden group">
            <div className="flex justify-between items-start z-10">
                <h3 className={`font-bold ${item.rarity === 'MYTHIC' ? 'text-red-400' : item.rarity === 'EPIC' ? 'text-purple-400' : 'text-slate-200'}`}>{item.name}</h3>
                <ItemIcon item={item} size={16} />
            </div>

            {item.setName && (
                 <div className="text-[10px] text-yellow-500 font-bold uppercase tracking-wider flex items-center gap-1 z-10">
                    <Layers size={10} /> {item.setName}
                 </div>
            )}

            <p className="text-xs text-slate-400 z-10">
                {item.description || Object.entries(item.stats).map(([k,v]) => `+${v} ${k}`).join(', ')}
            </p>

            {item.setName && (
                <p className="text-[10px] text-slate-500 italic z-10 mt-1">Set Bonus: {item.setBonus}</p>
            )}

            <div className="mt-auto pt-2 flex justify-between gap-2 items-center z-10">
                 <button 
                    onClick={() => buyItem(item, 1)}
                    disabled={score < price1}
                    className={`flex-1 py-1 rounded text-xs font-bold flex flex-col items-center ${score >= price1 ? 'bg-blue-600 hover:bg-blue-500 text-white' : 'bg-slate-700 text-slate-500 cursor-not-allowed'}`}
                >
                    <span>BUY 1</span>
                    <span className="font-mono">{price1} G</span>
                </button>
                <button 
                    onClick={() => buyItem(item, 10)}
                    disabled={score < price10}
                    className={`flex-1 py-1 rounded text-xs font-bold flex flex-col items-center border border-slate-600 ${score >= price10 ? 'bg-slate-800 hover:bg-slate-700 text-white' : 'bg-slate-900 text-slate-600 cursor-not-allowed'}`}
                >
                    <span>BUY 10</span>
                    <span className="font-mono text-yellow-500">{price10} G</span>
                </button>
            </div>
        </div>
    );
};

const EquipmentSlot = ({ 
    type, icon, label, item, onClick, onUpgrade, canUpgrade, onHover, textColorClass
}: { 
    type: ItemType, icon?: any, label: string, item: Item | null, onClick: () => void, onUpgrade?: () => void, canUpgrade?: boolean, onHover: (i: Item | null) => void, textColorClass?: string
}) => {
    // Determine icon based on type if not provided, or based on item if equipped
    const renderIcon = () => {
        if (item) return <ItemIcon item={item} size={24} />;
        if (type === 'WEAPON') return <Sword size={24} />;
        if (type === 'ARMOR') return <Shield size={24} />;
        if (type === 'ACCESSORY') return <Gem size={24} />;
        if (type === 'PET') return <Ghost size={24} />;
        return <Sword size={24} />;
    };

    return (
        <div 
            className="w-full flex gap-2"
            onMouseEnter={() => item && onHover(item)}
            onMouseLeave={() => onHover(null)}
        >
            <button onClick={onClick} disabled={!item} className={`flex-1 flex items-center gap-4 p-3 rounded border transition-colors ${item ? 'bg-slate-800 border-slate-600 hover:bg-slate-700' : 'bg-slate-900 border-slate-800 text-slate-600'}`}>
                <div className={`p-2 rounded-full ${item ? 'bg-blue-500/20 text-blue-400' : 'bg-slate-800'}`}>
                    {renderIcon()}
                </div>
                <div className="text-left">
                    <div className="text-xs uppercase font-bold tracking-wider opacity-50">{label}</div>
                    <div className={`font-serif ${item ? textColorClass || 'text-white' : 'text-slate-600'}`}>
                        {item ? `${item.name} ${item.level > 1 ? `+${item.level-1}` : ''}` : 'Empty'}
                    </div>
                </div>
            </button>
            {item && onUpgrade && (
                <button 
                    onClick={(e) => { e.stopPropagation(); onUpgrade(); }}
                    disabled={!canUpgrade}
                    className={`w-12 flex flex-col items-center justify-center border rounded ${canUpgrade ? 'bg-slate-800 border-slate-600 hover:bg-blue-900 hover:border-blue-400' : 'bg-slate-900 border-slate-800 opacity-50'}`}
                >
                    <Hammer size={16} className={canUpgrade ? "text-yellow-400" : "text-slate-600"} />
                    <span className="text-[9px] font-mono text-slate-400 mt-1">{item.level}</span>
                </button>
            )}
        </div>
    );
};

import { create } from 'zustand';
import { GameStatus, PlayerStats, Upgrade, Item, DropData, SkillLevels, Rarity, HeroClass, PassiveSkillState, Obstacle } from './types';
import { Vector3 } from 'three';
import { ITEMS_POOL, HERO_STATS, PETS_POOL, ARENA_SIZE } from './constants';

interface GameState {
  status: GameStatus;
  hero: HeroClass;
  score: number; // Used as GOLD
  gems: number; 
  level: number;
  experience: number;
  experienceToNextLevel: number;
  health: number;
  mana: number;
  playerPosition: Vector3;
  stats: PlayerStats;
  baseStats: PlayerStats;

  // Wave System
  wave: number;
  waveTimer: number; // Seconds elapsed in current wave
  recentRuns: number[]; // Store wave reached in previous runs

  skillLevels: SkillLevels;
  passiveSkillState: PassiveSkillState; // For UI cooldowns

  inventory: Item[];
  equipment: {
    weapon: Item | null;
    armor: Item | null;
    accessory: Item | null;
    pet: Item | null;
  };

  gachaResults: Item[];

  drops: DropData[];
  obstacles: Obstacle[];

  skills: {
    dash: number;
    weaponAbility: number;
  };
  skillMaxCooldowns: {
    dash: number;
    weaponAbility: number;
  };

  potionCooldown: number;
  isInvincible: boolean;

  // UI State
  isInventoryOpen: boolean;
  isShopOpen: boolean;

  setStatus: (status: GameStatus) => void;
  toggleInventory: () => void;
  toggleShop: () => void;
  closeAllUI: () => void;

  selectHero: (hero: HeroClass) => void;
  startGame: () => void;
  addScore: (amount: number) => void;
  addGems: (amount: number) => void;
  addExperience: (amount: number) => void;
  takeDamage: (amount: number) => void;
  useMana: (amount: number) => boolean;
  heal: (amount: number) => void;
  restoreMana: (amount: number) => void;
  setPlayerPosition: (pos: Vector3) => void;
  setInvincible: (invincible: boolean) => void;
  applyUpgrade: (upgrade: Upgrade) => void;
  equipItem: (item: Item) => void;
  unequipItem: (slot: 'weapon' | 'armor' | 'accessory' | 'pet') => void;
  buyItem: (item: Item, quantity?: number) => boolean;
  sellItem: (item: Item) => void;
  sellItems: (items: Item[]) => void;
  performSummon: (amount: 1 | 10) => boolean;
  clearGachaResults: () => void;
  upgradeItem: (item: Item) => { success: boolean, msg: string };
  resetGame: () => void;

  spawnDrop: (position: Vector3, type: 'ITEM' | 'XP' | 'GOLD' | 'GEM', value: number, rarityOverride?: Rarity) => void;
  collectDrop: (id: number) => void;
  triggerSkillCooldown: (skill: 'dash' | 'weaponAbility') => void;
  updatePassiveCooldowns: (state: Partial<PassiveSkillState>) => void;
  tickCooldowns: (delta: number) => void;

  advanceWave: () => void;
}

const INITIAL_STATS: PlayerStats = {
  maxHealth: 100,
  maxMana: 100,
  regen: 1.0, 
  manaRegen: 1.0,
  moveSpeed: 10,
  damage: 15,
  fireRate: 2.0,
  projectileSpeed: 20,
  multishot: 1,
  spread: 0.2,
  dashCooldown: 2.0,
  cooldownReduction: 0,
  magnetRadius: 5.0,
  critRate: 0.05,
  critDamage: 1.5,
  defense: 0,
  skillDamage: 1.0
};

const calculateStats = (base: PlayerStats, equipment: GameState['equipment']) => {
  const final = { ...base };
  const sets: Record<string, number> = {};

  // 1. Apply Equipment Stats (Including Pet)
  Object.values(equipment).forEach(item => {
    if (item) {
        if (item.stats) {
            Object.entries(item.stats).forEach(([key, val]) => {
                const k = key as keyof PlayerStats;
                let v = val as number;

                // NERF: Weapons give 50% less damage stat
                if (item.type === 'WEAPON' && k === 'damage') {
                    v *= 0.5;
                }
                // NERF: Armor gives 50% less defense stat
                if (item.type === 'ARMOR' && k === 'defense') {
                    v *= 0.5;
                }

                if (k === 'moveSpeed' || k === 'fireRate') {
                     // @ts-ignore
                     final[k] += v;
                } else if (k === 'cooldownReduction') {
                     // Additive percentage (capped at some point elsewhere if needed)
                     final[k] = Math.min(0.75, final[k] + v);
                } else {
                     // @ts-ignore
                     final[k] += v;
                }
            });
        }
        if (item.setName) {
            sets[item.setName] = (sets[item.setName] || 0) + 1;
        }
    }
  });

  // 2. Apply Set Bonuses
  Object.entries(sets).forEach(([setName, count]) => {
      if (count >= 3) {
          const setItem = Object.values(equipment).find(i => i?.setName === setName);
          if (setItem && setItem.setBonusStats) {
              Object.entries(setItem.setBonusStats).forEach(([stat, val]) => {
                  if (stat === 'damage' || stat === 'moveSpeed' || stat === 'fireRate') {
                      // Multiplier for these stats in bonus
                      // @ts-ignore
                      final[stat] *= (1 + val);
                  } else {
                      // Additive for others
                      // @ts-ignore
                      final[stat] += val;
                  }
              });
          }
      }
  });

  // 3. Staff Slowdown (50% slower attack speed)
  if (equipment.weapon && equipment.weapon.projectileType === 'MAGIC') {
      final.fireRate *= 0.5;
  }

  // CAP MULTISHOT at 7
  if (final.multishot > 7) final.multishot = 7;

  return final;
};

// Generate Obstacles
const generateObstacles = (): Obstacle[] => {
    const obs: Obstacle[] = [];

    // Trees
    for(let i=0; i<40; i++) {
        const x = (Math.random() - 0.5) * ARENA_SIZE * 1.8;
        const z = (Math.random() - 0.5) * ARENA_SIZE * 1.8;
        if (Math.sqrt(x*x + z*z) > 15) {
            obs.push({
                id: Math.random(),
                position: new Vector3(x, 0, z),
                radius: 1.0, // Collider radius
                type: 'TREE',
                scale: 1 + Math.random() * 2
            });
        }
    }

    // Rocks
    for(let i=0; i<20; i++) {
        const x = (Math.random() - 0.5) * ARENA_SIZE * 1.8;
        const z = (Math.random() - 0.5) * ARENA_SIZE * 1.8;
        if (Math.sqrt(x*x + z*z) > 10) {
            obs.push({
                id: Math.random(),
                position: new Vector3(x, 0, z),
                radius: 1.5,
                type: 'ROCK',
                scale: 0.5 + Math.random()
            });
        }
    }

    // House (Static position)
    obs.push({
        id: 999,
        position: new Vector3(-30, 0, 30),
        radius: 4.5, // Large collider for house
        type: 'HOUSE'
    });

    return obs;
};

export const useGameStore = create<GameState>((set, get) => ({
  status: GameStatus.MENU,
  hero: 'ARCHER',
  score: 10000, // Base Gold
  gems: 10000, // Base Gems
  level: 1,
  experience: 0,
  experienceToNextLevel: 100,
  health: 100,
  mana: 100,
  playerPosition: new Vector3(0, 0, 0),
  stats: { ...INITIAL_STATS },
  baseStats: { ...INITIAL_STATS },

  wave: 1,
  waveTimer: 0,
  recentRuns: [],

  skillLevels: { orbital: 0, thunder: 0, regen: 0, magnet: 0, dash: 0, weapon: 0 },
  passiveSkillState: { orbitalCooldown: 0, orbitalMaxCooldown: 1, thunderCooldown: 0, thunderMaxCooldown: 1 },
  inventory: [],
  equipment: { weapon: null, armor: null, accessory: null, pet: null },
  gachaResults: [],
  drops: [],
  obstacles: generateObstacles(), // Initialize obstacles once
  skills: { dash: 0, weaponAbility: 0 },
  skillMaxCooldowns: { dash: 2.0, weaponAbility: 8.0 },
  potionCooldown: 0,
  isInvincible: false,

  isInventoryOpen: false,
  isShopOpen: false,

  setStatus: (status) => set({ status }),

  toggleInventory: () => {
      const { isInventoryOpen, isShopOpen, status } = get();
      const newState = !isInventoryOpen;

      // Pause if any UI is open
      const willBePaused = newState || isShopOpen;

      set({ 
          isInventoryOpen: newState,
          status: willBePaused ? GameStatus.PAUSED : GameStatus.PLAYING
      });
  },

  toggleShop: () => {
      const { isInventoryOpen, isShopOpen, status } = get();
      const newState = !isShopOpen;

      const willBePaused = isInventoryOpen || newState;

      set({ 
          isShopOpen: newState,
          status: willBePaused ? GameStatus.PAUSED : GameStatus.PLAYING
      });
  },

  closeAllUI: () => set({ isInventoryOpen: false, isShopOpen: false, status: GameStatus.PLAYING }),

  selectHero: (hero) => set({ hero }),

  startGame: () => {
      const state = get();
      const heroStats = HERO_STATS[state.hero];
      const startStats = { ...INITIAL_STATS, ...heroStats.stats };

      const startWeapon = { ...ITEMS_POOL.find(i => i.id === heroStats.weaponId)!, id: 'start_wep', quantity: 1 };

      const equipment = { weapon: startWeapon, armor: null, accessory: null, pet: null };

      set({
        status: GameStatus.PLAYING,
        // Reset Level and XP, keep Gold/Gems
        level: 1,
        experience: 0,
        experienceToNextLevel: 100,
        health: startStats.maxHealth,
        mana: startStats.maxMana,
        baseStats: startStats,
        stats: calculateStats(startStats, equipment),
        skillLevels: { orbital: 0, thunder: 0, regen: 0, magnet: 0, dash: 0, weapon: 0 },
        playerPosition: new Vector3(0, 0, 0),
        // Base Potion Quantity 50
        inventory: [
            { ...ITEMS_POOL.find(i => i.id === 'potion_hp')!, id: 'start_hp', quantity: 50 },
            { ...ITEMS_POOL.find(i => i.id === 'potion_mana')!, id: 'start_mana', quantity: 50 }
        ], 
        equipment: equipment,
        drops: [],
        skills: { dash: 0, weaponAbility: 0 },
        obstacles: generateObstacles(),
        wave: 1,
        waveTimer: 0,
        isInventoryOpen: false,
        isShopOpen: false
      });
  },

  addScore: (amount) => set((state) => ({ score: state.score + amount })),
  addGems: (amount) => set((state) => ({ gems: state.gems + amount })),

  addExperience: (amount) => {
    const adjustedAmount = amount * 2;
    const { experience, experienceToNextLevel, level } = get();
    let newExp = experience + adjustedAmount;

    if (newExp >= experienceToNextLevel) {
      set({
        experience: newExp - experienceToNextLevel,
        experienceToNextLevel: Math.floor(experienceToNextLevel * 1.5),
        level: level + 1,
        status: GameStatus.LEVEL_UP,
      });
    } else {
      set({ experience: newExp });
    }
  },

  takeDamage: (amount) => {
    const { health, status, stats, playerPosition, isInvincible, wave, recentRuns } = get();
    if (status !== GameStatus.PLAYING || isInvincible) return;

    const reductionMultiplier = 100 / (100 + stats.defense);
    const actualDamage = Math.max(1, amount * reductionMultiplier);

    const newHealth = health - actualDamage;

    window.dispatchEvent(new CustomEvent('damage', { 
        detail: { position: playerPosition, damage: actualDamage, isCrit: false, isPlayer: true } 
    }));

    if (newHealth <= 0) {
      set({ 
          health: 0, 
          status: GameStatus.GAME_OVER,
          recentRuns: [wave, ...recentRuns.slice(0, 4)] // Store last 5 runs
      });
    } else {
      set({ health: newHealth });
    }
  },

  useMana: (amount) => {
      const { mana } = get();
      if (mana >= amount) {
          set({ mana: mana - amount });
          return true;
      }
      return false;
  },

  heal: (amount) => set((state) => ({ 
    health: Math.min(state.health + amount, state.stats.maxHealth) 
  })),

  restoreMana: (amount) => set((state) => ({ 
    mana: Math.min(state.mana + amount, state.stats.maxMana) 
  })),

  setPlayerPosition: (pos) => set({ playerPosition: pos }),
  setInvincible: (invincible) => set({ isInvincible: invincible }),

  spawnDrop: (position, type, value, rarityOverride) => set((state) => {
      if (state.drops.length > 99) return { drops: state.drops };

      let item = null;
      // Filter out PETS from spawning as loot
      if (type === 'ITEM') {
          let pool = ITEMS_POOL.filter(i => i.type !== 'PET');

          if (rarityOverride) {
              pool = pool.filter(i => i.rarity === rarityOverride && i.type !== 'POTION' && i.type !== 'CORE');
              if (pool.length === 0) pool = ITEMS_POOL.filter(i => i.type !== 'POTION' && i.type !== 'CORE' && i.type !== 'PET');
          } else {
               const r = Math.random();
               if (r > 0.90) { // 10% Potion
                   pool = pool.filter(i => i.type === 'POTION');
               } else if (r > 0.60) { // 30% Core
                   pool = pool.filter(i => i.type === 'CORE');
               } else { // 60% Gear
                   pool = pool.filter(i => (i.rarity === 'COMMON' || i.rarity === 'RARE') && i.type !== 'POTION' && i.type !== 'CORE');
               }
          }

          if (pool.length > 0) {
              const template = pool[Math.floor(Math.random() * pool.length)];
              item = { ...template, id: Math.random().toString(), stats: { ...template.stats }, onHitEffect: template.onHitEffect }; 
              item.quantity = 1;

              // Random Plus Logic
              if (item.type === 'WEAPON' || item.type === 'ARMOR' || item.type === 'ACCESSORY') {
                   const plusChance = Math.random();
                   let plus = 0;
                   if (plusChance > 0.95) plus = 3;
                   else if (plusChance > 0.85) plus = 2;
                   else if (plusChance > 0.60) plus = 1;

                   if (plus > 0) {
                       item.level += plus;
                       Object.keys(item.stats).forEach((k) => {
                           const key = k as keyof PlayerStats;
                           const v = item.stats[key]!;
                           if (key === 'fireRate' || key === 'moveSpeed' || key === 'critRate' || key === 'cooldownReduction' || key === 'skillDamage') {
                               item.stats[key] = parseFloat((v * (1 + 0.05 * plus)).toFixed(2));
                           } else {
                               item.stats[key] = Math.ceil(v * (1 + 0.1 * plus));
                           }
                       });
                   }
              }
          }
      }

      return {
          drops: [...state.drops, {
              id: Math.random(),
              position: position.clone(),
              type,
              value,
              item,
              active: true,
              rotation: Math.random() * Math.PI
          }]
      };
  }),

  collectDrop: (id) => set((state) => {
      const drop = state.drops.find(d => d.id === id);
      if (!drop) return { drops: state.drops };

      const newDrops = state.drops.filter(d => d.id !== id);

      if (drop.type === 'XP') {
         get().addExperience(drop.value);
      } else if (drop.type === 'GOLD') {
         get().addScore(drop.value);
      } else if (drop.type === 'GEM') {
         get().addGems(drop.value);
      } else if (drop.type === 'ITEM' && drop.item) {
          const existingStack = state.inventory.find(i => i.name === drop.item!.name && (i.type === 'POTION' || i.type === 'CORE'));
          if (existingStack) {
              existingStack.quantity = (existingStack.quantity || 1) + 1;
              return { drops: newDrops, inventory: [...state.inventory] };
          }
          return { drops: newDrops, inventory: [...state.inventory, { ...drop.item }] };
      }

      return { drops: newDrops };
  }),

  triggerSkillCooldown: (skill) => set((state) => {
      const level = skill === 'dash' ? state.skillLevels.dash : state.skillLevels.weapon;
      const reduction = Math.min(0.5, level * 0.1); 
      const cooldown = state.skillMaxCooldowns[skill] * (1 - state.stats.cooldownReduction) * (1 - reduction);

      return {
          skills: { ...state.skills, [skill]: cooldown }
      };
  }),

  updatePassiveCooldowns: (partial) => set((state) => ({
      passiveSkillState: { ...state.passiveSkillState, ...partial }
  })),

  advanceWave: () => set((state) => ({ wave: state.wave + 1, waveTimer: 0 })),

  tickCooldowns: (delta) => {
      const state = get();
      const newSkills = {
          dash: Math.max(0, state.skills.dash - delta),
          weaponAbility: Math.max(0, state.skills.weaponAbility - delta)
      };

      const regenAmount = (state.stats.regen + state.skillLevels.regen) * delta;
      const manaRegenAmount = state.stats.manaRegen * delta;

      const newHealth = Math.min(state.stats.maxHealth, state.health + regenAmount);
      const newMana = Math.min(state.stats.maxMana, state.mana + manaRegenAmount);

      // Auto Potion
      let newPotionCD = Math.max(0, state.potionCooldown - delta);
      let newHealthAfterPot = newHealth;
      let newManaAfterPot = newMana;
      let inventory = state.inventory;

      if (newPotionCD <= 0) {
          const hpThreshold = state.stats.maxHealth * 0.3;
          const manaThreshold = state.stats.maxMana * 0.3;
          let usedPotion = false;

          if (newHealth < hpThreshold) {
              const hpPotIndex = inventory.findIndex(i => i.id.includes('potion_hp'));
              if (hpPotIndex !== -1) {
                  const pot = inventory[hpPotIndex];
                  newHealthAfterPot = Math.min(state.stats.maxHealth, newHealth + (pot.stats.maxHealth || 50));
                  usedPotion = true;
                  if ((pot.quantity || 1) > 1) {
                      pot.quantity = (pot.quantity || 1) - 1;
                      inventory = [...inventory];
                  } else {
                      inventory = inventory.filter((_, idx) => idx !== hpPotIndex);
                  }
              }
          }

          if (!usedPotion && newMana < manaThreshold) {
               const manaPotIndex = inventory.findIndex(i => i.id.includes('potion_mana'));
               if (manaPotIndex !== -1) {
                  const pot = inventory[manaPotIndex];
                  newManaAfterPot = Math.min(state.stats.maxMana, newMana + (pot.stats.maxMana || 50));
                  usedPotion = true;
                   if ((pot.quantity || 1) > 1) {
                      pot.quantity = (pot.quantity || 1) - 1;
                      inventory = [...inventory];
                  } else {
                      inventory = inventory.filter((_, idx) => idx !== manaPotIndex);
                  }
               }
          }

          if (usedPotion) {
              newPotionCD = 5; 
          }
      }

      set({
          skills: newSkills,
          health: newHealthAfterPot,
          mana: newManaAfterPot,
          potionCooldown: newPotionCD,
          inventory: inventory,
          waveTimer: state.waveTimer + delta
      });
  },

  applyUpgrade: (upgrade) => set((state) => {
    const newBase = { ...state.baseStats };
    const newSkillLevels = { ...state.skillLevels };

    switch (upgrade.type) {
      case 'HEALTH': newBase.maxHealth += upgrade.value; break;
      case 'MAX_MANA': newBase.maxMana += upgrade.value; break;
      case 'DEFENSE': newBase.defense += upgrade.value; break;
      case 'SPEED': newBase.moveSpeed *= (1 + upgrade.value); break;
      case 'DAMAGE': newBase.damage *= (1 + upgrade.value); break;
      case 'FIRE_RATE': newBase.fireRate *= (1 + upgrade.value); break;
      case 'MULTISHOT': newBase.multishot += upgrade.value; break;
      case 'DASH_COOLDOWN': newBase.dashCooldown *= (1 - upgrade.value); break;
      case 'SKILL_MAGNET': newBase.magnetRadius += upgrade.value; break;
      case 'CRIT_RATE': newBase.critRate += upgrade.value; break;
      case 'CRIT_DAMAGE': newBase.critDamage += upgrade.value; break;
      case 'SKILL_ORBITAL': newSkillLevels.orbital++; break;
      case 'SKILL_THUNDER': newSkillLevels.thunder++; break;
      case 'SKILL_REGEN': newSkillLevels.regen += upgrade.value; break;
      case 'SKILL_MAGNET': newSkillLevels.magnet += upgrade.value; break;
      case 'SKILL_DASH': newSkillLevels.dash++; break;
      case 'SKILL_WEAPON': newSkillLevels.weapon++; break;
    }
    const newStats = calculateStats(newBase, state.equipment);
    return { 
        baseStats: newBase,
        stats: newStats, 
        skillLevels: newSkillLevels,
        health: upgrade.type === 'HEALTH' ? Math.min(state.health + 30, newStats.maxHealth) : state.health,
        mana: upgrade.type === 'MAX_MANA' ? Math.min(state.mana + 20, newStats.maxMana) : state.mana,
        status: GameStatus.PLAYING,
        skillMaxCooldowns: {
            ...state.skillMaxCooldowns,
            dash: upgrade.type === 'DASH_COOLDOWN' ? state.skillMaxCooldowns.dash * (1 - upgrade.value) : state.skillMaxCooldowns.dash
        }
    };
  }),

  equipItem: (item) => set((state) => {
    if (item.type === 'POTION' || item.type === 'CORE') return state;

    let reqLevel = 1;
    if (item.rarity === 'RARE') reqLevel = 10;
    if (item.rarity === 'EPIC') reqLevel = 20;
    if (item.rarity === 'LEGENDARY') reqLevel = 30;
    if (item.rarity === 'MYTHIC') reqLevel = 40;

    if (state.level < reqLevel) return state; 

    const slot = item.type.toLowerCase() as keyof GameState['equipment'];
    const oldItem = state.equipment[slot];
    const newEquipment = { ...state.equipment, [slot]: item };
    const newStats = calculateStats(state.baseStats, newEquipment);
    let newInv = state.inventory.filter(i => i !== item);
    if (oldItem) newInv.push(oldItem);
    return { equipment: newEquipment, stats: newStats, inventory: newInv };
  }),

  unequipItem: (slot) => set((state) => {
    const item = state.equipment[slot];
    if (!item) return state;
    const newEquipment = { ...state.equipment, [slot]: null };
    const newStats = calculateStats(state.baseStats, newEquipment);
    return { equipment: newEquipment, stats: newStats, inventory: [...state.inventory, item] };
  }),

  buyItem: (item, quantity = 1) => {
      const state = get();
      const totalCost = item.price * quantity;
      if (state.score >= totalCost) {
          const existing = state.inventory.find(i => i.name === item.name && (item.type === 'POTION' || item.type === 'CORE'));
          let newInv = [...state.inventory];
          if (existing) {
              existing.quantity = (existing.quantity || 1) + quantity;
          } else {
              if (item.type === 'POTION' || item.type === 'CORE') {
                  newInv.push({ ...item, quantity: quantity, id: Math.random().toString() });
              } else {
                  for(let i=0; i<quantity; i++) {
                       newInv.push({ ...item, quantity: 1, id: Math.random().toString(), stats: { ...item.stats } });
                  }
              }
          }
          set({ score: state.score - totalCost, inventory: newInv });
          return true;
      }
      return false;
  },

  sellItem: (item) => set((state) => {
      let newInv = state.inventory.filter(i => i !== item);
      const sellValue = Math.floor(item.price * 0.4);
      return { inventory: newInv, score: state.score + sellValue };
  }),

  sellItems: (items) => set((state) => {
      const idsToSell = new Set(items.map(i => i.id));
      let sellValueTotal = 0;
      const newInv = state.inventory.filter(i => {
          if (idsToSell.has(i.id)) {
              sellValueTotal += Math.floor(i.price * 0.4);
              return false;
          }
          return true;
      });
      return { inventory: newInv, score: state.score + sellValueTotal };
  }),

  performSummon: (amount) => {
    const state = get();
    const COST = amount === 1 ? 100 : 900; 

    if (state.gems < COST) return false;

    const combinedPool = [...ITEMS_POOL.filter(i => i.type !== 'POTION' && i.type !== 'CORE'), ...PETS_POOL];
    const results: Item[] = [];

    for(let i=0; i<amount; i++) {
        const roll = Math.random();
        let rarity: Rarity = 'COMMON';

        if (roll > 0.99) rarity = 'MYTHIC';
        else if (roll > 0.95) rarity = 'LEGENDARY';
        else if (roll > 0.80) rarity = 'EPIC';
        else if (roll > 0.50) rarity = 'RARE';

        let validItems = combinedPool.filter(item => item.rarity === rarity);
        if (validItems.length === 0) validItems = combinedPool.filter(item => item.rarity === 'COMMON'); 

        const template = validItems[Math.floor(Math.random() * validItems.length)];
        const newItem = { 
            ...template, 
            id: Math.random().toString(), 
            quantity: 1, 
            stats: { ...template.stats },
            onHitEffect: template.onHitEffect
        };

        const plusChance = Math.random();
        let plus = 0;
        if (plusChance > 0.90) plus = 1;
        if (plusChance > 0.98) plus = 2;
        if (plus > 0) {
            newItem.level += plus;
             Object.keys(newItem.stats).forEach((k) => {
                   const key = k as keyof PlayerStats;
                   const v = newItem.stats[key]!;
                   if (key === 'fireRate' || key === 'moveSpeed' || key === 'critRate' || key === 'cooldownReduction' || key === 'skillDamage') {
                       newItem.stats[key] = parseFloat((v * (1 + 0.05 * plus)).toFixed(2));
                   } else {
                       newItem.stats[key] = Math.ceil(v * (1 + 0.1 * plus));
                   }
             });
        }

        results.push(newItem);
    }

    set({ 
        gems: state.gems - COST, 
        gachaResults: results,
        inventory: [...state.inventory, ...results],
        status: GameStatus.GACHA_REVEAL,
        isInventoryOpen: false,
        isShopOpen: false
    });
    return true;
  },

  clearGachaResults: () => set({ gachaResults: [], status: GameStatus.PLAYING, isShopOpen: true }),

  gachaSummon: () => null,

  upgradeItem: (item) => {
      const state = get();
      const core = state.inventory.find(i => i.type === 'CORE');
      const coreIndex = state.inventory.findIndex(i => i.type === 'CORE');

      const requiredCores = Math.ceil(item.level / 2);
      const goldCost = Math.floor(item.price * item.level * 0.5);

      if (state.score < goldCost) return { success: false, msg: "Not enough Gold" };
      if (!core || (core.quantity || 1) < requiredCores) return { success: false, msg: `Need ${requiredCores} Cores` };

      // Success Chance
      const chance = Math.max(10, 100 - (item.level * 10));
      const roll = Math.random() * 100;
      const success = roll < chance;

      const newInventory = [...state.inventory];
      const coreItem = newInventory[coreIndex];
      if ((coreItem.quantity || 1) > requiredCores) {
          coreItem.quantity = (coreItem.quantity || 1) - requiredCores;
      } else {
          newInventory.splice(coreIndex, 1);
      }

      set({ score: state.score - goldCost, inventory: newInventory });

      if (success) {
           const upgradeLogic = (i: Item) => {
              if (i === item) {
                  const updatedStats = { ...i.stats };
                  Object.keys(updatedStats).forEach(k => {
                      const key = k as keyof PlayerStats;
                      const val = updatedStats[key]!;
                      if (key === 'fireRate' || key === 'moveSpeed' || key === 'critRate' || key === 'cooldownReduction' || key === 'skillDamage') {
                          updatedStats[key] = parseFloat((val * 1.05).toFixed(2));
                      } else {
                          updatedStats[key] = Math.ceil(val * 1.1);
                      }
                  });
                  return {
                      ...i,
                      level: i.level + 1,
                      stats: updatedStats
                  };
              }
              return i;
          };

          const updatedInventory = get().inventory.map(upgradeLogic);
          const updatedEquipment = {
              weapon: state.equipment.weapon ? upgradeLogic(state.equipment.weapon) : null,
              armor: state.equipment.armor ? upgradeLogic(state.equipment.armor) : null,
              accessory: state.equipment.accessory ? upgradeLogic(state.equipment.accessory) : null,
              pet: state.equipment.pet ? upgradeLogic(state.equipment.pet) : null,
          };
          const newStats = calculateStats(state.baseStats, updatedEquipment);

          set({ inventory: updatedInventory, equipment: updatedEquipment, stats: newStats });
          return { success: true, msg: "Upgrade Successful!" };
      } else {
          return { success: false, msg: "Upgrade Failed..." };
      }
  },

  resetGame: () => set({
    status: GameStatus.MENU,
  }),
}));

