                 <div className="bg-slate-900/80 px-4 py-2 rounded-md border-t-2 border-emerald-500 backdrop-blur-sm flex items-center gap-2 shadow-lg">
                    <Gem size={20} className="text-emerald-400" />
                    <div className="text-2xl font-mono text-emerald-400">{gems.toLocaleString()}</div>
                 </div>
                 <div className="bg-slate-900/80 px-4 py-2 rounded-md border-t-2 border-yellow-500 backdrop-blur-sm flex items-center gap-2 shadow-lg">
                    <Coins size={20} className="text-yellow-400" />
                    <div className="text-2xl font-mono text-yellow-400">{score.toLocaleString()}</div>
