                {/* HP Potion */}
                <PotionSlot 
                    icon={<Heart size={20} className="text-red-500" />} 
                    item={hpPotion} 
                    cooldown={potionCooldown} 
                    label="HP"
                />

                {/* Active: Weapon */}
                <ActiveSkillSlot 
                    icon={equipment.weapon?.ability === 'FIREBALL' ? <Flame size={28} className="text-orange-500"/> :
                         equipment.weapon?.ability === 'AXE_SPIN' ? <RotateCcw size={28} className="text-red-500"/> :
                         <Zap size={28} className={skills.weaponAbility > 0 ? 'text-slate-500' : 'text-purple-400'} />}
                    level={skillLevels.weapon}
                    cooldown={skills.weaponAbility}
                    label="R / Click"
                    desc={`Weapon Special. Mana Cost: 30`}
                    borderColor={skills.weaponAbility > 0 ? 'border-slate-600' : 'border-purple-400 shadow-[0_0_15px_rgba(168,85,247,0.5)]'}
                />

                {/* Active: Dash */}
                <ActiveSkillSlot 
                    icon={<Wind size={28} className={skills.dash > 0 ? 'text-slate-500' : 'text-green-400'} />}
                    level={skillLevels.dash}
                    cooldown={skills.dash}
                    label="SPACE"
                    desc="Dash. Invincible for 0.2s. Mana Cost: 2"
                    borderColor={skills.dash > 0 ? 'border-slate-600' : 'border-green-400 shadow-[0_0_15px_rgba(74,222,128,0.5)]'}
                />

                {/* Passives - Large Size, Hidden if 0 */}
                <SkillIcon icon={<Zap size={28} className="text-yellow-400"/>} level={skillLevels.thunder} cd={passiveSkillState.thunderCooldown} maxCd={passiveSkillState.thunderMaxCooldown} desc="Thundercaller: Strikes nearby enemies with lightning. Mana Cost: 2" />
                <SkillIcon icon={<Activity size={28} className="text-blue-400"/>} level={skillLevels.orbital} cd={passiveSkillState.orbitalCooldown} maxCd={passiveSkillState.orbitalMaxCooldown} desc="Orbital Blades: Summons rotating blades. Mana Cost: 7" />
                <SkillIcon icon={<Heart size={28} className="text-green-400"/>} level={skillLevels.regen} desc={`Regeneration: Heals ${skillLevels.regen * 2} HP/sec.`} />
                <SkillIcon icon={<Magnet size={28} className="text-purple-400"/>} level={skillLevels.magnet} desc="Magnet: Increases item pickup range." />

                {/* Mana Potion */}
                <PotionSlot 
                    icon={<FlaskConical size={20} className="text-blue-400" />} 
                    item={manaPotion} 
                    cooldown={potionCooldown} 
                    label="MP"
                />

             </div>

             {/* Status Bars */}
             <div className="flex flex-col gap-1 w-full">
                 <div className="relative h-6 bg-slate-900 rounded border border-slate-700 overflow-hidden shadow-lg">
                    <div className="absolute top-0 left-0 h-full bg-gradient-to-r from-red-700 to-red-500 transition-all duration-300" style={{ width: `${hpPercent}%` }} />
                    <div className="absolute inset-0 flex items-center justify-center text-xs font-bold drop-shadow-[0_1px_2px_rgba(0,0,0,0.8)] z-10 tracking-wider">
                        {Math.ceil(health)} / {stats.maxHealth} HP
                    </div>
                 </div>
                 <div className="relative h-6 bg-slate-900 rounded border border-slate-700 overflow-hidden shadow-lg">
                    <div className="absolute top-0 left-0 h-full bg-gradient-to-r from-blue-700 to-blue-500 transition-all duration-300" style={{ width: `${manaPercent}%` }} />
                    <div className="absolute inset-0 flex items-center justify-center text-xs font-bold drop-shadow-[0_1px_2px_rgba(0,0,0,0.8)] z-10 tracking-wider">
                        {Math.ceil(mana)} / {stats.maxMana} MP
                    </div>
                 </div>
                 <div className="relative h-2 bg-slate-900 rounded-full border border-slate-700 overflow-hidden mt-1">
                    <div className="absolute top-0 left-0 h-full bg-gradient-to-r from-yellow-600 to-yellow-400 transition-all duration-300" style={{ width: `${xpPercent}%` }} />
                 </div>
             </div>

             <div className="flex justify-center mt-2 pointer-events-auto gap-4">
                <button 
                    onClick={toggleInventory} 
                    className={`flex items-center gap-2 px-4 py-2 border rounded-md transition-all text-sm font-bold shadow-lg ${isInventoryOpen ? 'bg-blue-600 border-blue-400 text-white' : 'bg-slate-800 border-slate-600 hover:bg-slate-700 text-slate-300'}`}
