                <button 
                    onClick={toggleShop} 
                    className={`flex items-center gap-2 px-4 py-2 border rounded-md transition-all text-sm font-bold shadow-lg ${isShopOpen ? 'bg-blue-600 border-blue-400 text-white' : 'bg-slate-800 border-slate-600 hover:bg-slate-700 text-slate-300'}`}
                >
                    <ShoppingBag size={16} /> SHOP
                </button>
             </div>
          </div>
        </div>
      )}

      {/* Overlays */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
        <AnimatePresence>

