                  {recentRuns.length > 0 && (
                      <div className="bg-slate-800/50 p-4 rounded-lg w-full max-w-lg border border-slate-700">
                          <div className="text-slate-400 font-bold mb-2 text-center text-sm uppercase tracking-widest">Recent Expeditions</div>
                          <div className="flex justify-center gap-4">
                              {recentRuns.map((w, i) => (
                                  <div key={i} className="flex flex-col items-center">
                                      <div className="text-2xl font-serif text-purple-300">Wave {w}</div>
