                    <div className="flex flex-wrap justify-center gap-4 max-w-5xl overflow-y-auto p-4">
                        {gachaResults.map((item, idx) => (
                            <motion.div 
                                key={idx}
                                initial={{ scale: 0, rotateY: 180 }}
                                animate={{ scale: 1, rotateY: 0 }}
                                transition={{ delay: idx * 0.1, type: 'spring' }}
                                className={`w-40 h-56 bg-slate-800 rounded-xl border-2 flex flex-col items-center p-4 gap-2 shadow-2xl relative overflow-hidden ${
                                    item.rarity === 'MYTHIC' ? 'border-red-500 shadow-red-500/50' :
                                    item.rarity === 'LEGENDARY' ? 'border-yellow-400 shadow-yellow-400/50' :
                                    item.rarity === 'EPIC' ? 'border-purple-500 shadow-purple-500/50' :
                                    item.rarity === 'RARE' ? 'border-blue-400' : 'border-slate-600'
                                }`}
                            >
                                {/* Glow Effect for high tier */}
                                {(item.rarity === 'LEGENDARY' || item.rarity === 'MYTHIC') && (
                                    <div className="absolute inset-0 bg-gradient-to-t from-yellow-500/20 to-transparent animate-pulse" />
