                                <div className={`p-3 rounded-full bg-slate-900 border border-slate-700 mt-2`}>
                                     <ItemIcon item={item} size={32} />
                                </div>
                                <div className={`text-center font-bold text-sm leading-tight mt-2 ${getRarityTextColor(item.rarity)}`}>
                                    {item.name}
                                </div>
                                {item.level > 1 && <div className="text-xs text-yellow-500 font-bold">+{item.level-1}</div>}
                                {item.type === 'PET' && <div className="mt-auto mb-2 text-[10px] bg-slate-700 px-2 py-1 rounded text-white">PET</div>}
                            </motion.div>
                        ))}
                    </div>

                    <button 
                        onClick={clearGachaResults}
                        className="mt-auto px-8 py-3 bg-slate-800 hover:bg-slate-700 border border-slate-600 rounded text-lg font-bold"
                    >
                        CONTINUE
                    </button>
                </div>
             </div>
           )}

          {/* INVENTORY SCREEN - Left Side */}
          {isInventoryOpen && (
            <motion.div 
                initial={{ x: '-100%' }} animate={{ x: 0 }} exit={{ x: '-100%' }}
                className="absolute left-0 top-0 bottom-0 w-[500px] bg-slate-900/95 border-r border-slate-700 p-6 shadow-2xl flex flex-col gap-6 pointer-events-auto z-40 backdrop-blur-md"
            >
                <div className="flex justify-between items-center border-b border-slate-700 pb-4">
                    <h2 className="text-2xl font-serif text-slate-200">INVENTORY</h2>
                     <button onClick={toggleInventory} className="p-2 hover:bg-slate-800 rounded-full"><X size={24}/></button>
                </div>

                <div className="flex flex-col gap-6 h-full overflow-hidden">
                    {/* Character Equipment Panel */}
                    <div className="flex flex-col gap-4 items-center bg-slate-950/50 p-4 rounded-lg">
