                        <div className="grid grid-cols-2 gap-4 w-full">
                            <EquipmentSlot 
                                type="WEAPON"
                                label="Weapon" 
                                item={equipment.weapon} 
                                onClick={() => unequipItem('weapon')}
                                onUpgrade={() => equipment.weapon && upgradeItem(equipment.weapon)}
                                canUpgrade={!!equipment.weapon}
                                onHover={setHoveredItem}
                                textColorClass={getRarityTextColor(equipment.weapon?.rarity)}
                            />
                            <EquipmentSlot 
                                type="ARMOR"
                                label="Armor" 
                                item={equipment.armor} 
                                onClick={() => unequipItem('armor')} 
                                onUpgrade={() => equipment.armor && upgradeItem(equipment.armor)}
                                canUpgrade={!!equipment.armor}
                                onHover={setHoveredItem}
                                textColorClass={getRarityTextColor(equipment.armor?.rarity)}
                            />
                            <EquipmentSlot 
                                type="ACCESSORY"
                                label="Accessory" 
                                item={equipment.accessory} 
                                onClick={() => unequipItem('accessory')} 
                                onUpgrade={() => equipment.accessory && upgradeItem(equipment.accessory)}
                                canUpgrade={!!equipment.accessory}
                                onHover={setHoveredItem}
                                textColorClass={getRarityTextColor(equipment.accessory?.rarity)}
                            />
                            <EquipmentSlot 
                                type="PET"
                                label="Pet" 
                                item={equipment.pet} 
                                onClick={() => unequipItem('pet')} 
                                onUpgrade={() => equipment.pet && upgradeItem(equipment.pet)}
                                canUpgrade={!!equipment.pet}
                                onHover={setHoveredItem}
                                textColorClass={getRarityTextColor(equipment.pet?.rarity)}
                            />
                        </div>

                        {/* Stats Summary */}
                        <div className="w-full grid grid-cols-3 gap-2 text-[10px] text-slate-500 pt-4 border-t border-slate-800">
                            <div className="flex flex-col"><span className="font-bold text-slate-400">DMG</span> <span className="text-white text-base">{Math.round(stats.damage)}</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">DEF</span> <span className="text-blue-400 text-base">{Math.round(stats.defense)}</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">REGEN</span> <span className="text-green-400 text-base">{stats.regen.toFixed(1)}/s</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">MANA REG</span> <span className="text-blue-400 text-base">{stats.manaRegen.toFixed(1)}/s</span></div>
