                                            <div className="absolute top-1 right-1 bg-red-500 rounded-full text-white p-0.5">
                                                <CheckCircle2 size={12} />
                                            </div>
                                        )}
                                    </button>

                                    {/* Action Buttons Overlay - Moved to bottom */}
