const SkillTooltipWrapper = ({ children, desc }: { children?: React.ReactNode, desc?: string }) => {
    const [show, setShow] = useState(false);
    return (
        <div className="relative flex flex-col items-center" onMouseEnter={() => setShow(true)} onMouseLeave={() => setShow(false)}>
            {children}
            {show && desc && (
                <div className="absolute bottom-full mb-2 w-48 bg-slate-900 border border-slate-600 p-2 rounded text-xs text-slate-200 z-50 shadow-xl pointer-events-none">
                    {desc}
                </div>
            )}
        </div>
    )
}

const ActiveSkillSlot = ({ icon, level, cooldown, label, desc, borderColor }: any) => {
    return (
        <SkillTooltipWrapper desc={desc}>
             <div className="relative flex flex-col items-center">
                    <div className={`w-14 h-14 rounded border-2 flex items-center justify-center bg-slate-900 ${borderColor}`}>
                        {icon}
                        <div className="absolute -top-2 -right-2 bg-slate-800 border border-slate-600 w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold">
                            {level || 0}
                        </div>
                        {cooldown > 0 && (
                            <div className="absolute inset-0 bg-black/60 flex items-center justify-center font-bold text-lg">
                                {Math.ceil(cooldown)}
                            </div>
                        )}
                    </div>
                    <div className="text-[10px] font-bold mt-1 bg-black/50 px-2 rounded">{label}</div>
            </div>
        </SkillTooltipWrapper>
    )
}

const SkillIcon = ({ icon, level, cd, maxCd, desc }: { icon: any, level: number, cd?: number, maxCd?: number, desc?: string }) => {
    if (level <= 0) return null;
    return (
        <SkillTooltipWrapper desc={desc}>
            <div className="relative flex flex-col items-center">
                <div className="w-14 h-14 rounded border-2 flex items-center justify-center bg-slate-900 border-slate-600 shadow-md">
                    {icon}
                    <div className="absolute -top-2 -right-2 bg-slate-800 border border-slate-600 w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold z-10">
                        {level}
                    </div>
                    {cd !== undefined && maxCd !== undefined && cd > 0 && (
                        <div className="absolute inset-0 bg-black/60 flex items-center justify-center font-bold text-lg rounded overflow-hidden">
                            <div className="text-white">{Math.ceil(cd)}</div>
                        </div>
                    )}
                </div>
                <div className="text-[10px] font-bold mt-1 bg-black/50 px-2 rounded opacity-50">PASSIVE</div>
            </div>
        </SkillTooltipWrapper>
    )
}

const PotionSlot = ({ icon, item, cooldown, label }: { icon: any, item: Item | undefined, cooldown: number, label: string }) => {
    return (
        <div className="relative flex flex-col items-center">
            <div className={`w-10 h-10 rounded border flex items-center justify-center ${item ? 'bg-slate-800 border-slate-600' : 'bg-slate-900 border-slate-800 opacity-50'}`}>
                {icon}
                {item && (
                     <div className="absolute -top-2 -right-2 bg-slate-700 border border-slate-600 w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-mono z-10 shadow">
                        {item.quantity || 0}
                     </div>
                )}
                {cooldown > 0 && item && (
                     <div className="absolute inset-0 bg-black/60 flex items-center justify-center font-bold text-lg rounded overflow-hidden">
                        <div className="text-white">{Math.ceil(cooldown)}</div>
                     </div>
