                                            isMassSellMode && isSelected ? 'border-red-500 bg-red-900/20' : 
                                            isMassSellMode && !isConsumable ? 'border-slate-600 opacity-80 hover:opacity-100' :
                                            getRarityColor(item.rarity)
                                        } ${!canEquip && !isConsumable && !isMassSellMode ? 'opacity-50 cursor-not-allowed grayscale' : 'hover:scale-105'}`}
