                                                    <div className={`mt-2 text-xs font-bold ${level >= reqLevel ? 'text-green-400' : 'text-red-500'}`}>
                                                        Requires Level {reqLevel}
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    )}
                                </div>
                            )})}
