                        <div className="grid grid-cols-2 gap-4 w-full">
                            <EquipmentSlot 
                                type="WEAPON"
                                label="Weapon" 
                                item={equipment.weapon} 
                                onClick={() => unequipItem('weapon')}
                                onUpgrade={() => equipment.weapon && upgradeItem(equipment.weapon)}
                                canUpgrade={!!equipment.weapon}
                                onHover={setHoveredItem}
                                textColorClass={getRarityTextColor(equipment.weapon?.rarity)}
                            />
                            <EquipmentSlot 
                                type="ARMOR"
                                label="Armor" 
                                item={equipment.armor} 
                                onClick={() => unequipItem('armor')} 
                                onUpgrade={() => equipment.armor && upgradeItem(equipment.armor)}
                                canUpgrade={!!equipment.armor}
                                onHover={setHoveredItem}
                                textColorClass={getRarityTextColor(equipment.armor?.rarity)}
                            />
                            <EquipmentSlot 
                                type="ACCESSORY"
                                label="Accessory" 
                                item={equipment.accessory} 
                                onClick={() => unequipItem('accessory')} 
                                onUpgrade={() => equipment.accessory && upgradeItem(equipment.accessory)}
                                canUpgrade={!!equipment.accessory}
                                onHover={setHoveredItem}
                                textColorClass={getRarityTextColor(equipment.accessory?.rarity)}
                            />
                            <EquipmentSlot 
                                type="PET"
                                label="Pet" 
                                item={equipment.pet} 
                                onClick={() => unequipItem('pet')} 
                                onUpgrade={() => equipment.pet && upgradeItem(equipment.pet)}
                                canUpgrade={!!equipment.pet}
                                onHover={setHoveredItem}
                                textColorClass={getRarityTextColor(equipment.pet?.rarity)}
                            />
                        </div>

                        {/* Stats Summary */}
                        <div className="w-full grid grid-cols-3 gap-2 text-[10px] text-slate-500 pt-4 border-t border-slate-800">
                            <div className="flex flex-col"><span className="font-bold text-slate-400">DMG</span> <span className="text-white text-base">{Math.round(stats.damage)}</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">DEF</span> <span className="text-blue-400 text-base">{Math.round(stats.defense)}</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">REGEN</span> <span className="text-green-400 text-base">{stats.regen.toFixed(1)}/s</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">MANA REG</span> <span className="text-blue-400 text-base">{stats.manaRegen.toFixed(1)}/s</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">CRIT</span> <span className="text-yellow-400 text-base">{(stats.critRate * 100).toFixed(0)}%</span></div>
                            <div className="flex flex-col"><span className="font-bold text-slate-400">CDR</span> <span className="text-purple-400 text-base">{(stats.cooldownReduction * 100).toFixed(0)}%</span></div>
                        </div>
                    </div>

                    {/* Inventory Grid */}
                    <div className="flex-1 bg-slate-950/30 p-4 rounded-lg flex flex-col overflow-hidden relative">
                        <div className="w-full text-slate-400 mb-2 text-xs font-bold uppercase tracking-widest flex justify-between items-center h-8">
                            <span>Backpack</span>
                            {/* Mass Sell Toggle */}
                            <button 
                                onClick={toggleMassSell}
                                className={`text-[10px] font-bold px-2 py-1 rounded flex items-center gap-1 ${isMassSellMode ? 'bg-red-900 text-red-200 border border-red-500' : 'bg-slate-800 text-slate-400 border border-slate-600 hover:bg-slate-700'}`}
                            >
                                <Trash2 size={12} /> {isMassSellMode ? 'CANCEL' : 'MASS SELL'}
                            </button>
                        </div>

                        <div className="grid grid-cols-5 gap-2 overflow-y-auto pr-2 pb-12 custom-scrollbar">
                            {inventory.map((item, idx) => {
                                const isConsumable = item.type === 'POTION' || item.type === 'CORE';
                                const reqLevel = getLevelRequirement(item.rarity);
                                const canEquip = level >= reqLevel;
                                const isSelected = selectedItems.has(item.id);

                                return (
                                <div 
                                    key={idx} 
                                    className="relative group w-full aspect-square"
                                    onMouseEnter={() => setHoveredItem(item)}
                                    onMouseLeave={() => setHoveredItem(null)}
                                >
                                    <button 
                                        onClick={() => onInventoryItemClick(item, isConsumable, canEquip)}
                                        onContextMenu={(e) => { e.preventDefault(); !isMassSellMode && !isConsumable && canEquip && equipItem(item); }}
                                        className={`w-full h-full bg-slate-800 border-2 rounded flex flex-col items-center justify-center p-1 transition-transform relative ${
                                            isMassSellMode && isSelected ? 'border-red-500 bg-red-900/20' : 
                                            isMassSellMode && !isConsumable ? 'border-slate-600 opacity-80 hover:opacity-100' :
                                            getRarityColor(item.rarity)
                                        } ${!canEquip && !isConsumable && !isMassSellMode ? 'opacity-50 cursor-not-allowed grayscale' : 'hover:scale-105'}`}
                                    >
                                        <ItemIcon item={item} size={20} />

                                        {isConsumable && <div className="absolute top-0 right-0 bg-black/60 text-[10px] px-1 rounded-bl text-white font-mono">{item.quantity}</div>}
                                        {item.level > 1 && <div className="text-[10px] mt-1 text-yellow-400 font-bold">+{item.level - 1}</div>}

                                        {/* Level Lock Icon */}
                                        {!isConsumable && !canEquip && !isMassSellMode && (
                                            <div className="absolute inset-0 flex items-center justify-center bg-black/40 text-red-500 font-bold text-xs drop-shadow-md">
                                                Lv.{reqLevel}
                                            </div>
                                        )}

                                        {/* Selection Checkmark */}
                                        {isMassSellMode && isSelected && (
                                            <div className="absolute top-1 right-1 bg-red-500 rounded-full text-white p-0.5">
                                                <CheckCircle2 size={12} />
                                            </div>
                                        )}
                                    </button>

                                    {/* Action Buttons Overlay - Moved to bottom */}
                                    {!isMassSellMode && (
                                        <div className="absolute bottom-0 left-0 w-full flex justify-center gap-1 pb-1 z-10 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
                                            <div className="pointer-events-auto flex gap-1 bg-black/60 rounded-full px-1.5 py-0.5">
                                                {!isConsumable && (
                                                    <button 
                                                        onClick={(e) => { e.stopPropagation(); upgradeItem(item); }}
                                                        className="hover:text-yellow-400 text-slate-300"
                                                        title="Upgrade"
                                                    >
                                                        <Hammer size={12} />
                                                    </button>
                                                )}
                                                <button 
                                                    onClick={(e) => { e.stopPropagation(); sellItem(item); }}
                                                    className="hover:text-green-400 text-slate-300"
                                                    title="Sell"
                                                >
                                                    <CircleDollarSign size={12} />
                                                </button>
                                            </div>
                                        </div>
                                    )}

                                    {/* TOOLTIP - Enabled even in Mass Sell Mode as per request (removed !isMassSellMode check) */}
                                    {hoveredItem === item && (
                                        <div className={`fixed z-50 pointer-events-none p-4 rounded bg-slate-900 border border-slate-600 shadow-2xl w-64 text-left top-1/2 -translate-y-1/2 left-[520px]`}>
                                            <div className={`${getRarityColor(item.rarity)} border-b pb-2 mb-2 font-bold flex justify-between`}>
                                                <span>{item.name} {item.level > 1 && `+${item.level-1}`}</span>
                                            </div>
                                            <div className="text-sm text-slate-300">
                                                {/* Iterate stats */}
                                                {Object.entries(item.stats).map(([key, val]) => (
                                                    <div key={key}>+{val} {key}</div>
                                                ))}
                                                {item.ability && <div className="text-purple-400 italic text-xs mt-1">{item.description}</div>}
                                                {item.setName && (
                                                    <div className="mt-2 text-xs">
                                                        <div className="text-yellow-500 font-bold">{item.setName}</div>
                                                        <div className="text-slate-400">{item.setBonus}</div>
                                                        <div className="text-slate-500 italic">(3 pieces required)</div>
                                                    </div>
                                                )}
                                                {item.description && !item.ability && <div className="text-slate-500 italic text-xs mt-1">{item.description}</div>}

                                                {/* Equip Requirement */}
                                                {!isConsumable && (
                                                    <div className={`mt-2 text-xs font-bold ${level >= reqLevel ? 'text-green-400' : 'text-red-500'}`}>
                                                        Requires Level {reqLevel}
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    )}
                                </div>
                            )})}
                            {[...Array(Math.max(0, 30 - inventory.length))].map((_, i) => (
                                <div key={`empty-${i}`} className="aspect-square bg-slate-900/50 border border-slate-800 rounded" />
                            ))}
                        </div>

                        {/* Mass Sell Confirm Button */}
                        {isMassSellMode && selectedItems.size > 0 && (
                            <div className="absolute bottom-4 left-0 w-full flex justify-center px-4">
                                <button 
                                    onClick={executeMassSell}
                                    className="w-full bg-red-600 hover:bg-red-500 text-white font-bold py-2 rounded shadow-lg flex items-center justify-center gap-2 animate-bounce"
                                >
                                    <Trash2 size={16} /> SELL SELECTED ({selectedItems.size})
                                </button>
                            </div>
                        )}
                    </div>
                </div>
            </motion.div>
          )}

          {/* ... (Level Up and Game Over Overlays remain unchanged) */}
          {status === GameStatus.LEVEL_UP && (
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center pointer-events-auto z-50">
                <motion.div 
                    initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}
                    className="flex flex-col items-center gap-8"
                >
                    <h2 className="text-4xl font-serif text-yellow-400 drop-shadow-lg">LEVEL UP!</h2>
                    <div className="flex flex-wrap justify-center gap-6">
                        {availableUpgrades.map((upgrade, idx) => (
                            <motion.button 
                                key={idx}
                                initial={{ y: 50, opacity: 0 }}
                                animate={{ y: 0, opacity: 1 }}
                                transition={{ delay: idx * 0.1 }}
                                onClick={() => applyUpgrade(upgrade)}
                                className="relative w-64 aspect-[3/4] bg-slate-800 rounded-xl border-2 border-slate-600 hover:border-yellow-400 hover:scale-105 transition-all shadow-xl overflow-hidden flex flex-col p-6 text-center items-center justify-between group"
                            >
                                <div className="absolute inset-0 bg-gradient-to-b from-slate-700/50 to-slate-900/50 z-0" />
                                <div className="relative z-10 flex flex-col items-center gap-4">
                                    <div className={`p-4 rounded-full ${upgrade.rarity === 'LEGENDARY' ? 'bg-orange-500' : upgrade.rarity === 'RARE' ? 'bg-blue-500' : 'bg-slate-500'} text-white shadow-lg`}>
                                        <Sparkles size={32} />
                                    </div>
                                    <h3 className="text-xl font-bold">{upgrade.name}</h3>
                                    <div className="h-px w-full bg-slate-600 my-2" />
                                    <p className="text-sm text-slate-300">{upgrade.description}</p>
                                </div>
                                <div className="relative z-10 text-xs uppercase tracking-widest opacity-50 font-bold">
                                    {upgrade.rarity}
                                </div>
                            </motion.button>
                        ))}
                    </div>
                </motion.div>
            </div>
          )}

          {/* GAME OVER */}
          {status === GameStatus.GAME_OVER && (
            <motion.div 
                initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                className="bg-slate-900/95 border border-red-900 p-12 rounded-lg text-center flex flex-col items-center gap-6 shadow-2xl pointer-events-auto z-50"
            >
              <h2 className="text-5xl font-serif text-red-500 drop-shadow-md">YOU DIED</h2>
              <div className="flex flex-col gap-1 text-xl text-slate-300">
                 <p className="text-purple-400 font-bold text-2xl">Reached Wave {wave}</p>
                 <p>Gold Collected: <span className="text-yellow-400">{score.toLocaleString()}</span></p>
                 <p>Level Reached: {level}</p>
              </div>
              <button 
                onClick={resetGame}
                className="flex items-center gap-3 px-8 py-3 bg-red-800 hover:bg-red-700 text-white font-bold rounded shadow-lg mt-4"
              >
                <RotateCcw size={20} /> TRY AGAIN
              </button>
            </motion.div>
          )}

        </AnimatePresence>
      </div>
    </div>
  );
};

// ... Subcomponents ...
const SkillTooltipWrapper = ({ children, desc }: { children?: React.ReactNode, desc?: string }) => {
    const [show, setShow] = useState(false);
    return (
        <div className="relative flex flex-col items-center" onMouseEnter={() => setShow(true)} onMouseLeave={() => setShow(false)}>
            {children}
            {show && desc && (
                <div className="absolute bottom-full mb-2 w-48 bg-slate-900 border border-slate-600 p-2 rounded text-xs text-slate-200 z-50 shadow-xl pointer-events-none">
                    {desc}
                </div>
            )}
        </div>
    )
}

const ActiveSkillSlot = ({ icon, level, cooldown, label, desc, borderColor }: any) => {
    return (
        <SkillTooltipWrapper desc={desc}>
             <div className="relative flex flex-col items-center">
                    <div className={`w-14 h-14 rounded border-2 flex items-center justify-center bg-slate-900 ${borderColor}`}>
                        {icon}
                        <div className="absolute -top-2 -right-2 bg-slate-800 border border-slate-600 w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold">
                            {level || 0}
                        </div>
                        {cooldown > 0 && (
                            <div className="absolute inset-0 bg-black/60 flex items-center justify-center font-bold text-lg">
                                {Math.ceil(cooldown)}
                            </div>
                        )}
                    </div>
                    <div className="text-[10px] font-bold mt-1 bg-black/50 px-2 rounded">{label}</div>
            </div>
        </SkillTooltipWrapper>
    )
}

const SkillIcon = ({ icon, level, cd, maxCd, desc }: { icon: any, level: number, cd?: number, maxCd?: number, desc?: string }) => {
    if (level <= 0) return null;
    return (
        <SkillTooltipWrapper desc={desc}>
            <div className="relative flex flex-col items-center">
                <div className="w-14 h-14 rounded border-2 flex items-center justify-center bg-slate-900 border-slate-600 shadow-md">
                    {icon}
                    <div className="absolute -top-2 -right-2 bg-slate-800 border border-slate-600 w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold z-10">
                        {level}
                    </div>
                    {cd !== undefined && maxCd !== undefined && cd > 0 && (
                        <div className="absolute inset-0 bg-black/60 flex items-center justify-center font-bold text-lg rounded overflow-hidden">
                            <div className="text-white">{Math.ceil(cd)}</div>
                        </div>
                    )}
                </div>
                <div className="text-[10px] font-bold mt-1 bg-black/50 px-2 rounded opacity-50">PASSIVE</div>
            </div>
        </SkillTooltipWrapper>
    )
}

const PotionSlot = ({ icon, item, cooldown, label }: { icon: any, item: Item | undefined, cooldown: number, label: string }) => {
    return (
        <div className="relative flex flex-col items-center">
            <div className={`w-10 h-10 rounded border flex items-center justify-center ${item ? 'bg-slate-800 border-slate-600' : 'bg-slate-900 border-slate-800 opacity-50'}`}>
                {icon}
                {item && (
                     <div className="absolute -top-2 -right-2 bg-slate-700 border border-slate-600 w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-mono z-10 shadow">
                        {item.quantity || 0}
                     </div>
                )}
                {cooldown > 0 && item && (
                     <div className="absolute inset-0 bg-black/60 flex items-center justify-center font-bold text-lg rounded overflow-hidden">
                        <div className="text-white">{Math.ceil(cooldown)}</div>
                     </div>
                )}
            </div>
            <div className="text-[10px] font-bold mt-1 bg-black/50 px-2 rounded">{label}</div>
        </div>
    );
};

// Added missing components
const ItemIcon = ({ item, size = 24 }: { item: Item, size?: number }) => {
    switch (item.type) {
        case 'WEAPON': return <Sword size={size} className="text-slate-300" />;
        case 'ARMOR': return <Shield size={size} className="text-slate-300" />;
        case 'ACCESSORY': return <Hexagon size={size} className="text-slate-300" />;
        case 'POTION': return <FlaskConical size={size} className="text-red-400" />;
        case 'CORE': return <Layers size={size} className="text-blue-400" />;
        case 'PET': return <Ghost size={size} className="text-green-400" />;
        default: return <Package size={size} className="text-slate-500" />;
    }
};

const ShopItem: React.FC<{ item: Item, buyItem: (item: Item, quantity?: number) => boolean, score: number }> = ({ item, buyItem, score }) => {
    const canAfford = score >= item.price;
    return (
        <div className="flex flex-col bg-slate-800 p-2 rounded border border-slate-700 gap-2 relative">
             <div className="flex justify-between items-start">
                 <div className="p-2 bg-slate-900 rounded border border-slate-700">
                     <ItemIcon item={item} size={20} />
                 </div>
                 <div className="text-right flex-1 ml-2">
                     <div className="font-bold text-xs text-white leading-tight">{item.name}</div>
                     <div className="text-[10px] text-slate-500">{item.type}</div>
                 </div>
             </div>

             <div className="text-[10px] text-slate-400 h-8 overflow-hidden leading-tight">
                 {item.description || Object.keys(item.stats).map(k => `+${item.stats[k as keyof typeof item.stats]} ${k}`).join(', ')}
             </div>

             <button 
                 onClick={() => buyItem(item)}
                 disabled={!canAfford}
                 className={`w-full py-1 text-xs font-bold rounded flex items-center justify-center gap-1 ${canAfford ? 'bg-yellow-600 text-white hover:bg-yellow-500' : 'bg-slate-700 text-slate-500'}`}
             >
                 <Coins size={10} /> {item.price}
             </button>
        </div>
    )
}

const EquipmentSlot = ({ type, label, item, onClick, onUpgrade, canUpgrade, onHover, textColorClass }: any) => {
     return (
        <div className="flex flex-col items-center gap-1">
             <div className="text-[10px] text-slate-500 font-bold uppercase">{label}</div>
             <button 
                onClick={onClick}
                onMouseEnter={() => onHover && onHover(item)}
                onMouseLeave={() => onHover && onHover(null)}
                className={`w-14 h-14 rounded-lg border-2 flex items-center justify-center relative transition-all ${item ? 'bg-slate-800 border-slate-500' : 'bg-slate-900 border-slate-700 border-dashed opacity-50'}`}
             >
                 {item ? <ItemIcon item={item} size={28} /> : 
                    type === 'WEAPON' ? <Sword size={20} className="opacity-20"/> :
                    type === 'ARMOR' ? <Shield size={20} className="opacity-20"/> :
                    type === 'ACCESSORY' ? <Hexagon size={20} className="opacity-20"/> :
                    <Ghost size={20} className="opacity-20"/>
                 }

                 {item && item.level > 1 && (
                     <div className="absolute -top-2 -right-2 bg-slate-900 border border-slate-600 text-yellow-500 text-[10px] px-1 rounded-full z-10 font-bold">
                        +{item.level - 1}
                     </div>
                 )}
             </button>
             <div className={`text-[10px] font-bold max-w-[60px] truncate ${item ? textColorClass : 'text-slate-600'}`}>
                 {item ? item.name : 'Empty'}
             </div>
             {canUpgrade && (
                 <button onClick={(e) => { e.stopPropagation(); onUpgrade(); }} className="text-[9px] bg-slate-700 text-yellow-400 px-1.5 py-0.5 rounded flex items-center gap-1 hover:bg-slate-600">
                     <Hammer size={8} /> UP
                 </button>
             )}
        </div>
     )
}

import { Vector3 } from 'three';

export enum GameStatus {
  MENU = 'MENU',
  HERO_SELECT = 'HERO_SELECT',
  PLAYING = 'PLAYING',
  PAUSED = 'PAUSED',
  LEVEL_UP = 'LEVEL_UP',
  GAME_OVER = 'GAME_OVER',
  INVENTORY = 'INVENTORY',
  SHOP = 'SHOP',
  GACHA_REVEAL = 'GACHA_REVEAL', 
}

export type HeroClass = 'ARCHER' | 'WIZARD' | 'BARBARIAN';

export type UpgradeType = 
  'HEALTH' | 'SPEED' | 'DAMAGE' | 'FIRE_RATE' | 'MULTISHOT' | 'DASH_COOLDOWN' |
  'SKILL_ORBITAL' | 'SKILL_THUNDER' | 'SKILL_REGEN' | 'SKILL_MAGNET' |
  'SKILL_DASH' | 'SKILL_WEAPON' |
  'CRIT_RATE' | 'CRIT_DAMAGE' | 'DEFENSE' | 'MAX_MANA';

export interface Upgrade {
  id: string;
  type: UpgradeType;
  name: string;
  description: string;
  rarity: 'COMMON' | 'RARE' | 'LEGENDARY';
  value: number;
}

export type ProjectileType = 'MAGIC' | 'ARROW' | 'AXE' | 'FIREBALL' | 'ICE';
export type AbilityType = 'METEOR' | 'ARROW_RAIN' | 'AXE_AURA' | 'FIREBALL' | 'AXE_SPIN' | 'NONE';
export type ItemType = 'WEAPON' | 'ARMOR' | 'ACCESSORY' | 'POTION' | 'CORE' | 'PET';
export type Rarity = 'COMMON' | 'RARE' | 'EPIC' | 'LEGENDARY' | 'MYTHIC';
export type StatusEffectType = 'SLOW' | 'BURN' | 'STUN' | 'FREEZE' | 'POISON';

export interface PlayerStats {
  maxHealth: number;
  maxMana: number;
  regen: number; 
  manaRegen: number; 
  moveSpeed: number;
  damage: number;
  fireRate: number; 
  projectileSpeed: number;
  multishot: number;
  spread: number;
  dashCooldown: number;
  cooldownReduction: number; 
  magnetRadius: number;
  critRate: number; 
  critDamage: number; 
  defense: number; 
  skillDamage: number; 
  knockback: number; // Added knockback stat
}

export interface Item {
  id: string;
  name: string;
  type: ItemType;
  stats: Partial<PlayerStats>; 
  rarity: Rarity;
  price: number;
  level: number;
  projectileType?: ProjectileType;
  ability?: AbilityType;
  description?: string;
  stackSize?: number; 
  quantity?: number; 

  // Set Mechanics
  setName?: string;
  setBonus?: string; 
  setBonusStats?: Partial<PlayerStats>;

  // Status Effects
  onHitEffect?: {
      type: StatusEffectType;
      duration: number;
      value?: number; // e.g. 0.5 for 50% slow, or damage per tick
      chance?: number; // 0-1
  };
}

export interface EnemyData {
  id: number;
  position: Vector3;
  type: number; 
  health: number;
  maxHealth: number;
  speed: number;
  radius: number;
  scale: number;
  active: boolean;
  state?: 'CHASE' | 'CHARGE_PREP' | 'CHARGE' | 'SHOOT';
  stateTimer?: number;
  chargeDir?: Vector3;

  // Status Effects
  burnTimer?: number;
  burnDamage?: number; // Damage per second
  poisonTimer?: number;
  poisonDamage?: number; // Damage per second
  freezeTimer?: number; // Stun/Freeze
  slowTimer?: number;
  slowFactor?: number;
}

export interface BulletData {
  id: number;
  position: Vector3;
  velocity: Vector3;
  active: boolean;
  lifetime: number;
  type: ProjectileType; 
  state?: number; 
  pierce?: number; 
  hitIds: number[]; 
  damageMultiplier?: number;
  knockback?: number; // Added

  // Effect transfer
  effect?: {
      type: StatusEffectType;
      duration: number;
      value?: number;
      chance?: number;
  };
}

export interface Obstacle {
    id: number;
    position: Vector3;
    radius: number;
    type: 'TREE' | 'ROCK' | 'HOUSE';
    scale?: number;
}

export interface CrateData {
  id: number;
  position: Vector3;
  active: boolean;
  rotation: number;
  hp: number;
  maxHp: number;
}

export interface DropData {
