import React, { useRef, useEffect } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, Color } from 'three';
import { useGameStore } from '../store';
import { ARENA_SIZE, COLORS } from '../constants';
import { GameStatus, EnemyData, BulletData } from '../types';

const MAX_ENEMIES = 400;

const dummy = new Object3D();
const tempVec = new Vector3();
const tempColor = new Color();

interface EnemyManagerProps {
  bulletsDataRef: React.MutableRefObject<BulletData[]>;
  enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
}

export const EnemyManager: React.FC<EnemyManagerProps> = ({ bulletsDataRef, enemyBulletsDataRef }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const { playerPosition, addScore, addExperience, takeDamage, status, level, stats, spawnDrop, wave, waveTimer, advanceWave } = useGameStore();

  const enemies = useRef(new Array(MAX_ENEMIES).fill(0).map((_, i) => ({
    id: i,
    active: false,
    type: 0,
    health: 100,
    maxHealth: 100,
    position: new Vector3(),
    speed: 5,
    radius: 0.8,
    scale: 1,
    state: 'CHASE',
    stateTimer: 0,
    burnDuration: 0,
    burnDamage: 0,
    poisonTimer: 0,
    poisonDamage: 0,
    freezeTimer: 0,
    slowTimer: 0,
    slowFactor: 0
  } as EnemyData)));

  const spawnTimer = useRef(0);

  // Listen for Barrier Proc
  useEffect(() => {
      const handleBarrier = (e: CustomEvent) => {
          const { position } = e.detail; // Player position
          // Knockback all enemies near player
          const radius = 10.0;
          for(const enemy of enemies.current) {
              if (enemy.active) {
                  const dist = enemy.position.distanceTo(position);
                  if (dist < radius) {
                      // Push away
                      const pushDir = new Vector3().subVectors(enemy.position, position).normalize();
                      const force = 10.0; // Strong knockback
                      enemy.position.add(pushDir.multiplyScalar(force));
                      enemy.freezeTimer = 0.5; // Brief stun
                  }
              }
          }
      };

      window.addEventListener('barrier', handleBarrier as EventListener);
      return () => window.removeEventListener('barrier', handleBarrier as EventListener);
  }, []);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;
    if (!meshRef.current) return;

    if (!meshRef.current.userData.enemies) {
        meshRef.current.userData.enemies = enemies.current;
        meshRef.current.name = "EnemyMesh";
    }

    // Wave Progression Logic
    if (waveTimer > 60) {
        advanceWave();
    }

    // 1. Spawning
    spawnTimer.current += delta;
    // Spawn rate increases with wave
    const spawnRate = Math.max(0.05, 0.8 - (level * 0.02) - (wave * 0.05));

    if (spawnTimer.current > spawnRate) {
        spawnTimer.current = 0;
        const enemy = enemies.current.find(e => !e.active);
        if (enemy) {
            enemy.active = true;
            enemy.burnTimer = 0;
            enemy.poisonTimer = 0;
            enemy.freezeTimer = 0;
            enemy.slowTimer = 0;
            enemy.slowFactor = 0;

            let angle, dist, spawnPos;
            do {
                angle = Math.random() * Math.PI * 2;
                dist = (ARENA_SIZE / 2) - 5;
                spawnPos = new Vector3(Math.cos(angle) * dist, 0, Math.sin(angle) * dist);
            } while (spawnPos.distanceTo(playerPosition) < 20);

            enemy.position.copy(spawnPos);

            // Scaling multipliers
            const hpMult = 1 + (wave * 0.5) + (level * 0.1);
            const speedMult = 1 + (wave * 0.05);

            const r = Math.random();
            // Wave-gated Enemy Types

            // Reduced Health (60% less base)
            if (wave >= 5 && r > 0.98) {
                enemy.type = 2; // Boss
                enemy.health = (200 + (level * 100)) * hpMult; // Reduced from 500
                enemy.speed = (3 + (level * 0.1)) * speedMult;
                enemy.radius = 2.5;
                enemy.scale = 3.0;
                tempColor.set(COLORS.enemyBoss);
            } else if (wave >= 3 && r > 0.85) {
                enemy.type = 3; // Shooter
                enemy.health = (15 + (level * 5)) * hpMult; // Reduced from 40
                enemy.speed = 3.0 * speedMult;
                enemy.radius = 0.8;
                enemy.scale = 0.9;
                tempColor.set(COLORS.enemyShooter);
            } else if (wave >= 2 && r > 0.70) {
                enemy.type = 1; // Orc
                enemy.health = (25 + (level * 8)) * hpMult; // Reduced from 60
                enemy.speed = (3.5 + (level * 0.1)) * speedMult;
                enemy.radius = 1.0;
                enemy.scale = 1.2;
                tempColor.set(COLORS.enemyOrc);
            } else {
                enemy.type = 0; // Slime
                enemy.health = (10 + (level * 4)) * hpMult; // Reduced from 25
                enemy.speed = (4 + (level * 0.15)) * speedMult;
                enemy.radius = 0.6;
                enemy.scale = 0.8;
                tempColor.set(COLORS.enemySlime);
            }
            enemy.maxHealth = enemy.health;

            meshRef.current.setColorAt(enemies.current.indexOf(enemy), tempColor);
            meshRef.current.instanceColor!.needsUpdate = true;
        }
    }

    // 2. Logic & Collision
    const activeBullets = bulletsDataRef.current;
    const baseDamage = stats.damage;
    const critRate = stats.critRate;
    const critDamage = stats.critDamage;

    for (let i = 0; i < MAX_ENEMIES; i++) {
        const e = enemies.current[i];
        if (e.active) {

            const distToPlayer = e.position.distanceTo(playerPosition);

            // --- Status Effects Logic ---
            let currentSpeed = e.speed;
            let canMove = true;

            // Burn DoT
            if (e.burnTimer && e.burnTimer > 0) {
                e.burnTimer -= delta;
                e.health -= (e.burnDamage || 5) * delta; 
            }
            // Poison DoT
            if (e.poisonTimer && e.poisonTimer > 0) {
                e.poisonTimer -= delta;
                e.health -= (e.poisonDamage || 3) * delta; 
            }

            // Freeze / Stun
            if (e.freezeTimer && e.freezeTimer > 0) {
                e.freezeTimer -= delta;
                canMove = false;
                tempColor.set('#60a5fa');
                meshRef.current.setColorAt(i, tempColor);
                meshRef.current.instanceColor!.needsUpdate = true;
            } 

            // Slow
            if (e.slowTimer && e.slowTimer > 0) {
                e.slowTimer -= delta;
                currentSpeed *= (1 - (e.slowFactor || 0.5));
            }

            // Restore Color if not frozen
            if ((!e.freezeTimer || e.freezeTimer <= 0) && e.active) {
                 if (e.type === 2) tempColor.set(COLORS.enemyBoss);
                 else if (e.type === 3) tempColor.set(COLORS.enemyShooter);
                 else if (e.type === 1) tempColor.set(COLORS.enemyOrc);
                 else tempColor.set(COLORS.enemySlime);

                 // Poison Tint (Greenish)
                 if (e.poisonTimer && e.poisonTimer > 0) tempColor.lerp(new Color('#4ade80'), 0.5);
                 // Burn Tint (Reddish/Orange)
                 if (e.burnTimer && e.burnTimer > 0) tempColor.lerp(new Color('#f97316'), 0.5);

                 meshRef.current.setColorAt(i, tempColor);
                 meshRef.current.instanceColor!.needsUpdate = true;
            }

            // AI Movement
            if (canMove) {
                if (e.type === 3 && distToPlayer > 15) { // Shooter keep distance
                     tempVec.subVectors(playerPosition, e.position).normalize();
                     e.position.add(tempVec.multiplyScalar(currentSpeed * delta));
                } else if (e.type !== 3) {
                     tempVec.subVectors(playerPosition, e.position).normalize();
                     e.position.add(tempVec.multiplyScalar(currentSpeed * delta));
                }
            }

            // Shooter Firing Logic
            if (e.type === 3 && canMove) {
                e.stateTimer = (e.stateTimer || 0) + delta;
                if (e.stateTimer > 2.0 && distToPlayer < 25) {
                    e.stateTimer = 0;
                    const bullet = enemyBulletsDataRef.current.find(b => !b.active);
                    if (bullet) {
                        bullet.active = true;
                        bullet.lifetime = 3.0;
                        bullet.position.copy(e.position).add(new Vector3(0, 1, 0));
                        const aimDir = new Vector3().subVectors(playerPosition, e.position).normalize();
                        bullet.velocity.copy(aimDir).multiplyScalar(15);
                    }
                }
            }

            // Player Collision Damage
            if (e.type !== 3 && distToPlayer < e.radius + 0.5 && canMove) {
                const dmg = (e.type === 2 ? 30 : 10) * (1 + wave * 0.1); // Scale dmg with wave
                takeDamage(dmg * delta);
            }

            // Bullet Collision
            for(let b=0; b < activeBullets.length; b++) {
                const bullet = activeBullets[b];
                if (bullet.active) {
                    if (bullet.hitIds && bullet.hitIds.includes(e.id)) continue;

                    let hitRadius = e.radius + 0.5;
                    if (bullet.type === 'MAGIC') hitRadius += 1.0;
                    if (bullet.type === 'FIREBALL') hitRadius += 1.5;

                    if (bullet.position.distanceTo(e.position) < hitRadius) {

                        const isCrit = Math.random() < critRate;
                        let dmg = (isCrit ? baseDamage * critDamage : baseDamage);
                        if (bullet.damageMultiplier) dmg *= bullet.damageMultiplier;

                        e.health -= dmg;

                        window.dispatchEvent(new CustomEvent('damage', { 
                            detail: { position: e.position, damage: dmg, isCrit } 
                        }));

                        if (bullet.hitIds) bullet.hitIds.push(e.id);

                        // Apply Bullet Effects
                        if (bullet.effect) {
                            const { type, duration, value, chance } = bullet.effect;

                            // Check chance
                            if (Math.random() < (chance || 1.0)) {
                                if (type === 'BURN') {
                                    e.burnTimer = duration;
                                    e.burnDamage = value ?? 5;
                                }
                                if (type === 'POISON') {
                                    e.poisonTimer = duration;
                                    e.poisonDamage = value ?? 3;
                                }
                                if (type === 'STUN' || type === 'FREEZE') e.freezeTimer = duration;
                                if (type === 'SLOW') {
                                    e.slowTimer = duration;
                                    e.slowFactor = value || 0.5;
                                }
                            }
                        }

                        if (bullet.type === 'FIREBALL') {
                            e.burnTimer = 3.0;
                            e.burnDamage = 5;
                        }

                        if (bullet.type === 'MAGIC') {
                            for(let j=0; j<MAX_ENEMIES; j++) {
                                if(i!==j && enemies.current[j].active && enemies.current[j].position.distanceTo(e.position) < 4.0) {
                                    enemies.current[j].health -= dmg * 0.5; 
                                }
                            }
                        }

                        // Knockback
                        if (e.type !== 2 && canMove) {
                            const kbDir = e.position.clone().sub(bullet.position).normalize();
                            // Use bullet knockback or default
                            const kbForce = bullet.knockback ?? 0.5;
                            e.position.add(kbDir.multiplyScalar(kbForce));
                        }

                        if (bullet.pierce && bullet.pierce > 0) {
                            bullet.pierce--;
                            if (bullet.pierce <= 0) bullet.active = false;
                        } else {
                            bullet.active = false;
                        }
                    }
                }
            }

            // Death Logic
            if (e.health <= 0) {
                e.active = false;
                addScore(10 * (e.type + 1));

                if (e.type === 2) { 
                    const roll = Math.random();
                    if (roll > 0.995) spawnDrop(e.position, 'ITEM', 0, 'MYTHIC'); 
                    else if (roll > 0.99) spawnDrop(e.position, 'ITEM', 0, 'LEGENDARY'); 
                    else if (roll > 0.98) spawnDrop(e.position, 'ITEM', 0, 'EPIC'); 
                    else spawnDrop(e.position, 'ITEM', 0, 'RARE'); 

                    spawnDrop(e.position.clone().add(new Vector3(1,0,0)), 'XP', 1000); 
                } else {
                    if (Math.random() > 0.90) {
                        spawnDrop(e.position, 'ITEM', 0);
                    } else {
                        spawnDrop(e.position, 'XP', e.type === 3 ? 30 : 20);
                    }
                }
                dummy.position.set(0, -100, 0);
            } else {
                dummy.position.copy(e.position);
                dummy.scale.set(e.scale, e.scale, e.scale);
                if (e.type !== 2) dummy.position.y = Math.abs(Math.sin(state.clock.elapsedTime * 5)) * 0.5;
                dummy.lookAt(playerPosition);
            }

        } else {
            dummy.position.set(0, -100, 0);
        }

        dummy.updateMatrix();
        meshRef.current.setMatrixAt(i, dummy.matrix);
    }

    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, MAX_ENEMIES]} frustumCulled={false}>
      <boxGeometry args={[1, 1, 1]} />
      <meshStandardMaterial vertexColors roughness={0.5} metalness={0.2} />
    </instancedMesh>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { InstancedMesh, Object3D, Vector3, Line, Mesh } from 'three';
import { useGameStore } from '../store';
import { GameStatus, BulletData } from '../types';
import { COLORS } from '../constants';

const dummy = new Object3D();

interface SkillManagerProps {
    enemyBulletsDataRef: React.MutableRefObject<BulletData[]>;
}

export const SkillManager: React.FC<SkillManagerProps> = ({ enemyBulletsDataRef }) => {
  const { skillLevels, playerPosition, status, stats, heal, takeDamage, updatePassiveCooldowns, useMana } = useGameStore();
  const { scene } = useThree();

  // Orbital State Machine
  // 0: Spinning (4s), 1: Shooting (instant -> travel), 2: Cooldown (2s)
  const orbitalState = useRef(2); // Start in cooldown/ready state logic so we can check mana before activating
  const orbitalTimer = useRef(2.0); // Start ready
  const orbitalRef = useRef<InstancedMesh>(null);
  const orbitalBlades = useRef<{ active: boolean, pos: Vector3, vel: Vector3 }[]>([]);

  // Thunder
  const thunderTimer = useRef(0);
  const [thunderPositions, setThunderPositions] = useState<Vector3[]>([]);
  const thunderVisualTimer = useRef(0);

  // Regen
  const regenTimer = useRef(0);

  // Barrier Visuals
  const barrierRef = useRef<Mesh>(null);
  const barrierScale = useRef(0);
  const barrierActive = useRef(false);

  useEffect(() => {
    const handleBarrier = () => {
        barrierActive.current = true;
        barrierScale.current = 0;
    };
    window.addEventListener('barrier', handleBarrier);
    return () => window.removeEventListener('barrier', handleBarrier);
  }, []);

  useFrame((state, delta) => {
    if (status !== GameStatus.PLAYING) return;

    const time = state.clock.getElapsedTime();

    // --- BARRIER VISUAL ---
    if (barrierActive.current) {
        barrierScale.current += delta * 20; // Fast expand
        if (barrierScale.current > 10) {
            barrierActive.current = false;
            if (barrierRef.current) barrierRef.current.visible = false;
        } else if (barrierRef.current) {
            barrierRef.current.visible = true;
            barrierRef.current.position.copy(playerPosition);
            barrierRef.current.scale.set(barrierScale.current, barrierScale.current, barrierScale.current);
            // Pulse opacity
            const material = barrierRef.current.material as any;
            if (material) material.opacity = 1 - (barrierScale.current / 10);
        }
    }

    // --- ORBITAL BLADES ---
    if (skillLevels.orbital > 0) {
        const count = skillLevels.orbital + 2; 
        const damage = stats.damage * 0.8;

        // Initialize blade data if needed
        if (orbitalBlades.current.length !== count) {
            orbitalBlades.current = new Array(count).fill(0).map(() => ({ active: true, pos: new Vector3(), vel: new Vector3() }));
        }

        if (orbitalState.current === 2) {
            // COOLDOWN / READY PHASE
            orbitalTimer.current += delta;
            updatePassiveCooldowns({ orbitalCooldown: 2 - orbitalTimer.current, orbitalMaxCooldown: 2 });

            // Hide all
            for (let i = 0; i < 20; i++) {
                dummy.position.set(0, -100, 0);
                dummy.updateMatrix();
                orbitalRef.current?.setMatrixAt(i, dummy.matrix);
            }

            if (orbitalTimer.current > 2.0) {
                // Reduced mana cost to 7 (approx 50% of 15)
                if (useMana(7)) {
                    orbitalState.current = 0;
                    orbitalTimer.current = 0;
                }
            }
        } else if (orbitalState.current === 0) {
            // SPINNING PHASE (4s)
            orbitalTimer.current += delta;
            updatePassiveCooldowns({ orbitalCooldown: 4 - orbitalTimer.current, orbitalMaxCooldown: 4 });

            const radius = 4.0;
            const speed = 3.0;

            for (let i = 0; i < count; i++) {
                const angle = (time * speed) + (i * ((Math.PI * 2) / count));
                orbitalBlades.current[i].active = true;
                orbitalBlades.current[i].pos.set(
                    playerPosition.x + Math.cos(angle) * radius,
                    1.0,
                    playerPosition.z + Math.sin(angle) * radius
                );

                // Visual Update
                dummy.position.copy(orbitalBlades.current[i].pos);
                dummy.rotation.set(0, -angle, 0);
                dummy.scale.set(1.5, 1.5, 1.5);
                dummy.updateMatrix();
                orbitalRef.current?.setMatrixAt(i, dummy.matrix);
            }

            // Hit logic during spin
            const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
            if (enemiesMesh && enemiesMesh.userData.enemies) {
                const enemies = enemiesMesh.userData.enemies;
                for (let i = 0; i < count; i++) {
                    const bladePos = orbitalBlades.current[i].pos;
                    for (let e = 0; e < enemies.length; e++) {
                        if (enemies[e].active && enemies[e].position.distanceTo(bladePos) < 2.0) {
                             enemies[e].health -= damage * delta * 5; // DPS check
                        }
                    }
                }
            }

            if (orbitalTimer.current > 4.0) {
                orbitalState.current = 1;
                orbitalTimer.current = 0;

                // Calculate shoot directions
                const enemies = enemiesMesh?.userData?.enemies || [];
                const activeEnemies = enemies.filter((e: any) => e.active);

                for(let i=0; i<count; i++) {
                    let target = null;
                    let minDist = 50;

                    for(const e of activeEnemies) {
                         const d = e.position.distanceTo(playerPosition);
                         if (d < minDist) {
                             minDist = d;
                             target = e.position;
                         }
                    }

                    const dir = new Vector3();
                    if (target) {
                        dir.subVectors(target, orbitalBlades.current[i].pos).normalize();
                    } else {
                        dir.subVectors(orbitalBlades.current[i].pos, playerPosition).normalize();
                    }
                    orbitalBlades.current[i].vel.copy(dir).multiplyScalar(20);
                }
            }

        } else if (orbitalState.current === 1) {
            // SHOOTING PHASE
            let activeCount = 0;
            for (let i = 0; i < count; i++) {
                const blade = orbitalBlades.current[i];
                if (blade.active) {
                    blade.pos.add(blade.vel.clone().multiplyScalar(delta));

                    // Collision
                    const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
                    if (enemiesMesh && enemiesMesh.userData.enemies) {
                        const enemies = enemiesMesh.userData.enemies;
                         for (let e = 0; e < enemies.length; e++) {
                            if (enemies[e].active && enemies[e].position.distanceTo(blade.pos) < 1.5) {
                                 enemies[e].health -= damage * 5;
                                 blade.active = false; 
                                 window.dispatchEvent(new CustomEvent('damage', { 
                                    detail: { position: enemies[e].position, damage: damage * 5, isCrit: false } 
                                 }));
                            }
                        }
                    }

                    // Bounds check
                    if (blade.pos.distanceTo(playerPosition) > 50) blade.active = false;

                    // Update Visual
                    if (blade.active) {
                         dummy.position.copy(blade.pos);
                         dummy.rotation.set(0, time * 10, 0);
                         dummy.scale.set(1.5, 1.5, 1.5);
                         dummy.updateMatrix();
                         orbitalRef.current?.setMatrixAt(i, dummy.matrix);
                         activeCount++;
                    } else {
                         dummy.position.set(0, -100, 0);
                         dummy.updateMatrix();
                         orbitalRef.current?.setMatrixAt(i, dummy.matrix);
                    }
                } else {
                     dummy.position.set(0, -100, 0);
                     dummy.updateMatrix();
                     orbitalRef.current?.setMatrixAt(i, dummy.matrix);
                }
            }

            if (activeCount === 0 || orbitalTimer.current > 2.0) {
                orbitalState.current = 2;
                orbitalTimer.current = 0;
            }
            orbitalTimer.current += delta;
        }

        orbitalRef.current!.instanceMatrix.needsUpdate = true;
    } else {
        if (orbitalRef.current) orbitalRef.current.visible = false;
    }

    // --- THUNDER ---
    if (skillLevels.thunder > 0) {
        thunderTimer.current += delta;
        updatePassiveCooldowns({ thunderCooldown: 2 - thunderTimer.current, thunderMaxCooldown: 2 });

        if (thunderTimer.current > 2.0) { // Fixed 2s cooldown

            const enemiesMesh = scene.getObjectByName("EnemyMesh") as InstancedMesh;
            if (enemiesMesh && enemiesMesh.userData.enemies) {
                const enemies = enemiesMesh.userData.enemies;
                const activeEnemies = enemies.filter((e: any) => e.active && e.position.distanceTo(playerPosition) < 40);

                if (activeEnemies.length > 0) {
                    // Reduced mana cost to 2 (approx 50% of 5)
                    if (useMana(2)) {
                        thunderTimer.current = 0;
                        const hitCount = 1 + skillLevels.thunder; 
                        const hits: Vector3[] = [];

                        for(let i=0; i<hitCount; i++) {
                             if (activeEnemies.length === 0) break;
                             const idx = Math.floor(Math.random() * activeEnemies.length);
                             const target = activeEnemies[idx];

                             const isCrit = Math.random() < stats.critRate;
                             const dmg = (stats.damage * 4) * (isCrit ? stats.critDamage : 1);
                             target.health -= dmg;

                             window.dispatchEvent(new CustomEvent('damage', { 
                                detail: { position: target.position, damage: dmg, isCrit } 
                             }));

                             hits.push(target.position.clone());
                             activeEnemies.splice(idx, 1);
                        }

                        setThunderPositions(hits);
                        thunderVisualTimer.current = 0.25;
                    }
                }
            }
        }
    }

    // Thunder Visual Cleanup
    if (thunderVisualTimer.current > 0) {
        thunderVisualTimer.current -= delta;
        if (thunderVisualTimer.current <= 0) setThunderPositions([]);
    }

    // --- REGEN ---
    if (skillLevels.regen > 0) {
        regenTimer.current += delta;
        if (regenTimer.current > 1.0) {
            regenTimer.current = 0;
            heal(skillLevels.regen * 2);
        }
    }

  });

  return (
    <>
      {/* Orbitals */}
      <instancedMesh ref={orbitalRef} args={[undefined, undefined, 20]} frustumCulled={false} visible={skillLevels.orbital > 0}>
        <octahedronGeometry args={[0.4, 0]} />
        <meshStandardMaterial color="#0ea5e9" emissive="#0ea5e9" emissiveIntensity={2} />
      </instancedMesh>

      {/* Barrier Visual */}
      <mesh ref={barrierRef} visible={false}>
         <sphereGeometry args={[1, 32, 32]} />
         <meshStandardMaterial color="#a855f7" transparent opacity={0.5} emissive="#a855f7" emissiveIntensity={1} depthWrite={false} />
      </mesh>

      {/* Thunder Visual */}
      {thunderPositions.map((pos, i) => (
          <mesh key={i} position={pos}>
              <cylinderGeometry args={[0.1, 0.1, 30, 8]} />
              <meshBasicMaterial color="yellow" transparent opacity={0.8} />
          </mesh>
      ))}
    </>
  );
};

