  return (
    <div className="absolute inset-0 pointer-events-none z-10 font-sans text-slate-100 select-none">

      {/* HUD - Always visible except in Menu/GameOver/LevelUp if desired, but request implies persistence */}
      {(status === GameStatus.PLAYING || status === GameStatus.PAUSED || status === GameStatus.INVENTORY || status === GameStatus.SHOP) && (
        <div className="absolute inset-0 flex flex-col justify-between p-4 md:p-6 pointer-events-none">

          {/* Top Bar */}
          <div className="flex justify-between items-start pointer-events-auto w-full z-20">
             <div className="flex flex-col gap-2">
                 <div className="flex items-center gap-4 bg-slate-900/80 p-2 pr-6 rounded-r-full border-l-4 border-blue-500 backdrop-blur-sm shadow-xl">
                    <div className="bg-slate-800 p-2 rounded-full border border-slate-600">
                        <User size={24} className="text-blue-400" />
                    </div>
                    <div>
                        <div className="text-xl font-bold leading-none">Lv. {level}</div>
                        <div className="text-xs text-slate-400">{hero}</div>
                    </div>
                 </div>
                 {/* Total CP Display */}
                 <div className="flex items-center gap-2 bg-slate-900/60 p-1 px-3 rounded-r-lg backdrop-blur-sm">
                      <Swords size={16} className="text-orange-500" />
                      <span className="text-sm font-bold text-orange-200 tracking-wider">{totalCp.toLocaleString()} CP</span>
                 </div>
             </div>

             {/* Wave Display */}
             <div className="flex flex-col items-center">
                 <div className="bg-slate-900/80 px-6 py-2 rounded-b-xl border-b-2 border-purple-500 backdrop-blur-sm text-center shadow-lg">
                     <div className="text-2xl font-serif font-black tracking-widest text-purple-200">WAVE {wave}</div>
                     <div className="flex items-center justify-center gap-1 text-xs text-purple-400 font-mono">
                         <Timer size={12} /> {Math.floor(waveTimer / 60)}:{(Math.floor(waveTimer % 60)).toString().padStart(2, '0')}
                     </div>
                 </div>
             </div>

             <div className="flex items-center gap-4 bg-slate-900/80 p-2 pl-6 rounded-l-full border-r-4 border-yellow-500 backdrop-blur-sm shadow-xl">
                 <div className="text-right">
                    <div className="flex items-center justify-end gap-2 text-yellow-400 font-bold">
                        <span className="text-xl">{score.toLocaleString()}</span> <Coins size={16} />
                    </div>
                    <div className="flex items-center justify-end gap-2 text-emerald-400 text-sm font-semibold">
                         <span>{gems.toLocaleString()}</span> <Gem size={12} />
                    </div>
                 </div>
             </div>
          </div>

          {/* Buff / Passive Icons (Top Left below Stats) */}
          <div className="absolute top-24 left-6 flex flex-col gap-2 pointer-events-auto">
              {/* Similar logic can be added for buffs */}
          </div>

          {/* Bottom Bar: Health, Mana, XP, Skills */}
          <div className="w-full flex items-end justify-between gap-4 pointer-events-auto pb-4">
             {/* HP/Mana Orbs & XP */}
             <div className="relative flex flex-col gap-1 w-full max-w-md">
                 {/* Bars */}
                 <div className="relative h-6 bg-slate-900/80 rounded-full border border-slate-700 overflow-hidden shadow-lg">
                     <motion.div 
                        className="h-full bg-gradient-to-r from-red-600 to-red-400"
                        initial={{ width: 0 }}
                        animate={{ width: `${hpPercent}%` }}
                        transition={{ type: "spring", stiffness: 50 }}
                     />
                     <div className="absolute inset-0 flex items-center justify-center text-xs font-bold text-white drop-shadow-md">
                         <Heart size={12} className="mr-1 fill-white" /> {Math.ceil(health)} / {stats.maxHealth}
                     </div>
                 </div>
                 <div className="relative h-4 bg-slate-900/80 rounded-full border border-slate-700 overflow-hidden shadow-lg w-3/4">
                     <motion.div 
                        className="h-full bg-gradient-to-r from-blue-600 to-blue-400"
                        initial={{ width: 0 }}
                        animate={{ width: `${manaPercent}%` }}
                     />
                     <div className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white drop-shadow-md">
                         <Zap size={10} className="mr-1 fill-white" /> {Math.ceil(mana)} / {stats.maxMana}
                     </div>
                 </div>
                 {/* XP Bar (Thin line at bottom) */}
                 <div className="w-full h-1 bg-slate-800 rounded-full mt-1">
                     <motion.div 
                        className="h-full bg-purple-500 rounded-full"
                        animate={{ width: `${xpPercent}%` }}
                     />
                 </div>
             </div>

             {/* Potions & Skills */}
             <div className="flex items-center gap-3">
                 {/* Potions */}
                 <div className="flex flex-col gap-1 mr-4">
                    <div className="relative group">
                         <div className={`w-10 h-10 rounded-lg bg-slate-800 border-2 ${hpPotion ? 'border-red-500' : 'border-slate-700'} flex items-center justify-center shadow-lg`}>
                            <FlaskConical size={20} className={hpPotion ? 'text-red-500' : 'text-slate-600'} />
                            {potionCooldown > 0 && (
                                <div className="absolute inset-0 bg-black/60 rounded-lg flex items-center justify-center text-white text-xs font-bold">
                                    {Math.ceil(potionCooldown)}
                                </div>
                            )}
                         </div>
                         <div className="absolute -top-2 -right-2 bg-slate-900 text-white text-[10px] w-5 h-5 rounded-full flex items-center justify-center border border-slate-600">
                             {hpPotion ? hpPotion.quantity : 0}
                         </div>
                    </div>
                    <div className="relative group">
                         <div className={`w-10 h-10 rounded-lg bg-slate-800 border-2 ${manaPotion ? 'border-blue-500' : 'border-slate-700'} flex items-center justify-center shadow-lg`}>
                            <FlaskConical size={20} className={manaPotion ? 'text-blue-500' : 'text-slate-600'} />
                         </div>
                         <div className="absolute -top-2 -right-2 bg-slate-900 text-white text-[10px] w-5 h-5 rounded-full flex items-center justify-center border border-slate-600">
                             {manaPotion ? manaPotion.quantity : 0}
                         </div>
                    </div>
                 </div>

                 {/* Skills */}
                 <div className="flex gap-3">
                     {/* Dash */}
                     <div className="relative">
                        <div className="w-14 h-14 bg-slate-900/90 rounded-xl border-2 border-slate-600 flex items-center justify-center shadow-2xl relative overflow-hidden">
                            <Wind size={24} className="text-slate-200" />
                            <div className="absolute bottom-1 right-1 text-[10px] text-slate-400 font-bold">SPC</div>
                            {skills.dash > 0 && (
                                <div className="absolute inset-0 bg-black/70 flex items-center justify-center">
                                    <span className="text-white font-bold">{skills.dash.toFixed(1)}</span>
