                 >
                     <Backpack size={24} />
                 </button>
                 <button 
                    onClick={toggleShop}
                    className={`p-3 rounded-full border-2 transition-all ${isShopOpen ? 'bg-slate-700 border-white scale-110' : 'bg-slate-900 border-slate-600 hover:border-white'}`}
                 >
                     <ShoppingBag size={24} />
