                       {/* Equipment Slots */}
                       <div className="grid grid-cols-2 gap-4">
                           {/* Weapon */}
                           <div className="relative group">
                               <div 
                                    onClick={() => equipment.weapon && unequipItem('weapon')}
                                    className={`aspect-square rounded-xl bg-slate-800 border-2 ${equipment.weapon ? getRarityColor(equipment.weapon.rarity) : 'border-slate-700 border-dashed'} flex items-center justify-center cursor-pointer hover:bg-slate-750 transition-colors`}
                               >
                                   {equipment.weapon ? (
                                       <Sword size={32} className={getRarityTextColor(equipment.weapon.rarity)} />
                                   ) : <Sword size={24} className="text-slate-600" />}
                               </div>
                               {equipment.weapon && <div className="absolute bottom-1 right-1 bg-black/80 text-[10px] px-1 rounded text-white">Lv.{equipment.weapon.level}</div>}
                               <div className="text-center text-xs mt-1 text-slate-400">Weapon</div>
                           </div>

                           {/* Armor */}
                           <div className="relative group">
                               <div 
                                    onClick={() => equipment.armor && unequipItem('armor')}
                                    className={`aspect-square rounded-xl bg-slate-800 border-2 ${equipment.armor ? getRarityColor(equipment.armor.rarity) : 'border-slate-700 border-dashed'} flex items-center justify-center cursor-pointer hover:bg-slate-750 transition-colors`}
                               >
                                   {equipment.armor ? (
                                       <Shield size={32} className={getRarityTextColor(equipment.armor.rarity)} />
                                   ) : <Shield size={24} className="text-slate-600" />}
                               </div>
                               {equipment.armor && <div className="absolute bottom-1 right-1 bg-black/80 text-[10px] px-1 rounded text-white">Lv.{equipment.armor.level}</div>}
                               <div className="text-center text-xs mt-1 text-slate-400">Armor</div>
                           </div>

                           {/* Accessory */}
                           <div className="relative group">
                               <div 
                                    onClick={() => equipment.accessory && unequipItem('accessory')}
                                    className={`aspect-square rounded-xl bg-slate-800 border-2 ${equipment.accessory ? getRarityColor(equipment.accessory.rarity) : 'border-slate-700 border-dashed'} flex items-center justify-center cursor-pointer hover:bg-slate-750 transition-colors`}
                               >
                                   {equipment.accessory ? (
                                       <Gem size={32} className={getRarityTextColor(equipment.accessory.rarity)} />
                                   ) : <Gem size={24} className="text-slate-600" />}
                               </div>
                               {equipment.accessory && <div className="absolute bottom-1 right-1 bg-black/80 text-[10px] px-1 rounded text-white">Lv.{equipment.accessory.level}</div>}
                               <div className="text-center text-xs mt-1 text-slate-400">Accessory</div>
                           </div>

                            {/* Pet */}
                           <div className="relative group">
                               <div 
                                    onClick={() => equipment.pet && unequipItem('pet')}
                                    className={`aspect-square rounded-xl bg-slate-800 border-2 ${equipment.pet ? getRarityColor(equipment.pet.rarity) : 'border-slate-700 border-dashed'} flex items-center justify-center cursor-pointer hover:bg-slate-750 transition-colors`}
                               >
                                   {equipment.pet ? (
                                       <Ghost size={32} className={getRarityTextColor(equipment.pet.rarity)} />
                                   ) : <Ghost size={24} className="text-slate-600" />}
                               </div>
                               {equipment.pet && <div className="absolute bottom-1 right-1 bg-black/80 text-[10px] px-1 rounded text-white">Lv.{equipment.pet.level}</div>}
                               <div className="text-center text-xs mt-1 text-slate-400">Pet</div>
                           </div>
                       </div>

                       {/* Stats */}
                       <div className="flex-1 overflow-y-auto space-y-2 pr-2 text-sm text-slate-300">
                           <div className="bg-slate-900 p-2 rounded flex justify-between">
                               <span>Damage</span> <span className="text-white font-bold">{Math.round(stats.damage)}</span>
                           </div>
                           <div className="bg-slate-900 p-2 rounded flex justify-between">
                               <span>Attack Speed</span> <span className="text-white font-bold">{stats.fireRate.toFixed(2)}/s</span>
                           </div>
                           <div className="bg-slate-900 p-2 rounded flex justify-between">
                               <span>Crit Rate</span> <span className="text-white font-bold">{(stats.critRate * 100).toFixed(0)}%</span>
                           </div>
                           <div className="bg-slate-900 p-2 rounded flex justify-between">
                               <span>Crit Dmg</span> <span className="text-white font-bold">x{stats.critDamage.toFixed(1)}</span>
                           </div>
                           <div className="bg-slate-900 p-2 rounded flex justify-between">
                               <span>Defense</span> <span className="text-white font-bold">{stats.defense}</span>
                           </div>
                           <div className="bg-slate-900 p-2 rounded flex justify-between">
                               <span>Move Speed</span> <span className="text-white font-bold">{stats.moveSpeed.toFixed(1)}</span>
                           </div>
                           <div className="bg-slate-900 p-2 rounded flex justify-between">
                               <span>CDR</span> <span className="text-white font-bold">{(stats.cooldownReduction * 100).toFixed(0)}%</span>
                           </div>
                       </div>
                   </div>

                   {/* Right Panel: Inventory */}
                   <div className="flex-1 p-6 flex flex-col">
                       <div className="flex justify-between items-center mb-4">
                           <h2 className="text-2xl font-bold text-slate-100 flex items-center gap-2">
                               <Backpack /> Inventory
                           </h2>
                           <div className="flex gap-2">
                               {/* Auto Equip Button */}
                               <button 
                                   onClick={autoEquip}
                                   className="px-3 py-1 bg-blue-600 hover:bg-blue-500 rounded text-sm font-bold flex items-center gap-2 transition-colors"
                                   title="Auto Equip Best CP Items"
                               >
                                   <Sparkles size={16} /> Auto Equip
                               </button>

                               <button 
                                   onClick={toggleMassSell}
                                   className={`px-3 py-1 rounded text-sm font-bold flex items-center gap-2 transition-colors ${isMassSellMode ? 'bg-red-600 hover:bg-red-500 text-white' : 'bg-slate-700 hover:bg-slate-600'}`}
                               >
                                   {isMassSellMode ? <X size={16} /> : <Trash2 size={16} />} 
                                   {isMassSellMode ? 'Cancel' : 'Mass Sell'}
                               </button>
                               <button onClick={toggleInventory} className="bg-slate-800 hover:bg-slate-700 p-1 rounded-full"><X /></button>
                           </div>
                       </div>

                       {isMassSellMode && (
                           <div className="mb-4 bg-red-900/30 border border-red-500/50 p-2 rounded flex justify-between items-center">
                               <span className="text-red-200 text-sm">Select items to sell.</span>
                               <button 
                                   onClick={executeMassSell}
                                   disabled={selectedItems.size === 0}
                                   className="bg-red-600 hover:bg-red-500 disabled:opacity-50 disabled:cursor-not-allowed px-4 py-1 rounded text-sm font-bold"
                               >
                                   Sell Selected ({selectedItems.size})
                               </button>
                           </div>
                       )}

                       <div className="flex-1 overflow-y-auto pr-2 grid grid-cols-5 gap-3 content-start">
                           {inventory.map((item, idx) => {
                               const isConsumable = item.type === 'POTION' || item.type === 'CORE';
                               const isSelected = selectedItems.has(item.id);

                               // Check Level req
                               let reqLevel = getLevelRequirement(item.rarity);
                               const canEquip = level >= reqLevel;

                               return (
                                   <div 
                                      key={`${item.id}-${idx}`}
                                      className="relative group"
                                      onClick={() => onInventoryItemClick(item, isConsumable, canEquip)}
                                      onMouseEnter={() => setHoveredItem(item)}
                                      onMouseLeave={() => setHoveredItem(null)}
                                   >
                                       <div className={`aspect-square bg-slate-800 rounded-xl border-2 ${isSelected ? 'border-red-500 bg-red-900/20' : getRarityColor(item.rarity)} flex flex-col items-center justify-center cursor-pointer hover:scale-105 transition-transform relative`}>
