                                                <div className="absolute inset-0 bg-black/60 rounded-xl flex items-center justify-center z-10">
                                                    <span className="text-red-500 font-bold text-xs">Lv.{reqLevel}</span>
                                                </div>
                                            )}
                                            {isMassSellMode && isConsumable && (
                                                <div className="absolute inset-0 bg-black/60 rounded-xl flex items-center justify-center z-10">
                                                    <span className="text-slate-400 text-[10px]">Cannot Sell</span>
                                                </div>
