                                            {item.type === 'WEAPON' && <Sword size={24} className={getRarityTextColor(item.rarity)} />}
                                            {item.type === 'ARMOR' && <Shield size={24} className={getRarityTextColor(item.rarity)} />}
                                            {item.type === 'ACCESSORY' && <Gem size={24} className={getRarityTextColor(item.rarity)} />}
                                            {item.type === 'POTION' && <FlaskConical size={24} className="text-white" />}
                                            {item.type === 'CORE' && <Hexagon size={24} className="text-blue-300" />}
                                            {item.type === 'PET' && <Ghost size={24} className={getRarityTextColor(item.rarity)} />}

                                            {(item.quantity || 1) > 1 && (
                                                <div className="absolute top-1 right-1 bg-slate-900 text-xs px-1 rounded border border-slate-600">
                                                    x{item.quantity}
