                                            {isSelected && (
                                                <div className="absolute top-1 left-1 bg-red-600 rounded-full p-0.5">
                                                    <CheckCircle2 size={12} className="text-white" />
                                                </div>
                                            )}
                                       </div>
                                   </div>
