                                     {hoveredItem.type === 'WEAPON' && <Sword size={40} className={getRarityTextColor(hoveredItem.rarity)} />}
                                     {hoveredItem.type === 'ARMOR' && <Shield size={40} className={getRarityTextColor(hoveredItem.rarity)} />}
                                     {hoveredItem.type === 'ACCESSORY' && <Gem size={40} className={getRarityTextColor(hoveredItem.rarity)} />}
                                     {hoveredItem.type === 'POTION' && <FlaskConical size={40} className="text-white" />}
                                     {hoveredItem.type === 'CORE' && <Hexagon size={40} className="text-blue-300" />}
                                     {hoveredItem.type === 'PET' && <Ghost size={40} className={getRarityTextColor(hoveredItem.rarity)} />}
                                 </div>
                                 <div className="flex-1">
                                     <div className="flex justify-between">
                                         <h3 className={`font-bold text-lg ${getRarityTextColor(hoveredItem.rarity)}`}>{hoveredItem.name}</h3>
                                         <span className="text-sm text-yellow-500 flex items-center gap-1"><CircleDollarSign size={12} /> {hoveredItem.price}</span>
                                     </div>
                                     <div className="text-xs text-slate-400 mb-1">{hoveredItem.rarity} {hoveredItem.type} {hoveredItem.type !== 'POTION' && hoveredItem.type !== 'CORE' && `- Lv.${hoveredItem.level}`}</div>
                                     <div className="text-xs text-slate-300 mb-2">{hoveredItem.description || "No description."}</div>

                                     <div className="flex flex-wrap gap-2 text-xs">
                                         {Object.entries(hoveredItem.stats).map(([key, val]) => (
                                             <span key={key} className="bg-slate-800 px-2 py-0.5 rounded text-blue-200 border border-slate-700">
