import { Vector3 } from 'three';

export enum GameStatus {
  MENU = 'MENU',
  HERO_SELECT = 'HERO_SELECT',
  PLAYING = 'PLAYING',
  PAUSED = 'PAUSED',
  LEVEL_UP = 'LEVEL_UP',
  GAME_OVER = 'GAME_OVER',
  INVENTORY = 'INVENTORY',
  SHOP = 'SHOP',
  GACHA_REVEAL = 'GACHA_REVEAL', 
}

export type HeroClass = 'ARCHER' | 'WIZARD' | 'BARBARIAN';

export type UpgradeType = 
  'HEALTH' | 'SPEED' | 'DAMAGE' | 'FIRE_RATE' | 'MULTISHOT' | 'DASH_COOLDOWN' |
  'SKILL_ORBITAL' | 'SKILL_THUNDER' | 'SKILL_REGEN' | 'SKILL_MAGNET' |
  'SKILL_DASH' | 'SKILL_WEAPON' |
  'CRIT_RATE' | 'CRIT_DAMAGE' | 'DEFENSE' | 'MAX_MANA';

export interface Upgrade {
  id: string;
  type: UpgradeType;
  name: string;
  description: string;
  rarity: 'COMMON' | 'RARE' | 'LEGENDARY';
  value: number;
}

export type ProjectileType = 'MAGIC' | 'ARROW' | 'AXE' | 'FIREBALL' | 'ICE';
export type AbilityType = 'METEOR' | 'ARROW_RAIN' | 'AXE_AURA' | 'FIREBALL' | 'AXE_SPIN' | 'NONE';
export type ItemType = 'WEAPON' | 'ARMOR' | 'ACCESSORY' | 'POTION' | 'CORE' | 'PET';
export type Rarity = 'COMMON' | 'RARE' | 'EPIC' | 'LEGENDARY' | 'MYTHIC';
export type StatusEffectType = 'SLOW' | 'BURN' | 'STUN' | 'FREEZE' | 'POISON';

export interface PlayerStats {
  maxHealth: number;
  maxMana: number;
  regen: number; 
  manaRegen: number; 
  moveSpeed: number;
  damage: number;
  fireRate: number; 
  projectileSpeed: number;
  multishot: number;
  spread: number;
  dashCooldown: number;
  cooldownReduction: number; 
  magnetRadius: number;
  critRate: number; 
  critDamage: number; 
  defense: number; 
  skillDamage: number; 
  knockback: number; // Added knockback stat
}

export interface Item {
  id: string;
  name: string;
  type: ItemType;
  stats: Partial<PlayerStats>; 
  rarity: Rarity;
  price: number;
  level: number;
  cp?: number; // Combat Power
  projectileType?: ProjectileType;
  ability?: AbilityType;
  description?: string;
  stackSize?: number; 
  quantity?: number; 

  // Set Mechanics
  setName?: string;
  setBonus?: string; 
  setBonusStats?: Partial<PlayerStats>;

  // Status Effects
  onHitEffect?: {
      type: StatusEffectType;
      duration: number;
      value?: number; // e.g. 0.5 for 50% slow, or damage per tick
      chance?: number; // 0-1
  };
}

export interface EnemyData {
  id: number;
  position: Vector3;
  type: number; 
  health: number;
  maxHealth: number;
  speed: number;
  radius: number;
  scale: number;
  active: boolean;
  state?: 'CHASE' | 'CHARGE_PREP' | 'CHARGE' | 'SHOOT';
  stateTimer?: number;
  chargeDir?: Vector3;

  // Status Effects
  burnTimer?: number;
  burnDamage?: number; // Damage per second
  poisonTimer?: number;
  poisonDamage?: number; // Damage per second
  freezeTimer?: number; // Stun/Freeze
  slowTimer?: number;
  slowFactor?: number;
}

export interface BulletData {
  id: number;
  position: Vector3;
  velocity: Vector3;
  active: boolean;
  lifetime: number;
  type: ProjectileType; 
  state?: number; 
  pierce?: number; 
  hitIds: number[]; 
  damageMultiplier?: number;
  knockback?: number; // Added

  // Effect transfer
  effect?: {
      type: StatusEffectType;
      duration: number;
      value?: number;
      chance?: number;
  };
}

export interface Obstacle {
    id: number;
    position: Vector3;
    radius: number;
    type: 'TREE' | 'ROCK' | 'HOUSE';
    scale?: number;
}

export interface CrateData {
  id: number;
  position: Vector3;
  active: boolean;
  rotation: number;
  hp: number;
  maxHp: number;
}

export interface DropData {
  id: number;
  position: Vector3;
  item: Item | null; 
  type: 'ITEM' | 'GOLD' | 'XP' | 'GEM';
  active: boolean;
  value: number;
  rotation: number;
}

export interface SkillLevels {
    orbital: number;
    thunder: number;
    regen: number;
    magnet: number;
    dash: number;
    weapon: number;
}

export interface PassiveSkillState {
    orbitalCooldown: number;
    orbitalMaxCooldown: number;
    thunderCooldown: number;
    thunderMaxCooldown: number;
}

