const INITIAL_STATS: PlayerStats = {
  maxHealth: 100,
  maxMana: 100,
  regen: 1.0, 
  manaRegen: 1.0,
  moveSpeed: 10,
  damage: 15,
  fireRate: 2.0,
  projectileSpeed: 20,
  multishot: 1,
  spread: 0.2,
  dashCooldown: 4.0, 
  cooldownReduction: 0,
  magnetRadius: 5.0,
  critRate: 0.05,
  critDamage: 1.5,
  defense: 0,
  skillDamage: 1.0,
  knockback: 0.5 // Default knockback
};

// Helper to calculate CP
const calculateCP = (stats: Partial<PlayerStats>) => {
    let score = 0;
    // Weighted Stats
    if (stats.damage) score += stats.damage * 10;
    if (stats.maxHealth) score += stats.maxHealth * 0.5;
    if (stats.maxMana) score += stats.maxMana * 0.5;
    if (stats.defense) score += stats.defense * 8;
    if (stats.moveSpeed) score += stats.moveSpeed * 50; // Higher weight for speed
    if (stats.fireRate) score += stats.fireRate * 20;

    // Percentages (Stored as 0.1 for 10%)
    if (stats.critRate) score += stats.critRate * 500;
    if (stats.critDamage) score += stats.critDamage * 200;
    if (stats.cooldownReduction) score += stats.cooldownReduction * 300;
    if (stats.skillDamage) score += stats.skillDamage * 200;
    if (stats.multishot) score += stats.multishot * 100;
    if (stats.regen) score += stats.regen * 10;
    if (stats.manaRegen) score += stats.manaRegen * 10;
    if (stats.knockback) score += stats.knockback * 20;

    return Math.floor(score);
};

const calculateStats = (base: PlayerStats, equipment: GameState['equipment']) => {
  const final = { ...base };
  const sets: Record<string, number> = {};

  // 1. Apply Equipment Stats (Including Pet)
  Object.values(equipment).forEach(item => {
    if (item) {
        if (item.stats) {
            Object.entries(item.stats).forEach(([key, val]) => {
                const k = key as keyof PlayerStats;
                let v = val as number;

                // NERF: Weapons give 50% less damage stat
                if (item.type === 'WEAPON' && k === 'damage') {
                    v *= 0.5;
                }
                // NERF: Armor gives 50% less defense stat
                if (item.type === 'ARMOR' && k === 'defense') {
                    v *= 0.5;
                }

                if (k === 'moveSpeed' || k === 'fireRate') {
                     // @ts-ignore
                     final[k] += v;
                } else if (k === 'cooldownReduction') {
                     // Additive percentage (capped at some point elsewhere if needed)
                     final[k] = Math.min(0.75, final[k] + v);
                } else {
                     // @ts-ignore
                     final[k] += v;
                }
            });
        }
        if (item.setName) {
            sets[item.setName] = (sets[item.setName] || 0) + 1;
        }
    }
  });

  // 2. Apply Set Bonuses
  Object.entries(sets).forEach(([setName, count]) => {
      if (count >= 3) {
          const setItem = Object.values(equipment).find(i => i?.setName === setName);
          if (setItem && setItem.setBonusStats) {
              Object.entries(setItem.setBonusStats).forEach(([stat, val]) => {
                  if (stat === 'damage' || stat === 'moveSpeed' || stat === 'fireRate') {
                      // Multiplier for these stats in bonus
                      // @ts-ignore
                      final[stat] *= (1 + val);
                  } else {
                      // Additive for others
                      // @ts-ignore
                      final[stat] += val;
                  }
              });
          }
      }
  });

  // 3. Staff Slowdown (50% slower attack speed)
  if (equipment.weapon && equipment.weapon.projectileType === 'MAGIC') {
      final.fireRate *= 0.5;
  }

  // CAP MULTISHOT at 7
  if (final.multishot > 7) final.multishot = 7;

  return { stats: final, cp: calculateCP(final) };
};

// Generate Obstacles
const generateObstacles = (): Obstacle[] => {
    const obs: Obstacle[] = [];

    // Trees
    for(let i=0; i<40; i++) {
        const x = (Math.random() - 0.5) * ARENA_SIZE * 1.5; // Reduced spread slightly
        const z = (Math.random() - 0.5) * ARENA_SIZE * 1.5;
        if (Math.sqrt(x*x + z*z) > 20 && Math.sqrt(x*x + z*z) < (ARENA_SIZE / 2) - 5) {
            obs.push({
                id: Math.random(),
                position: new Vector3(x, 0, z),
                radius: 1.0, // Collider radius
                type: 'TREE',
                scale: 1 + Math.random() * 2
            });
        }
    }

    // Rocks
    for(let i=0; i<20; i++) {
        const x = (Math.random() - 0.5) * ARENA_SIZE * 1.5;
        const z = (Math.random() - 0.5) * ARENA_SIZE * 1.5;
        if (Math.sqrt(x*x + z*z) > 15 && Math.sqrt(x*x + z*z) < (ARENA_SIZE / 2) - 5) {
            obs.push({
                id: Math.random(),
                position: new Vector3(x, 0, z),
                radius: 1.5,
                type: 'ROCK',
                scale: 0.5 + Math.random()
            });
        }
    }

    // House (Static position)
    obs.push({
        id: 999,
        position: new Vector3(-30, 0, 30),
        radius: 4.5, // Large collider for house
        type: 'HOUSE'
    });

    return obs;
};

// Generate Crates
const generateCrates = (): CrateData[] => {
    return new Array(25).fill(0).map((_, i) => ({
        id: i,
        active: true,
        position: new Vector3(
            (Math.random() - 0.5) * ARENA_SIZE * 1.2, 
            1, 
            (Math.random() - 0.5) * ARENA_SIZE * 1.2
        ),
        rotation: Math.random() * Math.PI,
        hp: 30,
        maxHp: 30
    })).filter(c => c.position.length() > 20 && c.position.length() < (ARENA_SIZE / 2) - 5);
};

export const useGameStore = create<GameState>((set, get) => ({
  status: GameStatus.MENU,
  hero: 'ARCHER',
  score: 10000, // Base Gold
  gems: 10000, // Base Gems
  level: 1,
  experience: 0,
  experienceToNextLevel: 250, // Increased base from 100 to 250
  health: 100,
  mana: 100,
  playerPosition: new Vector3(0, 0, 0),
  stats: { ...INITIAL_STATS },
  baseStats: { ...INITIAL_STATS },
  totalCp: calculateCP(INITIAL_STATS),

  wave: 1,
  waveTimer: 0,
  recentRuns: [],

  skillLevels: { orbital: 0, thunder: 0, regen: 0, magnet: 0, dash: 0, weapon: 0 },
  passiveSkillState: { orbitalCooldown: 0, orbitalMaxCooldown: 1, thunderCooldown: 0, thunderMaxCooldown: 1 },
  inventory: [],
  equipment: { weapon: null, armor: null, accessory: null, pet: null },
  gachaResults: [],
  drops: [],
  obstacles: generateObstacles(), // Initialize obstacles once
  crates: [],
  skills: { dash: 0, weaponAbility: 0 },
  skillMaxCooldowns: { dash: 4.0, weaponAbility: 8.0 },
  potionCooldown: 0,
  isInvincible: false,

  isInventoryOpen: false,
  isShopOpen: false,

  setStatus: (status) => set({ status }),

  toggleInventory: () => {
      const { isInventoryOpen, isShopOpen, status } = get();
      const newState = !isInventoryOpen;

      // Pause if any UI is open
      const willBePaused = newState || isShopOpen;

      set({ 
          isInventoryOpen: newState,
          status: willBePaused ? GameStatus.PAUSED : GameStatus.PLAYING
      });
  },

  toggleShop: () => {
      const { isInventoryOpen, isShopOpen, status } = get();
      const newState = !isShopOpen;

      const willBePaused = isInventoryOpen || newState;

      set({ 
          isShopOpen: newState,
          status: willBePaused ? GameStatus.PAUSED : GameStatus.PLAYING
      });
  },

  closeAllUI: () => set({ isInventoryOpen: false, isShopOpen: false, status: GameStatus.PLAYING }),

  selectHero: (hero) => set({ hero }),

  startGame: () => {
      const state = get();
      const heroStats = HERO_STATS[state.hero];
      const startStats = { ...INITIAL_STATS, ...heroStats.stats };

      const startWeapon = { ...ITEMS_POOL.find(i => i.id === heroStats.weaponId)!, id: 'start_wep', quantity: 1 };
      startWeapon.cp = calculateCP(startWeapon.stats);

      const equipment = { weapon: startWeapon, armor: null, accessory: null, pet: null };
      const calculated = calculateStats(startStats, equipment);

      set({
        status: GameStatus.PLAYING,
        level: 1,
        experience: 0,
        experienceToNextLevel: 250, 
        health: startStats.maxHealth,
        mana: startStats.maxMana,
        baseStats: startStats,
        stats: calculated.stats,
        totalCp: calculated.cp,
        skillLevels: { orbital: 0, thunder: 0, regen: 0, magnet: 0, dash: 0, weapon: 0 },
        playerPosition: new Vector3(0, 0, 0),
        // Base Potion Quantity 50 - Ensure unique IDs to avoid conflicts, but matching is done by name/type
        inventory: [
            { ...ITEMS_POOL.find(i => i.id === 'potion_hp')!, id: `start_hp_${Math.random()}`, quantity: 50 },
            { ...ITEMS_POOL.find(i => i.id === 'potion_mana')!, id: `start_mana_${Math.random()}`, quantity: 50 }
        ], 
        equipment: equipment,
        drops: [],
        skills: { dash: 0, weaponAbility: 0 },
        obstacles: generateObstacles(),
        crates: generateCrates(),
        wave: 1,
        waveTimer: 0,
        isInventoryOpen: false,
        isShopOpen: false,
        potionCooldown: 0
      });
  },

  addScore: (amount) => set((state) => ({ score: state.score + amount })),
  addGems: (amount) => set((state) => ({ gems: state.gems + amount })),

  addExperience: (amount) => {
    const adjustedAmount = amount * 2;
    const { experience, experienceToNextLevel, level } = get();
    let newExp = experience + adjustedAmount;

    if (newExp >= experienceToNextLevel) {
      const multiplier = level < 10 ? 1.35 : 1.10;
      const nextReq = Math.floor(experienceToNextLevel * multiplier);

      set({
        experience: newExp - experienceToNextLevel,
        experienceToNextLevel: nextReq,
        level: level + 1,
        status: GameStatus.LEVEL_UP,
      });
    } else {
      set({ experience: newExp });
    }
  },

  takeDamage: (amount) => {
    const { health, status, stats, playerPosition, isInvincible, wave, recentRuns } = get();
    if (status !== GameStatus.PLAYING || isInvincible) return;

    const reductionMultiplier = 100 / (100 + stats.defense);
    const actualDamage = Math.max(1, amount * reductionMultiplier);

    const newHealth = health - actualDamage;

    window.dispatchEvent(new CustomEvent('damage', { 
        detail: { position: playerPosition, damage: actualDamage, isCrit: false, isPlayer: true } 
    }));

    if (newHealth <= 0) {
      set({ 
          health: 0, 
          status: GameStatus.GAME_OVER,
          recentRuns: [wave, ...recentRuns.slice(0, 4)] // Store last 5 runs
      });
    } else {
      set({ health: newHealth });
    }
  },

  damageCrate: (id, amount) => {
      set((state) => {
          const crateIndex = state.crates.findIndex(c => c.id === id);
          if (crateIndex === -1) return { crates: state.crates };

          const newCrates = [...state.crates];
          const crate = { ...newCrates[crateIndex] };

          if (!crate.active) return { crates: state.crates };

          crate.hp -= amount;

          if (crate.hp <= 0) {
              crate.active = false;
          }

          newCrates[crateIndex] = crate;
          return { crates: newCrates };
      });
  },

  useMana: (amount) => {
      const { mana } = get();
      if (mana >= amount) {
          set({ mana: mana - amount });
          return true;
      }
      return false;
  },

  heal: (amount) => set((state) => ({ 
    health: Math.min(state.health + amount, state.stats.maxHealth) 
  })),

  restoreMana: (amount) => set((state) => ({ 
    mana: Math.min(state.mana + amount, state.stats.maxMana) 
  })),

  setPlayerPosition: (pos) => set({ playerPosition: pos }),
  setInvincible: (invincible) => set({ isInvincible: invincible }),

  spawnDrop: (position, type, value, rarityOverride) => set((state) => {
      if (state.drops.length > 99) return { drops: state.drops };

      let item = null;
      // Filter out PETS from spawning as loot
      if (type === 'ITEM') {
          let pool = ITEMS_POOL.filter(i => i.type !== 'PET');

          if (rarityOverride) {
              pool = pool.filter(i => i.rarity === rarityOverride && i.type !== 'POTION' && i.type !== 'CORE');
              if (pool.length === 0) pool = ITEMS_POOL.filter(i => i.type !== 'POTION' && i.type !== 'CORE' && i.type !== 'PET');
          } else {
               const r = Math.random();
               if (r > 0.90) { // 10% Potion
                   pool = pool.filter(i => i.type === 'POTION');
               } else if (r > 0.60) { // 30% Core
                   pool = pool.filter(i => i.type === 'CORE');
               } else { // 60% Gear
                   pool = pool.filter(i => (i.rarity === 'COMMON' || i.rarity === 'RARE') && i.type !== 'POTION' && i.type !== 'CORE');
               }
          }

          if (pool.length > 0) {
              const template = pool[Math.floor(Math.random() * pool.length)];
              item = { ...template, id: Math.random().toString(), stats: { ...template.stats }, onHitEffect: template.onHitEffect }; 
              item.quantity = 1;

              // Random Plus Logic
              if (item.type === 'WEAPON' || item.type === 'ARMOR' || item.type === 'ACCESSORY') {
                   const plusChance = Math.random();
                   let plus = 0;
                   if (plusChance > 0.95) plus = 3;
                   else if (plusChance > 0.85) plus = 2;
                   else if (plusChance > 0.60) plus = 1;

                   if (plus > 0) {
                       item.level += plus;
                       Object.keys(item.stats).forEach((k) => {
                           const key = k as keyof PlayerStats;
                           const v = item.stats[key]!;
                           if (key === 'fireRate' || key === 'moveSpeed' || key === 'critRate' || key === 'cooldownReduction' || key === 'skillDamage') {
                               item.stats[key] = parseFloat((v * (1 + 0.05 * plus)).toFixed(2));
                           } else {
                               item.stats[key] = Math.ceil(v * (1 + 0.1 * plus));
                           }
                       });
                   }
              }
              // Calculate CP for new item
              item.cp = calculateCP(item.stats);
          }
      }

      return {
          drops: [...state.drops, {
              id: Math.random(),
              position: position.clone(),
              type,
              value,
              item,
              active: true,
              rotation: Math.random() * Math.PI
          }]
      };
  }),

  collectDrop: (id) => set((state) => {
      const drop = state.drops.find(d => d.id === id);
      if (!drop) return { drops: state.drops };

      const newDrops = state.drops.filter(d => d.id !== id);

      if (drop.type === 'XP') {
         get().addExperience(drop.value);
      } else if (drop.type === 'GOLD') {
         get().addScore(drop.value);
      } else if (drop.type === 'GEM') {
         get().addGems(drop.value);
      } else if (drop.type === 'ITEM' && drop.item) {
          const existingStack = state.inventory.find(i => i.name === drop.item!.name && (i.type === 'POTION' || i.type === 'CORE'));
          if (existingStack) {
              existingStack.quantity = (existingStack.quantity || 1) + 1;
              return { drops: newDrops, inventory: [...state.inventory] };
          }
          return { drops: newDrops, inventory: [...state.inventory, { ...drop.item }] };
      }

      return { drops: newDrops };
  }),

  triggerSkillCooldown: (skill) => set((state) => {
      const level = skill === 'dash' ? state.skillLevels.dash : state.skillLevels.weapon;
      const reduction = Math.min(0.5, level * 0.1); 
      const cooldown = state.skillMaxCooldowns[skill] * (1 - state.stats.cooldownReduction) * (1 - reduction);

      return {
          skills: { ...state.skills, [skill]: cooldown }
      };
  }),

  updatePassiveCooldowns: (partial) => set((state) => ({
      passiveSkillState: { ...state.passiveSkillState, ...partial }
  })),

  advanceWave: () => set((state) => ({ wave: state.wave + 1, waveTimer: 0 })),

  tickCooldowns: (delta) => {
      const state = get();
      const newSkills = {
          dash: Math.max(0, state.skills.dash - delta),
          weaponAbility: Math.max(0, state.skills.weaponAbility - delta)
      };

      const regenAmount = (state.stats.regen + state.skillLevels.regen) * delta;
      const manaRegenAmount = state.stats.manaRegen * delta;

      const newHealth = Math.min(state.stats.maxHealth, state.health + regenAmount);
      const newMana = Math.min(state.stats.maxMana, state.mana + manaRegenAmount);

      // Auto Potion
      let newPotionCD = Math.max(0, state.potionCooldown - delta);
      let newHealthAfterPot = newHealth;
      let newManaAfterPot = newMana;
      let inventory = state.inventory;

      if (newPotionCD <= 0) {
          const hpThreshold = state.stats.maxHealth * 0.3;
          const manaThreshold = state.stats.maxMana * 0.3;
          let usedPotion = false;

          // Find Potions by Name, as IDs vary
          if (newHealth < hpThreshold) {
              const hpPotIndex = inventory.findIndex(i => i.type === 'POTION' && i.name === 'Health Potion');
              if (hpPotIndex !== -1) {
                  const pot = inventory[hpPotIndex];
                  newHealthAfterPot = Math.min(state.stats.maxHealth, newHealth + (pot.stats.maxHealth || 50));
                  usedPotion = true;

                  // Clone inventory to trigger update
                  inventory = [...inventory];
                  if ((pot.quantity || 1) > 1) {
                      inventory[hpPotIndex] = { ...pot, quantity: (pot.quantity || 1) - 1 };
                  } else {
                      inventory.splice(hpPotIndex, 1);
                  }
              }
          }

          if (!usedPotion && newMana < manaThreshold) {
               const manaPotIndex = inventory.findIndex(i => i.type === 'POTION' && i.name === 'Mana Potion');
               if (manaPotIndex !== -1) {
                  const pot = inventory[manaPotIndex];
                  newManaAfterPot = Math.min(state.stats.maxMana, newMana + (pot.stats.maxMana || 50));
                  usedPotion = true;

                  inventory = [...inventory];
                  if ((pot.quantity || 1) > 1) {
                      inventory[manaPotIndex] = { ...pot, quantity: (pot.quantity || 1) - 1 };
                  } else {
                      inventory.splice(manaPotIndex, 1);
                  }
               }
          }

          if (usedPotion) {
              newPotionCD = 5; 
          }
      }

      set({
          skills: newSkills,
          health: newHealthAfterPot,
          mana: newManaAfterPot,
          potionCooldown: newPotionCD,
          inventory: inventory,
          waveTimer: state.waveTimer + delta
      });
  },

  applyUpgrade: (upgrade) => set((state) => {
    const newBase = { ...state.baseStats };
    const newSkillLevels = { ...state.skillLevels };

    switch (upgrade.type) {
      case 'HEALTH': newBase.maxHealth += upgrade.value; break;
      case 'MAX_MANA': newBase.maxMana += upgrade.value; break;
      case 'DEFENSE': newBase.defense += upgrade.value; break;
      case 'SPEED': newBase.moveSpeed *= (1 + upgrade.value); break;
      case 'DAMAGE': newBase.damage *= (1 + upgrade.value); break;
      case 'FIRE_RATE': newBase.fireRate *= (1 + upgrade.value); break;
      case 'MULTISHOT': newBase.multishot += upgrade.value; break;
      case 'DASH_COOLDOWN': newBase.dashCooldown *= (1 - upgrade.value); break;
      case 'SKILL_MAGNET': newBase.magnetRadius += upgrade.value; break;
      case 'CRIT_RATE': newBase.critRate += upgrade.value; break;
      case 'CRIT_DAMAGE': newBase.critDamage += upgrade.value; break;
      case 'SKILL_ORBITAL': newSkillLevels.orbital++; break;
      case 'SKILL_THUNDER': newSkillLevels.thunder++; break;
      case 'SKILL_REGEN': newSkillLevels.regen += upgrade.value; break;
      case 'SKILL_MAGNET': newSkillLevels.magnet += upgrade.value; break;
      case 'SKILL_DASH': newSkillLevels.dash++; break;
      case 'SKILL_WEAPON': newSkillLevels.weapon++; break;
    }
    const calculated = calculateStats(newBase, state.equipment);
    return { 
        baseStats: newBase,
        stats: calculated.stats,
        totalCp: calculated.cp,
        skillLevels: newSkillLevels,
        health: upgrade.type === 'HEALTH' ? Math.min(state.health + 30, calculated.stats.maxHealth) : state.health,
        mana: upgrade.type === 'MAX_MANA' ? Math.min(state.mana + 20, calculated.stats.maxMana) : state.mana,
        status: GameStatus.PLAYING,
        skillMaxCooldowns: {
            ...state.skillMaxCooldowns,
            dash: upgrade.type === 'DASH_COOLDOWN' ? state.skillMaxCooldowns.dash * (1 - upgrade.value) : state.skillMaxCooldowns.dash
        }
    };
  }),

  equipItem: (item) => set((state) => {
    if (item.type === 'POTION' || item.type === 'CORE') return state;

    let reqLevel = 1;
    if (item.rarity === 'RARE') reqLevel = 5;
    if (item.rarity === 'EPIC') reqLevel = 10;
    if (item.rarity === 'LEGENDARY') reqLevel = 15;
    if (item.rarity === 'MYTHIC') reqLevel = 20;

    if (state.level < reqLevel) return state; 

    const slot = item.type.toLowerCase() as keyof GameState['equipment'];
    const oldItem = state.equipment[slot];
    const newEquipment = { ...state.equipment, [slot]: item };
    const calculated = calculateStats(state.baseStats, newEquipment);
    let newInv = state.inventory.filter(i => i !== item);
    if (oldItem) newInv.push(oldItem);
    return { equipment: newEquipment, stats: calculated.stats, totalCp: calculated.cp, inventory: newInv };
  }),

  unequipItem: (slot) => set((state) => {
    const item = state.equipment[slot];
    if (!item) return state;
    const newEquipment = { ...state.equipment, [slot]: null };
    const calculated = calculateStats(state.baseStats, newEquipment);
    return { equipment: newEquipment, stats: calculated.stats, totalCp: calculated.cp, inventory: [...state.inventory, item] };
  }),

  // AUTO EQUIP LOGIC
  autoEquip: () => {
      const state = get();
      const slots: { slot: keyof GameState['equipment'], type: ItemType }[] = [
          { slot: 'weapon', type: 'WEAPON' },
          { slot: 'armor', type: 'ARMOR' },
          { slot: 'accessory', type: 'ACCESSORY' },
          { slot: 'pet', type: 'PET' }
      ];

      // Pool all available items (Inventory + Equipped)
      let pool = [...state.inventory];
      Object.values(state.equipment).forEach(item => {
          if (item) pool.push(item);
      });

      const newEquipment = { ...state.equipment };
      const newInventory: Item[] = [];

      // Determine level requirements per rarity
      const getReqLevel = (rarity: Rarity) => {
           if (rarity === 'MYTHIC') return 20;
           if (rarity === 'LEGENDARY') return 15;
           if (rarity === 'EPIC') return 10;
           if (rarity === 'RARE') return 5;
           return 1;
      };

      // Find best for each slot
      slots.forEach(({ slot, type }) => {
          const candidates = pool.filter(i => i.type === type && state.level >= getReqLevel(i.rarity));

          if (candidates.length > 0) {
              // Ensure CP is set
              candidates.forEach(c => { if(!c.cp) c.cp = calculateCP(c.stats) });
              // Sort Descending CP
              candidates.sort((a, b) => (b.cp || 0) - (a.cp || 0));

              const best = candidates[0];
              newEquipment[slot] = best;

              // Remove best from pool for subsequent checks
              pool = pool.filter(i => i.id !== best.id);
          } else {
              // No candidate?
              newEquipment[slot] = null;
          }
      });

      // Remainder goes to inventory
      newInventory.push(...pool);

      const calculated = calculateStats(state.baseStats, newEquipment);

      set({
          equipment: newEquipment,
          inventory: newInventory,
          stats: calculated.stats,
          totalCp: calculated.cp
      });
  },

  buyItem: (item, quantity = 1) => {
      const state = get();
      const totalCost = item.price * quantity;
      if (state.score >= totalCost) {
          const existing = state.inventory.find(i => i.name === item.name && (item.type === 'POTION' || item.type === 'CORE'));
          let newInv = [...state.inventory];
          if (existing) {
              existing.quantity = (existing.quantity || 1) + quantity;
          } else {
              if (item.type === 'POTION' || item.type === 'CORE') {
                  newInv.push({ ...item, quantity: quantity, id: Math.random().toString() });
              } else {
                  for(let i=0; i<quantity; i++) {
                       const newItem = { ...item, quantity: 1, id: Math.random().toString(), stats: { ...item.stats } };
                       newItem.cp = calculateCP(newItem.stats);
                       newInv.push(newItem);
                  }
              }
          }
          set({ score: state.score - totalCost, inventory: newInv });
          return true;
      }
      return false;
  },

  sellItem: (item) => set((state) => {
      let newInv = state.inventory.filter(i => i !== item);
      const sellValue = Math.floor(item.price * 0.4);
      return { inventory: newInv, score: state.score + sellValue };
  }),

  sellItems: (items) => set((state) => {
      const idsToSell = new Set(items.map(i => i.id));
      let sellValueTotal = 0;
      const newInv = state.inventory.filter(i => {
          if (idsToSell.has(i.id)) {
              sellValueTotal += Math.floor(i.price * 0.4);
              return false;
          }
          return true;
      });
      return { inventory: newInv, score: state.score + sellValueTotal };
  }),

  performSummon: (amount) => {
    const state = get();
    const COST = amount === 1 ? 100 : 900; 

    if (state.gems < COST) return false;

    const combinedPool = [...ITEMS_POOL.filter(i => i.type !== 'POTION' && i.type !== 'CORE'), ...PETS_POOL];
    const results: Item[] = [];

    for(let i=0; i<amount; i++) {
        const roll = Math.random();
        let rarity: Rarity = 'COMMON';

        if (roll > 0.99) rarity = 'MYTHIC';
        else if (roll > 0.95) rarity = 'LEGENDARY';
        else if (roll > 0.80) rarity = 'EPIC';
        else if (roll > 0.50) rarity = 'RARE';

        let validItems = combinedPool.filter(item => item.rarity === rarity);
        if (validItems.length === 0) validItems = combinedPool.filter(item => item.rarity === 'COMMON'); 

        const template = validItems[Math.floor(Math.random() * validItems.length)];
        const newItem = { 
            ...template, 
            id: Math.random().toString(), 
            quantity: 1, 
            stats: { ...template.stats },
            onHitEffect: template.onHitEffect
        };

        const plusChance = Math.random();
        let plus = 0;
        if (plusChance > 0.90) plus = 1;
        if (plusChance > 0.98) plus = 2;
        if (plus > 0) {
            newItem.level += plus;
             Object.keys(newItem.stats).forEach((k) => {
                   const key = k as keyof PlayerStats;
                   const v = newItem.stats[key]!;
                   if (key === 'fireRate' || key === 'moveSpeed' || key === 'critRate' || key === 'cooldownReduction' || key === 'skillDamage') {
                       newItem.stats[key] = parseFloat((v * (1 + 0.05 * plus)).toFixed(2));
                   } else {
                       newItem.stats[key] = Math.ceil(v * (1 + 0.1 * plus));
                   }
             });
        }
        // Calculate CP
        newItem.cp = calculateCP(newItem.stats);

        results.push(newItem);
    }

    set({ 
        gems: state.gems - COST, 
        gachaResults: results,
        inventory: [...state.inventory, ...results],
        status: GameStatus.GACHA_REVEAL,
        isInventoryOpen: false,
        isShopOpen: false
    });
    return true;
  },

  clearGachaResults: () => set({ gachaResults: [], status: GameStatus.PLAYING, isShopOpen: true }),

  gachaSummon: () => null,

  upgradeItem: (item) => {
      const state = get();
      const core = state.inventory.find(i => i.type === 'CORE');
      const coreIndex = state.inventory.findIndex(i => i.type === 'CORE');

      const requiredCores = Math.ceil(item.level / 2);
      const goldCost = Math.floor(item.price * item.level * 0.5);

      if (state.score < goldCost) return { success: false, msg: "Not enough Gold" };
      if (!core || (core.quantity || 1) < requiredCores) return { success: false, msg: `Need ${requiredCores} Cores` };

      // Success Chance
      const chance = Math.max(10, 100 - (item.level * 10));
      const roll = Math.random() * 100;
      const success = roll < chance;

      const newInventory = [...state.inventory];
      const coreItem = newInventory[coreIndex];
      if ((coreItem.quantity || 1) > requiredCores) {
          coreItem.quantity = (coreItem.quantity || 1) - requiredCores;
      } else {
          newInventory.splice(coreIndex, 1);
      }

      set({ score: state.score - goldCost, inventory: newInventory });

      if (success) {
           const upgradeLogic = (i: Item) => {
              if (i === item) {
                  const updatedStats = { ...i.stats };
                  Object.keys(updatedStats).forEach(k => {
                      const key = k as keyof PlayerStats;
                      const val = updatedStats[key]!;
                      if (key === 'fireRate' || key === 'moveSpeed' || key === 'critRate' || key === 'cooldownReduction' || key === 'skillDamage') {
                          updatedStats[key] = parseFloat((val * 1.05).toFixed(2));
                      } else {
                          updatedStats[key] = Math.ceil(val * 1.1);
                      }
                  });
                  return {
                      ...i,
                      level: i.level + 1,
                      stats: updatedStats,
                      cp: calculateCP(updatedStats)
                  };
              }
              return i;
          };

          const updatedInventory = get().inventory.map(upgradeLogic);
          const updatedEquipment = {
              weapon: state.equipment.weapon ? upgradeLogic(state.equipment.weapon) : null,
              armor: state.equipment.armor ? upgradeLogic(state.equipment.armor) : null,
              accessory: state.equipment.accessory ? upgradeLogic(state.equipment.accessory) : null,
              pet: state.equipment.pet ? upgradeLogic(state.equipment.pet) : null,
          };
          const calculated = calculateStats(state.baseStats, updatedEquipment);

          set({ inventory: updatedInventory, equipment: updatedEquipment, stats: calculated.stats, totalCp: calculated.cp });
          return { success: true, msg: "Upgrade Successful!" };
      } else {
          return { success: false, msg: "Upgrade Failed..." };
      }
  },

  resetGame: () => set({
    status: GameStatus.MENU,
  }),
}));

